def _onedrive_env_clean(value):
    """Strip whitespace, accidental line breaks, and wrapping quotes from pasted env values."""
    if not value:
        return ''
    s = str(value).strip().replace('\r', '').replace('\n', '')
    if len(s) >= 2 and s[0] == s[-1] and s[0] in '"\'':
        s = s[1:-1].strip()
    return s


