# ═══════════════════════════════════════════════════════════════
# BACKUP SYSTEM
# ═══════════════════════════════════════════════════════════════
def _onedrive_get_access_token():
    global _onedrive_refresh_runtime
    with ONEDRIVE_LOCK:
        current_refresh = _onedrive_refresh_runtime
    if not all([ONEDRIVE_CLIENT_ID, ONEDRIVE_CLIENT_SECRET, current_refresh]):
        return None
    token_url = f'https://login.microsoftonline.com/{ONEDRIVE_TENANT}/oauth2/v2.0/token'
    body = urlencode({
        'client_id': ONEDRIVE_CLIENT_ID,
        'client_secret': ONEDRIVE_CLIENT_SECRET,
        'refresh_token': current_refresh,
        'grant_type': 'refresh_token',
        'scope': 'Files.ReadWrite offline_access',
    }).encode()
    req = urllib.request.Request(token_url, data=body, method='POST')
    req.add_header('Content-Type', 'application/x-www-form-urlencoded')
    try:
        with urllib.request.urlopen(req, timeout=60) as resp:
            result = json.loads(resp.read().decode())
    except urllib.error.HTTPError as e:
        err = e.read().decode() if e.fp else str(e)
        print(f'[OneDrive] Token request failed: {e.code} {err}', flush=True)
        return None
    except Exception as e:
        print(f'[OneDrive] Token request failed: {e}', flush=True)
        return None
    if result.get('refresh_token'):
        with ONEDRIVE_LOCK:
            _onedrive_refresh_runtime = result['refresh_token']
    return result.get('access_token')

def _onedrive_upload_session(token, path, folder, filename):
    size = path.stat().st_size
    session_url = f'https://graph.microsoft.com/v1.0/me/drive/root:/{folder}/{filename}:/createUploadSession'
    body = json.dumps({'item': {'@microsoft.graph.conflictBehavior': 'replace', 'name': filename}}).encode()
    req = urllib.request.Request(session_url, data=body, method='POST')
    req.add_header('Authorization', f'Bearer {token}')
    req.add_header('Content-Type', 'application/json')
    with urllib.request.urlopen(req, timeout=60) as resp:
        session = json.loads(resp.read().decode())
    upload_url = session.get('uploadUrl')
    if not upload_url:
        raise RuntimeError('Upload session did not return uploadUrl')

    chunk_size = max(320 * 1024, ONEDRIVE_UPLOAD_CHUNK_BYTES)
    chunk_size = (chunk_size // (320 * 1024)) * (320 * 1024)
    if chunk_size <= 0:
        chunk_size = 320 * 1024
    sent = 0
    with path.open('rb') as fh:
        while sent < size:
            chunk = fh.read(min(chunk_size, size - sent))
            if not chunk:
                break
            start = sent
            end = sent + len(chunk) - 1
            put = urllib.request.Request(upload_url, data=chunk, method='PUT')
            put.add_header('Content-Length', str(len(chunk)))
            put.add_header('Content-Range', f'bytes {start}-{end}/{size}')
            with urllib.request.urlopen(put, timeout=120) as resp:
                resp.read()
            sent = end + 1
    return sent

def upload_to_onedrive(file_path, folder=None):
    """Upload a backup to OneDrive without reading large database files into RAM."""
    folder = folder or ONEDRIVE_FOLDER
    if not all([ONEDRIVE_CLIENT_ID, ONEDRIVE_CLIENT_SECRET, _onedrive_refresh_runtime or ONEDRIVE_REFRESH_TOKEN]):
        return False
    token = _onedrive_get_access_token()
    if not token:
        return False
    path = Path(file_path)
    if not path.is_file():
        print(f'[OneDrive] Missing file: {file_path}', flush=True)
        return False
    filename = path.name
    file_size = path.stat().st_size
    upload_url = f'https://graph.microsoft.com/v1.0/me/drive/root:/{folder}/{filename}:/content'
    try:
        if file_size > ONEDRIVE_SIMPLE_UPLOAD_MAX_BYTES:
            sent = _onedrive_upload_session(token, path, folder, filename)
            print(f'[OneDrive] Uploaded {filename} ({sent} bytes, chunked) → {folder}/', flush=True)
        else:
            file_data = path.read_bytes()
            req = urllib.request.Request(upload_url, data=file_data, method='PUT')
            req.add_header('Authorization', f'Bearer {token}')
            req.add_header('Content-Type', 'application/octet-stream')
            with urllib.request.urlopen(req, timeout=120) as resp:
                resp.read()
            print(f'[OneDrive] Uploaded {filename} ({len(file_data)} bytes) → {folder}/', flush=True)
        return True
    except urllib.error.HTTPError as e:
        err = e.read().decode() if e.fp else str(e)
        print(f'[OneDrive] Upload failed: {e.code} {err}', flush=True)
        return False
    except Exception as e:
        print(f'[OneDrive] Upload failed: {e}', flush=True)
        return False

def _onedrive_upload_async(file_path):
    try:
        upload_to_onedrive(file_path)
    except Exception as e:
        print(f'[OneDrive] Background upload error: {e}', flush=True)

def prune_local_backups(keep=LOCAL_BACKUP_KEEP_COUNT, preserve_paths=None):
    backups = []
    for backup in BACKUP_DIR.glob('evacuation_*.db'):
        try:
            backups.append((backup.stat().st_mtime, backup))
        except Exception as e:
            print(f'[Backup] Skipped local backup during prune {backup}: {e}', flush=True)
    backups.sort(key=lambda item: item[0], reverse=True)
    preserve_paths = {Path(path) for path in (preserve_paths or [])}
    keep_set = set()
    for _, backup in backups:
        if backup not in preserve_paths or backup in keep_set:
            continue
        keep_set.add(backup)
    for _, backup in backups:
        if len(keep_set) >= keep:
            break
        if backup in keep_set:
            continue
        keep_set.add(backup)
    for _, backup in backups:
        if backup in keep_set:
            continue
        try:
            backup.unlink()
            print(f'[Backup] Pruned local backup: {backup}', flush=True)
        except Exception as e:
            print(f'[Backup] Failed to prune local backup {backup}: {e}', flush=True)

def do_backup(reason='scheduled', preserve_paths=None):
    """Create a timestamped backup of the database"""
    BACKUP_DIR.mkdir(exist_ok=True)
    ts = datetime.now().strftime('%Y%m%d_%H%M%S')
    backup_path = BACKUP_DIR / f'evacuation_{ts}_{reason}.db'
    try:
        # Use SQLite's built-in backup (safe even while server is running)
        src = sqlite3.connect(str(DB_PATH))
        dst = sqlite3.connect(str(backup_path))
        src.backup(dst)
        dst.close()
        src.close()
        prune_local_backups(preserve_paths=[backup_path, *(preserve_paths or [])])
        if ONEDRIVE_CLIENT_ID and ONEDRIVE_CLIENT_SECRET and (ONEDRIVE_REFRESH_TOKEN or _onedrive_refresh_runtime):
            threading.Thread(target=_onedrive_upload_async, args=(str(backup_path),), daemon=True).start()
        return str(backup_path)
    except Exception as e:
        return f"Backup failed: {e}"

def list_backups():
    BACKUP_DIR.mkdir(exist_ok=True)
    backups = sorted(BACKUP_DIR.glob('*.db'), key=lambda p: p.stat().st_mtime, reverse=True)
    return [{'name': b.name, 'size': b.stat().st_size, 'date': datetime.fromtimestamp(b.stat().st_mtime).strftime('%Y-%m-%d %H:%M:%S')} for b in backups[:20]]

def restore_backup(backup_name):
    backup_path = BACKUP_DIR / backup_name
    if not backup_path.exists():
        return {'success': False, 'error': 'Backup not found'}
    # Backup current before restoring
    do_backup('pre_restore', preserve_paths=[backup_path])
    try:
        src = sqlite3.connect(str(backup_path))
        dst = sqlite3.connect(str(DB_PATH))
        src.backup(dst)
        dst.close()
        src.close()
        return {'success': True}
    except Exception as e:
        return {'success': False, 'error': str(e)}

def auto_backup_scheduler():
    """Run automatic backup every 2 hours"""
    while True:
        time.sleep(7200)  # 2 hours
        try:
            do_backup('auto')
            print(f"[{datetime.now().strftime('%H:%M:%S')}] Auto-backup completed")
        except: pass

# ═══════════════════════════════════════════════════════════════
# WORKFLOW ENGINE — Automatic Status Transitions
# ═══════════════════════════════════════════════════════════════
def apply_workflow_rules(db, record_id, field_changed, new_value, user='system'):
    """
    Automatic status transitions:
    1. visa_status → 'Approved'  ⇒  travel_status auto-set to 'Visa Obtained'
    2. ticket_number is filled   ⇒  travel_status auto-set to 'Departed' (if visa approved)
    3. airline is filled         ⇒  (same as ticket, helps catch partial updates)
    """
    changes = []
    rec = dict(db.execute("SELECT * FROM evacuees WHERE id = ?", [record_id]).fetchone())

    # Rule 1: Visa approved → move to "Visa Obtained"
    if field_changed == 'visa_status' and new_value == 'Approved':
        if rec['travel_status'] == 'Pending':
            db.execute("UPDATE evacuees SET travel_status = 'Visa Obtained', updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [user, record_id])
            changes.append('Travel status auto-updated: Pending → Visa Obtained (visa approved)')

    # Rule 2: Ticket number entered → move to "Departed" (if visa is approved)
    if field_changed == 'ticket_number' and new_value and new_value.strip() not in ['', '-', 'Transit']:
        if rec['visa_status'] == 'Approved' and rec['travel_status'] in ('Visa Obtained', 'Pending'):
            db.execute("UPDATE evacuees SET travel_status = 'Departed', updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [user, record_id])
            changes.append(f'Travel status auto-updated: {rec["travel_status"]} → Departed (ticket entered)')

    # Rule 3: Visa rejected → keep pending but add flag
    if field_changed == 'visa_status' and new_value == 'Rejected':
        if rec['travel_status'] == 'Visa Obtained':
            db.execute("UPDATE evacuees SET travel_status = 'Pending', updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [user, record_id])
            changes.append('Travel status auto-updated: Visa Obtained → Pending (visa rejected)')

    # Log workflow actions
    for change in changes:
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('workflow', ?, ?, ?)",
                   (record_id, user, change))

    return changes

def bulk_update_visa_status(passport_list, new_status, user='system'):
    """
    Bulk update visa status for a list of passport numbers.
    Used when you receive a batch of visa approvals from KSA.
    """
    db = get_db()
    results = {'updated': 0, 'not_found': 0, 'workflow_changes': [], 'details': []}
    for pp in passport_list:
        pp = pp.strip().upper()
        if not pp: continue
        rec = db.execute("SELECT id, name, passport, email, visa_status, travel_status FROM evacuees WHERE UPPER(TRIM(passport)) = ?", [pp]).fetchone()
        if rec:
            db.execute("UPDATE evacuees SET visa_status = ?, updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?",
                       [new_status, user, rec['id']])
            workflow = apply_workflow_rules(db, rec['id'], 'visa_status', new_status, user)
            if rec['visa_status'] != 'Approved' and new_status == 'Approved':
                _queue_visa_approved_email(dict(rec), user)
            _queue_iraq_final_approval_if_ready(db, rec['id'], user)
            results['updated'] += 1
            results['details'].append(f"{rec['name']} ({pp}): visa → {new_status}" + (f" | {'; '.join(workflow)}" if workflow else ""))
            results['workflow_changes'].extend(workflow)
        else:
            results['not_found'] += 1
            results['details'].append(f"Passport {pp}: NOT FOUND in system")

    db.commit()
    db.execute("INSERT INTO audit_log (action, user, details) VALUES ('bulk_visa_update', ?, ?)",
               (user, json.dumps(results)))
    db.commit()
    db.close()
    return results

# ═══════════════════════════════════════════════════════════════
# AUTH & SECURITY HELPERS
# ═══════════════════════════════════════════════════════════════
# Server-side encryption key — generated once per deployment, stored in DB
def _get_enc_key():
    db = get_db()
    row = db.execute("SELECT value FROM settings WHERE key='enc_key'").fetchone()
    if row:
        db.close()
        return row['value']
    key = secrets.token_hex(32)
    db.execute("INSERT OR REPLACE INTO settings (key, value) VALUES ('enc_key', ?)", [key])
    db.commit(); db.close()
    return key

def encrypt_pw(plain):
    """Encrypt password for admin-only storage (not for auth — hash is used for auth)"""
    if not plain: return ''
    key = _get_enc_key()
    key_bytes = key.encode()
    encrypted = bytes([plain.encode()[i] ^ key_bytes[i % len(key_bytes)] for i in range(len(plain.encode()))])
    return base64.b64encode(encrypted).decode()

def decrypt_pw(enc):
    """Decrypt password — only called when admin requests it"""
    if not enc: return ''
    try:
        key = _get_enc_key()
        key_bytes = key.encode()
        encrypted = base64.b64decode(enc.encode())
        return bytes([encrypted[i] ^ key_bytes[i % len(key_bytes)] for i in range(len(encrypted))]).decode()
    except Exception:
        return '(encrypted)'

def hash_pw(pw): return hashlib.sha256(pw.encode()).hexdigest()

def _password_strength_error(password):
    pw = str(password or '')
    if not pw:
        return 'New password is required'
    if len(pw) < 8:
        return 'New password must be at least 8 characters long'
    return ''

def _verify_user_password(db, username, password):
    username = (username or '').strip()
    if not username or password is None:
        return False
    row = db.execute("SELECT password_hash FROM users WHERE username = ?", [username]).fetchone()
    if not row:
        return False
    return (row['password_hash'] or '') == hash_pw(str(password))

def _office_expense_access_granted(session_user):
    if not session_user:
        return False
    if session_user.get('role') != 'fee_collector':
        return True
    try:
        unlocked_until = float(session_user.get('office_expense_unlock_until') or 0)
    except Exception:
        unlocked_until = 0
    return unlocked_until > time.time()

def _grant_office_expense_access(session_user, minutes=15):
    if not session_user:
        return
    session_user['office_expense_unlock_until'] = time.time() + max(1, int(minutes)) * 60

# ═══════════════════════════════════════════════════════════════
# EMAIL NOTIFICATIONS (SAFE BACKGROUND WORKER)
# ═══════════════════════════════════════════════════════════════
EMAIL_QUEUE_MAXSIZE = int(os.environ.get('EMAIL_QUEUE_MAXSIZE', '5000'))
ADVISORY_ENQUEUE_BATCH_SIZE = int(os.environ.get('ADVISORY_ENQUEUE_BATCH_SIZE', '100'))
EMAIL_QUEUE = Queue(maxsize=max(100, EMAIL_QUEUE_MAXSIZE))
EMAIL_WORKER_STARTED = False

def _enqueue_email_job(job):
    """Bounded enqueue to prevent broadcast/admin activity from exhausting RAM."""
    try:
        EMAIL_QUEUE.put_nowait(job)
        return True
    except Full:
        print(f"[EmailQueue] full; skipped {job.get('type', 'email')} to {job.get('to', '-')}", flush=True)
        return False

def _get_setting(db, key, default=''):
    row = db.execute("SELECT value FROM settings WHERE key = ?", [key]).fetchone()
    return row['value'] if row and row['value'] is not None else default

def _is_valid_email(addr):
    if not addr: return False
    return re.match(r'^[^@\s]+@[^@\s]+\.[^@\s]+$', addr.strip()) is not None

def _is_valid_email_loose(addr):
    """Advisory/broadcast: accept common real-world addresses (labels with dots, +tags, longer TLDs)."""
    if not addr:
        return False
    s = addr.strip()
    if len(s) < 5 or s.count('@') != 1:
        return False
    local, domain = s.split('@', 1)
    local, domain = local.strip(), domain.strip()
    if not local or not domain or '.' not in domain:
        return False
    if domain.startswith('.') or domain.endswith('.') or '..' in domain:
        return False
    return True

def _load_email_config(db=None):
    close_after = False
    if db is None:
        db = get_db()
        close_after = True
    try:
        cfg = {
            'enabled': _get_setting(db, 'smtp_enabled', 'disabled') == 'enabled',
            'from_email': _get_setting(db, 'smtp_gmail_address', '').strip(),
            'app_password_enc': _get_setting(db, 'smtp_gmail_app_password', ''),
            'embassy_contact': _get_setting(db, 'smtp_embassy_contact', '+965-55977292').strip(),
            'embassy_hours': _get_setting(db, 'smtp_embassy_hours', 'Embassy opening hours').strip(),
            'embassy_name': _get_setting(db, 'smtp_embassy_staff_name', 'Awais').strip()
        }
        return cfg
    finally:
        if close_after:
            db.close()

def _send_email_smtp(to_email, subject, body_text):
    db = get_db()
    try:
        cfg = _load_email_config(db)
        if not cfg['enabled']:
            return False, 'SMTP disabled'
        if not cfg['from_email'] or not cfg['app_password_enc']:
            return False, 'SMTP not configured'
        app_password = decrypt_pw(cfg['app_password_enc'])
        if not app_password or app_password == '(encrypted)':
            return False, 'Invalid SMTP app password'

        msg = EmailMessage()
        msg['From'] = cfg['from_email']
        msg['To'] = to_email
        msg['Subject'] = subject
        msg.set_content(body_text)

        context = ssl.create_default_context()
        with smtplib.SMTP_SSL('smtp.gmail.com', 465, context=context, timeout=25) as server:
            server.login(cfg['from_email'], app_password)
            server.send_message(msg)
        return True, 'sent'
    except Exception as e:
        return False, str(e)
    finally:
        db.close()

def _queue_visa_approved_email(record, changed_by='system'):
    email = (record.get('email') or '').strip()
    if not _is_valid_email_loose(email):
        return False
    return _enqueue_email_job({
        'type': 'visa_approved',
        'to': email,
        'name': (record.get('name') or 'Applicant').strip(),
        'passport': (record.get('passport') or '').strip(),
        'record_id': record.get('id'),
        'changed_by': changed_by
    })

def _tracking_no(record_id):
    try:
        return 'PKE-' + str(int(record_id)).zfill(4)
    except Exception:
        return 'PKE-0000'

def _normalize_passport_for_match(value):
    return re.sub(r'[\s-]+', '', str(value or '').strip().upper())

PUBLIC_TRAVEL_SUCCESS_MESSAGE = {
    'en': 'Your travel details have been submitted successfully. Please go to the Embassy immediately to collect the necessary documents and your travel letter.',
    'ur': 'آپ کی سفری تفصیلات کامیابی کے ساتھ جمع ہو گئی ہیں۔ براہِ کرم ضروری دستاویزات اور اپنا سفری خط حاصل کرنے کے لیے فوری طور پر سفارت خانے تشریف لائیں۔'
}
PUBLIC_TRAVEL_LOCKED_MESSAGE = {
    'en': 'Travel details are now locked. Please contact the Embassy for any further change.',
    'ur': 'سفری تفصیلات اب لاک ہو چکی ہیں۔ کسی بھی مزید تبدیلی کے لیے براہِ کرم سفارت خانے سے رابطہ کریں۔'
}

def _record_get(record, key, default=''):
    if not record:
        return default
    try:
        return record.get(key, default)
    except AttributeError:
        try:
            return record[key]
        except Exception:
            return default

def _public_tracking_token(record_id, passport):
    key = _get_enc_key().encode()
    msg = f"{int(record_id)}:{_normalize_passport_for_match(passport)}".encode()
    return hmac.new(key, msg, hashlib.sha256).hexdigest()

def _verify_public_tracking_token(record, token):
    if not record or not token:
        return False
    expected = _public_tracking_token(_record_get(record, 'id'), _record_get(record, 'passport'))
    return hmac.compare_digest(str(token), expected)

def _public_travel_details_eligible(record):
    visa = str(_record_get(record, 'visa_status') or '').strip().lower()
    travel = str(_record_get(record, 'travel_status') or '').strip().lower()
    mofa_ksa = str(_record_get(record, 'mofa_ksa_status') or '').strip().lower()
    mofa_status = str(_record_get(record, 'mofa_status') or '').strip().lower()
    if visa in ('rejected', 'returned', 'incomplete') or travel in ('returned',):
        return False
    return (
        visa in ('approved', 'visa approved', 'ksa approved')
        or travel in ('visa obtained', 'approved', 'ready for travel details')
        or mofa_ksa == 'approved'
        or mofa_status in ('approved', 'visa approved')
    )

def _public_travel_details_locked(record):
    if str(_record_get(record, 'applicant_travel_locked') or '').strip().lower() in ('1', 'true', 'yes', 'locked'):
        return True
    if str(_record_get(record, 'travel_status') or '').strip().lower() in ('departed', 'returned'):
        return True
    if str(_record_get(record, 'fee_status') or '').strip().lower() in ('paid', 'waived'):
        return True
    if str(_record_get(record, 'embassy_letter_issued_at') or '').strip():
        return True
    try:
        return int(_record_get(record, 'embassy_letter_print_count') or 0) > 0
    except Exception:
        return False

def _public_travel_details_payload(record):
    details = {
        'travel_date': _record_get(record, 'applicant_travel_date') or '',
        'airline': _record_get(record, 'applicant_airline') or '',
        'flight_number': _record_get(record, 'applicant_flight_number') or '',
        'ticket_number': _record_get(record, 'applicant_ticket_number') or '',
        'departure_from': _record_get(record, 'applicant_departure_from') or '',
        'arrival_to': _record_get(record, 'applicant_arrival_to') or '',
        'border_route': _record_get(record, 'applicant_border_route') or '',
        'remarks': _record_get(record, 'applicant_travel_remarks') or '',
        'submitted_at': _record_get(record, 'applicant_travel_submitted_at') or '',
        'updated_at': _record_get(record, 'applicant_travel_updated_at') or '',
        'source': _record_get(record, 'applicant_travel_source') or ''
    }
    return {
        'travel_details_eligible': _public_travel_details_eligible(record),
        'travel_details_locked': _public_travel_details_locked(record),
        'travel_details_submitted': bool(details['submitted_at'] or details['updated_at'] or any(details[k] for k in (
            'travel_date', 'airline', 'flight_number', 'ticket_number', 'departure_from', 'arrival_to', 'border_route'
        ))),
        'travel_details': details,
        'travel_locked_message': PUBLIC_TRAVEL_LOCKED_MESSAGE
    }

def _letter_field(record, staff_field, applicant_field=None):
    val = _record_get(record, staff_field) or ''
    if str(val).strip():
        return val
    return _record_get(record, applicant_field) if applicant_field else val

def _is_iraq_related_record(db, record):
    if not record:
        return False
    try:
        country_val = record.get('country', '')
    except Exception:
        country_val = record['country'] if 'country' in record else ''
    if 'iraq' in str(country_val or '').strip().lower():
        return True
    try:
        passport_val = record.get('passport', '')
    except Exception:
        passport_val = record['passport'] if 'passport' in record else ''
    normalized_passport = _normalize_passport_for_match(passport_val)
    if not normalized_passport:
        return False
    row = db.execute("""
        SELECT 1
        FROM iraq_public_submissions
        WHERE UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', ''), '-', '')) = ?
        LIMIT 1
    """, [normalized_passport]).fetchone()
    return bool(row)

