def can_show_assigned_staff_contact(user):
    user = user or {}
    role = (user.get("role") or "").strip()
    show_raw = user.get("show_contact_to_applicant")
    explicit_raw = user.get("show_contact_to_applicant_explicit")
    show_text = str(show_raw if show_raw is not None else "").strip().lower()
    explicit_flag = str(explicit_raw if explicit_raw is not None else "").strip().lower() in ("1", "true", "yes", "on")
    show_flag = show_text in ("1", "true", "yes", "on")

    default_public_roles = {"field_staff", "community_desk", "inspector_field", "staff_opf"}
    if role in default_public_roles:
        if explicit_flag and show_text in ("0", "false", "no", "off"):
            return False
        return True

    if role in ("nadra_staff", "passport_staff"):
        return show_flag

    officer_roles = {
        "admin", "operator", "operator_special", "welfare_officer", "legal_officer",
        "death_case_officer", "senior_review", "ambassador_review"
    }
    if role in officer_roles:
        return show_flag

    return show_flag


def _assignment_public_note_for_staff(username):
    uname = (username or '').strip()
    if not uname:
        return "The assigned officer/staff member may contact you if further information is required."
    db = get_db()
    try:
        row = db.execute("""SELECT username, role, COALESCE(full_name, username) AS full_name,
                                   COALESCE(email, '') AS email,
                                   COALESCE(mobile_number, '') AS mobile_number,
                                   COALESCE(department, '') AS department,
                                   COALESCE(designation, '') AS designation,
                                   show_contact_to_applicant,
                                   COALESCE(show_contact_to_applicant_explicit, 0) AS show_contact_to_applicant_explicit
                            FROM users WHERE username = ? LIMIT 1""", [uname]).fetchone()
        if not row:
            return "The assigned officer/staff member may contact you if further information is required."
        staff = dict(row)
        role = staff.get('role') or ''
        mobile = staff.get('mobile_number') or ''
        designation = staff.get('designation') or role.replace('_', ' ').title() or 'Assigned Staff'
        name = staff.get('full_name') or staff.get('username') or 'Assigned Staff'
        email = staff.get('email') or ''
        department = staff.get('department') or ''
        if can_show_assigned_staff_contact(staff):
            email_line = f"\nEmail: {email}" if email else ""
            mobile_line = f"\nMobile/WhatsApp: {mobile}" if mobile else ""
            department_line = f"\nDepartment/Desk: {department}" if department else ""
            return (
                "Your request has been assigned for follow-up. The assigned staff member may contact you "
                "to obtain further information or to process your request. You may also contact the assigned "
                "staff member during working hours, quoting your reference number.\n\n"
                "Assigned Staff:\n"
                f"Name: {name}\n"
                f"Designation: {designation}"
                f"{department_line}"
                f"{email_line}"
                f"{mobile_line}"
            )
        department_line = f"Department/Desk: {department}\n" if department else ""
        return (
            "Assigned Officer/Staff:\n"
            f"Name: {name}\n"
            f"Designation: {designation}\n\n"
            f"{department_line}"
            "The assigned officer/staff member may contact you if further information is required."
        )
    except Exception:
        return "The assigned officer/staff member may contact you if further information is required."
    finally:
        db.close()


def notify_case_event(case_type, case_reference, event_type, applicant_email=None, applicant_name=None,
                      staff_username=None, staff_email=None, status=None, public_note=None,
                      priority=None, due_date=None, tracking_link=None, admin_link=None):
    try:
        case_type = (case_type or '').strip()
        case_reference = (case_reference or '').strip()
        event_type = (event_type or '').strip()
        applicant_name = (applicant_name or 'Applicant').strip()
        status = _safe_status_label(status)
        tracking_link = _tracking_link_for_case(case_type, tracking_link or '')
        admin_link = _staff_admin_link(admin_link or '')
        public_note = (public_note or '').strip()
        applicant_events = {
            'request_received', 'status_updated', 'assigned_for_followup', 'applicant_note_added',
            'more_information_requested', 'resolved', 'closed', 'stay_confirmation_requested',
            'leaving_notice_received', 'notice_period_reminder'
        }
        staff_events = {'case_assigned_to_staff', 'case_due_soon', 'case_overdue', 'case_escalated', 'new_applicant_reply', 'ambassador_review_required'}

        def _applicant_payload():
            if event_type == 'request_received':
                subject = f'Community Welfare Wing – Request Received: {case_reference}'
                body = (
                    f"Dear {applicant_name},\n\n"
                    f"Your request has been received by the Community Welfare Wing, Embassy of Pakistan, Kuwait.\n\n"
                    f"Reference Number: {case_reference}\n"
                    f"Request Type: {case_type or 'Community Welfare'}\n"
                    f"Current Status: {status}\n\n"
                    f"Please keep this reference number for follow-up.\n\n"
                    f"You may track or update your request through the official portal:\n"
                    f"{tracking_link}\n\n"
                    f"Regards,\nCommunity Welfare Wing\nEmbassy of Pakistan, Kuwait"
                )
                return subject, body
            if event_type == 'more_information_requested':
                subject = f'Community Welfare Wing – Further Information Required: {case_reference}'
                body = (
                    f"Dear {applicant_name},\n\n"
                    f"The Community Welfare Wing requires further information to continue processing your request.\n\n"
                    f"Reference Number: {case_reference}\n\n"
                    f"{public_note or 'Please review the portal for the requested information.'}\n\n"
                    f"Please provide the requested information through the portal or contact the Embassy as instructed.\n\n"
                    f"Regards,\nCommunity Welfare Wing\nEmbassy of Pakistan, Kuwait"
                )
                return subject, body
            if event_type in ('resolved', 'closed'):
                subject = f'Community Welfare Wing – Request Update: {case_reference}'
                body = (
                    f"Dear {applicant_name},\n\n"
                    f"Your request has been updated.\n\n"
                    f"Reference Number: {case_reference}\n"
                    f"Status: {status}\n\n"
                    f"Action / Remarks:\n{public_note or 'Please log in or track your request for details.'}\n\n"
                    f"If you require further assistance, you may submit a new request through the official portal.\n\n"
                    f"Regards,\nCommunity Welfare Wing\nEmbassy of Pakistan, Kuwait"
                )
                return subject, body
            subject = f'Community Welfare Wing – Status Update: {case_reference}'
            body = (
                f"Dear {applicant_name},\n\n"
                f"There is an update regarding your request.\n\n"
                f"Reference Number: {case_reference}\n"
                f"Updated Status: {status}\n\n"
                f"{public_note + chr(10) + chr(10) if public_note else ''}"
                f"Please log in or track your request through the official portal for further details:\n"
                f"{tracking_link}\n\n"
                f"Regards,\nCommunity Welfare Wing\nEmbassy of Pakistan, Kuwait"
            )
            return subject, body

        if event_type in applicant_events:
            to_email = (applicant_email or '').strip()
            subject, body = _applicant_payload()
            mobile_included = 1 if event_type == 'assigned_for_followup' and 'Mobile/WhatsApp:' in body else 0
            if not to_email:
                _insert_notification_log(case_type, case_reference, 'applicant', applicant_name, '', '', 'email', event_type, subject, body, 'skipped_no_email', 'missing_applicant_email', mobile_included)
            else:
                send_res = send_notification_email(to_email, subject, body)
                if send_res.get('ok'):
                    _insert_notification_log(case_type, case_reference, 'applicant', applicant_name, to_email, '', 'email', event_type, subject, body, 'sent', '', mobile_included)
                else:
                    reason = send_res.get('reason') or 'send_failed'
                    status_key = 'skipped_smtp_missing' if reason == 'smtp_not_configured' else 'failed'
                    _insert_notification_log(case_type, case_reference, 'applicant', applicant_name, to_email, '', 'email', event_type, subject, body, status_key, reason, mobile_included)

        if event_type in staff_events:
            staff = _notification_staff_lookup(staff_username) if staff_username else None
            s_email = (staff_email or '').strip() or ((staff or {}).get('email') or '').strip()
            s_name = ((staff or {}).get('display_name') or staff_username or 'Officer').strip()
            s_id = str((staff or {}).get('id') or '')
            subject = 'Community Welfare Case Assigned: ' + case_reference if event_type == 'case_assigned_to_staff' else f'Community Welfare Case Submitted for Senior Review: {case_reference}'
            if event_type == 'case_assigned_to_staff':
                body = (
                    f"Dear {s_name},\n\nA Community Welfare case has been assigned to you for follow-up.\n\n"
                    f"Reference: {case_reference}\nCase Type: {case_type or 'Community Welfare'}\n"
                    f"Priority: {priority or 'Normal'}\nDue Date: {due_date or '—'}\nApplicant/Subject: {applicant_name}\n\n"
                    f"Please log in to the admin portal:\n{admin_link}\n\nRegards,\nCommunity Welfare Wing Portal"
                )
            else:
                body = (
                    f"Dear {s_name},\n\nA case has been submitted for senior review.\n\n"
                    f"Reference: {case_reference}\nCase Type: {case_type or 'Community Welfare'}\n"
                    f"Priority: {priority or 'Normal'}\n\nPlease log in to the admin portal for details.\n\n"
                    f"Regards,\nCommunity Welfare Wing Portal"
                )
            if not s_email:
                _insert_notification_log(case_type, case_reference, 'staff', s_name, '', s_id, 'email', event_type, subject, body, 'skipped_no_email', 'missing_staff_email')
            else:
                send_res = send_notification_email(s_email, subject, body)
                if send_res.get('ok'):
                    _insert_notification_log(case_type, case_reference, 'staff', s_name, s_email, s_id, 'email', event_type, subject, body, 'sent', '')
                else:
                    reason = send_res.get('reason') or 'send_failed'
                    status_key = 'skipped_smtp_missing' if reason == 'smtp_not_configured' else 'failed'
                    _insert_notification_log(case_type, case_reference, 'staff', s_name, s_email, s_id, 'email', event_type, subject, body, status_key, reason)

        return {'ok': True}
    except Exception as exc:
        print(f"[notify_case_event] suppressed error: {exc}", flush=True)
        return {'ok': False, 'reason': 'suppressed_error'}


def send_welfare_notification(person, message_type, channel='portal_message'):
    person = person or {}
    name = person.get('full_name') or person.get('name') or 'Applicant'
    reference = person.get('reference') or person.get('reference_id') or person.get('roster_reference') or ''
    base = _nurse_portal_public_base_url()
    messages = {
        'stay_confirmation_request': (
            f"Embassy of Pakistan, Kuwait - Community Welfare Wing\n\n"
            f"Dear {name}, please log in to the Health Workers Portal to confirm/update your current stay arrangement and welfare record.\n\n"
            f"Reference: {reference}\nPortal: {base}/nurses/login"
        ),
        'notice_period_reminder': (
            f"Dear {name}, this is a reminder regarding your current Embassy-arranged stay record. "
            f"If you intend to leave or change your stay arrangement, please submit a Leaving Notice through the portal for proper record and follow-up."
        ),
        'welfare_followup_assigned': (
            f"A Community Welfare follow-up has been assigned for reference {reference}."
        ),
        'leaving_notice_received': (
            f"Embassy of Pakistan, Kuwait - Community Welfare Wing\n\n"
            f"Dear {name}, your Leaving Notice / Change of Stay Arrangement has been received for review.\n\n"
            f"Reference: {reference}"
        ),
        'facility_assistance_request_received': (
            f"Embassy of Pakistan, Kuwait - Community Welfare Wing\n\n"
            f"Dear {name}, your facility assistance request has been received. The Community Welfare Wing may contact you for follow-up.\n\n"
            f"Reference: {reference}"
        ),
        'alternative_stay_option_available': (
            f"Embassy of Pakistan, Kuwait - Community Welfare Wing\n\n"
            f"Dear {name}, based on your request/follow-up, the Community Welfare Wing may discuss available alternative stay options with you. Please log in to the portal or wait for an officer to contact you."
        ),
    }
    body = messages.get(message_type) or messages['stay_confirmation_request']
    subject = f"Community Welfare notification: {reference}".strip()
    channel = (channel or 'portal_message').strip().lower()
    if channel == 'email':
        ok, detail = _nurse_send_email_smtp_env(person.get('email') or '', subject, body)
        _log_welfare_notification(person, message_type, channel, subject, body, 'sent' if ok else 'not_sent', detail)
        return {'ok': ok, 'detail': detail}
    if channel == 'whatsapp':
        if not (os.environ.get('WHATSAPP_API_URL') and os.environ.get('WHATSAPP_API_TOKEN')):
            print('WhatsApp not configured; notification queued/logged only.', flush=True)
            _log_welfare_notification(person, message_type, channel, subject, body, 'queued', 'whatsapp_not_configured')
            return {'ok': False, 'detail': 'whatsapp_not_configured', 'message': body}
        print('WhatsApp API configured but direct integration is not enabled in this server build.', flush=True)
        _log_welfare_notification(person, message_type, channel, subject, body, 'queued', 'whatsapp_integration_not_enabled')
        return {'ok': False, 'detail': 'whatsapp_integration_not_enabled', 'message': body}
    print(f"[WelfareNotification] {message_type}: {reference}", flush=True)
    _log_welfare_notification(person, message_type, channel, subject, body, 'logged', '')
    return {'ok': True, 'detail': 'logged', 'message': body}


def _facility_create_welfare_followup(db, roster, note, category='Facility Assistance Request', priority='Normal'):
    roster = _facility_roster_to_dict(roster)
    try:
        reference = _welfare_next_reference(db, 'NUR')
    except Exception:
        reference = f"CWA-NUR-{datetime.now().strftime('%Y')}-{int(time.time()) % 10000:04d}"
    cur = db.execute(
        """INSERT INTO welfare_cases
           (case_reference, case_type, category, requester_name, requester_phone, requester_email,
            subject_name, subject_passport, subject_civil_id, subject_phone, subject_address,
            concern_summary, details, priority, status, escalation_level)
           VALUES (?, 'nurse', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'New', 'normal')""",
        [
            reference,
            category or 'Facility Assistance Request',
            roster.get('full_name', ''),
            roster.get('phone', ''),
            roster.get('email', ''),
            roster.get('full_name', ''),
            roster.get('passport_number', ''),
            roster.get('civil_id', ''),
            roster.get('phone', ''),
            roster.get('facility_name', ''),
            note or 'Welfare follow-up requested from stay confirmation workflow.',
            json.dumps({
                'source': 'facility_roster',
                'roster_reference': roster.get('roster_reference', ''),
                'facility_name': roster.get('facility_name', ''),
                'vendor_name': roster.get('vendor_name', ''),
                'facility_area': roster.get('facility_area') or roster.get('area', ''),
            }),
            priority or 'Normal'
        ]
    )
    _welfare_insert_action(db, cur.lastrowid, 'system', 'created', '', 'New', f'{category} created from facility workflow', False)
    return reference


def _kuwait_now():
    return datetime.utcnow() + timedelta(hours=3)


def _sql_now():
    return datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')


def _sql_dt(dt):
    return dt.strftime('%Y-%m-%d %H:%M:%S')


def _rowish_get(record, key, default=''):
    if not record:
        return default
    try:
        if isinstance(record, sqlite3.Row):
            return record[key] if key in record.keys() else default
        if isinstance(record, dict):
            return record.get(key, default)
        return getattr(record, key, default)
    except Exception:
        return default


def _normalized_vendor(value):
    return (value or '').strip()


def is_vendor_facility_checkin_eligible(record):
    professional_category = _nurse_professional_category(
        _rowish_get(record, 'professional_category') or _rowish_get(record, 'nurse_professional_category'),
        _rowish_get(record, 'designation') or _rowish_get(record, 'job_title_moh') or ''
    )
    current_arrangement = (
        _rowish_get(record, 'current_arrangement')
        or _rowish_get(record, 'current_accommodation')
        or _rowish_get(record, 'current_accommodation_status')
        or ''
    ).strip()
    if not current_arrangement and (
        _rowish_get(record, 'roster_id') or _rowish_get(record, 'roster_reference') or _rowish_get(record, 'facility_name')
    ):
        current_arrangement = 'Embassy Contracted / Arranged'
    vendor_name = _normalized_vendor(_rowish_get(record, 'vendor_name') or _rowish_get(record, 'linked_vendor_name'))
    current_status = (_rowish_get(record, 'current_status') or _rowish_get(record, 'facility_current_status') or '').strip()
    email = (_rowish_get(record, 'email') or '').strip()
    whatsapp = (_rowish_get(record, 'whatsapp_full') or '').strip()
    mobile = (_rowish_get(record, 'mobile_full') or _rowish_get(record, 'mobile') or _rowish_get(record, 'phone') or '').strip()
    active = _facility_int_value(_rowish_get(record, 'active', 1), 1)
    explicit = _facility_int_value(
        _rowish_get(record, 'vendor_facility_checkin_eligible', 0)
        or _rowish_get(record, 'vendor_facility_eligible', 0)
        or _rowish_get(record, 'aja_care_resident', 0),
        0
    )
    aja_resident = _facility_int_value(_rowish_get(record, 'aja_care_resident', 0), 0)
    return (
        professional_category in ("Nurse", "Other Health Worker")
        and (current_arrangement == "Embassy Contracted / Arranged" or aja_resident == 1)
        and (vendor_name == FACILITY_VENDOR_DEFAULT or aja_resident == 1)
        and current_status not in MONTHLY_WELFARE_CHECKIN_EXCLUDED_STATUSES
        and (active == 1 or explicit == 1)
        and bool(email or whatsapp or mobile)
    )


def _monthly_checkin_log(db, event_type, status, row=None, subject='', body='', error='', channel='email'):
    row = row or {}
    recipient_reference = (
        _rowish_get(row, 'nurse_reference')
        or _rowish_get(row, 'reference_id')
        or _rowish_get(row, 'roster_reference')
        or _rowish_get(row, 'campaign_reference')
        or ''
    )
    try:
        db.execute(
            """INSERT INTO notification_log
               (case_type, case_reference, recipient_type, recipient_name, recipient_phone, recipient_email,
                recipient_reference, channel, event_type, message_type, subject, message_body, status, error,
                sent_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, CASE WHEN ? = 'sent' THEN CURRENT_TIMESTAMP ELSE NULL END)""",
            [
                'monthly_welfare_checkin',
                _rowish_get(row, 'campaign_reference') or _rowish_get(row, 'roster_reference') or recipient_reference,
                'health_worker',
                _rowish_get(row, 'full_name') or _rowish_get(row, 'name') or '',
                _rowish_get(row, 'whatsapp_full') or _rowish_get(row, 'mobile_full') or _rowish_get(row, 'phone') or '',
                _rowish_get(row, 'email') or '',
                recipient_reference,
                channel or 'email',
                event_type,
                event_type,
                subject or '',
                body or '',
                status or '',
                error or '',
                status or '',
            ]
        )
    except Exception as exc:
        print(f'[MonthlyWelfareCheckin] notification log failed: {exc}', flush=True)


def _monthly_campaign_reference(year, month, vendor, channel):
    vendor_part = re.sub(r'[^A-Z0-9]+', '', (vendor or FACILITY_VENDOR_DEFAULT).upper())[:12] or 'VENDOR'
    channel_part = re.sub(r'[^A-Z0-9]+', '', (channel or 'email').upper())[:8] or 'EMAIL'
    return f"WCHK-{int(year):04d}{int(month):02d}-{vendor_part}-{channel_part}-{secrets.token_hex(3).upper()}"


def _select_monthly_checkin_targets(db, vendor=FACILITY_VENDOR_DEFAULT, facility_name='', target='active_vendor_residents'):
    where = [
        "COALESCE(f.vendor_name, '') = ?",
        "(COALESCE(f.active, 1) = 1 OR COALESCE(f.vendor_facility_checkin_eligible, 0) = 1)",
        "COALESCE(f.current_status, '') NOT IN ('Left Facility','Closed / Archived','Inactive')",
    ]
    vals = [vendor or FACILITY_VENDOR_DEFAULT]
    if target == 'selected_facility' and facility_name:
        where.append("COALESCE(f.facility_name, '') = ?")
        vals.append(facility_name)
    elif target == 'pending_confirmation':
        where.append("""(
            COALESCE(f.confirmation_status, '') IN ('Pending', 'Pending Nurse Confirmation')
            OR COALESCE(f.monthly_checkin_status, '') IN ('Sent', 'Pending Response')
        )""")
    elif target == 'notice_due':
        where.append("""(
            COALESCE(f.notice_period_start_date, '') != ''
            AND date(f.notice_period_start_date) <= date('now')
        )""")
    rows = db.execute(
        f"""SELECT f.id AS roster_id, f.roster_reference, f.nurse_registration_id,
                  f.full_name, f.passport_number, f.civil_id, f.phone, f.email AS roster_email,
                  f.vendor_name, f.facility_name, f.facility_area, f.area, f.current_status,
                  f.confirmation_status, f.active, f.vendor_facility_checkin_eligible,
                  f.monthly_checkin_status, f.welfare_followup_required,
                  n.id AS nurse_id, n.reference_id AS nurse_reference,
                  n.full_name AS nurse_full_name, n.email AS nurse_email,
                  n.mobile AS nurse_mobile, n.mobile_full, n.whatsapp_full,
                  n.professional_category, n.designation, n.job_title_moh,
                  n.current_accommodation, n.current_accommodation_status,
                  n.vendor_facility_checkin_eligible AS nurse_explicit_eligible
           FROM facility_roster f
           LEFT JOIN nurse_registrations n ON n.id = f.nurse_registration_id
           WHERE {' AND '.join(where)}
           ORDER BY f.facility_name, f.full_name""",
        vals
    ).fetchall()
    targets = []
    seen = set()
    for row in rows:
        d = dict(row)
        d['email'] = (d.get('nurse_email') or d.get('roster_email') or '').strip()
        d['mobile_full'] = d.get('mobile_full') or d.get('nurse_mobile') or d.get('phone') or ''
        d['whatsapp_full'] = d.get('whatsapp_full') or d.get('mobile_full') or d.get('phone') or ''
        d['full_name'] = d.get('nurse_full_name') or d.get('full_name') or ''
        d['id'] = d.get('roster_id')
        d['current_arrangement'] = d.get('current_accommodation') or d.get('current_accommodation_status') or 'Embassy Contracted / Arranged'
        d['vendor_facility_checkin_eligible'] = d.get('vendor_facility_checkin_eligible') or d.get('nurse_explicit_eligible') or 0
        key = d.get('roster_id') or f"nurse:{d.get('nurse_id') or d.get('nurse_reference')}"
        nurse_key = f"nurse:{d.get('nurse_id') or d.get('nurse_reference')}" if (d.get('nurse_id') or d.get('nurse_reference')) else ''
        if key in seen or (nurse_key and nurse_key in seen):
            continue
        if is_vendor_facility_checkin_eligible(d):
            targets.append(d)
            seen.add(key)
            if nurse_key:
                seen.add(nurse_key)
    explicit_rows = db.execute(
        """SELECT n.id AS nurse_id, n.reference_id AS nurse_reference,
                  n.full_name, n.email, n.mobile AS nurse_mobile, n.mobile_full, n.whatsapp_full,
                  n.professional_category, n.designation, n.job_title_moh,
                  n.current_accommodation, n.current_accommodation_status,
                  n.current_status, n.vendor_name,
                  n.current_hostel AS facility_name, n.facility_area, n.vendor_facility_checkin_eligible
           FROM nurse_registrations n
           LEFT JOIN facility_roster f ON f.nurse_registration_id = n.id
                AND (COALESCE(f.active, 1) = 1 OR COALESCE(f.current_status, '') = 'Left Facility')
           WHERE COALESCE(n.vendor_facility_checkin_eligible, 0) = 1
             AND COALESCE(n.vendor_name, '') = ?
             AND COALESCE(f.id, 0) = 0
           ORDER BY n.full_name""",
        [vendor or FACILITY_VENDOR_DEFAULT]
    ).fetchall()
    for row in explicit_rows:
        d = dict(row)
        d['roster_id'] = None
        d['roster_reference'] = ''
        d['nurse_registration_id'] = d.get('nurse_id')
        d['email'] = (d.get('email') or '').strip()
        d['mobile_full'] = d.get('mobile_full') or d.get('nurse_mobile') or ''
        d['whatsapp_full'] = d.get('whatsapp_full') or d.get('mobile_full') or ''
        d['current_arrangement'] = d.get('current_accommodation') or d.get('current_accommodation_status') or ''
        d['id'] = None
        key = f"nurse:{d.get('nurse_id') or d.get('nurse_reference')}"
        if key in seen:
            continue
        if is_vendor_facility_checkin_eligible(d):
            targets.append(d)
            seen.add(key)
    return targets


def _refresh_campaign_totals(db, campaign_id):
    if not campaign_id:
        return
    row = db.execute(
        """SELECT
              COUNT(*) total_targeted,
              SUM(CASE WHEN status IN ('sent','used','no_response') THEN 1 ELSE 0 END) total_sent,
              SUM(CASE WHEN status IN ('failed','skipped_smtp_missing','skipped_no_email','whatsapp_not_configured') THEN 1 ELSE 0 END) total_failed,
              SUM(CASE WHEN action_taken = 'confirmed_staying' THEN 1 ELSE 0 END) total_confirmed,
              SUM(CASE WHEN action_taken = 'intends_to_leave' THEN 1 ELSE 0 END) total_intends_to_leave,
              SUM(CASE WHEN action_taken = 'left_facility' THEN 1 ELSE 0 END) total_left_facility,
              SUM(CASE WHEN action_taken = 'details_correction' THEN 1 ELSE 0 END) total_details_correction,
              SUM(CASE WHEN welfare_response IN ('needs_assistance','callback_requested','service_difficulty') THEN 1 ELSE 0 END) total_needs_assistance,
              SUM(CASE WHEN status = 'no_response' THEN 1 ELSE 0 END) total_no_response
           FROM stay_confirmation_tokens WHERE campaign_id = ?""",
        [campaign_id]
    ).fetchone()
    d = dict(row or {})
    db.execute(
        """UPDATE stay_confirmation_campaigns
           SET total_targeted = ?, total_sent = ?, total_failed = ?, total_confirmed = ?,
               total_intends_to_leave = ?, total_left_facility = ?, total_details_correction = ?,
               total_needs_assistance = ?, total_no_response = ?, updated_at = CURRENT_TIMESTAMP
           WHERE id = ?""",
        [
            int(d.get('total_targeted') or 0), int(d.get('total_sent') or 0), int(d.get('total_failed') or 0),
            int(d.get('total_confirmed') or 0), int(d.get('total_intends_to_leave') or 0),
            int(d.get('total_left_facility') or 0), int(d.get('total_details_correction') or 0),
            int(d.get('total_needs_assistance') or 0), int(d.get('total_no_response') or 0),
            campaign_id
        ]
    )


