def _run_monthly_welfare_campaign(vendor=FACILITY_VENDOR_DEFAULT, facility_name='', channel='email',
                                  target='active_vendor_residents', created_by='system'):
    vendor = (vendor or FACILITY_VENDOR_DEFAULT).strip() or FACILITY_VENDOR_DEFAULT
    channel = (channel or MONTHLY_WELFARE_CHECKIN_CHANNEL).strip().lower() or MONTHLY_WELFARE_CHECKIN_CHANNEL
    target = (target or 'active_vendor_residents').strip() or 'active_vendor_residents'
    if vendor != FACILITY_VENDOR_DEFAULT:
        return {'success': False, 'error': 'Only AJA Care is currently approved for automated monthly welfare check-ins.'}
    if channel not in ('email', 'whatsapp'):
        return {'success': False, 'error': 'Unsupported campaign channel.'}
    now_kw = _kuwait_now()
    year, month = now_kw.year, now_kw.month
    db = get_db()
    campaign_id = None
    try:
        existing = db.execute(
            """SELECT * FROM stay_confirmation_campaigns
               WHERE campaign_year = ? AND campaign_month = ? AND campaign_type = ?
                 AND vendor_name = ? AND channel = ?
               ORDER BY id DESC LIMIT 1""",
            [year, month, MONTHLY_WELFARE_CHECKIN_TYPE, vendor, channel]
        ).fetchone()
        if existing:
            return {
                'success': True,
                'skipped': True,
                'reason': 'campaign_already_exists',
                'campaign': dict(existing),
            }
        campaign_reference = _monthly_campaign_reference(year, month, vendor, channel)
        cur = db.execute(
            """INSERT INTO stay_confirmation_campaigns
               (campaign_reference, campaign_year, campaign_month, campaign_type, vendor_name,
                facility_name, channel, target, status, created_by, started_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'running', ?, CURRENT_TIMESTAMP)""",
            [
                campaign_reference, year, month, MONTHLY_WELFARE_CHECKIN_TYPE, vendor,
                facility_name or '', channel, target, created_by or 'system'
            ]
        )
        campaign_id = cur.lastrowid
        targets = _select_monthly_checkin_targets(db, vendor=vendor, facility_name=facility_name, target=target)
        total_sent = 0
        total_failed = 0
        smtp_missing = False
        subject = 'Community Welfare Wing – Monthly Welfare Check-in'
        base = _nurse_portal_public_base_url()
        for person in targets:
            token = secrets.token_urlsafe(32)
            expires_at = _sql_dt(datetime.utcnow() + timedelta(days=14))
            reference = person.get('nurse_reference') or person.get('roster_reference') or ''
            link = f"{base}/stay-confirm?token={quote(token, safe='')}"
            email = (person.get('email') or '').strip()
            whatsapp = (person.get('whatsapp_full') or '').strip()
            mobile = (person.get('mobile_full') or person.get('phone') or '').strip()
            cur_t = db.execute(
                """INSERT INTO stay_confirmation_tokens
                   (token, campaign_id, roster_id, roster_reference, nurse_registration_id,
                    nurse_reference, vendor_name, facility_name, email, whatsapp_full, mobile_full,
                    expires_at, created_by, channel, status)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'created')""",
                [
                    token, campaign_id, person.get('roster_id'), person.get('roster_reference') or '',
                    person.get('nurse_id') or person.get('nurse_registration_id'), person.get('nurse_reference') or '',
                    vendor, person.get('facility_name') or '', email, whatsapp, mobile, expires_at,
                    created_by or 'system', channel
                ]
            )
            token_id = cur_t.lastrowid
            send_status = 'failed'
            error = ''
            body = _monthly_checkin_email_body(person.get('full_name') or '', reference, link)
            body_html = _monthly_checkin_email_html(person.get('full_name') or '', reference, link)
            if channel == 'email':
                if not email:
                    send_status = 'skipped_no_email'
                    error = 'missing_email'
                else:
                    send_res = send_notification_email(email, subject, body, body_html)
                    if send_res.get('ok'):
                        send_status = 'sent'
                    else:
                        error = send_res.get('reason') or 'send_failed'
                        send_status = 'skipped_smtp_missing' if error == 'smtp_not_configured' else 'failed'
                        smtp_missing = smtp_missing or send_status == 'skipped_smtp_missing'
            else:
                body = _monthly_checkin_whatsapp_body(person.get('full_name') or '', link)
                if not (os.environ.get('WHATSAPP_API_URL') and os.environ.get('WHATSAPP_API_TOKEN')):
                    print('WhatsApp not configured; monthly check-in not sent.', flush=True)
                    send_status = 'whatsapp_not_configured'
                    error = 'whatsapp_not_configured'
                else:
                    send_status = 'failed'
                    error = 'whatsapp_integration_not_enabled'
            db.execute(
                "UPDATE stay_confirmation_tokens SET status = ? WHERE id = ?",
                [send_status, token_id]
            )
            if person.get('roster_id'):
                roster_monthly_status = 'Sent' if send_status == 'sent' else ('Failed Delivery' if send_status in ('failed', 'skipped_smtp_missing', 'skipped_no_email', 'whatsapp_not_configured') else send_status)
                db.execute(
                    """UPDATE facility_roster
                       SET last_monthly_checkin_sent_at = CURRENT_TIMESTAMP,
                           last_monthly_checkin_campaign = ?,
                           monthly_checkin_status = ?,
                           updated_at = CURRENT_TIMESTAMP
                       WHERE id = ?""",
                    [campaign_reference, roster_monthly_status, person.get('roster_id')]
                )
            log_row = {**person, 'campaign_reference': campaign_reference, 'email': email}
            _monthly_checkin_log(db, 'monthly_welfare_checkin_sent', send_status, log_row, subject, body, error, channel)
            if send_status == 'sent':
                total_sent += 1
            else:
                total_failed += 1
        _refresh_campaign_totals(db, campaign_id)
        final_status = 'completed'
        if smtp_missing and total_sent == 0:
            final_status = 'skipped_smtp_missing'
        elif total_failed:
            final_status = 'completed_with_errors'
        db.execute(
            """UPDATE stay_confirmation_campaigns
               SET status = ?, completed_at = CURRENT_TIMESTAMP, updated_at = CURRENT_TIMESTAMP
               WHERE id = ?""",
            [final_status, campaign_id]
        )
        _refresh_campaign_totals(db, campaign_id)
        db.commit()
        campaign = dict(db.execute("SELECT * FROM stay_confirmation_campaigns WHERE id = ?", [campaign_id]).fetchone())
        return {'success': True, 'campaign': campaign, 'targeted': len(targets), 'sent': total_sent, 'failed': total_failed}
    except sqlite3.IntegrityError:
        db.rollback()
        existing = db.execute(
            """SELECT * FROM stay_confirmation_campaigns
               WHERE campaign_year = ? AND campaign_month = ? AND campaign_type = ?
                 AND vendor_name = ? AND channel = ?
               ORDER BY id DESC LIMIT 1""",
            [year, month, MONTHLY_WELFARE_CHECKIN_TYPE, vendor, channel]
        ).fetchone()
        return {'success': True, 'skipped': True, 'reason': 'campaign_already_exists', 'campaign': dict(existing) if existing else None}
    except Exception as exc:
        db.rollback()
        if campaign_id:
            try:
                db.execute(
                    "UPDATE stay_confirmation_campaigns SET status = 'completed_with_errors', updated_at = CURRENT_TIMESTAMP WHERE id = ?",
                    [campaign_id]
                )
                db.commit()
            except Exception:
                pass
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


def run_due_monthly_welfare_checkin_campaign(force=False):
    if not MONTHLY_WELFARE_CHECKIN_LOCK.acquire(blocking=False):
        return {'success': True, 'skipped': True, 'reason': 'already_running'}
    try:
        mark_monthly_checkin_no_response()
        now_kw = _kuwait_now()
        if not force and (now_kw.day != 1 or now_kw.hour < 9):
            return {'success': True, 'skipped': True, 'reason': 'not_due', 'kuwait_time': now_kw.isoformat(timespec='seconds')}
        return _run_monthly_welfare_campaign(
            vendor=FACILITY_VENDOR_DEFAULT,
            channel=MONTHLY_WELFARE_CHECKIN_CHANNEL,
            target='active_vendor_residents',
            created_by='monthly_scheduler'
        )
    except Exception as exc:
        print(f'[MonthlyWelfareCheckin] scheduler suppressed error: {exc}', flush=True)
        return {'success': False, 'error': str(exc)}
    finally:
        try:
            MONTHLY_WELFARE_CHECKIN_LOCK.release()
        except RuntimeError:
            pass


def monthly_welfare_checkin_scheduler_loop():
    while True:
        try:
            run_due_monthly_welfare_checkin_campaign(force=False)
        except Exception as exc:
            print(f'[MonthlyWelfareCheckin] background loop suppressed error: {exc}', flush=True)
        time.sleep(6 * 60 * 60)


def _load_stay_confirmation_token(db, token):
    return db.execute(
        """SELECT t.*,
                  f.roster_reference AS roster_reference_actual,
                  f.full_name AS roster_full_name,
                  f.current_status AS roster_current_status,
                  f.confirmation_status AS roster_confirmation_status,
                  f.facility_area AS roster_facility_area,
                  f.area AS roster_area,
                  f.welfare_followup_required AS roster_welfare_followup_required,
                  f.reconciliation_status AS roster_reconciliation_status,
                  f.active AS roster_active,
                  n.id AS nurse_id_actual,
                  n.reference_id AS nurse_reference_actual,
                  n.full_name AS nurse_full_name
           FROM stay_confirmation_tokens t
           LEFT JOIN facility_roster f ON f.id = t.roster_id
           LEFT JOIN nurse_registrations n ON n.id = t.nurse_registration_id
           WHERE t.token = ?
           ORDER BY t.id DESC LIMIT 1""",
        [token]
    ).fetchone()


def _stay_confirmation_token_valid(row):
    if not row:
        return False
    if row['used_at'] or row['action_taken']:
        return False
    exp = (row['expires_at'] or '').strip()
    if not exp:
        return False
    try:
        return datetime.fromisoformat(exp.replace(' ', 'T')) >= datetime.utcnow()
    except Exception:
        return False


def _monthly_checkin_followup_case(db, roster_payload, stay_action, welfare_response, remarks, preferred_contact=''):
    roster_payload = roster_payload or {}
    try:
        reference = _welfare_next_reference(db, 'MWC')
    except Exception:
        reference = f"CWA-MWC-{datetime.now().strftime('%Y')}-{int(time.time()) % 10000:04d}"
    action_label = {
        'intends_to_leave': 'Stay Arrangement Change / Intends to Leave',
        'left_facility': 'Left Facility Confirmation',
        'details_correction': 'Facility Details Correction',
    }.get(stay_action, 'Health Worker Facility Follow-up')
    if welfare_response in MONTHLY_WELFARE_CHECKIN_WELFARE_RESPONSES:
        action_label = 'Health Worker Facility Follow-up'
    details = {
        'source': 'Monthly Welfare Check-in',
        'stay_action': stay_action,
        'welfare_response': welfare_response,
        'nurse_reference': roster_payload.get('nurse_reference') or roster_payload.get('reference_id') or '',
        'roster_reference': roster_payload.get('roster_reference') or '',
        'vendor_name': roster_payload.get('vendor_name') or FACILITY_VENDOR_DEFAULT,
        'facility_name': roster_payload.get('facility_name') or '',
        'preferred_contact_method': preferred_contact or '',
    }
    cur = db.execute(
        """INSERT INTO welfare_cases
           (case_reference, case_type, category, requester_name, requester_phone, requester_email,
            subject_name, subject_phone, subject_address, concern_summary, details, priority,
            status, escalation_level)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'Normal', 'New', 'normal')""",
        [
            reference,
            'Health Worker Facility Follow-up',
            action_label,
            roster_payload.get('full_name') or roster_payload.get('nurse_name') or '',
            roster_payload.get('phone') or roster_payload.get('mobile_full') or roster_payload.get('whatsapp_full') or '',
            roster_payload.get('email') or '',
            roster_payload.get('full_name') or roster_payload.get('nurse_name') or '',
            roster_payload.get('phone') or roster_payload.get('mobile_full') or roster_payload.get('whatsapp_full') or '',
            roster_payload.get('facility_name') or '',
            remarks or action_label,
            json.dumps(details)
        ]
    )
    _welfare_insert_action(db, cur.lastrowid, 'monthly_checkin', 'created', '', 'New', action_label, False)
    return reference


def mark_monthly_checkin_no_response(campaign_id=None):
    db = get_db()
    try:
        vals = []
        where = [
            "COALESCE(action_taken, '') = ''",
            "used_at IS NULL",
            "status IN ('sent','created')",
            "datetime(created_at) <= datetime('now', '-7 days')",
        ]
        if campaign_id:
            where.append("campaign_id = ?")
            vals.append(campaign_id)
        rows = db.execute(
            f"SELECT * FROM stay_confirmation_tokens WHERE {' AND '.join(where)} LIMIT 1000",
            vals
        ).fetchall()
        campaign_ids = set()
        for row in rows:
            d = dict(row)
            db.execute("UPDATE stay_confirmation_tokens SET status = 'no_response' WHERE id = ?", [d['id']])
            if d.get('roster_id'):
                db.execute(
                    """UPDATE facility_roster
                       SET monthly_checkin_status = 'No Response',
                           updated_at = CURRENT_TIMESTAMP
                       WHERE id = ?""",
                    [d.get('roster_id')]
                )
            _monthly_checkin_log(db, 'monthly_welfare_checkin_no_response', 'no_response', d, '', '', '', d.get('channel') or 'email')
            if d.get('campaign_id'):
                campaign_ids.add(d.get('campaign_id'))
        for cid in campaign_ids:
            _refresh_campaign_totals(db, cid)
        db.commit()
        return {'success': True, 'marked': len(rows)}
    except Exception as exc:
        db.rollback()
        print(f'[MonthlyWelfareCheckin] no-response marking failed: {exc}', flush=True)
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


def stay_confirmation_page_html(token):
    token = (token or '').strip()
    invalid_html = """<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Monthly Welfare Check-in</title><style>body{font-family:Arial,sans-serif;background:#f6f9fc;color:#1f2937;margin:0}.wrap{max-width:680px;margin:0 auto;padding:32px 18px}.card{background:#fff;border:1px solid #dbe5ea;border-radius:10px;padding:22px;box-shadow:0 8px 24px rgba(15,23,42,.08)}h1{color:#15324a;margin:0 0 10px}.muted{color:#64748b;line-height:1.55}</style></head><body><main class="wrap"><section class="card"><h1>Monthly Welfare Check-in</h1><p class="muted">This confirmation link is invalid or has expired. Please log in to the Health Workers Portal to update your stay arrangement.</p></section></main></body></html>"""
    if not token:
        return invalid_html, 400
    db = get_db()
    try:
        row = _load_stay_confirmation_token(db, token)
        if not _stay_confirmation_token_valid(row):
            if row and not row['used_at'] and not row['action_taken']:
                try:
                    db.execute("UPDATE stay_confirmation_tokens SET status = 'expired' WHERE id = ?", [row['id']])
                    db.commit()
                except Exception:
                    pass
            return invalid_html, 410
        d = dict(row)
        name = d.get('nurse_full_name') or d.get('roster_full_name') or 'Health Worker'
        reference = d.get('nurse_reference_actual') or d.get('nurse_reference') or d.get('roster_reference_actual') or d.get('roster_reference') or ''
        facility = d.get('facility_name') or ''
        area = d.get('roster_facility_area') or d.get('roster_area') or ''
        vendor = d.get('vendor_name') or FACILITY_VENDOR_DEFAULT
        safe_context = ''.join([
            f"<div><span>Name</span><b>{esc(name)}</b></div>",
            f"<div><span>Reference</span><b>{esc(reference or 'N/A')}</b></div>",
            f"<div><span>Facility / Area</span><b>{esc(' / '.join([x for x in (facility, area) if x]) or 'To be confirmed')}</b></div>",
            f"<div><span>Approved Vendor / Service Provider</span><b>{esc(vendor)}</b></div>",
        ])
        html = f"""<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Monthly Welfare Check-in</title>
<style>*{{box-sizing:border-box}}body{{font-family:Arial,sans-serif;background:#f6f9fc;color:#172033;margin:0}}.wrap{{max-width:760px;margin:0 auto;padding:28px 16px}}.card{{background:#fff;border:1px solid #dbe5ea;border-radius:10px;padding:22px;box-shadow:0 8px 24px rgba(15,23,42,.08)}}h1{{color:#15324a;margin:0 0 10px;font-size:26px}}h2{{font-size:17px;color:#15324a;margin:24px 0 8px}}p{{line-height:1.55;color:#475569}}.section-note{{margin:0 0 12px;color:#64748b;font-size:14px}}.ctx{{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px;margin:14px 0 18px}}.ctx div{{border:1px solid #e2e8f0;border-radius:8px;padding:10px;background:#f8fafc}}.ctx span{{display:block;font-size:11px;text-transform:uppercase;color:#64748b;font-weight:700;margin-bottom:4px}}.ctx b{{font-size:13px}}.option-list{{display:grid;gap:12px}}label.opt{{display:block;position:relative;cursor:pointer}}label.opt input[type=radio]{{position:absolute;opacity:0;pointer-events:none}}.opt-body{{display:block;min-height:62px;border:2px solid #dbe5ea;border-radius:8px;padding:15px 16px;background:#fff;box-shadow:0 1px 0 rgba(15,23,42,.03)}}.opt-title{{display:block;font-size:16px;font-weight:800;color:#172033;line-height:1.35}}.opt-help{{display:block;margin-top:4px;color:#64748b;font-size:13px;line-height:1.35}}label.opt input:checked+.opt-body{{border-color:#2f7d4e;background:#f0fdf4;box-shadow:0 0 0 3px rgba(47,125,78,.12)}}label.opt input:focus+.opt-body{{outline:3px solid rgba(47,125,78,.22)}}textarea,input,select{{width:100%;border:1px solid #cbd5e1;border-radius:8px;padding:10px;font:inherit}}textarea{{margin-top:6px}}button{{border:0;border-radius:8px;background:#2f7d4e;color:white;padding:14px 16px;font-weight:800;cursor:pointer;width:100%;margin-top:16px;font-size:16px}}.msg{{display:none;border-radius:8px;padding:12px;margin-top:14px}}.ok{{display:block;background:#f0fdf4;color:#166534;border:1px solid #bbf7d0}}.err{{display:block;background:#fff4f4;color:#991b1b;border:1px solid #fecaca}}@media(max-width:520px){{.wrap{{padding:16px 10px}}.card{{padding:16px}}h1{{font-size:22px}}.opt-body{{min-height:68px;padding:14px}}.opt-title{{font-size:15px}}}}</style></head>
<body><main class="wrap"><section class="card"><h1>Monthly Welfare Check-in</h1><p>Please confirm your current stay arrangement so the Community Welfare Wing can maintain accurate welfare records and provide timely assistance where required.</p><div class="ctx">{safe_context}</div>
<form id="checkinForm">
<h2>Current Stay Arrangement</h2>
<p class="section-note">Choose one option.</p>
<div class="option-list">
<label class="opt"><input type="radio" name="stay_action" value="confirmed_staying" required><span class="opt-body"><span class="opt-title">I am still staying at the listed facility</span><span class="opt-help">Select this if your current stay arrangement is correct.</span></span></label>
<label class="opt"><input type="radio" name="stay_action" value="intends_to_leave"><span class="opt-body"><span class="opt-title">I intend to leave / change my stay arrangement</span><span class="opt-help">Select this if you plan to move or need guidance.</span></span></label>
<label class="opt"><input type="radio" name="stay_action" value="left_facility"><span class="opt-body"><span class="opt-title">I have already left the facility</span><span class="opt-help">Select this if you are no longer staying there.</span></span></label>
<label class="opt"><input type="radio" name="stay_action" value="details_correction"><span class="opt-body"><span class="opt-title">My facility details need correction</span><span class="opt-help">Select this if the listed facility or area is not correct.</span></span></label>
</div>
<div id="conditionalFields" style="display:grid;gap:8px;margin:10px 0"></div>
<h2>Welfare Check-in</h2>
<p class="section-note">Tell us if any welfare follow-up is needed.</p>
<div class="option-list">
<label class="opt"><input type="radio" name="welfare_response" value="no_followup" required><span class="opt-body"><span class="opt-title">I am okay and no follow-up is required</span></span></label>
<label class="opt"><input type="radio" name="welfare_response" value="needs_assistance"><span class="opt-body"><span class="opt-title">I need Embassy welfare assistance</span></span></label>
<label class="opt"><input type="radio" name="welfare_response" value="callback_requested"><span class="opt-body"><span class="opt-title">I would like a callback / meeting</span></span></label>
<label class="opt"><input type="radio" name="welfare_response" value="service_difficulty"><span class="opt-body"><span class="opt-title">I want to share a service difficulty</span></span></label>
</div>
<label style="display:block;margin-top:12px">Remarks / details for Embassy follow-up<textarea name="remarks" rows="4"></textarea></label>
<label style="display:block;margin-top:12px">Preferred contact method<select name="preferred_contact_method"><option>WhatsApp</option><option>Phone Call</option><option>Email</option></select></label>
<button id="submitBtn" type="submit">Submit Monthly Welfare Check-in</button>
</form><div id="msg" class="msg"></div></section></main>
<script>
const token={json.dumps(token)};
const fields=document.getElementById('conditionalFields');
document.querySelectorAll('input[name="stay_action"]').forEach(el=>el.addEventListener('change',()=>{{
  const v=document.querySelector('input[name="stay_action"]:checked')?.value||'';
  fields.innerHTML='';
  if(v==='intends_to_leave')fields.innerHTML='<label>Intended leaving date<input type="date" name="intended_leaving_date"></label>';
  if(v==='left_facility')fields.innerHTML='<label>Date left facility<input type="date" name="left_date"></label>';
  if(v==='details_correction')fields.innerHTML='<label>Correct facility if known<input name="correct_facility"></label><label>Correct area if known<input name="correct_area"></label>';
}}));
document.getElementById('checkinForm').addEventListener('submit',async(ev)=>{{
  ev.preventDefault();
  const fd=new FormData(ev.currentTarget);
  const payload=Object.fromEntries(fd.entries());
  payload.token=token;
  const msg=document.getElementById('msg');
  const btn=document.getElementById('submitBtn');
  btn.disabled=true;btn.textContent='Submitting...';msg.className='msg';msg.textContent='';
  try{{
    const r=await fetch('/api/stay-confirm',{{method:'POST',headers:{{'Content-Type':'application/json'}},body:JSON.stringify(payload)}});
    const d=await r.json().catch(()=>({{}}));
    if(!r.ok||d.success===false)throw new Error(d.error||'Could not submit confirmation.');
    ev.currentTarget.style.display='none';
    msg.className='msg ok';
    msg.textContent='Thank you. Your welfare check-in has been received by the Community Welfare Wing.';
  }}catch(e){{msg.className='msg err';msg.textContent=e.message||'Could not submit confirmation.';btn.disabled=false;btn.textContent='Submit Monthly Welfare Check-in';}}
}});
</script></body></html>"""
        return html, 200
    finally:
        db.close()


def api_stay_confirm_submit(data):
    token = (data.get('token') or '').strip()
    stay_action = (data.get('stay_action') or '').strip()
    welfare_response = (data.get('welfare_response') or '').strip()
    remarks = _clean_text(data.get('remarks'), 3000)
    if stay_action not in ('confirmed_staying', 'intends_to_leave', 'left_facility', 'details_correction'):
        return {'success': False, 'error': 'Please select a valid stay arrangement option.'}
    if welfare_response not in ('no_followup', 'needs_assistance', 'callback_requested', 'service_difficulty'):
        return {'success': False, 'error': 'Please select a valid welfare check-in option.'}
    db = get_db()
    try:
        row = _load_stay_confirmation_token(db, token)
        if not row:
            return {'success': False, 'error': 'This confirmation link is invalid or has expired.'}
        if row['used_at'] or row['action_taken']:
            return {'success': False, 'error': 'This monthly welfare check-in link has already been used.'}
        if not _stay_confirmation_token_valid(row):
            db.execute("UPDATE stay_confirmation_tokens SET status = 'expired' WHERE id = ?", [row['id']])
            db.commit()
            return {'success': False, 'error': 'This confirmation link is invalid or has expired.'}
        d = dict(row)
        roster_id = d.get('roster_id')
        nurse_id = d.get('nurse_registration_id')
        now = _sql_now()
        old_status = d.get('roster_current_status') or ''
        current_status = old_status
        confirmation_status = d.get('roster_confirmation_status') or ''
        monthly_status = ''
        active_value = None
        welfare_required = 1 if welfare_response in MONTHLY_WELFARE_CHECKIN_WELFARE_RESPONSES else 0
        reconciliation_status = d.get('roster_reconciliation_status') or ''
        action_required = ''
        left_date = _clean_text(data.get('left_date'), 40) or _kuwait_now().date().isoformat()
        if stay_action == 'confirmed_staying':
            current_status = 'Confirmed Staying'
            confirmation_status = 'Confirmed'
            monthly_status = 'Needs Assistance' if welfare_required else 'Confirmed Staying'
            active_value = 1
        elif stay_action == 'intends_to_leave':
            current_status = 'Intends to Leave'
            monthly_status = 'Intends to Leave'
            welfare_required = 1
            active_value = 1
            action_required = 'Stay arrangement change follow-up required'
        elif stay_action == 'left_facility':
            current_status = 'Left Facility'
            monthly_status = 'Left Facility'
            welfare_required = 1
            active_value = 0
            action_required = 'Left facility confirmation follow-up required'
        elif stay_action == 'details_correction':
            monthly_status = 'Details Correction'
            welfare_required = 1
            reconciliation_status = 'Reconciliation Required'
            action_required = 'Facility details correction required'
        if welfare_response in MONTHLY_WELFARE_CHECKIN_WELFARE_RESPONSES and stay_action == 'confirmed_staying':
            monthly_status = 'Needs Assistance'
            action_required = 'Welfare follow-up required'
        structured_note = {
            'stay_action': stay_action,
            'welfare_response': welfare_response,
            'remarks': remarks,
            'intended_leaving_date': _clean_text(data.get('intended_leaving_date'), 40),
            'left_date': _clean_text(data.get('left_date'), 40),
            'correct_facility': _clean_text(data.get('correct_facility'), 220),
            'correct_area': _clean_text(data.get('correct_area'), 160),
            'preferred_contact_method': _clean_text(data.get('preferred_contact_method'), 80),
            'token_id': d.get('id'),
            'campaign_id': d.get('campaign_id'),
        }
        roster_payload = {
            'full_name': d.get('nurse_full_name') or d.get('roster_full_name') or '',
            'nurse_reference': d.get('nurse_reference_actual') or d.get('nurse_reference') or '',
            'roster_reference': d.get('roster_reference_actual') or d.get('roster_reference') or '',
            'vendor_name': d.get('vendor_name') or FACILITY_VENDOR_DEFAULT,
            'facility_name': structured_note['correct_facility'] or d.get('facility_name') or '',
            'email': d.get('email') or '',
            'whatsapp_full': d.get('whatsapp_full') or '',
            'mobile_full': d.get('mobile_full') or '',
        }
        if roster_id:
            updates = [
                "current_status = ?",
                "monthly_checkin_status = ?",
                "last_monthly_checkin_response_at = ?",
                "welfare_followup_required = ?",
                "reconciliation_status = ?",
                "action_required = COALESCE(NULLIF(?, ''), action_required)",
                "updated_at = CURRENT_TIMESTAMP",
            ]
            vals = [current_status, monthly_status, now, welfare_required, reconciliation_status, action_required]
            if confirmation_status:
                updates.append("confirmation_status = ?")
                vals.append(confirmation_status)
            if stay_action == 'confirmed_staying':
                updates.append("last_confirmed_at = ?")
                vals.append(now)
            if active_value is not None:
                updates.append("active = ?")
                vals.append(active_value)
            if stay_action == 'left_facility':
                updates.append("left_date = ?")
                vals.append(left_date)
            if stay_action == 'details_correction':
                if structured_note['correct_facility']:
                    updates.append("facility_name = ?")
                    vals.append(structured_note['correct_facility'])
                if structured_note['correct_area']:
                    updates.append("facility_area = ?")
                    vals.append(structured_note['correct_area'])
                    updates.append("area = ?")
                    vals.append(structured_note['correct_area'])
            vals.append(roster_id)
            db.execute(f"UPDATE facility_roster SET {', '.join(updates)} WHERE id = ?", vals)
            _facility_insert_action(
                db, roster_id, 'nurse/self-service/monthly_checkin',
                'monthly_welfare_checkin_response',
                old_status,
                current_status,
                json.dumps(structured_note),
                True
            )
            if not nurse_id:
                _facility_insert_action(db, roster_id, 'monthly_checkin', 'admin_note', '', '', 'Nurse registration is not linked to this roster record.', False)
        if nurse_id:
            db.execute(
                """UPDATE nurse_registrations
                   SET current_status = ?, facility_status = ?, stay_confirmation_status = ?,
                       monthly_checkin_status = ?, updated_at = CURRENT_TIMESTAMP
                   WHERE id = ?""",
                [current_status, current_status, confirmation_status or monthly_status, monthly_status, nurse_id]
            )
            if not roster_id:
                _nurse_log(db, 'monthly_checkin_roster_link_required', d.get('nurse_reference') or '', '', 'monthly_checkin',
                           {'token_id': d.get('id'), 'campaign_id': d.get('campaign_id')})
        if not roster_id and nurse_id:
            _monthly_checkin_followup_case(db, roster_payload, 'details_correction', welfare_response, 'Monthly check-in response received without a linked roster record. Please reconcile roster linkage.', structured_note['preferred_contact_method'])
        elif stay_action in ('intends_to_leave', 'left_facility', 'details_correction') or welfare_response in MONTHLY_WELFARE_CHECKIN_WELFARE_RESPONSES:
            _monthly_checkin_followup_case(db, roster_payload, stay_action, welfare_response, remarks, structured_note['preferred_contact_method'])
        db.execute(
            """UPDATE stay_confirmation_tokens
               SET action_taken = ?, welfare_response = ?, remarks = ?, used_at = CURRENT_TIMESTAMP,
                   status = 'used'
               WHERE id = ?""",
            [stay_action, welfare_response, json.dumps(structured_note), d['id']]
        )
        _monthly_checkin_log(db, 'monthly_welfare_checkin_response', 'received', {**d, **roster_payload}, '', json.dumps(structured_note), '', d.get('channel') or 'email')
        if d.get('campaign_id'):
            _refresh_campaign_totals(db, d.get('campaign_id'))
        db.commit()
        return {'success': True, 'message': 'Thank you. Your welfare check-in has been received by the Community Welfare Wing.'}
    except Exception as exc:
        db.rollback()
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


def api_nurse_stay_confirmation(data):
    ref = (data.get('nurse_reference_id') or data.get('reference_id') or '').strip()
    passport = _nurse_normalize_passport(data.get('passport_number') or '')
    verifier = (data.get('verifier') or '').strip()
    if not ref and not passport:
        return {'success': False, 'error': 'Nurse reference or passport is required.'}
    db = get_db()
    try:
        nurse = db.execute(
            """SELECT * FROM nurse_registrations
               WHERE (UPPER(TRIM(reference_id)) = UPPER(TRIM(?)) OR UPPER(REPLACE(TRIM(passport_number), ' ', '')) = ?)
                 AND (TRIM(mobile) = TRIM(?) OR TRIM(civil_id) = TRIM(?) OR TRIM(cnic) = TRIM(?) OR ? = '')
               ORDER BY id DESC LIMIT 1""",
            [ref, passport, verifier, verifier, verifier, verifier]
        ).fetchone()
        if not nurse:
            return {'success': False, 'error': 'Unable to verify nurse record.'}
        nurse_d = dict(nurse)
        roster = _facility_find_linked_roster(db, nurse_d)
        if not roster:
            return {'success': False, 'error': 'No linked facility occupancy record was found. Please contact the Community Welfare Wing.'}
        roster_d = _facility_roster_to_dict(roster)
        option = (data.get('confirmation_option') or data.get('status') or '').strip()
        remarks = (data.get('remarks') or '').strip()
        current_facility = (data.get('current_facility_name') or data.get('facility_name') or roster_d.get('facility_name') or '').strip()
        area = (data.get('area') or data.get('facility_area') or roster_d.get('facility_area') or roster_d.get('area') or '').strip()
        room = (data.get('room_number') or roster_d.get('room_number') or '').strip()
        bed = (data.get('bed_number') or roster_d.get('bed_number') or '').strip()
        phone = (data.get('current_phone') or nurse_d.get('mobile') or roster_d.get('phone') or '').strip()
        if not option:
            return {'success': False, 'error': 'Please select your stay arrangement confirmation option.'}
        current_status = roster_d.get('current_status') or 'Assigned'
        confirmation_status = roster_d.get('confirmation_status') or 'Pending Nurse Confirmation'
        welfare_followup = int(roster_d.get('welfare_followup_required') or 0)
        visible_note = 'Stay arrangement confirmation submitted.'
        if option == 'currently_staying':
            current_status = 'Confirmed Staying'
            confirmation_status = 'Stay Confirmed'
        elif option == 'shifted_from_facility':
            current_status = 'Left Facility'
            confirmation_status = 'Shifted from Facility'
            visible_note = 'Resident update submitted: shifted from facility.'
        elif option == 'intends_to_leave':
            current_status = 'Intends to Leave'
            confirmation_status = 'Intends to Leave'
            visible_note = 'Resident update submitted: intends to leave or change stay arrangement.'
        elif option == 'details_correction':
            current_status = 'Reconciliation Required'
            confirmation_status = 'Correction Requested'
            visible_note = 'Resident update submitted: facility details require correction.'
        elif option == 'assistance_requested':
            current_status = 'Field Follow-up Required'
            confirmation_status = 'Welfare Follow-up Requested'
            welfare_followup = 1
            visible_note = 'Facility assistance request submitted.'
        else:
            return {'success': False, 'error': 'Invalid stay arrangement option.'}
        db.execute(
            """UPDATE facility_roster
               SET facility_name = COALESCE(NULLIF(?, ''), facility_name),
                   area = COALESCE(NULLIF(?, ''), area),
                   facility_area = COALESCE(NULLIF(?, ''), facility_area),
                   room_number = COALESCE(NULLIF(?, ''), room_number),
                   bed_number = COALESCE(NULLIF(?, ''), bed_number),
                   phone = COALESCE(NULLIF(?, ''), phone),
                   current_status = ?,
                   confirmation_status = ?,
                   welfare_followup_required = ?,
                   alternative_stay_review_required = CASE WHEN ? IN ('shifted_from_facility','intends_to_leave','assistance_requested') THEN 1 ELSE alternative_stay_review_required END,
                   reconciliation_status = CASE WHEN ? = 'details_correction' THEN 'Reconciliation Required' ELSE reconciliation_status END,
                   action_required = CASE WHEN ? IN ('shifted_from_facility','intends_to_leave') THEN 'Review change of stay arrangement'
                                          WHEN ? = 'details_correction' THEN 'Resident Confirmation Required'
                                          WHEN ? = 'assistance_requested' THEN 'Welfare Follow-up Required'
                                          ELSE action_required END,
                   last_confirmed_at = CURRENT_TIMESTAMP,
                   updated_at = CURRENT_TIMESTAMP
               WHERE id = ?""",
            [current_facility, area, area, room, bed, phone, current_status, confirmation_status, welfare_followup, option, option, option, option, option, roster_d['id']]
        )
        _facility_insert_action(
            db, roster_d['id'], nurse_d.get('reference_id') or 'nurse', 'stay_confirmation',
            roster_d.get('current_status', ''), current_status,
            f"{visible_note} {remarks}".strip(), True
        )
        welfare_reference = ''
        if option in ('shifted_from_facility', 'intends_to_leave', 'assistance_requested', 'details_correction'):
            category = 'Facility Assistance Request'
            if option in ('shifted_from_facility', 'intends_to_leave'):
                category = 'Change of Stay Arrangement'
            elif option == 'details_correction':
                category = 'Resident Update'
            welfare_reference = _facility_create_welfare_followup(
                db,
                {**roster_d, 'facility_name': current_facility, 'facility_area': area, 'phone': phone},
                remarks or visible_note,
                category=category
            )
        db.commit()
        return {'success': True, 'message': 'Stay arrangement confirmation submitted.', 'welfare_reference': welfare_reference}
    except Exception as e:
        db.rollback()
        return {'success': False, 'error': str(e)}
    finally:
        db.close()


def _build_nurse_public_profile_bundle(db, rec):
    """Build portal-safe JSON for a nurse row (no password fields)."""
    professional_category = _nurse_professional_category(rec.get('professional_category'), rec.get('designation') or rec.get('job_title_moh') or '')
    acc = db.execute("""SELECT request_status, admin_remarks
                        FROM nurse_accommodation_requests
                        WHERE nurse_reference_id = ? OR UPPER(TRIM(passport_number)) = UPPER(TRIM(?))
                        ORDER BY id DESC LIMIT 1""", [rec.get('reference_id', ''), rec.get('passport_number', '')]).fetchone()
    steps = []
    completed = 0
    for col, label in NURSE_PROCESS_STEPS:
        st = 1 if int(rec.get(col, 0) or 0) == 1 else 0
        completed += st
        steps.append({'key': col, 'label': label, 'status': 'Completed' if st else 'Not Completed', 'value': st})
    total = len(NURSE_PROCESS_STEPS)
    complaints_rows = db.execute("""SELECT complaint_id, subject, category, complaint_category, priority,
                                           COALESCE(status, complaint_status) AS status,
                                           created_at, updated_at, public_response
                                    FROM nurse_complaints
                                    WHERE nurse_reference_id = ? OR UPPER(TRIM(passport_number)) = UPPER(TRIM(?))
                                    ORDER BY id DESC LIMIT 50""", [rec.get('reference_id', ''), rec.get('passport_number', '')]).fetchall()
    complaints = []
    for c in complaints_rows:
        cd = dict(c)
        actions = db.execute("""SELECT action_type, note, created_at
                                FROM nurse_complaint_actions
                                WHERE complaint_id = ? AND visible_to_nurse = 1
                                ORDER BY id DESC LIMIT 5""", [cd.get('complaint_id', '')]).fetchall()
        complaints.append({
            'complaint_id': cd.get('complaint_id', ''),
            'subject': cd.get('subject', ''),
            'category': cd.get('category', '') or cd.get('complaint_category', ''),
            'priority': cd.get('priority', ''),
            'status': cd.get('status', ''),
            'submitted_date': cd.get('created_at', ''),
            'last_update_date': cd.get('updated_at', ''),
            'public_response': cd.get('public_response', ''),
            'public_actions': [dict(a) for a in actions]
        })
    facility_row = None if professional_category == 'Doctor' else _facility_find_linked_roster(db, rec)
    facility_record = _facility_portal_dict(facility_row) if facility_row else _nurse_registration_facility_portal_dict(rec)
    if facility_record:
        latest_token = db.execute(
            """SELECT token, status, action_taken, welfare_response, used_at, created_at, expires_at
               FROM stay_confirmation_tokens
               WHERE (
                   (? != 0 AND roster_id = ?)
                   OR (? != 0 AND nurse_registration_id = ?)
               )
               ORDER BY id DESC LIMIT 1""",
            [
                int(facility_record.get('id') or 0), int(facility_record.get('id') or 0),
                int(rec.get('id') or 0), int(rec.get('id') or 0)
            ]
        ).fetchone()
        if latest_token:
            td = dict(latest_token)
            pending = (
                not td.get('used_at')
                and not td.get('action_taken')
                and (td.get('status') or '') in ('created', 'sent', 'no_response')
                and (td.get('expires_at') or '')
            )
            try:
                pending = pending and datetime.fromisoformat(str(td.get('expires_at')).replace(' ', 'T')) >= datetime.utcnow()
            except Exception:
                pending = False
            facility_record['latest_monthly_checkin_status'] = td.get('action_taken') or td.get('status') or ''
            facility_record['latest_monthly_checkin_received_at'] = td.get('used_at') or ''
            facility_record['latest_monthly_checkin_pending'] = bool(pending)
            facility_record['latest_monthly_checkin_url'] = f"/stay-confirm?token={quote(td.get('token') or '', safe='')}" if pending else ''
    return {
        'nurse_db_id': int(rec.get('id') or 0),
        'reference_id': rec.get('reference_id', ''),
        'professional_category': professional_category,
        'full_name': rec.get('full_name', ''),
        'passport_number': rec.get('passport_number', ''),
        'cnic': rec.get('cnic', ''),
        'civil_id': rec.get('civil_id', ''),
        'mobile': rec.get('mobile', ''),
        'mobile_country_code': rec.get('mobile_country_code', '') or '+965',
        'mobile_number': rec.get('mobile_number', ''),
        'mobile_full': rec.get('mobile_full', '') or rec.get('mobile', ''),
        'whatsapp_country_code': rec.get('whatsapp_country_code', '') or rec.get('mobile_country_code', '') or '+965',
        'whatsapp_number': rec.get('whatsapp_number', ''),
        'whatsapp_full': rec.get('whatsapp_full', '') or rec.get('mobile_full', '') or rec.get('mobile', ''),
        'whatsapp_same_as_mobile': int(rec.get('whatsapp_same_as_mobile') or 0),
        'emergency_country_code': rec.get('emergency_country_code', '') or '+965',
        'emergency_contact_full': rec.get('emergency_contact_full', '') or rec.get('emergency_contact', ''),
        'email': rec.get('email', ''),
        'email_status': _email_status_label(rec),
        'email_verification_sent_at': rec.get('email_verification_sent_at', ''),
        'batch_number': rec.get('batch_number', ''),
        'arrival_date': rec.get('arrival_date', ''),
        'hospital': rec.get('hospital', '') or rec.get('hospital_or_medical_center', ''),
        'qualification_degree': rec.get('qualification_degree', ''),
        'qualification_degree_other': rec.get('qualification_degree_other', ''),
        'degree_type': rec.get('degree_type', ''),
        'job_title_moh': rec.get('job_title_moh', '') or rec.get('designation', ''),
        'moh_offer_salary_kwd': rec.get('moh_offer_salary_kwd', ''),
        'grading_letter_issued': rec.get('grading_letter_issued', ''),
        'registration_status': rec.get('registration_status', ''),
        'documents_status': rec.get('documents_status', ''),
        'accommodation_status': (acc['request_status'] if acc else rec.get('accommodation_status', '') or 'N/A'),
        'remarks': rec.get('remarks', ''),
        'issue_notice': rec.get('issue_notice', ''),
        'latest_admin_remarks': rec.get('admin_remarks', ''),
        'steps': steps,
        'steps_completed': completed,
        'steps_pending': total - completed,
        'steps_total': total,
        'progress_percent': int(round((completed * 100.0) / total)) if total else 0,
        'process_last_updated_at': rec.get('updated_at', '') or rec.get('created_at', ''),
        'complaints': complaints,
        'facility_roster': facility_record,
        'login_at': rec.get('last_login_at', ''),
    }


def _find_nurse_by_login_identity(db, identity_raw):
    raw = (identity_raw or '').strip()
    if not raw:
        return None
    if '@' in raw:
        em = _nurse_normalize_email(raw)
        return db.execute(
            "SELECT * FROM nurse_registrations WHERE LOWER(TRIM(COALESCE(email,''))) = ? ORDER BY id DESC LIMIT 1",
            [em]
        ).fetchone()
    ppn = _nurse_normalize_passport(raw)
    nid = _nurse_normalize_id_key(raw)
    return db.execute(
        """SELECT * FROM nurse_registrations WHERE
            UPPER(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', '')) = ?
            OR (
                TRIM(COALESCE(civil_id,'')) != ''
                AND REPLACE(REPLACE(REPLACE(UPPER(TRIM(civil_id)), '-', ''), ' ', ''), '_', '') = ?
            )
            OR REPLACE(REPLACE(REPLACE(UPPER(TRIM(COALESCE(cnic,''))), '-', ''), ' ', ''), '_', '') = ?
            ORDER BY id DESC LIMIT 1""",
        [ppn, nid, nid]
    ).fetchone()


def _send_nurse_ack_email(record):
    to_email = (record.get('email') or '').strip()
    if not to_email or not _is_valid_email_loose(to_email):
        return False, 'missing_or_invalid_email'
    full_name = record.get('full_name', '')
    ref_id = record.get('reference_id', '')
    base = _nurse_portal_public_base_url()
    body = (
        f"Dear {full_name or 'Applicant'},\n\n"
        f"Your Pakistan Nurses Registration has been received.\n\n"
        f"Full Name: {full_name}\n"
        f"Reference ID: {ref_id}\n"
        f"Registration Status: {record.get('registration_status', 'Pending Review')}\n\n"
        f"Please log in to access your Nurse Portal:\n{base}/nurses/login\n\n"
        f"Community Welfare Wing Contact:\n"
        f"Email: parepkuwaitcwa37@gmail.com\n"
        f"Mobile: +965 5597 7292\n\n"
        f"Please send supporting documents, if requested, by email to parepkuwaitcwa37@gmail.com using this subject format:\n"
        f"NURSE DOCUMENTS - [{ref_id}] - [{full_name}]\n\n"
        f"Regards,\nCommunity Welfare Wing\nEmbassy of Pakistan, Kuwait"
    )
    return _nurse_send_email_smtp_env(to_email, 'Nurse Registration Acknowledgment', body)


def api_nurse_register(data):
    full_name = (data.get('full_name') or '').strip()
    passport = _nurse_normalize_passport(data.get('passport_number') or '')
    cnic = (data.get('cnic') or '').strip()
    civil_id = (data.get('civil_id') or '').strip()  # optional — new arrivals may not have Civil ID yet
    mobile_country_code = _normalize_country_code(data.get('mobile_country_code') or '+965')
    mobile_number = _phone_digits(data.get('mobile_number') or data.get('mobile') or '')
    mobile_full = _compose_phone(mobile_country_code, mobile_number)
    if not mobile_full:
        mobile_full = (data.get('mobile_full') or '').strip()
        mobile_number = _phone_digits(mobile_full)
    whatsapp_same_as_mobile = 1 if str(data.get('whatsapp_same_as_mobile', 1)).strip().lower() in ('1', 'true', 'yes', 'on') else 0
    whatsapp_country_code = _normalize_country_code(data.get('whatsapp_country_code') or mobile_country_code)
    whatsapp_number = _phone_digits(data.get('whatsapp_number') or '')
    whatsapp_full = mobile_full if whatsapp_same_as_mobile else _compose_phone(whatsapp_country_code, whatsapp_number)
    emergency_country_code = _normalize_country_code(data.get('emergency_country_code') or '+965')
    emergency_contact_number = _phone_digits(data.get('emergency_contact') or '')
    emergency_contact_full = _compose_phone(emergency_country_code, emergency_contact_number)
    mobile = mobile_full or (data.get('mobile') or '').strip()
    arrival_date = (data.get('arrival_date') or '').strip()
    batch_number = (data.get('batch_number') or '').strip()
    hospital = (data.get('hospital') or '').strip()
    designation = (data.get('designation') or '').strip()
    professional_category = _nurse_professional_category(data.get('professional_category'), designation)
    qualification_degree = (data.get('qualification_degree') or '').strip()
    qualification_degree_other = (data.get('qualification_degree_other') or '').strip()
    current_arrangement = (data.get('current_arrangement') or data.get('current_accommodation') or '').strip()
    if professional_category == 'Doctor':
        current_arrangement = ''
    eligible_vendor_category = professional_category in NURSE_VENDOR_ELIGIBLE_CATEGORIES
    if eligible_vendor_category and not current_arrangement:
        return {'success': False, 'ok': False, 'error': 'Current Stay Arrangement is required for Nurse / Other Health Worker.'}
    embassy_arranged = eligible_vendor_category and current_arrangement == 'Embassy Contracted / Arranged'
    moh_hotel_arranged = eligible_vendor_category and current_arrangement == 'MOH Provided Hotel - Arrival Stay'
    vendor_name = ''
    facility_name = ''
    facility_area = ''
    date_shifted_to_facility = ''
    contract_start_date = ''
    contract_end_date = ''
    notice_period_start_date = ''
    contract_months = 6
    notice_period_months = 3
    stay_reminders_opt_in = ''
    moh_hotel_name = ''
    moh_hotel_area = ''
    moh_hotel_start_date = ''
    moh_hotel_expected_end_date = ''
    moh_hotel_duration_months = 3
    if embassy_arranged:
        vendor_name = (data.get('vendor_name') or '').strip()
        if vendor_name not in NURSE_APPROVED_VENDOR_VALUES:
            return {'success': False, 'ok': False, 'error': 'Invalid vendor selection.'}
        facility_name = (data.get('facility_name') or data.get('facility_building_name') or '').strip()
        facility_area = (data.get('facility_area') or data.get('area') or '').strip()
        date_shifted_to_facility = (data.get('date_shifted_to_facility') or '').strip()
        contract_start_date = (data.get('contract_start_date') or data.get('stay_period_start_date') or '').strip()
        contract_start_date, contract_end_date, contract_months, notice_period_months, notice_period_start_date = _stay_date_defaults(
            contract_start_date or date_shifted_to_facility,
            data.get('contract_months') or 6,
            data.get('notice_period_months') or 3
        )
        stay_reminders_opt_in = (data.get('stay_reminders_opt_in') or data.get('receive_notice_reminders') or '').strip() or 'Yes'
    if moh_hotel_arranged:
        moh_hotel_name = (data.get('moh_hotel_name') or data.get('facility_name') or '').strip()
        moh_hotel_area = (data.get('moh_hotel_area') or data.get('facility_area') or data.get('area') or '').strip()
        moh_hotel_start_date = (data.get('moh_hotel_start_date') or data.get('date_shifted_to_facility') or '').strip()
        try:
            moh_hotel_duration_months = int(data.get('moh_hotel_duration_months') or 3)
        except Exception:
            moh_hotel_duration_months = 3
        moh_hotel_duration_months = max(1, min(12, moh_hotel_duration_months))
        moh_hotel_expected_end_date = (data.get('moh_hotel_expected_end_date') or '').strip()
        if moh_hotel_start_date and not moh_hotel_expected_end_date:
            moh_hotel_expected_end_date = _date_add_months(moh_hotel_start_date, moh_hotel_duration_months)
        facility_area = moh_hotel_area
    vendor_flags = _registration_vendor_flags(professional_category, current_arrangement, vendor_name)
    if professional_category == 'Doctor' or not embassy_arranged:
        vendor_name = ''
    facility_status = vendor_flags['facility_status']
    current_status = facility_status
    stay_confirmation_status = vendor_flags['stay_confirmation_status']
    email = _nurse_normalize_email(data.get('email') or '')
    password = data.get('password') or ''
    confirm_password = data.get('confirm_password') or ''
    if not full_name or not passport or not mobile or not cnic or not arrival_date or not batch_number or not hospital or not designation:
        return {'success': False, 'ok': False, 'error': 'Please fill all required fields.'}
    if not mobile_number or len(mobile_number) < 7 or len(mobile_number) > 15:
        return {'success': False, 'ok': False, 'error': 'Primary mobile number must be 7 to 15 digits.'}
    if not emergency_contact_number or len(emergency_contact_number) < 7 or len(emergency_contact_number) > 15:
        return {'success': False, 'ok': False, 'error': 'Emergency contact number must be 7 to 15 digits.'}
    if not whatsapp_same_as_mobile and (len(whatsapp_number) < 7 or len(whatsapp_number) > 15):
        return {'success': False, 'ok': False, 'error': 'WhatsApp number must be 7 to 15 digits when different from mobile.'}
    if not qualification_degree:
        return {'success': False, 'ok': False, 'error': 'Qualification / Degree is required.'}
    if qualification_degree == 'Other' and not qualification_degree_other:
        return {'success': False, 'ok': False, 'error': 'Other Qualification / Degree is required.'}
    if not email or not _is_valid_email_loose(email):
        return {'success': False, 'ok': False, 'error': 'A valid email address is required for your nurse account.'}
    ok_pw, pw_err = _nurse_validate_password_strength(password)
    if not ok_pw:
        return {'success': False, 'ok': False, 'error': pw_err}
    if password != confirm_password:
        return {'success': False, 'ok': False, 'error': 'Password and confirmation do not match.'}
    cnic_key = _nurse_normalize_id_key(cnic) if cnic.strip() else ''
    civil_key = _nurse_normalize_id_key(civil_id) if civil_id.strip() else ''
    db = get_db()
    try:
        conds = ['UPPER(REPLACE(TRIM(COALESCE(passport_number,\'\')), \' \', \'\')) = ?']
        vals = [passport]
        # Duplicate civil ID only when the applicant provided one (ignore blank / not-yet-issued)
        if civil_key:
            conds.append(
                "(TRIM(COALESCE(civil_id,'')) != '' AND REPLACE(REPLACE(REPLACE(UPPER(TRIM(civil_id)), '-', ''), ' ', ''), '_', '') = ?)"
            )
            vals.append(civil_key)
        if cnic_key:
            conds.append("REPLACE(REPLACE(REPLACE(UPPER(TRIM(COALESCE(cnic,''))), '-', ''), ' ', ''), '_', '') = ?")
            vals.append(cnic_key)
        conds.append("LOWER(TRIM(COALESCE(email,''))) = ?")
        vals.append(email)
        dup_sql = "SELECT id, reference_id FROM nurse_registrations WHERE (" + " OR ".join(conds) + ") ORDER BY id DESC LIMIT 1"
        dup = db.execute(dup_sql, vals).fetchone()
        if dup:
            return {'success': False, 'ok': False, 'error': NURSE_ACCOUNT_DUP_MSG, 'duplicate': True, 'reference_id': dup['reference_id']}
        ref = _next_nurse_reference(db)
        apply_acc = 'Yes' if embassy_arranged else 'No'
        step_values = [_nurse_step_value(data.get(col, 0)) for col, _ in NURSE_PROCESS_STEPS]
        ph, psalt = _nurse_hash_password_pbkdf2(password)
        insert_columns = [
            'reference_id', 'full_name', 'passport_number', 'arrival_date', 'batch_number',
            'cnic', 'civil_id', 'mobile', 'email', 'hospital', 'hospital_or_medical_center',
            'mobile_country_code', 'mobile_number', 'mobile_full',
            'whatsapp_country_code', 'whatsapp_number', 'whatsapp_full', 'whatsapp_same_as_mobile',
            'emergency_country_code', 'emergency_contact', 'emergency_contact_full',
            'designation', 'job_title_moh', 'professional_category', 'degree_type',
            'qualification_degree', 'qualification_degree_other',
            'moh_offer_salary_kwd', 'grading_letter_issued', 'accommodation_status',
            'current_accommodation', 'current_arrangement', 'applying_for_accommodation', 'vendor_name',
            'current_hostel', 'facility_area', 'date_shifted_to_facility',
            'contract_start_date', 'contract_end_date', 'contract_months',
            'notice_period_months', 'notice_period_start_date',
            'facility_status', 'current_status', 'stay_confirmation_status',
            'vendor_facility_eligible', 'vendor_facility_checkin_eligible',
            'embassy_facilitated_resident', 'aja_care_resident',
            'moh_hotel_name', 'moh_hotel_area', 'moh_hotel_start_date',
            'moh_hotel_expected_end_date', 'moh_hotel_duration_months',
            'stay_reminders_opt_in', 'remarks', 'issue_notice',
            *[col for col, _ in NURSE_PROCESS_STEPS],
            'password_hash', 'password_salt', 'password_updated_at', 'email_verified'
        ]
        insert_values = [
            ref, full_name, passport, arrival_date, batch_number, cnic, civil_id, mobile, email,
            hospital, (data.get('hospital_or_medical_center') or hospital).strip(),
            mobile_country_code, mobile_number, mobile_full,
            whatsapp_country_code, whatsapp_number, whatsapp_full, whatsapp_same_as_mobile,
            emergency_country_code, emergency_contact_number, emergency_contact_full,
            designation, designation,
            professional_category, (data.get('degree_type') or '').strip(),
            qualification_degree, qualification_degree_other if qualification_degree == 'Other' else '',
            (data.get('moh_offer_salary_kwd') or '').strip(), (data.get('grading_letter_issued') or 'No').strip(),
            current_arrangement, current_arrangement, current_arrangement, apply_acc, vendor_name, facility_name,
            facility_area, date_shifted_to_facility, contract_start_date, contract_end_date,
            contract_months, notice_period_months, notice_period_start_date,
            facility_status, current_status, stay_confirmation_status,
            vendor_flags['vendor_facility_eligible'], vendor_flags['vendor_facility_checkin_eligible'],
            vendor_flags['embassy_facilitated_resident'], vendor_flags['aja_care_resident'],
            moh_hotel_name, moh_hotel_area, moh_hotel_start_date, moh_hotel_expected_end_date,
            moh_hotel_duration_months, stay_reminders_opt_in,
            (data.get('remarks') or '').strip(), (data.get('issue_notice') or '').strip(),
            *step_values, ph, psalt, datetime.utcnow().isoformat(timespec='seconds'), 0
        ]
        cur = db.execute(
            f"""INSERT INTO nurse_registrations
                ({', '.join(insert_columns)})
                VALUES ({', '.join(['?'] * len(insert_columns))})""",
            insert_values
        )
        nurse_id = cur.lastrowid
        room_bed = (data.get('room_bed') or data.get('room_number') or '').strip() if embassy_arranged else ''
        if embassy_arranged and (facility_name or room_bed):
            db.execute(
                """UPDATE nurse_registrations
                   SET current_hostel = COALESCE(NULLIF(?, ''), current_hostel),
                       room_number = COALESCE(NULLIF(?, ''), room_number),
                       updated_at = CURRENT_TIMESTAMP
                   WHERE id = ?""",
                [facility_name, room_bed, nurse_id]
            )
        _nurse_log(db, 'registration_submitted', ref, passport, 'public', {'full_name': full_name, 'batch_number': batch_number, 'professional_category': professional_category})
        if vendor_flags['aja_care_resident']:
            match = _sync_vendor_facility_roster_for_registration(db, nurse_id, {
                'id': nurse_id,
                'reference_id': ref,
                'full_name': full_name,
                'passport_number': passport,
                'civil_id': civil_id,
                'mobile': mobile,
                'mobile_full': mobile_full,
                'email': email,
                'hospital': hospital,
                'professional_category': professional_category,
                'current_arrangement': current_arrangement,
                'current_accommodation': current_arrangement,
                'vendor_name': vendor_name,
                'facility_name': facility_name,
                'current_hostel': facility_name,
                'facility_area': facility_area,
                'date_shifted_to_facility': date_shifted_to_facility,
                'contract_start_date': contract_start_date,
                'contract_end_date': contract_end_date,
                'contract_months': contract_months,
                'notice_period_months': notice_period_months,
                'notice_period_start_date': notice_period_start_date,
            }, actor='public_registration')
            if not match.get('matched'):
                _nurse_log(db, 'facility_roster_link_skipped', ref, passport, 'system', {'error': match.get('error') or match.get('reason')})
        db.commit()
        verification = _send_email_verification_for_record(
            'nurse_registrations', nurse_id, ref, full_name, email, 'nurse_registration'
        )
        record = {'reference_id': ref, 'full_name': full_name, 'passport_number': passport, 'email': email, 'registration_status': 'Pending Review'}
        ok, detail = _send_nurse_ack_email(record)
        db2 = get_db()
        try:
            _nurse_log(db2, 'registration_email_ack', ref, passport, 'system', {'ok': ok, 'detail': detail})
            db2.commit()
        finally:
            db2.close()
        msg = 'Your registration has been received. Please check your email inbox and verify your email address using the verification link sent to you. Once your email is verified, your portal account will be activated.'
        notify_case_event(
            case_type='nurse_registration',
            case_reference=ref,
            event_type='request_received',
            applicant_email=email,
            applicant_name=full_name,
            status='Submitted',
            tracking_link='https://cwakuwait.com/nurses/login'
        )
        return {
            'success': True, 'ok': True, 'reference': ref, 'reference_id': ref,
            'message': msg,
            'email_status': verification.get('status') or ('sent' if ok else 'not_sent'),
            'email_detail': detail,
            'email_verification_status': verification.get('status'),
        }
    finally:
        db.close()


def api_nurse_track(data):
    identity = (data.get('identity') or '').strip()
    verifier = (data.get('verifier') or '').strip()
    if not identity or not verifier:
        return {'success': False, 'error': 'No matching registration found. Please check your details.'}
    db = get_db()
    try:
        row = db.execute("""SELECT * FROM nurse_registrations
                            WHERE (UPPER(TRIM(reference_id)) = UPPER(TRIM(?)) OR UPPER(TRIM(passport_number)) = UPPER(TRIM(?)))
                              AND (TRIM(mobile) = TRIM(?) OR TRIM(civil_id) = TRIM(?) OR TRIM(cnic) = TRIM(?))
                            ORDER BY id DESC LIMIT 1""", [identity, identity, verifier, verifier, verifier]).fetchone()
        if not row:
            return {'success': False, 'error': 'No matching registration found. Please check your details.'}
        rec = dict(row)
        return {'success': True, 'data': _build_nurse_public_profile_bundle(db, rec)}
    finally:
        db.close()


def api_nurse_login(data):
    identity = (data.get('identity') or '').strip()
    password = data.get('password') or ''
    if not identity or not password:
        return {'success': False, 'error': 'Invalid email, passport, Civil ID, or password.'}
    db = get_db()
    try:
        row = _find_nurse_by_login_identity(db, identity)
        if not row:
            return {'success': False, 'error': 'Invalid email, passport, Civil ID, or password.'}
        rec = dict(row)
        ph = (rec.get('password_hash') or '').strip()
        ps = (rec.get('password_salt') or '').strip()
        if not ph or not ps or not _nurse_verify_password_pbkdf2(password, ps, ph):
            return {'success': False, 'error': 'Invalid email, passport, Civil ID, or password.'}
        session_marker = secrets.token_hex(24)
        session_expires_at = (datetime.utcnow() + timedelta(days=1)).isoformat(timespec='seconds')
        db.execute(
            "UPDATE nurse_registrations SET last_login_at = CURRENT_TIMESTAMP, session_marker = ?, session_expires_at = ? WHERE id = ?",
            [session_marker, session_expires_at, rec.get('id')]
        )
        db.commit()
        rec['last_login_at'] = time.strftime('%Y-%m-%d %H:%M:%S')
        bundle = _build_nurse_public_profile_bundle(db, rec)
        bundle['session_marker'] = session_marker
        return {'success': True, 'data': bundle}
    finally:
        db.close()


def api_nurse_forgot_password(data):
    identity = (data.get('identity') or data.get('email') or '').strip()
    if not identity:
        return {'ok': True, 'message': NURSE_GENERIC_RESET_MSG}
    db = get_db()
    try:
        row = _find_nurse_by_login_identity(db, identity)
        if not row:
            return {'ok': True, 'message': NURSE_GENERIC_RESET_MSG}
        rec = dict(row)
        ph = (rec.get('password_hash') or '').strip()
        to_email = (rec.get('email') or '').strip()
        if not ph or not to_email or not _is_valid_email_loose(to_email):
            return {'ok': True, 'message': NURSE_GENERIC_RESET_MSG}
        token = secrets.token_urlsafe(32)
        th = hashlib.sha256(token.encode('utf-8')).hexdigest()
        exp = (datetime.now() + timedelta(hours=1)).strftime('%Y-%m-%d %H:%M:%S')
        db.execute(
            """UPDATE nurse_registrations SET reset_token_hash = ?, reset_token_expires_at = ?,
               reset_token_used_at = NULL WHERE id = ?""",
            [th, exp, rec.get('id')]
        )
        db.commit()
        base = _nurse_portal_public_base_url()
        link = f"{base}/nurses/reset-password?token={quote(token, safe='')}"
        name = rec.get('full_name') or 'Applicant'
        body = (
            f"Dear {name},\n\n"
            f"We received a request to reset your Nurse Portal password.\n\n"
            f"Reset link (valid for a limited time):\n{link}\n\n"
            f"If you did not request this reset, please ignore this email or contact the Embassy.\n\n"
            f"Embassy of Pakistan Kuwait - Community Welfare Wing\n"
        )
        ok, _detail = _nurse_send_email_smtp_env(to_email, 'Nurse Portal — Password reset', body)
        if not ok:
            print('[NurseSMTP] forgot-password email not sent', flush=True)
        return {'ok': True, 'message': NURSE_GENERIC_RESET_MSG}
    finally:
        db.close()


def api_nurse_reset_password(data):
    token = (data.get('token') or '').strip()
    new_pw = data.get('new_password') or data.get('password') or ''
    confirm = data.get('confirm_password') or ''
    if not token:
        return {'success': False, 'error': 'Invalid or expired reset link.'}
    ok_pw, pw_err = _nurse_validate_password_strength(new_pw)
    if not ok_pw:
        return {'success': False, 'error': pw_err}
    if new_pw != confirm:
        return {'success': False, 'error': 'Password and confirmation do not match.'}
    th = hashlib.sha256(token.encode('utf-8')).hexdigest()
    db = get_db()
    try:
        row = db.execute(
            "SELECT * FROM nurse_registrations WHERE reset_token_hash = ? ORDER BY id DESC LIMIT 1",
            [th]
        ).fetchone()
        if not row:
            return {'success': False, 'error': 'Invalid or expired reset link.'}
        rec = dict(row)
        if (rec.get('reset_token_used_at') or '').strip():
            return {'success': False, 'error': 'This reset link has already been used.'}
        exp_s = (rec.get('reset_token_expires_at') or '').strip()
        if not exp_s:
            return {'success': False, 'error': 'Invalid or expired reset link.'}
        try:
            exp_dt = datetime.strptime(exp_s[:19], '%Y-%m-%d %H:%M:%S')
        except Exception:
            return {'success': False, 'error': 'Invalid or expired reset link.'}
        if datetime.now() > exp_dt:
            return {'success': False, 'error': 'Invalid or expired reset link.'}
        nh, ns = _nurse_hash_password_pbkdf2(new_pw)
        db.execute(
            """UPDATE nurse_registrations SET password_hash = ?, password_salt = ?, password_updated_at = CURRENT_TIMESTAMP,
               reset_token_hash = NULL, reset_token_expires_at = NULL, reset_token_used_at = CURRENT_TIMESTAMP
               WHERE id = ?""",
            [nh, ns, rec.get('id')]
        )
        db.commit()
        to_email = (rec.get('email') or '').strip()
        if to_email and _is_valid_email_loose(to_email):
            body = (
                f"Dear {rec.get('full_name') or 'Applicant'},\n\n"
                f"Your Nurse Portal password was changed successfully.\n\n"
                f"If you did not make this change, contact the Embassy immediately.\n\n"
                f"Embassy of Pakistan Kuwait - Community Welfare Wing\n"
            )
            _nurse_send_email_smtp_env(to_email, 'Nurse Portal — Password changed', body)
        return {'success': True, 'message': 'Your password has been updated. You can log in now.'}
    finally:
        db.close()


def api_nurse_change_password(data):
    ref = (data.get('nurse_reference_id') or data.get('reference_id') or '').strip().upper()
    current = data.get('current_password') or ''
    new_pw = data.get('new_password') or ''
    confirm = data.get('confirm_password') or ''
    if not ref or not current:
        return {'success': False, 'error': 'Reference and current password are required.'}
    ok_pw, pw_err = _nurse_validate_password_strength(new_pw)
    if not ok_pw:
        return {'success': False, 'error': pw_err}
    if new_pw != confirm:
        return {'success': False, 'error': 'Password and confirmation do not match.'}
    db = get_db()
    try:
        row = db.execute(
            "SELECT * FROM nurse_registrations WHERE UPPER(TRIM(reference_id)) = ? ORDER BY id DESC LIMIT 1",
            [ref]
        ).fetchone()
        if not row:
            return {'success': False, 'error': 'Account not found.'}
        rec = dict(row)
        ph = (rec.get('password_hash') or '').strip()
        ps = (rec.get('password_salt') or '').strip()
        if not ph or not ps or not _nurse_verify_password_pbkdf2(current, ps, ph):
            return {'success': False, 'error': 'Current password is incorrect.'}
        nh, ns = _nurse_hash_password_pbkdf2(new_pw)
        db.execute(
            """UPDATE nurse_registrations SET password_hash = ?, password_salt = ?, password_updated_at = CURRENT_TIMESTAMP
               WHERE id = ?""",
            [nh, ns, rec.get('id')]
        )
        db.commit()
        to_email = (rec.get('email') or '').strip()
        if to_email and _is_valid_email_loose(to_email):
            body = (
                f"Dear {rec.get('full_name') or 'Applicant'},\n\n"
                f"Your Nurse Portal password was changed.\n\n"
                f"If you did not make this change, contact the Embassy immediately.\n\n"
                f"Embassy of Pakistan Kuwait - Community Welfare Wing\n"
            )
            _nurse_send_email_smtp_env(to_email, 'Nurse Portal — Password changed', body)
        return {'success': True, 'message': 'Password updated.'}
    finally:
        db.close()


def api_nurse_update_email(data):
    ref = (data.get('nurse_reference_id') or data.get('reference_id') or '').strip().upper()
    session_marker = (data.get('session_marker') or '').strip()
    new_email = _nurse_normalize_email(data.get('email') or '')
    if not ref or not session_marker:
        return {'success': False, 'error': 'Session required. Please sign in again.'}
    if not new_email or not _is_valid_email_loose(new_email):
        return {'success': False, 'error': 'Please enter a valid email address.'}
    db = get_db()
    try:
        rec = _nurse_session_lookup(db, ref, session_marker)
        if not rec:
            return {'success': False, 'error': 'Session expired. Please sign in again.'}
        if _nurse_normalize_email(rec.get('email') or '') == new_email and int(rec.get('email_verified') or 0) == 1:
            return {'success': True, 'message': 'Email verified. Your portal account is active.'}
        dup = db.execute(
            "SELECT id FROM nurse_registrations WHERE LOWER(TRIM(COALESCE(email,''))) = ? AND id != ? LIMIT 1",
            [new_email, rec.get('id')]
        ).fetchone()
        if dup:
            return {'success': False, 'error': 'This email is already used by another nurse account.'}
        db.execute(
            """UPDATE nurse_registrations
               SET email = ?, email_verified = 0, email_verified_at = NULL, email_verification_token = '',
                   email_last_status = 'pending', updated_at = CURRENT_TIMESTAMP
               WHERE id = ?""",
            [new_email, rec.get('id')]
        )
        _nurse_log(
            db, 'contact_email_updated', rec.get('reference_id', ''), rec.get('passport_number', ''), 'nurse_portal',
            {'old_email': rec.get('email', ''), 'new_email': new_email}
        )
        db.commit()
        send_result = _send_email_verification_for_record(
            'nurse_registrations',
            rec.get('id'),
            rec.get('reference_id', ''),
            rec.get('full_name', ''),
            new_email,
            'nurse_registration'
        )
        _nurse_log(
            db, 'email_verification_sent', rec.get('reference_id', ''), rec.get('passport_number', ''), 'system',
            {'status': send_result.get('status', ''), 'email': new_email}
        )
        db.commit()
        if send_result.get('status') == 'sent':
            return {'success': True, 'message': 'Email updated. Verification email sent.'}
        return {
            'success': True,
            'message': 'Email updated. Please verify your new email address.',
            'warning': 'Verification email could not be sent at this time.'
        }
    except Exception as exc:
        try:
            db.rollback()
        except Exception:
            pass
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


def api_nurse_resend_email_verification(data):
    ref = (data.get('nurse_reference_id') or data.get('reference_id') or '').strip().upper()
    session_marker = (data.get('session_marker') or '').strip()
    if not ref or not session_marker:
        return {'success': False, 'error': 'Session required. Please sign in again.'}
    db = get_db()
    try:
        rec = _nurse_session_lookup(db, ref, session_marker)
        if not rec:
            return {'success': False, 'error': 'Session expired. Please sign in again.'}
        if int(rec.get('email_verified') or 0) == 1:
            return {'success': False, 'error': 'Email already verified.'}
        sent_at = _parse_email_verification_timestamp(rec.get('email_verification_sent_at') or '')
        if sent_at and sent_at > (datetime.utcnow() - timedelta(minutes=10)):
            return {'success': False, 'error': 'Please wait 10 minutes before requesting another verification email.'}
        send_result = _send_email_verification_for_record(
            'nurse_registrations',
            rec.get('id'),
            rec.get('reference_id', ''),
            rec.get('full_name', ''),
            rec.get('email', ''),
            'nurse_registration'
        )
        _nurse_log(
            db, 'email_verification_sent', rec.get('reference_id', ''), rec.get('passport_number', ''), 'system',
            {'status': send_result.get('status', ''), 'email': rec.get('email', '')}
        )
        db.commit()
        if send_result.get('status') == 'sent':
            return {'success': True, 'message': 'Verification email sent.'}
        return {
            'success': True,
            'message': 'Email verification pending. Please verify your email address to activate your portal account and receive official updates.',
            'warning': 'Verification email could not be sent at this time.'
        }
    except Exception as exc:
        try:
            db.rollback()
        except Exception:
            pass
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


