LEGAL_CASE_TYPES = [
    'Labour Complaint', 'Civil Case', 'Criminal Case', 'Family / Personal Status',
    'Salary / Indemnity Claim', 'Sponsorship / Residency Issue', 'Document / OPF Card',
    'Detention / Police Matter', 'Welfare Assistance', 'Other'
]
LEGAL_CASE_STATUSES = ['Submitted', 'Seen by Admin', 'Assigned', 'In Progress',
                       'Awaiting Applicant Response', 'Resolved', 'Closed', 'Reopened']
DEATH_CASE_STATUSES = ['Submitted', 'Seen by Admin', 'Assigned', 'In Progress',
                       'Awaiting Family Response', 'Resolved', 'Closed', 'Reopened']


def _next_legal_case_reference(db):
    row = db.execute("SELECT IFNULL(MAX(id), 0) + 1 AS n FROM legal_case_requests").fetchone()
    return f"LGL-{int(row['n']):05d}"


def _next_death_case_reference(db):
    row = db.execute("SELECT IFNULL(MAX(id), 0) + 1 AS n FROM death_case_requests").fetchone()
    return f"DTH-{int(row['n']):05d}"


def _add_legal_case_action(db, reference_id, action_type, actor_username, actor_role, note='',
                           old_status='', new_status='', old_assigned_to='', new_assigned_to='',
                           visible_to_applicant=0):
    db.execute("""INSERT INTO legal_case_actions
        (reference_id, action_type, old_status, new_status, old_assigned_to, new_assigned_to,
         note, visible_to_applicant, actor_username, actor_role)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
        [reference_id, action_type, old_status, new_status, old_assigned_to, new_assigned_to,
         note, int(visible_to_applicant), actor_username, actor_role])


def _add_death_case_action(db, reference_id, action_type, actor_username, actor_role, note='',
                           old_status='', new_status='', old_assigned_to='', new_assigned_to='',
                           visible_to_reporter=0):
    db.execute("""INSERT INTO death_case_actions
        (reference_id, action_type, old_status, new_status, old_assigned_to, new_assigned_to,
         note, visible_to_reporter, actor_username, actor_role)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
        [reference_id, action_type, old_status, new_status, old_assigned_to, new_assigned_to,
         note, int(visible_to_reporter), actor_username, actor_role])


def api_legal_case_intake(data):
    full_name = (data.get('full_name') or '').strip()
    passport = (data.get('passport_number') or '').strip().upper()
    cnic = (data.get('cnic') or '').strip()
    mobile = (data.get('mobile') or '').strip()
    email = (data.get('email') or '').strip()
    case_type = (data.get('case_type') or '').strip() or 'Other'
    subject = (data.get('subject') or '').strip()
    description = (data.get('description') or '').strip()
    priority = (data.get('priority') or 'Normal').strip()
    consent = bool(data.get('consent'))
    if not full_name:
        return {'success': False, 'error': 'Full Name is required.'}
    if not (passport or cnic):
        return {'success': False, 'error': 'Passport Number or CNIC is required.'}
    if not subject or not description:
        return {'success': False, 'error': 'Subject and detailed description are required.'}
    if not consent:
        return {'success': False, 'error': 'Consent is required to submit the request.'}
    if priority not in ('Normal', 'Important', 'Urgent'):
        priority = 'Normal'
    if case_type not in LEGAL_CASE_TYPES:
        case_type = 'Other'
    db = get_db()
    try:
        ref = _next_legal_case_reference(db)
        cur = db.execute("""INSERT INTO legal_case_requests
            (reference_id, full_name, passport_number, cnic, civil_id, mobile, email, current_address,
             case_type, priority, subject, description, opposing_party, kuwaiti_court_case_no, next_hearing_date,
             status, last_action_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'Submitted', CURRENT_TIMESTAMP)""",
            [ref, full_name, passport, cnic, (data.get('civil_id') or '').strip(),
             mobile, email, (data.get('current_address') or '').strip(),
             case_type, priority, subject, description,
             (data.get('opposing_party') or '').strip(),
             (data.get('kuwaiti_court_case_no') or '').strip(),
             (data.get('next_hearing_date') or '').strip()])
        _add_legal_case_action(db, ref, 'Submitted', 'public', 'public',
                               note=description, new_status='Submitted', visible_to_applicant=1)
        desk = _detect_internal_welfare_desk(case_type=case_type, category=case_type, subject=subject, details=description)
        if desk.get('matched') and (desk.get('assigned_to') or '').strip():
            assignee_username = (desk.get('assigned_to') or '').strip()
            assignee_row = db.execute(
                """SELECT id, username, COALESCE(full_name, username) AS display_name, role,
                          COALESCE(department, '') AS department, COALESCE(email, '') AS email
                   FROM users WHERE username = ? LIMIT 1""",
                [assignee_username]
            ).fetchone()
            assignee = dict(assignee_row) if assignee_row else {}
            assigned_role = (desk.get('assigned_role') or '').strip() or (assignee.get('role') or '')
            assigned_department = (desk.get('assigned_department') or '').strip() or (desk.get('desk_name') or '').strip() or (assignee.get('department') or '')
            route_priority = (desk.get('priority') or '').strip()
            legal_priority = route_priority if route_priority in ('Normal', 'Important', 'Urgent') else priority
            old_status = 'Submitted'
            old_assigned = ''
            db.execute(
                """UPDATE legal_case_requests
                   SET assigned_to_user_id = ?, assigned_to_username = ?, assigned_to_name = ?,
                       assigned_role = ?, assigned_department = ?, assigned_by = 'system',
                       assigned_at = CURRENT_TIMESTAMP, status = 'Assigned',
                       priority = ?, last_action_at = CURRENT_TIMESTAMP, updated_at = CURRENT_TIMESTAMP,
                       updated_by = 'system'
                   WHERE reference_id = ?""",
                [
                    str(assignee.get('id') or ''),
                    assignee_username,
                    assignee.get('display_name') or assignee_username,
                    assigned_role,
                    assigned_department,
                    legal_priority,
                    ref
                ]
            )
            matched_keywords = ', '.join(desk.get('matched_keywords') or []) or 'routing keywords detected'
            _add_legal_case_action(
                db, ref, 'auto_assignment', 'system', 'system',
                note=f"Auto-assigned to {desk.get('desk_name')} ({assignee_username}) based on keywords: {matched_keywords}.",
                old_status=old_status, new_status='Assigned',
                old_assigned_to=old_assigned, new_assigned_to=assignee_username,
                visible_to_applicant=0
            )
            if assignee:
                _queue_welfare_assignment_email(db, assignee, ref, changed_by='system',
                                                assignment_note=f"Auto-assigned based on keywords: {matched_keywords}.",
                                                module_hint='legal')
        db.commit()
        verification = _send_email_verification_for_record(
            'legal_case_requests', cur.lastrowid, ref, full_name, email, 'legal'
        )
        if email and _is_valid_email_loose(email):
            _enqueue_email_job({
                'type': 'nurse_request_submitted',  # reuse existing email worker template
                'to': email,
                'complaint_id': ref,
                'name': full_name,
                'status': 'Submitted',
                'changed_by': 'system'
            })
        notify_case_event(
            case_type='legal',
            case_reference=ref,
            event_type='request_received',
            applicant_email=email,
            applicant_name=full_name,
            status='Submitted',
            tracking_link='https://cwakuwait.com/legal-cases/track'
        )
        return {
            'success': True,
            'reference_id': ref,
            'message': 'Your request has been received. Email verification pending.',
            'email_verification_status': verification.get('status'),
        }
    finally:
        db.close()


def api_death_case_intake(data):
    deceased_name = (data.get('deceased_name') or '').strip()
    deceased_passport = (data.get('deceased_passport') or '').strip().upper()
    deceased_cnic = (data.get('deceased_cnic') or '').strip()
    date_of_death = (data.get('date_of_death') or '').strip()
    reporter_name = (data.get('reporter_name') or '').strip()
    reporter_mobile = (data.get('reporter_mobile') or '').strip()
    reporter_email = (data.get('reporter_email') or '').strip()
    description = (data.get('description') or '').strip()
    priority = (data.get('priority') or 'Normal').strip()
    consent = bool(data.get('consent'))
    if not deceased_name:
        return {'success': False, 'error': 'Deceased name is required.'}
    if not (deceased_passport or deceased_cnic):
        return {'success': False, 'error': 'Deceased Passport Number or CNIC is required.'}
    if not reporter_name or not reporter_mobile:
        return {'success': False, 'error': 'Reporter name and mobile are required.'}
    if not consent:
        return {'success': False, 'error': 'Consent is required to submit the request.'}
    if priority not in ('Normal', 'Important', 'Urgent'):
        priority = 'Normal'
    db = get_db()
    try:
        ref = _next_death_case_reference(db)
        cur = db.execute("""INSERT INTO death_case_requests
            (reference_id, deceased_name, deceased_passport, deceased_cnic, deceased_civil_id,
             deceased_dob, deceased_gender, date_of_death, place_of_death, cause_of_death, hospital_or_authority,
             repatriation_required, burial_preference,
             next_of_kin_name, next_of_kin_relation, next_of_kin_mobile, next_of_kin_email, next_of_kin_address,
             reporter_name, reporter_mobile, reporter_email, reporter_relation,
             priority, description, status, last_action_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'Submitted', CURRENT_TIMESTAMP)""",
            [ref, deceased_name, deceased_passport, deceased_cnic,
             (data.get('deceased_civil_id') or '').strip(),
             (data.get('deceased_dob') or '').strip(),
             (data.get('deceased_gender') or '').strip(),
             date_of_death,
             (data.get('place_of_death') or '').strip(),
             (data.get('cause_of_death') or '').strip(),
             (data.get('hospital_or_authority') or '').strip(),
             (data.get('repatriation_required') or 'Yes').strip(),
             (data.get('burial_preference') or '').strip(),
             (data.get('next_of_kin_name') or '').strip(),
             (data.get('next_of_kin_relation') or '').strip(),
             (data.get('next_of_kin_mobile') or '').strip(),
             (data.get('next_of_kin_email') or '').strip(),
             (data.get('next_of_kin_address') or '').strip(),
             reporter_name, reporter_mobile, reporter_email,
             (data.get('reporter_relation') or '').strip(),
             priority, description])
        _add_death_case_action(db, ref, 'Submitted', 'public', 'public',
                               note=description, new_status='Submitted', visible_to_reporter=1)
        db.commit()
        verification = _send_email_verification_for_record(
            'death_case_requests', cur.lastrowid, ref, reporter_name, reporter_email, 'death'
        )
        if reporter_email and _is_valid_email_loose(reporter_email):
            _enqueue_email_job({
                'type': 'nurse_request_submitted',
                'to': reporter_email,
                'complaint_id': ref,
                'name': reporter_name,
                'status': 'Submitted',
                'changed_by': 'system'
            })
        notify_case_event(
            case_type='death',
            case_reference=ref,
            event_type='request_received',
            applicant_email=reporter_email,
            applicant_name=reporter_name,
            status='Submitted',
            tracking_link='https://cwakuwait.com/death-cases/track'
        )
        return {
            'success': True,
            'reference_id': ref,
            'message': 'Your request has been received. Email verification pending.',
            'email_verification_status': verification.get('status'),
        }
    finally:
        db.close()


def api_admin_legal_summary():
    db = get_db()
    try:
        def _count(sql):
            return int((db.execute(sql).fetchone()['c']) or 0)
        return {'success': True, 'totals': {
            'total': _count("SELECT COUNT(*) c FROM legal_case_requests"),
            'submitted': _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status='Submitted'"),
            'assigned': _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status='Assigned'"),
            'in_progress': _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status='In Progress'"),
            'resolved': _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status='Resolved'"),
            'closed': _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status='Closed'")
        }}
    finally:
        db.close()


def api_admin_death_summary():
    db = get_db()
    try:
        def _count(sql):
            return int((db.execute(sql).fetchone()['c']) or 0)
        return {'success': True, 'totals': {
            'total': _count("SELECT COUNT(*) c FROM death_case_requests"),
            'submitted': _count("SELECT COUNT(*) c FROM death_case_requests WHERE status='Submitted'"),
            'assigned': _count("SELECT COUNT(*) c FROM death_case_requests WHERE status='Assigned'"),
            'in_progress': _count("SELECT COUNT(*) c FROM death_case_requests WHERE status='In Progress'"),
            'resolved': _count("SELECT COUNT(*) c FROM death_case_requests WHERE status='Resolved'"),
            'closed': _count("SELECT COUNT(*) c FROM death_case_requests WHERE status='Closed'"),
            'urgent': _count("SELECT COUNT(*) c FROM death_case_requests WHERE LOWER(IFNULL(priority,''))='urgent' AND status NOT IN ('Resolved','Closed')")
        }}
    finally:
        db.close()


