def _aja_reconciliation_role_allowed(user):
    return bool(user) and (user.get('role') or '') in AJA_RECONCILIATION_PAGE_ROLES


def _aja_reconciliation_access_clause(user, params=None, force_assigned=False):
    params = params or {}
    role = (user or {}).get('role') or ''
    username = (user or {}).get('user') or ''
    assigned_to = _clean_text(params.get('assigned_to'), 120)
    where = []
    vals = []
    if role in RESTRICTED_STAFF_ROLES or force_assigned:
        where.append("COALESCE(f.assigned_to, '') = ?")
        vals.append(username)
    elif assigned_to and assigned_to != 'all':
        if assigned_to == 'me':
            assigned_to = username
        where.append("COALESCE(f.assigned_to, '') = ?")
        vals.append(assigned_to)
    return where, vals


def _aja_reconciliation_base_where(user, params=None, force_assigned=False):
    where = [
        """(COALESCE(f.vendor_name, '') = ?
             OR COALESCE(f.current_arrangement, '') = 'Embassy Contracted / Arranged'
             OR COALESCE(n.aja_care_resident, 0) = 1)""",
        "COALESCE(f.current_status, '') NOT IN ('Closed / Archived', 'Inactive')",
    ]
    vals = [FACILITY_VENDOR_DEFAULT]
    access_where, access_vals = _aja_reconciliation_access_clause(user, params, force_assigned=force_assigned)
    where.extend(access_where)
    vals.extend(access_vals)
    return where, vals


def _aja_reconciliation_status_filter(status):
    status = (status or 'pending').strip().lower()
    if status == 'all':
        return '', []
    if status == 'pending':
        return """AND COALESCE(f.reconciliation_status, '') IN ('', 'Pending Reconciliation')
                  AND COALESCE(f.current_status, '') NOT IN ('Left Facility', 'Private Self Arranged', 'MOH Arranged', 'MOH Provided Hotel - Arrival Stay')""", []
    if status == 'call_later':
        return "AND COALESCE(f.reconciliation_status, '') = 'Call Later'", []
    if status == 'no_answer':
        return "AND COALESCE(f.reconciliation_status, '') = 'No Answer'", []
    if status == 'reconciled':
        return "AND COALESCE(f.reconciliation_status, '') = 'Reconciled'", []
    if status == 'left':
        return "AND (COALESCE(f.reconciliation_outcome, '') = 'Left AJA Care' OR COALESCE(f.current_status, '') = 'Left Facility')", []
    if status == 'private':
        return "AND (COALESCE(f.reconciliation_outcome, '') = 'Private Self Arranged' OR COALESCE(f.current_arrangement, '') = 'Private (Self Arranged)' OR COALESCE(f.current_status, '') = 'Private Self Arranged')", []
    if status == 'moh_arranged':
        return "AND (COALESCE(f.reconciliation_outcome, '') = 'MOH Arranged' OR COALESCE(f.current_arrangement, '') = 'MOH Arranged' OR COALESCE(f.current_status, '') = 'MOH Arranged')", []
    if status == 'moh_hotel':
        return "AND (COALESCE(f.reconciliation_outcome, '') = 'MOH Provided Hotel' OR COALESCE(f.current_arrangement, '') = 'MOH Provided Hotel - Arrival Stay' OR COALESCE(f.current_status, '') = 'MOH Provided Hotel - Arrival Stay')", []
    if status == 'needs_assistance':
        return "AND (COALESCE(f.welfare_followup_required, 0) = 1 OR COALESCE(f.reconciliation_outcome, '') = 'Needs Embassy Assistance')", []
    if status == 'unable_to_reach':
        return "AND COALESCE(f.reconciliation_status, '') = 'Unable to Reach'", []
    if status == 'needs_followup':
        return "AND COALESCE(f.reconciliation_status, '') IN ('Needs Follow-up', 'Reconciliation Required')", []
    return "AND COALESCE(f.reconciliation_status, '') = ?", [status]


def _aja_reconciliation_select_sql(extra_sql=''):
    return f"""SELECT f.*,
                      n.reference_id AS linked_nurse_reference,
                      n.full_name AS linked_nurse_name,
                      n.mobile_full AS linked_mobile_full,
                      n.whatsapp_full AS linked_whatsapp_full,
                      n.email AS linked_email,
                      n.professional_category AS linked_professional_category,
                      n.aja_care_resident AS linked_aja_care_resident
               FROM facility_roster f
               LEFT JOIN nurse_registrations n ON n.id = f.nurse_registration_id
               {extra_sql}"""


def _aja_reconciliation_to_dict(row):
    raw = dict(row or {})
    d = _facility_roster_to_dict(raw)
    d['nurse_reference'] = d.get('nurse_reference') or raw.get('linked_nurse_reference') or ''
    d['full_name'] = d.get('full_name') or raw.get('linked_nurse_name') or ''
    d['phone'] = d.get('phone') or raw.get('linked_mobile_full') or d.get('mobile_full') or ''
    d['mobile_full'] = d.get('mobile_full') or raw.get('linked_mobile_full') or d.get('phone') or ''
    d['whatsapp_full'] = d.get('whatsapp_full') or raw.get('linked_whatsapp_full') or d.get('phone') or ''
    d['email'] = d.get('email') or raw.get('linked_email') or ''
    d['vendor_name'] = d.get('vendor_name') or FACILITY_VENDOR_DEFAULT
    d['facility_name'] = d.get('facility_name') or 'AJA Care - To be confirmed'
    d['assigned_to'] = d.get('assigned_to') or 'Unassigned'
    d['source_file_remarks'] = d.get('remarks') or d.get('reconciliation_source') or ''
    d['is_aja_reconciliation_record'] = True
    return d


def _aja_reconciliation_summary(db, user):
    where, vals = _aja_reconciliation_base_where(user, {}, force_assigned=(user.get('role') in RESTRICTED_STAFF_ROLES))
    where_sql = ' AND '.join(where)

    def count(extra='', extra_vals=()):
        sql = _aja_reconciliation_select_sql(f"WHERE {where_sql} {extra}")
        return int(db.execute(f"SELECT COUNT(*) c FROM ({sql})", vals + list(extra_vals)).fetchone()['c'] or 0)

    return {
        'total_aja_records': count(),
        'pending_reconciliation': count("AND COALESCE(f.reconciliation_status, '') IN ('', 'Pending Reconciliation')"),
        'reconciled': count("AND COALESCE(f.reconciliation_status, '') = 'Reconciled'"),
        'confirmed_staying': count("AND COALESCE(f.current_status, '') = 'Confirmed Staying' AND COALESCE(f.vendor_name, '') = ? AND COALESCE(f.active, 1) = 1", [FACILITY_VENDOR_DEFAULT]),
        'left_facility': count("AND (COALESCE(f.current_status, '') = 'Left Facility' OR COALESCE(f.reconciliation_outcome, '') = 'Left AJA Care')"),
        'private_self_arranged': count("AND (COALESCE(f.current_arrangement, '') = 'Private (Self Arranged)' OR COALESCE(f.current_status, '') = 'Private Self Arranged')"),
        'moh_arranged': count("AND (COALESCE(f.current_arrangement, '') = 'MOH Arranged' OR COALESCE(f.current_status, '') = 'MOH Arranged')"),
        'moh_hotel': count("AND (COALESCE(f.current_arrangement, '') = 'MOH Provided Hotel - Arrival Stay' OR COALESCE(f.current_status, '') = 'MOH Provided Hotel - Arrival Stay')"),
        'intends_to_leave': count("AND COALESCE(f.current_status, '') = 'Intends to Leave'"),
        'needs_assistance': count("AND COALESCE(f.welfare_followup_required, 0) = 1"),
        'call_later': count("AND COALESCE(f.reconciliation_status, '') = 'Call Later'"),
        'no_answer': count("AND COALESCE(f.reconciliation_status, '') = 'No Answer'"),
        'unable_to_reach': count("AND COALESCE(f.reconciliation_status, '') = 'Unable to Reach'"),
        'assigned_to_me': count("AND COALESCE(f.assigned_to, '') = ?", [user.get('user') or '']),
    }


def _aja_reconciliation_next_id(db, user, after_id=0, status='pending', assigned_to='all'):
    params = {'assigned_to': assigned_to or 'all'}
    where, vals = _aja_reconciliation_base_where(user, params, force_assigned=(user.get('role') in RESTRICTED_STAFF_ROLES))
    if int(after_id or 0) > 0:
        where.append("f.id > ?")
        vals.append(int(after_id or 0))
    status_sql, status_vals = _aja_reconciliation_status_filter(status)
    sql = _aja_reconciliation_select_sql(f"WHERE {' AND '.join(where)} {status_sql} ORDER BY f.id ASC LIMIT 1")
    row = db.execute(sql, vals + status_vals).fetchone()
    if not row and int(after_id or 0) > 0:
        where2, vals2 = _aja_reconciliation_base_where(user, params, force_assigned=(user.get('role') in RESTRICTED_STAFF_ROLES))
        sql = _aja_reconciliation_select_sql(f"WHERE {' AND '.join(where2)} {status_sql} ORDER BY f.id ASC LIMIT 1")
        row = db.execute(sql, vals2 + status_vals).fetchone()
    return int(row['id']) if row else None


def api_admin_aja_reconciliation_queue(params, user):
    if not _aja_reconciliation_role_allowed(user):
        return {'success': False, 'error': 'Unauthorized'}
    status = _clean_text(params.get('status') or 'pending', 40).lower()
    try:
        limit = max(1, min(100, int(params.get('limit') or 25)))
    except Exception:
        limit = 25
    try:
        offset = max(0, int(params.get('offset') or 0))
    except Exception:
        offset = 0
    if user.get('role') in RESTRICTED_STAFF_ROLES:
        params = {**params, 'assigned_to': 'me'}
    db = get_db()
    try:
        where, vals = _aja_reconciliation_base_where(user, params, force_assigned=(user.get('role') in RESTRICTED_STAFF_ROLES))
        status_sql, status_vals = _aja_reconciliation_status_filter(status)
        sql = _aja_reconciliation_select_sql(
            f"WHERE {' AND '.join(where)} {status_sql} ORDER BY f.id ASC LIMIT ? OFFSET ?"
        )
        rows = db.execute(sql, vals + status_vals + [limit, offset]).fetchall()
        items = [_aja_reconciliation_to_dict(r) for r in rows]
        where_joined = ' AND '.join(where)
        count_sql = _aja_reconciliation_select_sql(f"WHERE {where_joined} {status_sql}")
        total = int(db.execute(
            f"SELECT COUNT(*) c FROM ({count_sql})",
            vals + status_vals
        ).fetchone()['c'] or 0)
        current = items[0] if items else None
        next_id = items[1]['id'] if len(items) > 1 else _aja_reconciliation_next_id(
            db, user, current.get('id') if current else 0, status, params.get('assigned_to') or 'all'
        )
        return {
            'success': True,
            'summary': _aja_reconciliation_summary(db, user),
            'current': current,
            'next_id': next_id,
            'items': items,
            'total': total,
            'limit': limit,
            'offset': offset,
        }
    except Exception as exc:
        traceback.print_exc()
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


def _aja_reconciliation_can_update(row, user):
    if not row or not user:
        return False
    role = user.get('role') or ''
    if role in AJA_RECONCILIATION_ADMIN_ROLES or role in ('admin', 'operator'):
        return True
    return role in RESTRICTED_STAFF_ROLES and (row['assigned_to'] or '') == (user.get('user') or '')


def _update_linked_nurse_after_reconciliation(db, roster, updates):
    nurse_id = int(roster.get('nurse_registration_id') or 0)
    if nurse_id <= 0:
        return
    cols = _table_columns(db, 'nurse_registrations')
    assignments, vals = [], []
    for col, value in updates.items():
        if col in cols:
            assignments.append(f"{col} = ?")
            vals.append(value)
    if assignments:
        vals.append(nurse_id)
        db.execute(f"UPDATE nurse_registrations SET {', '.join(assignments)}, updated_at = CURRENT_TIMESTAMP WHERE id = ?", vals)


def api_admin_aja_reconciliation_update(data, user):
    if not _aja_reconciliation_role_allowed(user):
        return {'success': False, 'error': 'Unauthorized'}
    roster_id = int(data.get('roster_id') or data.get('id') or 0)
    if roster_id <= 0:
        return {'success': False, 'error': 'roster_id is required'}
    outcome = _clean_text(data.get('outcome'), 120)
    call_result = _clean_text(data.get('call_result'), 80)
    remarks = _clean_text(data.get('remarks'), 3000)
    mode = _clean_text(data.get('mode') or data.get('action'), 40).lower()
    db = get_db()
    try:
        row = db.execute("SELECT * FROM facility_roster WHERE id = ?", [roster_id]).fetchone()
        if not row:
            return {'success': False, 'error': 'Roster entry not found'}
        current = _facility_roster_to_dict(row)
        if not _aja_reconciliation_can_update(row, user):
            return {'success': False, 'error': 'Forbidden. This record is not assigned to you.'}
        old_status = current.get('current_status') or ''
        old_recon = current.get('reconciliation_status') or ''
        now = _sql_now()
        today = _kuwait_now().date().isoformat()
        if mode == 'skip':
            _facility_insert_action(db, roster_id, user.get('user'), 'aja_reconciliation_skipped', old_recon, old_recon, remarks or 'Skipped to next record.', False)
            db.commit()
            return {'success': True, 'next_id': _aja_reconciliation_next_id(db, user, roster_id, data.get('status') or 'pending', data.get('assigned_to') or 'all')}

        if mode == 'no_answer' and not call_result:
            call_result = 'No Answer'
        if mode == 'call_later' and not call_result:
            call_result = 'Asked to Call Later'
        if outcome and outcome not in AJA_RECONCILIATION_OUTCOMES:
            return {'success': False, 'error': 'Invalid reconciliation outcome'}

        updates = {
            'reconciliation_called_at': now,
            'reconciliation_called_by': user.get('user') or '',
            'reconciliation_contact_result': call_result,
            'reconciliation_last_note': remarks,
            'reconciliation_next_followup_at': _clean_text(data.get('next_followup_at'), 80),
            'preferred_contact_method': _clean_text(data.get('preferred_contact_method'), 80),
            'updated_at': now,
        }
        attempts_delta = 1 if (call_result or outcome or mode in ('no_answer', 'call_later')) else 0
        if attempts_delta:
            updates['reconciliation_attempts'] = int(current.get('reconciliation_attempts') or 0) + attempts_delta
        corrected_phone = _clean_text(data.get('corrected_phone'), 80)
        corrected_whatsapp = _clean_text(data.get('corrected_whatsapp'), 80)
        corrected_email = _clean_text(data.get('corrected_email'), 180)
        if corrected_phone:
            updates['phone'] = corrected_phone
            updates['mobile_full'] = corrected_phone
        if corrected_whatsapp:
            updates['whatsapp_full'] = corrected_whatsapp
        if corrected_email:
            updates['email'] = corrected_email

        nurse_updates = {}
        if corrected_phone:
            nurse_updates.update({'mobile': corrected_phone, 'mobile_full': corrected_phone})
        if corrected_whatsapp:
            nurse_updates['whatsapp_full'] = corrected_whatsapp
        if corrected_email:
            nurse_updates['email'] = corrected_email

        status_only_call = call_result in ('No Answer', 'Switched Off', 'Asked to Call Later') and not outcome
        if status_only_call:
            updates['reconciliation_status'] = 'No Answer' if call_result in ('No Answer', 'Switched Off') else 'Call Later'
            updates['current_status'] = old_status or 'Assigned to Facility'
        elif outcome == 'Confirmed Staying at AJA Care':
            updates.update({
                'current_status': 'Confirmed Staying',
                'confirmation_status': 'Confirmed',
                'reconciliation_status': 'Reconciled',
                'reconciliation_outcome': outcome,
                'reconciliation_completed_at': now,
                'active': 1,
                'last_confirmed_at': now,
                'vendor_name': FACILITY_VENDOR_DEFAULT,
                'current_arrangement': 'Embassy Contracted / Arranged',
                'vendor_facility_checkin_eligible': 1,
            })
            if data.get('date_shifted_to_facility'):
                updates['date_shifted_to_facility'] = _clean_text(data.get('date_shifted_to_facility'), 40)
            nurse_updates.update({
                'current_status': 'Confirmed Staying',
                'facility_status': 'Confirmed Staying',
                'stay_confirmation_status': 'Confirmed',
                'current_arrangement': 'Embassy Contracted / Arranged',
                'current_accommodation': 'Embassy Contracted / Arranged',
                'vendor_name': FACILITY_VENDOR_DEFAULT,
                'vendor_facility_eligible': 1,
                'vendor_facility_checkin_eligible': 1,
                'embassy_facilitated_resident': 1,
                'aja_care_resident': 1,
            })
        elif outcome == 'Left AJA Care':
            left_date = _clean_text(data.get('left_date'), 40) or today
            updates.update({
                'current_status': 'Left Facility',
                'reconciliation_status': 'Reconciled',
                'reconciliation_outcome': outcome,
                'reconciliation_completed_at': now,
                'active': 0,
                'left_date': left_date,
                'action_required': 'Left AJA Care confirmation recorded',
            })
            nurse_updates.update({'current_status': 'Left Facility', 'facility_status': 'Left Facility'})
            _facility_create_welfare_followup(db, {**current, **updates}, remarks or 'Nurse reported leaving AJA Care.', category='Left Facility Confirmation', priority='Normal')
        elif outcome == 'Intends to Leave':
            updates.update({
                'current_status': 'Intends to Leave',
                'reconciliation_status': 'Needs Follow-up',
                'reconciliation_outcome': outcome,
                'welfare_followup_required': 1,
                'active': 1,
                'action_required': 'Stay arrangement change follow-up required',
            })
            nurse_updates.update({'current_status': 'Intends to Leave', 'facility_status': 'Intends to Leave'})
            _facility_create_welfare_followup(db, {**current, **updates}, remarks or 'Nurse intends to leave or change stay arrangement.', category='Stay Arrangement Change / Intends to Leave', priority='Normal')
        elif outcome == 'Private Self Arranged':
            updates.update({
                'current_status': 'Private Self Arranged',
                'current_arrangement': 'Private (Self Arranged)',
                'reconciliation_status': 'Reconciled',
                'reconciliation_outcome': outcome,
                'reconciliation_completed_at': now,
                'private_arrangement_area': _clean_text(data.get('private_arrangement_area') or data.get('current_area_facility'), 180),
                'active': 0,
                'vendor_facility_checkin_eligible': 0,
            })
            nurse_updates.update({'current_status': 'Private Self Arranged', 'facility_status': 'Private Self Arranged', 'current_arrangement': 'Private (Self Arranged)', 'current_accommodation': 'Private (Self Arranged)', 'vendor_name': '', 'vendor_facility_eligible': 0, 'vendor_facility_checkin_eligible': 0, 'embassy_facilitated_resident': 0, 'aja_care_resident': 0})
        elif outcome == 'MOH Arranged':
            updates.update({
                'current_status': 'MOH Arranged',
                'current_arrangement': 'MOH Arranged',
                'reconciliation_status': 'Reconciled',
                'reconciliation_outcome': outcome,
                'reconciliation_completed_at': now,
                'facility_area': _clean_text(data.get('private_arrangement_area') or data.get('current_area_facility'), 180),
                'active': 0,
                'vendor_facility_checkin_eligible': 0,
            })
            nurse_updates.update({'current_status': 'MOH Arranged', 'facility_status': 'MOH Arranged', 'current_arrangement': 'MOH Arranged', 'current_accommodation': 'MOH Arranged', 'vendor_name': '', 'vendor_facility_eligible': 0, 'vendor_facility_checkin_eligible': 0, 'embassy_facilitated_resident': 0, 'aja_care_resident': 0})
        elif outcome == 'MOH Provided Hotel':
            start_date = _clean_text(data.get('moh_hotel_start_date'), 40)
            expected_end = _clean_text(data.get('moh_hotel_expected_end_date'), 40)
            if start_date and not expected_end:
                expected_end = _date_add_months(start_date, 3)
            updates.update({
                'current_status': 'MOH Provided Hotel - Arrival Stay',
                'current_arrangement': 'MOH Provided Hotel - Arrival Stay',
                'reconciliation_status': 'Reconciled',
                'reconciliation_outcome': outcome,
                'reconciliation_completed_at': now,
                'moh_hotel_name': _clean_text(data.get('moh_hotel_name'), 220),
                'moh_hotel_area': _clean_text(data.get('moh_hotel_area') or data.get('private_arrangement_area'), 180),
                'moh_hotel_start_date': start_date,
                'moh_hotel_expected_end_date': expected_end,
                'active': 0,
                'vendor_facility_checkin_eligible': 0,
            })
            nurse_updates.update({'current_status': 'MOH Provided Hotel - Arrival Stay', 'facility_status': 'MOH Provided Hotel - Arrival Stay', 'current_arrangement': 'MOH Provided Hotel - Arrival Stay', 'current_accommodation': 'MOH Provided Hotel - Arrival Stay', 'vendor_name': '', 'vendor_facility_eligible': 0, 'vendor_facility_checkin_eligible': 0, 'embassy_facilitated_resident': 0, 'aja_care_resident': 0, 'moh_hotel_name': updates['moh_hotel_name'], 'moh_hotel_area': updates['moh_hotel_area'], 'moh_hotel_start_date': start_date, 'moh_hotel_expected_end_date': expected_end})
        elif outcome == 'Details Correction Required':
            updates.update({
                'reconciliation_status': 'Reconciliation Required',
                'reconciliation_outcome': outcome,
                'welfare_followup_required': 1,
                'action_required': 'Facility details correction required',
            })
            _facility_create_welfare_followup(db, {**current, **updates}, remarks or 'Facility details require correction after reconciliation call.', category='Facility Details Correction', priority='Normal')
        elif outcome == 'Needs Embassy Assistance':
            updates.update({
                'current_status': 'Needs Embassy Assistance',
                'reconciliation_status': 'Needs Follow-up',
                'reconciliation_outcome': outcome,
                'welfare_followup_required': 1,
                'action_required': 'Welfare follow-up required',
            })
            _facility_create_welfare_followup(db, {**current, **updates}, remarks or 'Nurse requested Embassy welfare assistance during reconciliation call.', category='Health Worker Facility Follow-up', priority='High')
        elif outcome == 'Unable to Confirm':
            updates.update({
                'reconciliation_status': 'Unable to Reach',
                'reconciliation_outcome': outcome,
                'action_required': 'Reconciliation follow-up required',
            })
        elif not outcome and call_result:
            updates['reconciliation_status'] = 'Call Later' if call_result == 'Asked to Call Later' else ('No Answer' if call_result in ('No Answer', 'Switched Off') else 'Needs Follow-up')

        assignments = [f"{col} = ?" for col in updates.keys()]
        db.execute(f"UPDATE facility_roster SET {', '.join(assignments)} WHERE id = ?", list(updates.values()) + [roster_id])
        _update_linked_nurse_after_reconciliation(db, current, nurse_updates)
        note = remarks or f'Reconciliation call result: {call_result or "—"}; outcome: {outcome or updates.get("reconciliation_status") or "—"}'
        _facility_insert_action(db, roster_id, user.get('user'), 'aja_reconciliation_update', old_status or old_recon, updates.get('current_status') or updates.get('reconciliation_status') or '', note, False)
        try:
            db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES (?, ?, ?, ?)",
                       ['aja_reconciliation_update', roster_id, user.get('user'), json.dumps({'role': user.get('role'), 'outcome': outcome, 'call_result': call_result})])
        except Exception:
            pass
        db.commit()
        return {
            'success': True,
            'id': roster_id,
            'status': updates.get('current_status') or old_status,
            'reconciliation_status': updates.get('reconciliation_status') or old_recon,
            'next_id': _aja_reconciliation_next_id(db, user, roster_id, data.get('status') or 'pending', data.get('assigned_to') or 'all')
        }
    except Exception as e:
        traceback.print_exc()
        db.rollback()
        return {'success': False, 'error': str(e)}
    finally:
        db.close()


def api_admin_aja_reconciliation_assign(data, user):
    if (user or {}).get('role') not in AJA_RECONCILIATION_ADMIN_ROLES:
        return {'success': False, 'error': 'Only authorized administrators can assign reconciliation records.'}
    roster_ids = data.get('roster_ids') or []
    if data.get('roster_id') and not roster_ids:
        roster_ids = [data.get('roster_id')]
    try:
        roster_ids = [int(x) for x in roster_ids if int(x) > 0]
    except Exception:
        return {'success': False, 'error': 'Invalid roster_ids'}
    assigned_to = _clean_text(data.get('assigned_to'), 120)
    due_date = _clean_text(data.get('due_date'), 40)
    note = _clean_text(data.get('note'), 2000)
    if not roster_ids or not assigned_to:
        return {'success': False, 'error': 'roster_ids and assigned_to are required'}
    db = get_db()
    try:
        assignee = db.execute("SELECT username, role, COALESCE(full_name, username) AS full_name, COALESCE(email,'') AS email, COALESCE(department,'') AS department FROM users WHERE username = ? AND COALESCE(is_active,1)=1", [assigned_to]).fetchone()
        if not assignee:
            return {'success': False, 'error': 'Assignee not found or inactive'}
        updated = 0
        for rid in roster_ids:
            row = db.execute("SELECT * FROM facility_roster WHERE id = ?", [rid]).fetchone()
            if not row:
                continue
            old_assigned = row['assigned_to'] or ''
            db.execute("""UPDATE facility_roster
                          SET assigned_to = ?, assigned_role = ?, assigned_department = ?, due_date = ?,
                              reconciliation_status = CASE WHEN COALESCE(reconciliation_status,'') = '' THEN 'Pending Reconciliation' ELSE reconciliation_status END,
                              updated_at = CURRENT_TIMESTAMP
                          WHERE id = ?""",
                       [assigned_to, assignee['role'] or '', assignee['department'] or '', due_date, rid])
            _facility_insert_action(db, rid, user.get('user'), 'aja_reconciliation_assigned', old_assigned, assigned_to, note, False)
            updated += 1
        db.commit()
        if assignee['email']:
            notify_case_event(
                case_type='facility',
                case_reference=f'{updated} AJA roster record(s)',
                event_type='case_assigned_to_staff',
                applicant_name='AJA Care reconciliation queue',
                staff_username=assigned_to,
                staff_email=assignee['email'],
                priority='Normal',
                due_date=due_date,
                admin_link='https://portal.cwakuwait.com/admin/aja-reconciliation'
            )
        return {'success': True, 'assigned': updated}
    except Exception as e:
        traceback.print_exc()
        db.rollback()
        return {'success': False, 'error': str(e)}
    finally:
        db.close()


def api_admin_aja_reconciliation_export(user):
    if not _aja_reconciliation_role_allowed(user):
        return None, {'success': False, 'error': 'Unauthorized'}
    db = get_db()
    try:
        where, vals = _aja_reconciliation_base_where(user, {}, force_assigned=(user.get('role') in RESTRICTED_STAFF_ROLES))
        rows = db.execute(_aja_reconciliation_select_sql(f"WHERE {' AND '.join(where)} ORDER BY f.id ASC"), vals).fetchall()
        out = io.StringIO()
        writer = csv.writer(out)
        headers = [
            'roster_reference', 'full_name', 'passport_number', 'civil_id', 'phone', 'whatsapp',
            'email', 'vendor_name', 'facility_name', 'reconciliation_status',
            'reconciliation_outcome', 'current_status', 'active', 'called_by', 'called_at',
            'attempts', 'next_followup_at', 'remarks'
        ]
        writer.writerow(headers)
        for row in rows:
            r = _aja_reconciliation_to_dict(row)
            writer.writerow([
                r.get('roster_reference', ''), r.get('full_name', ''), r.get('passport_number', ''),
                r.get('civil_id', ''), r.get('phone', ''), r.get('whatsapp_full', ''),
                r.get('email', ''), r.get('vendor_name', ''), r.get('facility_name', ''),
                r.get('reconciliation_status', ''), r.get('reconciliation_outcome', ''),
                r.get('current_status', ''), r.get('active', ''), r.get('reconciliation_called_by', ''),
                r.get('reconciliation_called_at', ''), r.get('reconciliation_attempts', ''),
                r.get('reconciliation_next_followup_at', ''), r.get('reconciliation_last_note', '') or r.get('remarks', '')
            ])
        return out.getvalue().encode('utf-8-sig'), None
    finally:
        db.close()


def _staff_cases_user_allowed(user):
    return bool(user) and (user.get('role') or '') in LIMITED_STAFF_CASE_ROLES


def _staff_department_match(user, item):
    role = (user or {}).get('role') or ''
    if role not in ('nadra_staff', 'passport_staff'):
        return True
    dept = (item.get('assigned_department') or '').strip().lower()
    haystack = ' '.join(str(item.get(k) or '') for k in (
        'module', 'case_type', 'category', 'subject', 'details', 'latest_note_summary'
    )).lower()
    if role == 'nadra_staff':
        return dept == 'nadra' or any(term in haystack for term in ('nadra', 'cnic', 'nicop', 'poc', 'identity card', 'identity document'))
    if role == 'passport_staff':
        return dept == 'passport' or any(term in haystack for term in ('passport', 'travel document', 'passport renewal', 'passport issue'))
    return True


def _staff_module_allowed_for_role(user, item):
    role = ((user or {}).get('role') or '').strip()
    module = (item.get('module') or '').strip()
    haystack = ' '.join(str(item.get(k) or '') for k in (
        'module', 'case_type', 'category', 'subject', 'details', 'latest_note_summary',
        'assigned_department'
    )).lower()
    if role in COMMUNITY_DESK_ROLES:
        return module in ('welfare', 'nurse_complaint', 'facility_reconciliation')
    if role == 'legal_officer':
        return module == 'legal'
    if role == 'death_case_officer':
        return module == 'death'
    if role == 'welfare_officer':
        return module == 'welfare'
    if role == 'staff_opf':
        return module in ('welfare', 'legal', 'nurse_complaint')
    if role in ('field_staff', 'inspector_field'):
        return module in ('facility_reconciliation', 'welfare', 'nurse_complaint')
    if role == 'nadra_staff':
        return module in ('welfare', 'legal', 'nurse_complaint')
    if role == 'passport_staff':
        return module in ('welfare', 'legal', 'nurse_complaint')
    if role in ('senior_review', 'ambassador_review'):
        return module == 'welfare'
    return role in WELFARE_CASE_ACCESS_ROLES


def _staff_item(module, source_id, reference, case_type='', applicant_name='', phone='', whatsapp='', email='',
                subject='', status='', priority='', assigned_at='', due_date='', latest_note_summary='',
                action_required='', assigned_department='', category='', details=''):
    item = {
        'module': module,
        'id': source_id,
        'reference': reference or str(source_id or ''),
        'case_type': case_type or category or module,
        'category': category or '',
        'applicant_name': applicant_name or '',
        'requester_name': applicant_name or '',
        'phone': phone or '',
        'whatsapp': whatsapp or phone or '',
        'email': email or '',
        'subject': subject or '',
        'status': status or '',
        'priority': priority or 'Normal',
        'assigned_at': assigned_at or '',
        'due_date': due_date or '',
        'latest_note_summary': latest_note_summary or '',
        'action_required': action_required or '',
        'assigned_department': assigned_department or '',
        'details': details or '',
    }
    return item


def _staff_case_status_bucket(status):
    s = (status or '').strip().lower()
    if s in ('follow-up completed', 'resolved by staff', 'resolved', 'closed'):
        return 'completed'
    if s in ('in progress', 'assigned', 'seen by staff', 'field verification required', 'needs follow-up'):
        return 'in_progress'
    return 'pending'


def api_staff_my_cases(params, user):
    if not _staff_cases_user_allowed(user):
        return {'success': False, 'error': 'Unauthorized'}
    username = user.get('user') or ''
    db = get_db()
    try:
        items = []
        for r in db.execute("""SELECT id, case_reference, case_type, category, requester_name,
                                      requester_phone, requester_email, subject_name, concern_summary,
                                      details, priority, status, assigned_at, due_date,
                                      assigned_department
                               FROM welfare_cases
                               WHERE COALESCE(assigned_to, '') = ?
                               ORDER BY id DESC LIMIT 300""", [username]).fetchall():
            d = dict(r)
            items.append(_staff_item(
                'welfare', d.get('id'), d.get('case_reference'), d.get('case_type'),
                d.get('requester_name') or d.get('subject_name'), d.get('requester_phone'), '',
                d.get('requester_email'), d.get('concern_summary') or d.get('subject_name'),
                d.get('status'), d.get('priority'), d.get('assigned_at'), d.get('due_date'),
                d.get('details'), '', d.get('assigned_department'), d.get('category'), d.get('details')
            ))
        for r in db.execute("""SELECT c.id, c.complaint_id, COALESCE(c.category, c.complaint_category) AS category,
                                      c.subject, COALESCE(c.status, c.complaint_status) AS status,
                                      c.priority, c.assigned_at, c.due_date, c.assigned_department,
                                      c.nurse_full_name, c.nurse_reference_id, c.passport_number,
                                      c.description, c.internal_notes, c.public_response,
                                      n.mobile_full, n.whatsapp_full, n.email, n.full_name
                               FROM nurse_complaints c
                               LEFT JOIN nurse_registrations n ON n.reference_id = c.nurse_reference_id
                               WHERE COALESCE(c.assigned_to_username, '') = ?
                               ORDER BY c.id DESC LIMIT 300""", [username]).fetchall():
            d = dict(r)
            items.append(_staff_item(
                'nurse_complaint', d.get('id'), d.get('complaint_id'), d.get('category'),
                d.get('nurse_full_name') or d.get('full_name'), d.get('mobile_full'), d.get('whatsapp_full'),
                d.get('email'), d.get('subject'), d.get('status'), d.get('priority'),
                d.get('assigned_at'), d.get('due_date'), d.get('internal_notes') or d.get('public_response'),
                '', d.get('assigned_department'), d.get('category'), d.get('description')
            ))
        for r in db.execute("""SELECT * FROM facility_roster
                               WHERE COALESCE(assigned_to, '') = ?
                               ORDER BY id DESC LIMIT 300""", [username]).fetchall():
            d = _facility_roster_to_dict(r)
            items.append(_staff_item(
                'facility_reconciliation', d.get('id'), d.get('roster_reference'),
                'AJA Care Reconciliation', d.get('full_name'), d.get('phone'),
                d.get('whatsapp_full'), d.get('email'),
                d.get('action_required') or d.get('reconciliation_outcome') or 'Facility reconciliation',
                d.get('reconciliation_status') or d.get('current_status'),
                'Normal', '', d.get('due_date'), d.get('reconciliation_last_note') or d.get('remarks'),
                d.get('action_required'), d.get('assigned_department'), 'Facility Roster',
                d.get('remarks')
            ))
        for r in db.execute("""SELECT id, reference_id, full_name, mobile, email, case_type, subject,
                                      description, priority, status, assigned_at, due_date,
                                      assigned_department, internal_notes, public_response
                               FROM legal_case_requests
                               WHERE COALESCE(assigned_to_username, '') = ?
                               ORDER BY id DESC LIMIT 300""", [username]).fetchall():
            d = dict(r)
            items.append(_staff_item(
                'legal', d.get('id'), d.get('reference_id'), d.get('case_type'), d.get('full_name'),
                d.get('mobile'), '', d.get('email'), d.get('subject'), d.get('status'), d.get('priority'),
                d.get('assigned_at'), d.get('due_date'), d.get('internal_notes') or d.get('public_response'),
                '', d.get('assigned_department'), d.get('case_type'), d.get('description')
            ))
        for r in db.execute("""SELECT id, reference_id, deceased_name, reporter_name, reporter_mobile,
                                      reporter_email, priority, status, assigned_at, due_date,
                                      assigned_department, description, internal_notes, public_response
                               FROM death_case_requests
                               WHERE COALESCE(assigned_to_username, '') = ?
                               ORDER BY id DESC LIMIT 300""", [username]).fetchall():
            d = dict(r)
            items.append(_staff_item(
                'death', d.get('id'), d.get('reference_id'), 'Death Case Follow-up',
                d.get('reporter_name') or d.get('deceased_name'), d.get('reporter_mobile'), '',
                d.get('reporter_email'), d.get('deceased_name'), d.get('status'), d.get('priority'),
                d.get('assigned_at'), d.get('due_date'), d.get('internal_notes') or d.get('public_response'),
                '', d.get('assigned_department'), 'Death Case', d.get('description')
            ))
        items = [i for i in items if _staff_module_allowed_for_role(user, i) and _staff_department_match(user, i)]
        status_filter = _clean_text(params.get('status'), 60).lower()
        if status_filter:
            if status_filter == 'pending':
                items = [i for i in items if _staff_case_status_bucket(i.get('status')) == 'pending']
            elif status_filter == 'in_progress':
                items = [i for i in items if _staff_case_status_bucket(i.get('status')) == 'in_progress']
            elif status_filter == 'completed':
                items = [i for i in items if _staff_case_status_bucket(i.get('status')) == 'completed']
        counters = {
            'assigned_to_me': len(items),
            'pending': sum(1 for i in items if _staff_case_status_bucket(i.get('status')) == 'pending'),
            'in_progress': sum(1 for i in items if _staff_case_status_bucket(i.get('status')) == 'in_progress'),
            'followup_completed': sum(1 for i in items if _staff_case_status_bucket(i.get('status')) == 'completed'),
        }
        items.sort(key=lambda x: (x.get('due_date') or '9999-99-99', x.get('assigned_at') or ''), reverse=False)
        return {'success': True, 'items': items[:500], 'total': len(items), 'counters': counters}
    finally:
        db.close()


def _staff_load_case(db, user, module, ident):
    module = (module or '').strip()
    ident = (ident or '').strip()
    username = user.get('user') or ''
    if not module or not ident:
        return None, [], {'success': False, 'error': 'module and id are required'}
    row = None
    actions = []
    if module == 'welfare':
        if ident.isdigit():
            row = db.execute("SELECT * FROM welfare_cases WHERE id = ?", [int(ident)]).fetchone()
        else:
            row = db.execute("SELECT * FROM welfare_cases WHERE case_reference = ?", [ident]).fetchone()
        if row and (row['assigned_to'] or '') == username:
            actions = [dict(a) for a in db.execute("SELECT * FROM welfare_case_actions WHERE case_id = ? ORDER BY id DESC LIMIT 100", [row['id']]).fetchall()]
    elif module == 'nurse_complaint':
        row = _find_nurse_complaint(db, ident)
        if row and (row['assigned_to_username'] or '') == username:
            ref = _nurse_complaint_reference(dict(row))
            actions = [dict(a) for a in db.execute("SELECT * FROM nurse_complaint_actions WHERE complaint_id = ? ORDER BY id DESC LIMIT 100", [ref]).fetchall()]
    elif module == 'facility_reconciliation':
        if not ident.isdigit():
            row = db.execute("SELECT * FROM facility_roster WHERE roster_reference = ?", [ident]).fetchone()
        else:
            row = db.execute("SELECT * FROM facility_roster WHERE id = ?", [int(ident)]).fetchone()
        if row and (row['assigned_to'] or '') == username:
            actions = [dict(a) for a in db.execute("SELECT * FROM facility_roster_actions WHERE roster_id = ? ORDER BY id DESC LIMIT 100", [row['id']]).fetchall()]
    elif module == 'legal':
        if ident.isdigit():
            row = db.execute("SELECT * FROM legal_case_requests WHERE id = ?", [int(ident)]).fetchone()
        else:
            row = db.execute("SELECT * FROM legal_case_requests WHERE reference_id = ?", [ident]).fetchone()
        if row and (row['assigned_to_username'] or '') == username:
            actions = [dict(a) for a in db.execute("SELECT * FROM legal_case_actions WHERE reference_id = ? ORDER BY id DESC LIMIT 100", [row['reference_id']]).fetchall()]
    elif module == 'death':
        if ident.isdigit():
            row = db.execute("SELECT * FROM death_case_requests WHERE id = ?", [int(ident)]).fetchone()
        else:
            row = db.execute("SELECT * FROM death_case_requests WHERE reference_id = ?", [ident]).fetchone()
        if row and (row['assigned_to_username'] or '') == username:
            actions = [dict(a) for a in db.execute("SELECT * FROM death_case_actions WHERE reference_id = ? ORDER BY id DESC LIMIT 100", [row['reference_id']]).fetchall()]
    if not row:
        return None, [], {'success': False, 'error': 'Forbidden or not found'}
    record = dict(row)
    probe = _staff_item(module, record.get('id'), record.get('case_reference') or record.get('complaint_id') or record.get('roster_reference') or record.get('reference_id'), details=json.dumps(record, default=str), assigned_department=record.get('assigned_department') or '')
    if not _staff_module_allowed_for_role(user, probe) or not _staff_department_match(user, probe):
        return None, [], {'success': False, 'error': 'Forbidden'}
    return record, actions, None


def api_staff_case_detail(params, user):
    if not _staff_cases_user_allowed(user):
        return {'success': False, 'error': 'Unauthorized'}
    db = get_db()
    try:
        record, actions, err = _staff_load_case(db, user, params.get('module'), params.get('id') or params.get('reference'))
        if err:
            return err
        return {'success': True, 'record': record, 'actions': actions}
    finally:
        db.close()


def api_staff_transfer_destinations(user):
    if not _staff_cases_user_allowed(user) and (user or {}).get('role') != 'admin':
        return {'success': False, 'error': 'Unauthorized'}
    quick_keys = [
        'opf_welfare',
        'legal_advisor',
        'nurses_matters',
        'field_inspection',
        'general_welfare',
        'death_body_case',
    ]
    db = get_db()
    try:
        rules = []
        table_exists = db.execute(
            "SELECT 1 FROM sqlite_master WHERE type='table' AND name='welfare_auto_routing_rules' LIMIT 1"
        ).fetchone()
        if table_exists:
            placeholders = ','.join(['?'] * len(quick_keys))
            rows = db.execute(
                f"""SELECT rule_key, desk_name, assigned_to, assigned_role, assigned_department,
                          officer_name, officer_email, officer_phone, priority, sort_order
                   FROM welfare_auto_routing_rules
                   WHERE COALESCE(is_active, 1) = 1
                     AND rule_key IN ({placeholders})""",
                quick_keys
            ).fetchall()
            by_key = {r['rule_key']: dict(r) for r in rows}
            rules = [by_key[k] for k in quick_keys if k in by_key]
        if not rules:
            defaults = {r.get('rule_key'): dict(r) for r in WELFARE_AUTO_ROUTING_DEFAULTS}
            rules = [defaults[k] for k in quick_keys if k in defaults]
        usernames = sorted({(r.get('assigned_to') or '').strip() for r in rules if (r.get('assigned_to') or '').strip()})
        users_by_name = {}
        if usernames:
            placeholders = ','.join(['?'] * len(usernames))
            for row in db.execute(
                f"""SELECT username, COALESCE(full_name, username) AS full_name,
                          COALESCE(email, '') AS email,
                          COALESCE(mobile_number, '') AS mobile_number,
                          COALESCE(department, '') AS department,
                          COALESCE(designation, '') AS designation
                   FROM users
                   WHERE COALESCE(is_active, 1) = 1
                     AND username IN ({placeholders})""",
                usernames
            ).fetchall():
                users_by_name[row['username']] = dict(row)
        items = []
        for rule in rules:
            assigned_to = _clean_text(rule.get('assigned_to'), 120)
            staff = users_by_name.get(assigned_to, {})
            items.append({
                'rule_key': _clean_text(rule.get('rule_key'), 120),
                'desk_name': _clean_text(rule.get('desk_name'), 200),
                'assigned_to': assigned_to,
                'assigned_department': _clean_text(rule.get('assigned_department') or staff.get('department'), 200),
                'officer_name': _clean_text(rule.get('officer_name') or staff.get('full_name') or assigned_to, 200),
                'officer_email': _clean_text(rule.get('officer_email') or staff.get('email'), 200),
                'officer_phone': _clean_text(rule.get('officer_phone') or staff.get('mobile_number'), 100),
                'assigned_role': _clean_text(rule.get('assigned_role') or staff.get('designation'), 120),
            })
        return {'success': True, 'items': items}
    finally:
        db.close()


def _audit_staff_action(db, user, module, reference, action_type, old_status='', new_status='', visible=False):
    try:
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES (?, ?, ?, ?)",
                   [action_type, reference or '', user.get('user') or '', json.dumps({
                       'role': user.get('role') or '',
                       'module': module,
                       'old_status': old_status or '',
                       'new_status': new_status or '',
                       'visible_to_applicant': 1 if visible else 0,
                   })])
    except Exception:
        pass


def api_staff_case_action(data, user, action):
    if not _staff_cases_user_allowed(user):
        return {'success': False, 'error': 'Unauthorized'}
    module = _clean_text(data.get('module'), 80)
    ident = _clean_text(data.get('id') or data.get('reference'), 120)
    note = _clean_text(data.get('note') or data.get('resolution_note'), 3000)
    requested_status = _clean_text(data.get('status'), 80)
    db = get_db()
    try:
        record, actions, err = _staff_load_case(db, user, module, ident)
        if err:
            return err
        role = user.get('role') or ''
        visible_requested = str(data.get('visible_to_applicant') or data.get('visible_to_nurse') or '').lower() in ('1', 'true', 'yes', 'on')
        visible = visible_requested and role in ('field_staff', 'community_desk', 'inspector_field', 'staff_opf')
        reference = record.get('case_reference') or record.get('complaint_id') or record.get('roster_reference') or record.get('reference_id') or str(record.get('id'))
        old_status = record.get('status') or record.get('complaint_status') or record.get('reconciliation_status') or ''
        new_status = requested_status
        if action == 'resolve':
            new_status = requested_status if requested_status in STAFF_LIMITED_STATUSES else 'Follow-up Completed'
        if action == 'status':
            if new_status not in STAFF_LIMITED_STATUSES:
                return {'success': False, 'error': 'Status not allowed for staff workflow'}
        if action == 'note' and not note:
            return {'success': False, 'error': 'note is required'}

        if module == 'welfare':
            if action in ('status', 'resolve'):
                db.execute("UPDATE welfare_cases SET status = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?", [new_status, record['id']])
                _welfare_insert_action(db, record['id'], user.get('user'), 'staff_status' if action == 'status' else 'staff_resolved', old_status, new_status, note, visible)
            else:
                _welfare_insert_action(db, record['id'], user.get('user'), 'staff_note', '', '', note, visible)
        elif module == 'nurse_complaint':
            ref = _nurse_complaint_reference(record)
            if action in ('status', 'resolve'):
                db.execute("""UPDATE nurse_complaints SET complaint_status = ?, status = ?,
                              updated_at = CURRENT_TIMESTAMP, last_action_at = CURRENT_TIMESTAMP, updated_by = ?
                              WHERE id = ?""", [new_status, new_status, user.get('user'), record['id']])
                _add_nurse_complaint_action(db, ref, 'Staff Status' if action == 'status' else 'Staff Follow-up Completed', user.get('user'), role, note=note, old_status=old_status, new_status=new_status, visible_to_nurse=visible)
            else:
                col = 'public_response' if visible else 'internal_notes'
                db.execute(f"UPDATE nurse_complaints SET {col} = ?, updated_at = CURRENT_TIMESTAMP, last_action_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [note, user.get('user'), record['id']])
                _add_nurse_complaint_action(db, ref, 'Nurse-Visible Message' if visible else 'Internal Note', user.get('user'), role, note=note, visible_to_nurse=visible)
        elif module == 'facility_reconciliation':
            if action in ('status', 'resolve'):
                recon_status = 'Unable to Reach' if new_status == 'Unable to Contact' else ('Needs Follow-up' if new_status in ('In Progress', 'Information Requested', 'Seen by Staff') else old_status)
                db.execute("""UPDATE facility_roster SET reconciliation_status = COALESCE(NULLIF(?, ''), reconciliation_status),
                              action_required = ?, reconciliation_last_note = COALESCE(NULLIF(?, ''), reconciliation_last_note),
                              updated_at = CURRENT_TIMESTAMP WHERE id = ?""",
                           [recon_status, new_status, note, record['id']])
                _facility_insert_action(db, record['id'], user.get('user'), 'staff_status' if action == 'status' else 'staff_followup_completed', old_status, new_status, note, visible)
            else:
                _facility_insert_action(db, record['id'], user.get('user'), 'nurse_visible_message' if visible else 'internal_note', '', '', note, visible)
        elif module == 'legal':
            ref = record['reference_id']
            if action in ('status', 'resolve'):
                db.execute("UPDATE legal_case_requests SET status = ?, updated_at = CURRENT_TIMESTAMP, last_action_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [new_status, user.get('user'), record['id']])
                _add_legal_case_action(db, ref, 'Staff Status' if action == 'status' else 'Staff Follow-up Completed', user.get('user'), role, note=note, old_status=old_status, new_status=new_status, visible_to_applicant=visible)
            else:
                col = 'public_response' if visible else 'internal_notes'
                db.execute(f"UPDATE legal_case_requests SET {col} = ?, updated_at = CURRENT_TIMESTAMP, last_action_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [note, user.get('user'), record['id']])
                _add_legal_case_action(db, ref, 'Public Reply' if visible else 'Internal Note', user.get('user'), role, note=note, visible_to_applicant=visible)
        elif module == 'death':
            ref = record['reference_id']
            if action in ('status', 'resolve'):
                db.execute("UPDATE death_case_requests SET status = ?, updated_at = CURRENT_TIMESTAMP, last_action_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [new_status, user.get('user'), record['id']])
                _add_death_case_action(db, ref, 'Staff Status' if action == 'status' else 'Staff Follow-up Completed', user.get('user'), role, note=note, old_status=old_status, new_status=new_status, visible_to_reporter=visible)
            else:
                col = 'public_response' if visible else 'internal_notes'
                db.execute(f"UPDATE death_case_requests SET {col} = ?, updated_at = CURRENT_TIMESTAMP, last_action_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?", [note, user.get('user'), record['id']])
                _add_death_case_action(db, ref, 'Public Reply' if visible else 'Internal Note', user.get('user'), role, note=note, visible_to_reporter=visible)
        _audit_staff_action(db, user, module, reference, f'staff_{action}', old_status, new_status, visible)
        db.commit()
        return {'success': True, 'status': new_status or old_status}
    except Exception as e:
        traceback.print_exc()
        db.rollback()
        return {'success': False, 'error': str(e)}
    finally:
        db.close()


def api_admin_facility_matches(user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    db = get_db()
    try:
        unmatched = [_facility_roster_to_dict(r) for r in db.execute(
            """SELECT * FROM facility_roster
               WHERE active = 1 AND (nurse_registration_id IS NULL OR nurse_registration_id = 0)
               ORDER BY id DESC LIMIT 200"""
        ).fetchall()]
        linked = [_facility_roster_to_dict(r) for r in db.execute(
            """SELECT * FROM facility_roster
               WHERE active = 1 AND nurse_registration_id IS NOT NULL AND nurse_registration_id != 0
               ORDER BY updated_at DESC LIMIT 200"""
        ).fetchall()]
        potential = []
        for r in unmatched[:100]:
            partial_passport = (r.get('passport_number') or '')[-4:]
            name_token = (r.get('full_name') or '').split(' ')[0]
            row = db.execute(
                """SELECT id, reference_id, full_name, passport_number, civil_id, mobile
                   FROM nurse_registrations
                   WHERE (
                     UPPER(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', '')) = UPPER(REPLACE(TRIM(?), ' ', ''))
                     OR (TRIM(COALESCE(civil_id,'')) != '' AND TRIM(COALESCE(civil_id,'')) = TRIM(?))
                     OR (TRIM(COALESCE(mobile,'')) != '' AND TRIM(COALESCE(mobile,'')) = TRIM(?))
                     OR (? != '' AND UPPER(full_name) LIKE UPPER(?) AND passport_number LIKE ?)
                   )
                   ORDER BY id DESC LIMIT 3""",
                [r.get('passport_number', ''), r.get('civil_id', ''), r.get('phone', ''),
                 partial_passport, f'%{name_token}%', f'%{partial_passport}%']
            ).fetchall()
            if row:
                potential.append({'roster': r, 'matches': [dict(x) for x in row]})
        return {'success': True, 'unmatched': unmatched, 'potential_matches': potential, 'linked': linked}
    finally:
        db.close()


def _aja_vendor_people_count(db, roster_clause='', nurse_clause='', roster_vals=(), nurse_vals=()):
    roster_clause = f" {roster_clause}" if roster_clause else ''
    nurse_clause = f" {nurse_clause}" if nurse_clause else ''
    sql = f"""SELECT COUNT(*) c FROM (
        SELECT 'n:' || n.id AS person_key
        FROM nurse_registrations n
        WHERE COALESCE(n.professional_category, 'Nurse') != 'Doctor'
          AND COALESCE(n.current_arrangement, n.current_accommodation, '') = 'Embassy Contracted / Arranged'
          AND COALESCE(n.vendor_name, '') = ?
          {nurse_clause}
        UNION
        SELECT CASE WHEN COALESCE(f.nurse_registration_id, 0) != 0
                    THEN 'n:' || f.nurse_registration_id
                    ELSE 'r:' || f.id END AS person_key
        FROM facility_roster f
        LEFT JOIN nurse_registrations n ON n.id = f.nurse_registration_id
        WHERE COALESCE(n.professional_category, 'Nurse') != 'Doctor'
          AND COALESCE(f.current_arrangement, 'Embassy Contracted / Arranged') = 'Embassy Contracted / Arranged'
          AND COALESCE(f.vendor_name, '') = ?
          {roster_clause}
    )"""
    try:
        return int(db.execute(sql, [FACILITY_VENDOR_DEFAULT, *list(nurse_vals), FACILITY_VENDOR_DEFAULT, *list(roster_vals)]).fetchone()['c'] or 0)
    except Exception as exc:
        print(f'[FacilityKPI] AJA count failed: {exc}', flush=True)
        return 0


def _facility_occupancy_kpis(db):
    def count(sql, vals=()):
        try:
            return int(db.execute(sql, vals).fetchone()['c'] or 0)
        except Exception:
            return 0
    vendor = FACILITY_VENDOR_DEFAULT
    kpis = {
        'total_assigned': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1"),
        'embassy_facilitated_residents': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1"),
        'confirmed_staying': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND current_status = 'Confirmed Staying'"),
        'pending_confirmation': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND confirmation_status = 'Pending Nurse Confirmation'"),
        'intending_to_leave': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND current_status = 'Intends to Leave'"),
        'leaving_notice_submitted': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND current_status = 'Leaving Notice Submitted'"),
        'left_facility': count("SELECT COUNT(*) c FROM facility_roster WHERE current_status = 'Left Facility'"),
        'vendor_mismatch_records': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND reconciliation_status = 'Reconciliation Required'"),
        'reconciliation_required': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND reconciliation_status = 'Reconciliation Required'"),
        'welfare_followup_required': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND welfare_followup_required = 1"),
        'open_welfare_requests': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND welfare_followup_required = 1"),
        'alternative_stay_review': count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND alternative_stay_review_required = 1"),
        'notice_period_due': 0,
    }
    active_roster = "AND COALESCE(f.active, 1) = 1 AND COALESCE(f.current_status, '') NOT IN ('Left Facility','Closed / Archived','Inactive')"
    active_nurse = "AND COALESCE(n.current_status, n.facility_status, '') NOT IN ('Left Facility','Closed / Archived','Inactive')"
    pending_roster = """AND (
        COALESCE(f.current_status, '') IN ('Pending Stay Confirmation','Registered - Vendor Facility','Sent','Pending Response','Pending Nurse Confirmation','Assigned','Assigned to Facility')
        OR COALESCE(f.monthly_checkin_status, '') IN ('Sent','Pending Response')
        OR COALESCE(f.confirmation_status, '') IN ('Pending','Pending Nurse Confirmation')
    )"""
    pending_nurse = """AND (
        COALESCE(n.current_status, n.facility_status, '') IN ('Pending Stay Confirmation','Registered - Vendor Facility','Sent','Pending Response')
        OR COALESCE(n.stay_confirmation_status, '') IN ('Pending','Pending Nurse Confirmation')
    )"""
    kpis.update({
        'total_vendor_linked_residents': _aja_vendor_people_count(db, active_roster, active_nurse),
        'total_aja_care_residents': _aja_vendor_people_count(db, active_roster, active_nurse),
        'active_currently_staying': _aja_vendor_people_count(db, active_roster, active_nurse),
        'aja_confirmed_staying': _aja_vendor_people_count(db, "AND COALESCE(f.current_status, '') = 'Confirmed Staying'", "AND COALESCE(n.current_status, n.facility_status, '') = 'Confirmed Staying'"),
        'aja_intending_to_leave': _aja_vendor_people_count(db, "AND COALESCE(f.current_status, '') = 'Intends to Leave'", "AND COALESCE(n.current_status, n.facility_status, '') = 'Intends to Leave'"),
        'aja_left_facility': _aja_vendor_people_count(db, "AND COALESCE(f.current_status, '') = 'Left Facility'", "AND COALESCE(n.current_status, n.facility_status, '') = 'Left Facility'"),
        'details_correction': count(
            "SELECT COUNT(*) c FROM facility_roster WHERE vendor_name = ? AND (monthly_checkin_status = 'Details Correction' OR reconciliation_status = 'Reconciliation Required')",
            [vendor]
        ),
        'needs_assistance': count("SELECT COUNT(*) c FROM facility_roster WHERE vendor_name = ? AND welfare_followup_required = 1", [vendor]),
        'no_response': count("SELECT COUNT(*) c FROM facility_roster WHERE vendor_name = ? AND monthly_checkin_status = 'No Response'", [vendor]),
        'aja_pending_confirmation': _aja_vendor_people_count(db, pending_roster, pending_nurse),
        'pending_reconciliation': count("SELECT COUNT(*) c FROM facility_roster WHERE vendor_name = ? AND reconciliation_status = 'Reconciliation Required'", [vendor]),
    })
    kpis['confirmed_staying'] = kpis['aja_confirmed_staying']
    kpis['intending_to_leave'] = kpis['aja_intending_to_leave']
    kpis['left_facility'] = kpis['aja_left_facility']
    kpis['pending_confirmation'] = kpis['aja_pending_confirmation']
    kpis['embassy_facilitated_residents'] = kpis['total_aja_care_residents']
    kpis['total_assigned'] = kpis['total_aja_care_residents']
    kpis['reconciliation_required'] = kpis['pending_reconciliation']
    kpis['open_welfare_requests'] = kpis['needs_assistance']
    kpis['welfare_followup_required'] = kpis['needs_assistance']
    return kpis


def api_admin_facility_occupancy(params, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    db = get_db()
    try:
        where = ["(active = 1 OR current_status = 'Left Facility')"]
        vals = []
        for param, col in (
            ('facility', 'facility_name'), ('facility_name', 'facility_name'),
            ('vendor', 'vendor_name'), ('vendor_name', 'vendor_name'),
            ('status', 'current_status'), ('confirmation_status', 'confirmation_status'),
            ('assigned_officer', 'assigned_to'), ('assigned_to', 'assigned_to')
        ):
            value = _clean_text(params.get(param), 160)
            if value:
                where.append(f"{col} = ?")
                vals.append(value)
        area_filter = _clean_text(params.get('area') or params.get('facility_area'), 160)
        if area_filter:
            where.append("(facility_area = ? OR area = ?)")
            vals.extend([area_filter, area_filter])
        notice_due = _clean_text(params.get('notice_due'), 20)
        if notice_due:
            where.append("""(
                COALESCE(notice_period_start_date,'') != ''
                AND date(notice_period_start_date) <= date('now')
                AND COALESCE(current_status,'') NOT IN ('Leaving Notice Submitted','Left Facility','Closed / Archived','Inactive')
            )""")
        rows = [_facility_roster_to_dict(r) for r in db.execute(
            f"SELECT * FROM facility_roster WHERE {' AND '.join(where)} ORDER BY facility_name, full_name",
            vals
        ).fetchall()]
        kpis = _facility_occupancy_kpis(db)
        kpis['notice_period_due'] = sum(1 for r in rows if r.get('notice_flag') in ('Notice Period Active', 'Notice Response Pending'))
        grouped = {}
        for r in rows:
            key = (r.get('facility_name') or 'Unspecified Facility', r.get('vendor_name') or '', r.get('facility_area') or r.get('area') or '')
            g = grouped.setdefault(key, {
                'facility_name': key[0],
                'vendor_name': key[1],
                'area': key[2],
                'expected_residents': 0,
                'confirmed_staying': 0,
                'pending_confirmation': 0,
                'intending_to_leave': 0,
                'leaving_notice_submitted': 0,
                'left_facility': 0,
                'notice_period_due': 0,
                'open_welfare_requests': 0,
                'reconciliation_required': 0,
                'last_vendor_update': '',
                'last_embassy_verification': '',
            })
            g['expected_residents'] += 1
            if r.get('current_status') == 'Confirmed Staying':
                g['confirmed_staying'] += 1
            if r.get('confirmation_status') == 'Pending Nurse Confirmation':
                g['pending_confirmation'] += 1
            if r.get('current_status') == 'Intends to Leave':
                g['intending_to_leave'] += 1
            if r.get('current_status') == 'Leaving Notice Submitted':
                g['leaving_notice_submitted'] += 1
            if r.get('current_status') == 'Left Facility':
                g['left_facility'] += 1
            if r.get('notice_flag') in ('Notice Period Active', 'Notice Response Pending'):
                g['notice_period_due'] += 1
            if r.get('welfare_followup_required'):
                g['open_welfare_requests'] += 1
            if r.get('reconciliation_status') == 'Reconciliation Required':
                g['reconciliation_required'] += 1
            g['last_vendor_update'] = max(g['last_vendor_update'], r.get('last_vendor_update_at') or '')
            g['last_embassy_verification'] = max(g['last_embassy_verification'], r.get('last_embassy_verification_at') or r.get('last_confirmed_at') or '')
        return {'success': True, 'kpis': kpis, 'facilities': list(grouped.values())}
    finally:
        db.close()


def api_admin_facility_detail(params, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    facility = _clean_text(params.get('facility'), 220)
    vendor = _clean_text(params.get('vendor'), 220)
    area = _clean_text(params.get('area') or params.get('facility_area'), 160)
    db = get_db()
    try:
        vals = []
        where = ["(active = 1 OR current_status = 'Left Facility')"]
        if facility:
            where.append("facility_name = ?")
            vals.append(facility)
        if vendor:
            where.append("vendor_name = ?")
            vals.append(vendor)
        if area:
            where.append("(facility_area = ? OR area = ?)")
            vals.extend([area, area])
        rows = [_facility_roster_to_dict(r) for r in db.execute(
            f"SELECT * FROM facility_roster WHERE {' AND '.join(where)} ORDER BY full_name",
            vals
        ).fetchall()]
        actions = []
        if rows:
            ids = [str(int(r['id'])) for r in rows if r.get('id')]
            if ids:
                actions = [dict(a) for a in db.execute(
                    f"""SELECT * FROM facility_roster_actions
                        WHERE roster_id IN ({','.join(['?'] * len(ids))})
                        ORDER BY id DESC LIMIT 100""",
                    ids
                ).fetchall()]
        return {
            'success': True,
            'facility': facility or (rows[0].get('facility_name') if rows else ''),
            'vendor_name': rows[0].get('vendor_name', '') if rows else '',
            'area': rows[0].get('facility_area') or rows[0].get('area', '') if rows else '',
            'summary': {
                'expected_residents': len(rows),
                'confirmed_residents': sum(1 for r in rows if r.get('current_status') == 'Confirmed Staying'),
                'unconfirmed_residents': sum(1 for r in rows if r.get('confirmation_status') == 'Pending Nurse Confirmation'),
                'leaving_notices': sum(1 for r in rows if r.get('current_status') == 'Leaving Notice Submitted'),
                'open_welfare_requests': sum(1 for r in rows if r.get('welfare_followup_required')),
                'notice_period_due': sum(1 for r in rows if r.get('notice_flag') in ('Notice Period Active', 'Notice Response Pending')),
                'reconciliation_required': sum(1 for r in rows if r.get('reconciliation_status') == 'Reconciliation Required'),
            },
            'items': rows,
            'actions': actions
        }
    finally:
        db.close()


def api_admin_send_confirmation_campaign(data, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    vendor = _clean_text(data.get('vendor') or data.get('vendor_name') or FACILITY_VENDOR_DEFAULT, 120) or FACILITY_VENDOR_DEFAULT
    facility_name = _clean_text(data.get('facility_name'), 220)
    channel = _clean_text(data.get('channel') or MONTHLY_WELFARE_CHECKIN_CHANNEL, 40).lower() or MONTHLY_WELFARE_CHECKIN_CHANNEL
    target = _clean_text(data.get('target') or 'active_vendor_residents', 80) or 'active_vendor_residents'
    if target not in ('active_vendor_residents', 'pending_confirmation', 'notice_due', 'selected_facility'):
        return {'success': False, 'error': 'Invalid campaign target.'}
    if target == 'selected_facility' and not facility_name:
        return {'success': False, 'error': 'Facility name is required for selected facility campaigns.'}
    return _run_monthly_welfare_campaign(
        vendor=vendor,
        facility_name=facility_name,
        channel=channel,
        target=target,
        created_by=(user or {}).get('user') or 'admin'
    )


def api_admin_facility_checkin_campaigns(params, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    mark_monthly_checkin_no_response()
    db = get_db()
    try:
        campaigns = [dict(r) for r in db.execute(
            """SELECT * FROM stay_confirmation_campaigns
               WHERE campaign_type = ?
               ORDER BY campaign_year DESC, campaign_month DESC, id DESC
               LIMIT 24""",
            [MONTHLY_WELFARE_CHECKIN_TYPE]
        ).fetchall()]
        for c in campaigns:
            c['total_confirmed_staying'] = c.get('total_confirmed') or 0
        campaign_id = int(params.get('campaign_id') or (campaigns[0]['id'] if campaigns else 0) or 0)
        tokens = []
        if campaign_id:
            tokens = [dict(r) for r in db.execute(
                """SELECT t.id, t.campaign_id, t.roster_id, t.roster_reference, t.nurse_registration_id,
                          t.nurse_reference, t.vendor_name, t.facility_name, t.email, t.whatsapp_full,
                          t.mobile_full, t.action_taken, t.welfare_response, t.used_at, t.created_at,
                          t.channel, t.status,
                          COALESCE(n.full_name, f.full_name, '') AS nurse_name,
                          f.current_status, f.monthly_checkin_status, f.last_confirmed_at,
                          f.last_monthly_checkin_response_at, f.welfare_followup_required,
                          f.reconciliation_status
                   FROM stay_confirmation_tokens t
                   LEFT JOIN facility_roster f ON f.id = t.roster_id
                   LEFT JOIN nurse_registrations n ON n.id = t.nurse_registration_id
                   WHERE t.campaign_id = ?
                   ORDER BY t.id DESC LIMIT 500""",
                [campaign_id]
            ).fetchall()]
        no_response = [dict(r) for r in db.execute(
            """SELECT f.id, f.roster_reference, f.nurse_registration_id, f.full_name, f.vendor_name,
                      f.facility_name, f.current_status, f.monthly_checkin_status,
                      f.last_monthly_checkin_sent_at, f.last_monthly_checkin_response_at,
                      f.welfare_followup_required, f.reconciliation_status, f.assigned_to
               FROM facility_roster f
               WHERE f.vendor_name = ? AND f.monthly_checkin_status = 'No Response'
               ORDER BY datetime(f.updated_at) DESC LIMIT 200""",
            [FACILITY_VENDOR_DEFAULT]
        ).fetchall()]
        return {'success': True, 'campaigns': campaigns, 'items': tokens, 'no_response': no_response, 'kpis': _facility_occupancy_kpis(db)}
    finally:
        db.close()


def api_admin_stay_confirmation_resend(data, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    token_id = int(data.get('token_id') or 0)
    roster_id = int(data.get('roster_id') or 0)
    db = get_db()
    try:
        row = None
        if token_id:
            row = db.execute("SELECT * FROM stay_confirmation_tokens WHERE id = ?", [token_id]).fetchone()
        elif roster_id:
            row = db.execute(
                """SELECT * FROM stay_confirmation_tokens
                   WHERE roster_id = ? ORDER BY id DESC LIMIT 1""",
                [roster_id]
            ).fetchone()
        if not row:
            return {'success': False, 'error': 'Check-in token not found.'}
        d = dict(row)
        email = (d.get('email') or '').strip()
        if not email:
            _monthly_checkin_log(db, 'monthly_welfare_checkin_resend', 'skipped_no_email', d, '', '', 'missing_email', 'email')
            db.commit()
            return {'success': False, 'error': 'No email address is available for this record.'}
        new_token = secrets.token_urlsafe(32)
        expires_at = _sql_dt(datetime.utcnow() + timedelta(days=14))
        base = _nurse_portal_public_base_url()
        link = f"{base}/stay-confirm?token={quote(new_token, safe='')}"
        name = ''
        if d.get('roster_id'):
            rr = db.execute("SELECT full_name FROM facility_roster WHERE id = ?", [d.get('roster_id')]).fetchone()
            name = rr['full_name'] if rr else ''
        if not name and d.get('nurse_registration_id'):
            nr = db.execute("SELECT full_name FROM nurse_registrations WHERE id = ?", [d.get('nurse_registration_id')]).fetchone()
            name = nr['full_name'] if nr else ''
        subject = 'Community Welfare Wing – Monthly Welfare Check-in'
        body = _monthly_checkin_email_body(name, d.get('nurse_reference') or d.get('roster_reference') or '', link)
        body_html = _monthly_checkin_email_html(name, d.get('nurse_reference') or d.get('roster_reference') or '', link)
        send_res = send_notification_email(email, subject, body, body_html)
        status = 'sent' if send_res.get('ok') else ('skipped_smtp_missing' if send_res.get('reason') == 'smtp_not_configured' else 'failed')
        db.execute(
            """UPDATE stay_confirmation_tokens
               SET token = ?, expires_at = ?, status = ?, action_taken = '', welfare_response = '',
                   remarks = '', used_at = NULL, created_at = CURRENT_TIMESTAMP, created_by = ?
               WHERE id = ?""",
            [new_token, expires_at, status, (user or {}).get('user') or 'admin', d['id']]
        )
        if d.get('roster_id'):
            db.execute(
                """UPDATE facility_roster
                   SET monthly_checkin_status = ?, last_monthly_checkin_sent_at = CURRENT_TIMESTAMP,
                       updated_at = CURRENT_TIMESTAMP
                   WHERE id = ?""",
                ['Sent' if status == 'sent' else 'Failed Delivery', d.get('roster_id')]
            )
        _monthly_checkin_log(db, 'monthly_welfare_checkin_resend', status, d, subject, body, send_res.get('reason') or '', 'email')
        if d.get('campaign_id'):
            _refresh_campaign_totals(db, d.get('campaign_id'))
        db.commit()
        return {'success': status == 'sent', 'status': status, 'error': '' if status == 'sent' else send_res.get('reason') or status}
    except Exception as exc:
        db.rollback()
        return {'success': False, 'error': str(exc)}
    finally:
        db.close()


def api_admin_facility_checkin_report_csv(user):
    if not _facility_user_can_access(user):
        return None, {'success': False, 'error': 'Unauthorized'}
    db = get_db()
    try:
        rows = db.execute(
            """SELECT c.campaign_year, c.campaign_month, c.campaign_reference, c.vendor_name AS campaign_vendor,
                      c.facility_name AS campaign_facility, c.channel, c.status AS campaign_status,
                      c.total_targeted, c.total_sent, c.total_failed, c.total_confirmed,
                      c.total_intends_to_leave, c.total_left_facility, c.total_details_correction,
                      c.total_needs_assistance, c.total_no_response, c.started_at, c.completed_at,
                      t.roster_reference, t.nurse_reference, COALESCE(n.full_name, f.full_name, '') AS nurse_name,
                      t.facility_name, t.action_taken, t.welfare_response, t.status AS token_status,
                      t.created_at AS sent_at, t.used_at AS responded_at,
                      f.current_status, f.monthly_checkin_status, f.welfare_followup_required,
                      f.reconciliation_status
               FROM stay_confirmation_campaigns c
               LEFT JOIN stay_confirmation_tokens t ON t.campaign_id = c.id
               LEFT JOIN facility_roster f ON f.id = t.roster_id
               LEFT JOIN nurse_registrations n ON n.id = t.nurse_registration_id
               WHERE c.campaign_type = ?
               ORDER BY c.campaign_year DESC, c.campaign_month DESC, c.id DESC, t.id DESC""",
            [MONTHLY_WELFARE_CHECKIN_TYPE]
        ).fetchall()
        out = io.StringIO()
        writer = csv.writer(out)
        headers = [
            'campaign_year', 'campaign_month', 'campaign_reference', 'vendor', 'facility', 'channel',
            'campaign_status', 'total_targeted', 'total_sent', 'total_failed', 'total_confirmed_staying',
            'total_intends_to_leave', 'total_left_facility', 'total_details_correction',
            'total_needs_assistance', 'total_no_response', 'started_at', 'completed_at',
            'nurse_name', 'nurse_reference', 'roster_reference', 'token_facility', 'sent_at',
            'stay_response', 'welfare_response', 'responded_at', 'token_status',
            'current_status', 'monthly_checkin_status', 'welfare_followup_required',
            'reconciliation_status'
        ]
        writer.writerow(headers)
        for row in rows:
            d = dict(row)
            writer.writerow([
                d.get('campaign_year', ''), d.get('campaign_month', ''), d.get('campaign_reference', ''),
                d.get('campaign_vendor', ''), d.get('campaign_facility', ''), d.get('channel', ''),
                d.get('campaign_status', ''), d.get('total_targeted', ''), d.get('total_sent', ''),
                d.get('total_failed', ''), d.get('total_confirmed', ''), d.get('total_intends_to_leave', ''),
                d.get('total_left_facility', ''), d.get('total_details_correction', ''),
                d.get('total_needs_assistance', ''), d.get('total_no_response', ''),
                d.get('started_at', ''), d.get('completed_at', ''), d.get('nurse_name', ''),
                d.get('nurse_reference', ''), d.get('roster_reference', ''), d.get('facility_name', ''),
                d.get('sent_at', ''), d.get('action_taken', ''), d.get('welfare_response', ''),
                d.get('responded_at', ''), d.get('token_status', ''), d.get('current_status', ''),
                d.get('monthly_checkin_status', ''), d.get('welfare_followup_required', ''),
                d.get('reconciliation_status', '')
            ])
        return out.getvalue().encode('utf-8-sig'), None
    finally:
        db.close()


def _alternative_facility_payload(data):
    def _num(name, default=0):
        try:
            return float(data.get(name) or default)
        except Exception:
            return default
    def _int(name, default=0):
        try:
            return int(data.get(name) or default)
        except Exception:
            return default
    return {
        'vendor_name': _clean_text(data.get('vendor_name'), 220) or FACILITY_VENDOR_DEFAULT,
        'facility_name': _clean_text(data.get('facility_name'), 220),
        'area': _clean_text(data.get('area') or data.get('facility_area'), 160),
        'address': _clean_text(data.get('address') or data.get('facility_address'), 300),
        'contact_person': _clean_text(data.get('contact_person'), 160),
        'contact_phone': _clean_text(data.get('contact_phone'), 80),
        'capacity': max(0, _int('capacity', 0)),
        'available_capacity': max(0, _int('available_capacity', 0)),
        'indicative_monthly_cost_kwd': max(0, _num('indicative_monthly_cost_kwd', 0)),
        'transport_available': _clean_text(data.get('transport_available'), 40),
        'female_suitable': _clean_text(data.get('female_suitable'), 20) or 'Yes',
        'notes': _clean_text(data.get('notes'), 3000),
        'active': 0 if str(data.get('active')).strip().lower() in ('0', 'false', 'no', 'inactive') else 1,
    }


def api_admin_alternative_facilities(params, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    db = get_db()
    try:
        where = ["1=1"]
        vals = []
        if _clean_text(params.get('active'), 20):
            where.append("active = ?")
            vals.append(1 if params.get('active') in ('1', 'true', 'yes') else 0)
        q = _clean_text(params.get('q') or params.get('search'), 120)
        if q:
            sv = f"%{q}%"
            where.append("(vendor_name LIKE ? OR facility_name LIKE ? OR area LIKE ? OR address LIKE ?)")
            vals.extend([sv, sv, sv, sv])
        rows = [dict(r) for r in db.execute(
            f"SELECT * FROM alternative_facilities WHERE {' AND '.join(where)} ORDER BY active DESC, facility_name ASC",
            vals
        ).fetchall()]
        return {'success': True, 'items': rows, 'total': len(rows)}
    finally:
        db.close()


def api_admin_alternative_facility_save(data, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    payload = _alternative_facility_payload(data)
    if not payload['facility_name']:
        return {'success': False, 'error': 'Facility / Building name is required.'}
    entry_id = int(data.get('id') or 0)
    db = get_db()
    try:
        if entry_id:
            row = db.execute("SELECT id FROM alternative_facilities WHERE id = ?", [entry_id]).fetchone()
            if not row:
                return {'success': False, 'error': 'Alternative facility not found.'}
            db.execute(
                """UPDATE alternative_facilities
                   SET vendor_name = ?, facility_name = ?, area = ?, address = ?,
                       contact_person = ?, contact_phone = ?, capacity = ?, available_capacity = ?,
                       indicative_monthly_cost_kwd = ?, transport_available = ?, female_suitable = ?,
                       notes = ?, active = ?, updated_at = CURRENT_TIMESTAMP
                   WHERE id = ?""",
                [
                    payload['vendor_name'], payload['facility_name'], payload['area'], payload['address'],
                    payload['contact_person'], payload['contact_phone'], payload['capacity'],
                    payload['available_capacity'], payload['indicative_monthly_cost_kwd'],
                    payload['transport_available'], payload['female_suitable'], payload['notes'],
                    payload['active'], entry_id
                ]
            )
        else:
            cur = db.execute(
                """INSERT INTO alternative_facilities
                   (vendor_name, facility_name, area, address, contact_person, contact_phone,
                    capacity, available_capacity, indicative_monthly_cost_kwd, transport_available,
                    female_suitable, notes, active)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                [
                    payload['vendor_name'], payload['facility_name'], payload['area'], payload['address'],
                    payload['contact_person'], payload['contact_phone'], payload['capacity'],
                    payload['available_capacity'], payload['indicative_monthly_cost_kwd'],
                    payload['transport_available'], payload['female_suitable'], payload['notes'],
                    payload['active']
                ]
            )
            entry_id = cur.lastrowid
        db.commit()
        return {'success': True, 'id': entry_id}
    except Exception as e:
        db.rollback()
        return {'success': False, 'error': str(e)}
    finally:
        db.close()


def api_admin_facility_reports(params, user):
    if not _facility_user_can_access(user):
        return {'success': False, 'error': 'Unauthorized'}
    report_type = _clean_text(params.get('type') or 'facility_occupancy', 80)
    db = get_db()
    try:
        kpis = _facility_occupancy_kpis(db)
        rows = [_facility_roster_to_dict(r) for r in db.execute(
            "SELECT * FROM facility_roster WHERE active = 1 ORDER BY vendor_name, facility_name, full_name"
        ).fetchall()]
        kpis['notice_period_due'] = sum(1 for r in rows if r.get('notice_flag') in ('Notice Period Active', 'Notice Response Pending'))
        category_counts = {}
        for r in rows:
            key = r.get('action_required') or r.get('current_status') or 'Unspecified'
            category_counts[key] = category_counts.get(key, 0) + 1
        return {
            'success': True,
            'type': report_type,
            'generated_at': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            'vendor_label': f'Vendor: {FACILITY_VENDOR_DEFAULT}',
            'summary': kpis,
            'category_counts': category_counts,
            'items': rows[:1000],
            'reports_prepared': [
                'Facility Occupancy Report',
                'Vendor Coordination Report',
                'Notice Period Due Report',
                'Leaving Notice Report',
                'Welfare Follow-up Report',
                'Monthly Vendor Review Report',
            ]
        }
    finally:
        db.close()


def api_admin_community_welfare_summary(user):
    """Aggregated KPIs across nurses, legal cases, and death cases for the
    /admin/community-welfare overview page. Safely handles missing tables."""
    db = get_db()
    try:
        def _count(sql, vals=()):
            try:
                return int((db.execute(sql, vals).fetchone()['c']) or 0)
            except Exception:
                return 0
        username = (user or {}).get('user', '') or ''
        community_scope = is_community_desk_role((user or {}).get('role', ''))
        # Per-module counts (degrade to 0 if table missing)
        nurse_complaints_total = _count("SELECT COUNT(*) c FROM nurse_complaints")
        nurse_complaints_pending = _count("SELECT COUNT(*) c FROM nurse_complaints WHERE complaint_status IN ('Submitted','Seen','Pending')")
        nurse_complaints_progress = _count("SELECT COUNT(*) c FROM nurse_complaints WHERE complaint_status IN ('Assigned','In Progress')")
        nurse_complaints_resolved_week = _count(
            "SELECT COUNT(*) c FROM nurse_complaints WHERE complaint_status='Resolved' "
            "AND date(IFNULL(updated_at,created_at)) >= date('now','-7 days')")
        nurse_complaints_urgent = _count("SELECT COUNT(*) c FROM nurse_complaints WHERE LOWER(IFNULL(priority,''))='urgent' AND complaint_status NOT IN ('Resolved','Closed')")
        nurse_complaints_mine = _count("SELECT COUNT(*) c FROM nurse_complaints WHERE assigned_to_username=? AND complaint_status NOT IN ('Resolved','Closed')", (username,))

        if community_scope:
            legal_total = legal_pending = legal_progress = legal_resolved_week = legal_urgent = legal_mine = 0
            death_total = death_pending = death_progress = death_resolved_week = death_urgent = death_mine = 0
        else:
            legal_total = _count("SELECT COUNT(*) c FROM legal_case_requests")
            legal_pending = _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status IN ('Submitted','Seen by Admin')")
            legal_progress = _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status IN ('Assigned','In Progress')")
            legal_resolved_week = _count(
                "SELECT COUNT(*) c FROM legal_case_requests WHERE status='Resolved' "
                "AND date(IFNULL(updated_at,created_at)) >= date('now','-7 days')")
            legal_urgent = _count("SELECT COUNT(*) c FROM legal_case_requests WHERE LOWER(IFNULL(priority,''))='urgent' AND status NOT IN ('Resolved','Closed')")
            legal_mine = _count("SELECT COUNT(*) c FROM legal_case_requests WHERE assigned_to_username=? AND status NOT IN ('Resolved','Closed')", (username,))

            death_total = _count("SELECT COUNT(*) c FROM death_case_requests")
            death_pending = _count("SELECT COUNT(*) c FROM death_case_requests WHERE status IN ('Submitted','Seen by Admin')")
            death_progress = _count("SELECT COUNT(*) c FROM death_case_requests WHERE status IN ('Assigned','In Progress')")
            death_resolved_week = _count(
                "SELECT COUNT(*) c FROM death_case_requests WHERE status='Resolved' "
                "AND date(IFNULL(updated_at,created_at)) >= date('now','-7 days')")
            death_urgent = _count("SELECT COUNT(*) c FROM death_case_requests WHERE LOWER(IFNULL(priority,''))='urgent' AND status NOT IN ('Resolved','Closed')")
            death_mine = _count("SELECT COUNT(*) c FROM death_case_requests WHERE assigned_to_username=? AND status NOT IN ('Resolved','Closed')", (username,))

        # Build urgent_list from the three tables (top 6 most recent urgent unresolved)
        urgent_list = []
        try:
            for r in db.execute(
                "SELECT complaint_id AS reference, nurse_full_name AS applicant, "
                "IFNULL(category,IFNULL(complaint_category,'Complaint')) AS type, "
                "complaint_status AS status, IFNULL(updated_at,created_at) AS time, "
                "assigned_to_username AS assigned "
                "FROM nurse_complaints WHERE LOWER(IFNULL(priority,''))='urgent' "
                "AND complaint_status NOT IN ('Resolved','Closed') "
                "ORDER BY IFNULL(updated_at,created_at) DESC LIMIT 4").fetchall():
                d = dict(r); d['module'] = 'nurses'; urgent_list.append(d)
        except Exception:
            pass
        if not community_scope:
            try:
                for r in db.execute(
                    "SELECT reference_id AS reference, full_name AS applicant, "
                    "case_type AS type, status AS status, "
                    "IFNULL(updated_at,created_at) AS time, assigned_to_username AS assigned "
                    "FROM legal_case_requests WHERE LOWER(IFNULL(priority,''))='urgent' "
                    "AND status NOT IN ('Resolved','Closed') "
                    "ORDER BY IFNULL(updated_at,created_at) DESC LIMIT 3").fetchall():
                    d = dict(r); d['module'] = 'legal'; urgent_list.append(d)
            except Exception:
                pass
        if not community_scope:
            try:
                for r in db.execute(
                    "SELECT reference_id AS reference, deceased_name AS applicant, "
                    "'Death Case' AS type, status AS status, "
                    "IFNULL(updated_at,created_at) AS time, assigned_to_username AS assigned "
                    "FROM death_case_requests WHERE LOWER(IFNULL(priority,''))='urgent' "
                    "AND status NOT IN ('Resolved','Closed') "
                    "ORDER BY IFNULL(updated_at,created_at) DESC LIMIT 3").fetchall():
                    d = dict(r); d['module'] = 'death'; urgent_list.append(d)
            except Exception:
                pass
        return {
            'success': True,
            'user_display': (user or {}).get('user', 'Officer'),
            'user_role': (user or {}).get('role', ''),
            'totals': {
                'total': nurse_complaints_total + legal_total + death_total,
                'pending': nurse_complaints_pending + legal_pending + death_pending,
                'in_progress': nurse_complaints_progress + legal_progress + death_progress,
                'urgent': nurse_complaints_urgent + legal_urgent + death_urgent,
                'resolved_week': nurse_complaints_resolved_week + legal_resolved_week + death_resolved_week,
                'assigned_to_me': nurse_complaints_mine + legal_mine + death_mine,
            },
            'modules': {
                'nurses_active': nurse_complaints_progress + nurse_complaints_pending,
                'nurses_pending': nurse_complaints_pending,
                'legal_active': legal_progress + legal_pending,
                'legal_pending': legal_pending,
                'death_active': death_progress + death_pending,
                'death_pending': death_pending,
            },
            'urgent_list': urgent_list[:6],
        }
    finally:
        db.close()


def api_admin_community_welfare_recent(limit=10, user=None):
    """Combined recent activity feed across nurses/legal/death."""
    db = get_db()
    try:
        rows = []
        community_scope = is_community_desk_role((user or {}).get('role', ''))
        try:
            for r in db.execute(
                "SELECT complaint_id AS reference, nurse_full_name AS applicant, "
                "IFNULL(category,IFNULL(complaint_category,'Complaint')) AS type, "
                "complaint_status AS status, IFNULL(updated_at,created_at) AS time, "
                "assigned_to_username AS assigned "
                "FROM nurse_complaints ORDER BY IFNULL(updated_at,created_at) DESC LIMIT ?",
                (limit,)).fetchall():
                d = dict(r); d['module'] = 'nurses'; rows.append(d)
        except Exception:
            pass
        if not community_scope:
            try:
                for r in db.execute(
                    "SELECT reference_id AS reference, full_name AS applicant, "
                    "case_type AS type, status AS status, "
                    "IFNULL(updated_at,created_at) AS time, assigned_to_username AS assigned "
                    "FROM legal_case_requests ORDER BY IFNULL(updated_at,created_at) DESC LIMIT ?",
                    (limit,)).fetchall():
                    d = dict(r); d['module'] = 'legal'; rows.append(d)
            except Exception:
                pass
            try:
                for r in db.execute(
                    "SELECT reference_id AS reference, deceased_name AS applicant, "
                    "'Death Case' AS type, status AS status, "
                    "IFNULL(updated_at,created_at) AS time, assigned_to_username AS assigned "
                    "FROM death_case_requests ORDER BY IFNULL(updated_at,created_at) DESC LIMIT ?",
                    (limit,)).fetchall():
                    d = dict(r); d['module'] = 'death'; rows.append(d)
            except Exception:
                pass
        # Sort merged feed by time desc and trim
        def _key(r):
            return r.get('time') or ''
        rows.sort(key=_key, reverse=True)
        return {'success': True, 'items': rows[:limit]}
    finally:
        db.close()


def _case_age_days(created_at_or_assigned_at):
    ts = _clean_text(created_at_or_assigned_at, 80)
    if not ts:
        return 0
    try:
        value = ts.replace('T', ' ').replace('Z', '')
        if '.' in value:
            value = value.split('.', 1)[0]
        dt = datetime.fromisoformat(value)
        age = datetime.now() - dt
        return max(0, int(age.total_seconds() // 86400))
    except Exception:
        return 0


def _is_case_resolved_status(status):
    normalized = _clean_text(status, 80).lower()
    return normalized in ('resolved', 'closed', 'cancelled', 'canceled')


def _is_case_overdue(status, assigned_at, created_at, threshold_days=5):
    if _is_case_resolved_status(status):
        return False
    if not _clean_text(assigned_at, 80):
        return False
    anchor = _clean_text(assigned_at, 80) or _clean_text(created_at, 80)
    return _case_age_days(anchor) > int(threshold_days or 5)


def _staff_action_exists_after_assignment(case_type, case_id, assigned_at):
    db = get_db()
    try:
        ctype = _clean_text(case_type, 40).lower()
        if ctype == 'welfare':
            row = db.execute(
                """SELECT 1
                   FROM welfare_case_actions
                   WHERE case_id = ?
                     AND COALESCE(actor_username, '') NOT IN ('', 'public', 'system')
                     AND datetime(created_at) >= datetime(COALESCE(NULLIF(?, ''), created_at))
                   ORDER BY datetime(created_at) DESC, id DESC
                   LIMIT 1""",
                [case_id, _clean_text(assigned_at, 80)]
            ).fetchone()
            return bool(row)
        if ctype == 'legal':
            row = db.execute(
                """SELECT 1
                   FROM legal_case_actions
                   WHERE reference_id = ?
                     AND COALESCE(actor_username, '') NOT IN ('', 'public', 'system')
                     AND datetime(created_at) >= datetime(COALESCE(NULLIF(?, ''), created_at))
                   ORDER BY datetime(created_at) DESC, id DESC
                   LIMIT 1""",
                [str(case_id or ''), _clean_text(assigned_at, 80)]
            ).fetchone()
            return bool(row)
        if ctype == 'death':
            row = db.execute(
                """SELECT 1
                   FROM death_case_actions
                   WHERE reference_id = ?
                     AND COALESCE(actor_username, '') NOT IN ('', 'public', 'system')
                     AND datetime(created_at) >= datetime(COALESCE(NULLIF(?, ''), created_at))
                   ORDER BY datetime(created_at) DESC, id DESC
                   LIMIT 1""",
                [str(case_id or ''), _clean_text(assigned_at, 80)]
            ).fetchone()
            return bool(row)
        if ctype == 'nurse':
            row = db.execute(
                """SELECT 1
                   FROM nurse_complaint_actions
                   WHERE complaint_id = ?
                     AND COALESCE(actor_username, '') NOT IN ('', 'public', 'system')
                     AND datetime(created_at) >= datetime(COALESCE(NULLIF(?, ''), created_at))
                   ORDER BY datetime(created_at) DESC, id DESC
                   LIMIT 1""",
                [str(case_id or ''), _clean_text(assigned_at, 80)]
            ).fetchone()
            return bool(row)
    except Exception:
        return False
    finally:
        db.close()
    return False


def api_admin_staff_accountability(user):
    role = (user or {}).get('role')
    if not is_full_admin_role(role):
        return {'success': False, 'error': 'Unauthorized'}
    threshold_days = 5
    db = get_db()
    try:
        by_officer = {}
        overdue_cases = []
        no_action_cases = []

        def _officer_entry(username, department=''):
            key = _clean_text(username, 120) or 'Unassigned'
            if key not in by_officer:
                by_officer[key] = {
                    'assigned_to': key,
                    'officer_name': key,
                    'department': _clean_text(department, 200),
                    'assigned_open': 0,
                    'overdue_5_days': 0,
                    'no_action_after_assignment': 0,
                    'resolved_this_week': 0
                }
            return by_officer[key]

        users_map = {}
        try:
            for r in db.execute(
                "SELECT username, COALESCE(full_name, username) AS full_name, COALESCE(department, '') AS department FROM users"
            ).fetchall():
                users_map[r['username']] = {'full_name': r['full_name'], 'department': r['department']}
        except Exception:
            users_map = {}

        module_rows = []
        try:
            for r in db.execute(
                """SELECT id AS case_id, case_reference AS reference, 'Welfare' AS module,
                          COALESCE(subject_name, concern_summary, category, '') AS subject,
                          COALESCE(requester_name, '') AS requester,
                          COALESCE(assigned_to, '') AS assigned_to,
                          COALESCE(assigned_department, '') AS department,
                          COALESCE(status, '') AS status,
                          COALESCE(assigned_at, '') AS assigned_at,
                          COALESCE(created_at, '') AS created_at,
                          COALESCE(updated_at, '') AS updated_at
                   FROM welfare_cases
                   WHERE COALESCE(assigned_to, '') != ''"""
            ).fetchall():
                d = dict(r); d['case_type'] = 'welfare'; module_rows.append(d)
        except Exception:
            pass
        try:
            for r in db.execute(
                """SELECT reference_id AS case_id, reference_id AS reference, 'Legal' AS module,
                          COALESCE(subject, case_type, '') AS subject,
                          COALESCE(full_name, '') AS requester,
                          COALESCE(assigned_to_username, '') AS assigned_to,
                          COALESCE(assigned_department, '') AS department,
                          COALESCE(status, '') AS status,
                          COALESCE(assigned_at, '') AS assigned_at,
                          COALESCE(created_at, '') AS created_at,
                          COALESCE(updated_at, '') AS updated_at
                   FROM legal_case_requests
                   WHERE COALESCE(assigned_to_username, '') != ''"""
            ).fetchall():
                d = dict(r); d['case_type'] = 'legal'; module_rows.append(d)
        except Exception:
            pass
        try:
            for r in db.execute(
                """SELECT reference_id AS case_id, reference_id AS reference, 'Death' AS module,
                          'Death Case' AS subject,
                          COALESCE(reporter_name, deceased_name, '') AS requester,
                          COALESCE(assigned_to_username, '') AS assigned_to,
                          COALESCE(assigned_department, '') AS department,
                          COALESCE(status, '') AS status,
                          COALESCE(assigned_at, '') AS assigned_at,
                          COALESCE(created_at, '') AS created_at,
                          COALESCE(updated_at, '') AS updated_at
                   FROM death_case_requests
                   WHERE COALESCE(assigned_to_username, '') != ''"""
            ).fetchall():
                d = dict(r); d['case_type'] = 'death'; module_rows.append(d)
        except Exception:
            pass
        try:
            for r in db.execute(
                """SELECT COALESCE(complaint_id, nurse_reference_id, CAST(id AS TEXT)) AS case_id,
                          COALESCE(complaint_id, nurse_reference_id, CAST(id AS TEXT)) AS reference,
                          'Nurse' AS module,
                          COALESCE(subject, category, complaint_category, '') AS subject,
                          COALESCE(nurse_full_name, '') AS requester,
                          COALESCE(assigned_to_username, '') AS assigned_to,
                          COALESCE(assigned_department, '') AS department,
                          COALESCE(status, complaint_status, '') AS status,
                          COALESCE(assigned_at, '') AS assigned_at,
                          COALESCE(created_at, '') AS created_at,
                          COALESCE(updated_at, '') AS updated_at
                   FROM nurse_complaints
                   WHERE COALESCE(assigned_to_username, '') != ''"""
            ).fetchall():
                d = dict(r); d['case_type'] = 'nurse'; module_rows.append(d)
        except Exception:
            pass

        total_assigned_open = overdue_5_days = no_action_after_assignment = resolved_this_week = 0

        for row in module_rows:
            assigned_to = _clean_text(row.get('assigned_to'), 120)
            status = _clean_text(row.get('status'), 120)
            department = _clean_text(row.get('department'), 200)
            user_meta = users_map.get(assigned_to, {})
            entry = _officer_entry(assigned_to, department or user_meta.get('department', ''))
            if user_meta.get('full_name'):
                entry['officer_name'] = user_meta.get('full_name')
            if not entry.get('department'):
                entry['department'] = department or user_meta.get('department', '')

            assigned_anchor = _clean_text(row.get('assigned_at'), 80) or _clean_text(row.get('created_at'), 80)
            is_resolved = _is_case_resolved_status(status)
            is_overdue = _is_case_overdue(status, row.get('assigned_at'), row.get('created_at'), threshold_days)
            staff_action_exists = _staff_action_exists_after_assignment(row.get('case_type'), row.get('case_id'), assigned_anchor)

            if not is_resolved:
                total_assigned_open += 1
                entry['assigned_open'] += 1
                if is_overdue:
                    overdue_5_days += 1
                    entry['overdue_5_days'] += 1
                if not staff_action_exists:
                    no_action_after_assignment += 1
                    entry['no_action_after_assignment'] += 1
            else:
                updated = _clean_text(row.get('updated_at'), 80) or _clean_text(row.get('created_at'), 80)
                if _case_age_days(updated) <= 7:
                    resolved_this_week += 1
                    entry['resolved_this_week'] += 1

            days_pending = _case_age_days(assigned_anchor)
            case_item = {
                'module': row.get('module'),
                'reference': row.get('reference'),
                'subject': row.get('subject'),
                'requester': row.get('requester'),
                'assigned_to': assigned_to,
                'department': entry.get('department', ''),
                'status': status,
                'assigned_at': assigned_anchor,
                'days_pending': days_pending,
                'last_action_at': _clean_text(row.get('updated_at'), 80),
                'last_action_note': 'No recorded staff action after assignment' if not staff_action_exists else 'Staff action recorded after assignment'
            }
            if (not is_resolved) and is_overdue and len(overdue_cases) < 50:
                overdue_cases.append(case_item)
            if (not is_resolved) and (not staff_action_exists) and len(no_action_cases) < 50:
                no_action_cases.append(case_item)

        by_officer_rows = sorted(
            by_officer.values(),
            key=lambda x: (-(x.get('overdue_5_days') or 0), -(x.get('no_action_after_assignment') or 0), x.get('assigned_to') or '')
        )
        overdue_cases.sort(key=lambda x: (-(x.get('days_pending') or 0), x.get('module') or '', x.get('reference') or ''))
        no_action_cases.sort(key=lambda x: (-(x.get('days_pending') or 0), x.get('module') or '', x.get('reference') or ''))

        return {
            'success': True,
            'generated_at': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
            'threshold_days': threshold_days,
            'summary': {
                'total_assigned_open': total_assigned_open,
                'overdue_5_days': overdue_5_days,
                'no_action_after_assignment': no_action_after_assignment,
                'resolved_this_week': resolved_this_week
            },
            'by_officer': by_officer_rows,
            'overdue_cases': overdue_cases[:50],
            'no_action_cases': no_action_cases[:50]
        }
    finally:
        db.close()


def _parse_pulse_date_range(start_date='', end_date=''):
    today = datetime.now().date()
    default_start = today - timedelta(days=6)

    def _parse(value, fallback):
        text = _clean_text(value, 20)
        if not text:
            return fallback
        try:
            return datetime.strptime(text, '%Y-%m-%d').date()
        except Exception:
            return fallback

    start = _parse(start_date, default_start)
    end = _parse(end_date, today)
    if end < start:
        start, end = end, start
    return start.strftime('%Y-%m-%d'), end.strftime('%Y-%m-%d')


def _mask_tail(value, keep=4):
    text = _clean_text(value, 120)
    if not text:
        return ''
    suffix = text[-keep:] if len(text) > keep else text
    return ('*' * max(0, len(text) - len(suffix))) + suffix


def _mask_email(value):
    text = _clean_text(value, 200)
    if not text or '@' not in text:
        return ''
    local, domain = text.split('@', 1)
    if not local:
        return f"***@{domain}"
    return f"{local[:1]}***@{domain}"


def _classify_pulse_theme(text='', source_module='', category='', case_type=''):
    haystack = ' '.join([
        str(text or ''),
        str(source_module or ''),
        str(category or ''),
        str(case_type or '')
    ]).lower()
    rules = [
        {
            'theme_key': 'family_visa_restrictions',
            'theme_label': 'Family / Dependent Visa Restrictions',
            'sensitivity': 'High',
            'authority': 'MOI Kuwait / Residency Affairs',
            'keywords': ['family visa', 'dependent visa', 'wife visa', 'children visa', 'child visa', 'family dependent', 'residency', 'residence visa', 'visa closed', 'visas closed', 'visa processing closed', 'pakistanis closed', 'pakistani nationals closed', 'moi', 'ministry of interior', 'farwaniya', 'al ahmadi'],
            'suggested_action': 'Seek official clarification from concerned Kuwaiti authorities regarding current policy for Pakistani nationals.',
        },
        {
            'theme_key': 'visit_visa_restrictions',
            'theme_label': 'Visit Visa Restrictions',
            'sensitivity': 'High',
            'authority': 'MOI Kuwait / Residency Affairs',
            'keywords': ['visit visa', 'tourist visa', 'family visit', 'visa visit', 'visit visas closed', 'entry visa', 'no visit visa'],
            'suggested_action': 'Compile cases and seek clarification on current visit visa policy for Pakistani nationals.',
        },
        {
            'theme_key': 'koc_gate_pass',
            'theme_label': 'KOC Gate Pass / GP Validity',
            'sensitivity': 'High',
            'authority': 'KOC / Contractor / Concerned Kuwaiti Authority',
            'keywords': ['koc', 'gate pass', 'gp', 'drilling', 'oil field', 'site access', 'production', 'contractor', 'validity', 'three months', 'six months', 'one year', 'replace pakistani employees'],
            'suggested_action': 'Verify with employer/company and consider formal clarification from KOC or concerned authority.',
        },
        {
            'theme_key': 'nationality_differential_treatment',
            'theme_label': 'Differential Treatment by Nationality',
            'sensitivity': 'High',
            'authority': 'Relevant Kuwaiti Authority / Employer / Company',
            'keywords': ['other nationalities', 'indian', 'bangladeshi', 'chinese', 'kuwaiti nationals', 'pakistani nationals only', 'discrimination', 'different treatment', 'nationality', 'only pakistanis', 'pakistanis only', 'equal treatment'],
            'suggested_action': 'Verify facts through case evidence and consider raising through appropriate diplomatic channel if confirmed.',
        },
        {
            'theme_key': 'legal_detention_police',
            'theme_label': 'Legal / Detention / Police Matter',
            'sensitivity': 'High',
            'authority': 'Police / Courts / Kuwaiti Legal Authorities',
            'keywords': ['police', 'jail', 'detention', 'arrested', 'arrest', 'deportation', 'travel ban', 'court', 'legal notice', 'criminal case', 'civil case', 'lawyer', 'advocate'],
            'suggested_action': 'Ensure legal desk follow-up and senior review for urgent or detention-related matters.',
        },
        {
            'theme_key': 'death_mortal_remains',
            'theme_label': 'Death / Mortal Remains',
            'sensitivity': 'High',
            'authority': 'Hospital / Mortuary / Local Authorities',
            'keywords': ['death', 'dead body', 'deceased', 'mortal remains', 'burial', 'janaza', 'funeral', 'mortuary', 'death certificate', 'repatriation'],
            'suggested_action': 'Ensure urgent handling and family communication.',
        },
        {
            'theme_key': 'domestic_worker_shelter',
            'theme_label': 'Domestic Worker / Shelter / Abuse',
            'sensitivity': 'High',
            'authority': 'Employer / Sponsor / Shelter / Police',
            'keywords': ['domestic worker', 'housemaid', 'maid', 'khadama', 'runaway', 'shelter', 'abuse', 'passport held', 'passport confiscated', 'sponsor', 'kafeel', 'escape'],
            'suggested_action': 'Prioritize protection and shelter/legal handling.',
        },
        {
            'theme_key': 'labour_salary_employer',
            'theme_label': 'Labour / Salary / Employer Dispute',
            'sensitivity': 'Medium',
            'authority': 'PAM / Labour Department / Employer',
            'keywords': ['salary', 'unpaid salary', 'indemnity', 'employer', 'company', 'sponsor', 'kafeel', 'labour', 'labor', 'contract', 'termination', 'end of service', 'dues', 'overtime'],
            'suggested_action': 'Monitor recurring employers and refer individual cases to legal/labour support.',
        },
        {
            'theme_key': 'nurses_welfare',
            'theme_label': 'Nurses / Health Worker Welfare',
            'sensitivity': 'Medium',
            'authority': 'MOH / Employer / Facility',
            'keywords': ['nurse', 'nurses', 'nursing', 'moh', 'ministry of health', 'hospital', 'hostel', 'accommodation', 'duty', 'shift', 'health worker', 'medical staff'],
            'suggested_action': 'Review with CWA/AP desk and identify recurring facilities or accommodation issues.',
        },
        {
            'theme_key': 'opf_insurance_compensation',
            'theme_label': 'OPF / Insurance / Compensation',
            'sensitivity': 'Medium',
            'authority': 'OPF / Pakistan-side Institution',
            'keywords': ['opf', 'insurance', 'compensation', 'pension', 'dues', 'death grant', 'overseas pakistanis foundation', 'financial assistance'],
            'suggested_action': 'Forward or coordinate with concerned Pakistan-side institution as required.',
        },
        {
            'theme_key': 'passport_nadra_consular',
            'theme_label': 'Passport / NADRA / Consular Services',
            'sensitivity': 'Low',
            'authority': 'Embassy Consular Section',
            'keywords': ['passport', 'nadra', 'cnic', 'nicop', 'poc', 'attestation', 'degree attestation', 'document attestation', 'power of attorney', 'affidavit', 'frc', 'b-form'],
            'suggested_action': 'Review volume and ensure correct Counsellor Branch handover/contact guidance.',
        },
        {
            'theme_key': 'general_welfare',
            'theme_label': 'General Welfare / Guidance',
            'sensitivity': 'Low',
            'authority': 'Community Welfare Wing',
            'keywords': ['help', 'assistance', 'guidance', 'support', 'complaint', 'problem', 'welfare'],
            'suggested_action': 'Continue desk-level handling and monitor repeat patterns.',
        },
    ]
    for rule in rules:
        hits = sorted(set([k for k in rule['keywords'] if k in haystack]))
        if hits:
            return {
                'theme_key': rule['theme_key'],
                'theme_label': rule['theme_label'],
                'sensitivity': rule['sensitivity'],
                'authority': rule['authority'],
                'matched_keywords': hits,
                'suggested_action': rule['suggested_action'],
            }
    return {
        'theme_key': 'other',
        'theme_label': 'Other / Unclassified',
        'sensitivity': 'Low',
        'authority': '',
        'matched_keywords': [],
        'suggested_action': 'Review manually if repeated or sensitive.',
    }


def _pulse_theme_why_it_matters(theme_key):
    key = _clean_text(theme_key, 80)
    reasons = {
        'family_visa_restrictions': 'Reported restrictions on family/dependent visas directly affect family unity and may require official policy clarification.',
        'visit_visa_restrictions': 'Visit visa restrictions affect family contact and short-term travel for Pakistani nationals.',
        'koc_gate_pass': 'Reported shorter gate-pass validity for Pakistani workers may affect employment continuity and raises equal-treatment concerns if verified.',
        'nationality_differential_treatment': 'Reports comparing treatment of Pakistani nationals with other nationalities may require careful verification and diplomatic handling.',
        'legal_detention_police': 'Detention and police-linked cases require urgent legal follow-up and careful senior-level monitoring.',
        'death_mortal_remains': 'Death and mortal-remains cases are highly sensitive and require coordinated handling with relevant authorities.',
        'domestic_worker_shelter': 'Domestic worker abuse or shelter-linked complaints can involve urgent protection and legal risk.',
        'labour_salary_employer': 'Recurring labour and salary disputes may indicate employer-side patterns requiring structured follow-up.',
        'opf_insurance_compensation': 'High OPF-related volume indicates recurring demand for Pakistan-side welfare/insurance/compensation guidance.',
        'passport_nadra_consular': 'Consular service requests indicate need for clear public guidance and correct branch handover.',
        'general_welfare': 'General welfare requests indicate broad community service needs but may not require diplomatic escalation unless repeated.',
        'nurses_welfare': 'Nurses welfare complaints can signal recurring workplace or accommodation issues needing desk-level coordination.',
        'other': 'Mixed issues require manual triage to determine whether diplomatic escalation is needed.'
    }
    return reasons.get(key, reasons['other'])


def _collect_pulse_report_cases(start_date, end_date, include_full_details=False):
    cases = []
    limitations = []
    db = get_db()
    try:
        def _append_case(module, reference, created_at, status, assigned_to, department, requester_name, masked_identity, subject, category, case_type, details):
            details_text = _clean_text(details, 12000)
            theme = _classify_pulse_theme(
                text=' '.join([subject or '', category or '', case_type or '', details_text]),
                source_module=module,
                category=category,
                case_type=case_type
            )
            excerpt = details_text[:500]
            cases.append({
                'module': module,
                'reference': _clean_text(reference, 120),
                'created_at': _clean_text(created_at, 40),
                'status': _clean_text(status, 120),
                'assigned_to': _clean_text(assigned_to, 120),
                'department': _clean_text(department, 200),
                'requester_name': _clean_text(requester_name, 200),
                'masked_identity': _clean_text(masked_identity, 250),
                'subject': _clean_text(subject, 400),
                'category': _clean_text(category, 200),
                'case_type': _clean_text(case_type, 200),
                'details_excerpt': excerpt,
                'details_full': details_text if include_full_details else '',
                'theme': theme
            })

        try:
            rows = db.execute(
                """SELECT case_reference, created_at, status, assigned_to, assigned_department,
                          requester_name, requester_phone, requester_email, subject_name, category, case_type,
                          details, subject_passport, subject_civil_id
                   FROM welfare_cases
                   WHERE date(COALESCE(created_at, updated_at)) BETWEEN date(?) AND date(?)""",
                [start_date, end_date]
            ).fetchall()
            for r in rows:
                identity = ', '.join([x for x in [
                    _mask_tail(r['subject_passport']),
                    _mask_tail(r['subject_civil_id']),
                    _mask_tail(r['requester_phone']),
                    _mask_email(r['requester_email'])
                ] if x])
                _append_case(
                    'Welfare', r['case_reference'], r['created_at'], r['status'], r['assigned_to'],
                    r['assigned_department'], r['requester_name'], identity,
                    r['subject_name'], r['category'], r['case_type'], r['details']
                )
        except Exception:
            limitations.append('welfare_cases unavailable or incompatible')

        try:
            rows = db.execute(
                """SELECT reference_id, created_at, status, assigned_to_username, assigned_department,
                          full_name, mobile, email, subject, case_type, description, passport_number, cnic
                   FROM legal_case_requests
                   WHERE date(COALESCE(created_at, updated_at)) BETWEEN date(?) AND date(?)""",
                [start_date, end_date]
            ).fetchall()
            for r in rows:
                identity = ', '.join([x for x in [
                    _mask_tail(r['passport_number']),
                    _mask_tail(r['cnic']),
                    _mask_tail(r['mobile']),
                    _mask_email(r['email'])
                ] if x])
                _append_case(
                    'Legal/OPF', r['reference_id'], r['created_at'], r['status'], r['assigned_to_username'],
                    r['assigned_department'], r['full_name'], identity,
                    r['subject'], r['case_type'], r['case_type'], r['description']
                )
        except Exception:
            limitations.append('legal_case_requests unavailable or incompatible')

        try:
            rows = db.execute(
                """SELECT COALESCE(complaint_id, nurse_reference_id, CAST(id AS TEXT)) AS reference,
                          created_at, COALESCE(status, complaint_status) AS status,
                          assigned_to_username, assigned_department, nurse_full_name, mobile_number, email_address,
                          subject, COALESCE(category, complaint_category) AS category, complaint_category, complaint_details,
                          passport_number, civil_id
                   FROM nurse_complaints
                   WHERE date(COALESCE(created_at, updated_at)) BETWEEN date(?) AND date(?)""",
                [start_date, end_date]
            ).fetchall()
            for r in rows:
                identity = ', '.join([x for x in [
                    _mask_tail(r['passport_number']),
                    _mask_tail(r['civil_id']),
                    _mask_tail(r['mobile_number']),
                    _mask_email(r['email_address'])
                ] if x])
                _append_case(
                    'Nurses', r['reference'], r['created_at'], r['status'], r['assigned_to_username'],
                    r['assigned_department'], r['nurse_full_name'], identity,
                    r['subject'], r['category'], r['complaint_category'], r['complaint_details']
                )
        except Exception:
            limitations.append('nurse_complaints unavailable or incompatible')

        try:
            rows = db.execute(
                """SELECT reference_id, created_at, status, assigned_to_username, assigned_department,
                          reporter_name, reporter_mobile, reporter_email, deceased_name, description,
                          deceased_passport, deceased_civil_id
                   FROM death_case_requests
                   WHERE date(COALESCE(created_at, updated_at)) BETWEEN date(?) AND date(?)""",
                [start_date, end_date]
            ).fetchall()
            for r in rows:
                identity = ', '.join([x for x in [
                    _mask_tail(r['deceased_passport']),
                    _mask_tail(r['deceased_civil_id']),
                    _mask_tail(r['reporter_mobile']),
                    _mask_email(r['reporter_email'])
                ] if x])
                _append_case(
                    'Death', r['reference_id'], r['created_at'], r['status'], r['assigned_to_username'],
                    r['assigned_department'], r['reporter_name'] or r['deceased_name'], identity,
                    r['deceased_name'], 'Death Case', 'Death Case', r['description']
                )
        except Exception:
            limitations.append('death_case_requests unavailable or incompatible')

        try:
            rows = db.execute(
                """SELECT id, created_at, requester_name, requester_phone, requester_email, category, subject, details
                   FROM public_feedback_messages
                   WHERE date(COALESCE(created_at)) BETWEEN date(?) AND date(?)""",
                [start_date, end_date]
            ).fetchall()
            for r in rows:
                identity = ', '.join([x for x in [
                    _mask_tail(r['requester_phone']),
                    _mask_email(r['requester_email'])
                ] if x])
                _append_case(
                    'Feedback', f"FBMSG-{int(r['id'])}", r['created_at'], 'Received', '',
                    'Community Welfare Wing', r['requester_name'], identity,
                    r['subject'], r['category'], 'Feedback', r['details']
                )
        except Exception:
            limitations.append('public_feedback_messages unavailable or incompatible')
    finally:
        db.close()
    _collect_pulse_report_cases.last_limitations = limitations
    return cases


def _build_ambassador_pulse_report(cases, start_date, end_date, include_full_details=False):
    sensitivity_rank = {'High': 0, 'Medium': 1, 'Low': 2}
    diplomatic_priority = [
        'family_visa_restrictions',
        'visit_visa_restrictions',
        'koc_gate_pass',
        'nationality_differential_treatment',
        'legal_detention_police',
        'death_mortal_remains',
        'domestic_worker_shelter',
        'labour_salary_employer'
    ]
    diplomatic_priority_index = {k: i for i, k in enumerate(diplomatic_priority)}
    diplomatic_force_keys = set(diplomatic_priority)
    operational_theme_keys = {
        'opf_insurance_compensation',
        'passport_nadra_consular',
        'general_welfare',
        'nurses_welfare',
        'labour_salary_employer'
    }
    by_module = {}
    by_status = {}
    theme_map = {}
    authority_counts = {}

    for c in cases:
        module = c.get('module') or 'Unknown'
        status = c.get('status') or 'Unknown'
        by_module[module] = by_module.get(module, 0) + 1
        by_status[status] = by_status.get(status, 0) + 1
        theme = c.get('theme') or {}
        key = theme.get('theme_key') or 'other'
        item = theme_map.setdefault(key, {
            'theme_key': key,
            'theme_label': theme.get('theme_label') or 'Other / Unclassified',
            'count': 0,
            'sensitivity': theme.get('sensitivity') or 'Low',
            'authority': theme.get('authority') or '',
            'sample_references': [],
            'suggested_action': theme.get('suggested_action') or ''
        })
        item['count'] += 1
        if c.get('reference') and len(item['sample_references']) < 5:
            item['sample_references'].append(c['reference'])
        authority = theme.get('authority') or ''
        if authority:
            authority_counts[authority] = authority_counts.get(authority, 0) + 1

    top_themes = sorted(theme_map.values(), key=lambda x: (-x['count'], sensitivity_rank.get(x.get('sensitivity'), 9), x['theme_label']))
    for t in top_themes:
        authority = t.get('authority') or 'Not specified'
        t['short_summary'] = f"{t['count']} submissions during the period related to {t['theme_label']}. Main authority mentioned: {authority}."
        t['why_it_matters'] = _pulse_theme_why_it_matters(t.get('theme_key'))

    policy_sensitive_issues = []
    for t in top_themes:
        if t.get('sensitivity') != 'High' or t.get('count', 0) < 1:
            continue
        sample_case = next((x for x in cases if (x.get('theme') or {}).get('theme_key') == t.get('theme_key')), {})
        policy_sensitive_issues.append({
            'theme_key': t.get('theme_key'),
            'theme_label': t.get('theme_label'),
            'count': t.get('count'),
            'authority': t.get('authority'),
            'sample_references': t.get('sample_references') or [],
            'suggested_action': t.get('suggested_action') or '',
            'why_it_matters': _pulse_theme_why_it_matters(t.get('theme_key')),
            'representative_excerpt': _clean_text(sample_case.get('details_excerpt'), 300)
        })

    authority_mentions = [
        {'authority': k, 'count': v}
        for k, v in sorted(authority_counts.items(), key=lambda kv: (-kv[1], kv[0]))
    ]

    sorted_cases = sorted(
        cases,
        key=lambda c: (
            sensitivity_rank.get((c.get('theme') or {}).get('sensitivity'), 9),
            -(int(_case_age_days(c.get('created_at')) or 0)),
            c.get('reference') or ''
        )
    )

    high_count = sum(1 for c in cases if (c.get('theme') or {}).get('sensitivity') == 'High')
    medium_count = sum(1 for c in cases if (c.get('theme') or {}).get('sensitivity') == 'Medium')
    top_theme_label = top_themes[0]['theme_label'] if top_themes else 'None'
    top_theme_count = int(top_themes[0]['count']) if top_themes else 0

    diplomatic_candidates = [
        t for t in top_themes
        if (t.get('sensitivity') == 'High') and (t.get('theme_key') in diplomatic_force_keys)
    ]
    diplomatic_candidates.sort(
        key=lambda t: (
            diplomatic_priority_index.get(t.get('theme_key'), 999),
            -(t.get('count') or 0),
            t.get('theme_label') or ''
        )
    )
    top_diplomatic = diplomatic_candidates[0] if diplomatic_candidates else None

    operational_candidates = [t for t in top_themes if t.get('theme_key') in operational_theme_keys]
    operational_candidates.sort(key=lambda t: (-(t.get('count') or 0), t.get('theme_label') or ''))
    top_operational = operational_candidates[0] if operational_candidates else (top_themes[0] if top_themes else None)

    diplomatic_issues = []
    for t in top_themes:
        tkey = t.get('theme_key')
        tsens = t.get('sensitivity')
        tcount = int(t.get('count') or 0)
        include_issue = (
            (tsens == 'High') or
            (tsens == 'Medium' and tcount >= 3) or
            (tkey in diplomatic_force_keys)
        )
        if not include_issue or tcount <= 0:
            continue
        sample_case = next((x for x in sorted_cases if (x.get('theme') or {}).get('theme_key') == tkey), {})
        diplomatic_issues.append({
            'theme_key': tkey,
            'issue_title': t.get('theme_label'),
            'why_it_matters': _pulse_theme_why_it_matters(tkey),
            'authority': t.get('authority') or '',
            'count': tcount,
            'evidence_references': (t.get('sample_references') or [])[:5],
            'suggested_action': t.get('suggested_action') or '',
            'representative_excerpt': _clean_text(sample_case.get('details_excerpt'), 300),
            'sensitivity': tsens or 'Low',
        })
    diplomatic_issues.sort(
        key=lambda x: (
            diplomatic_priority_index.get(x.get('theme_key'), 999),
            -(x.get('count') or 0),
            x.get('issue_title') or ''
        )
    )

    community_service_workload = []
    for t in top_themes:
        tkey = t.get('theme_key')
        if tkey not in operational_theme_keys:
            continue
        community_service_workload.append({
            'theme_key': tkey,
            'theme_label': t.get('theme_label'),
            'count': int(t.get('count') or 0),
            'responsible_section': t.get('authority') or 'Community Welfare Wing',
            'sample_references': (t.get('sample_references') or [])[:3],
            'note': 'Operational/service handling' if t.get('sensitivity') != 'High' else 'Sensitive: monitor for senior review'
        })
    community_service_workload.sort(key=lambda x: (-x.get('count', 0), x.get('theme_label') or ''))

    policy_evidence_cases = [c for c in sorted_cases if (c.get('theme') or {}).get('sensitivity') == 'High']
    operational_evidence_pool = [c for c in sorted_cases if (c.get('theme') or {}).get('sensitivity') != 'High']
    operational_limit = 30 if include_full_details else 10
    operational_evidence_cases = operational_evidence_pool[:operational_limit]
    evidence_cases = (policy_evidence_cases + operational_evidence_cases) if not include_full_details else sorted_cases[:200]

    staff_accountability = getattr(_build_ambassador_pulse_report, '_staff_accountability', {}) or {}
    staff_summary = (staff_accountability or {}).get('summary') or {}
    operational_status = {
        'total_open': sum(v for k, v in by_status.items() if not _is_case_resolved_status(k)),
        'total_resolved': sum(v for k, v in by_status.items() if _clean_text(k, 80).lower() == 'resolved'),
        'total_assigned': sum(1 for c in cases if _clean_text(c.get('assigned_to'), 120)),
        'total_overdue': int(staff_summary.get('overdue_5_days') or 0),
    }

    recommendations = []
    theme_counts = {t['theme_key']: t['count'] for t in top_themes}
    if theme_counts.get('family_visa_restrictions', 0) > 0:
        recommendations.append('Compile family/dependent visa cases and seek MOI/MFA clarification on Pakistani nationals policy.')
    if theme_counts.get('koc_gate_pass', 0) > 0:
        recommendations.append('Verify KOC GP validity concerns with employer/contractor records before formal representation.')
    if theme_counts.get('nationality_differential_treatment', 0) > 0:
        recommendations.append('Escalate differential treatment claims for senior verification before diplomatic outreach.')
    if int(staff_summary.get('overdue_5_days') or 0) > 0:
        recommendations.append('Conduct desk-wise overdue follow-up with assigned officers and document immediate action plans.')

    high_theme_names = [x.get('theme_label') for x in top_themes if x.get('sensitivity') == 'High']
    high_theme_text = ', '.join(high_theme_names[:4]) if high_theme_names else 'None'
    top_diplomatic_label = (top_diplomatic or {}).get('theme_label') or 'No high-sensitivity diplomatic issue identified'
    top_diplomatic_count = int((top_diplomatic or {}).get('count') or 0)
    top_operational_label = (top_operational or {}).get('theme_label') if top_operational else 'None'
    top_operational_count = int((top_operational or {}).get('count') or 0)
    top_diplomatic_refs = ', '.join(((top_diplomatic or {}).get('sample_references') or [])[:3]) or 'No references'
    other_high = [x for x in high_theme_names if x != top_diplomatic_label]
    other_high_text = ', '.join(other_high[:3]) if other_high else 'None'

    ambassador_brief_points = [
        f"The portal recorded {len(cases)} submissions during the reporting period.",
        f"{high_count} issue(s) were assessed as high-sensitivity and may require senior review.",
        f"The highest-volume operational theme was {top_operational_label} with {top_operational_count} submissions.",
        f"The key diplomatic issue was {top_diplomatic_label}.",
        f"Policy-sensitive themes identified include: {high_theme_text}.",
        f"{int(staff_summary.get('overdue_5_days') or 0)} assigned case(s) are overdue beyond the monitoring threshold.",
        "Evidence references are included below for verification."
    ]

    report = {
        'success': True,
        'title': 'Ambassador Pulse Brief',
        'period': {'start_date': start_date, 'end_date': end_date},
        'generated_at': datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
        'summary': {
            'total_items': len(cases),
            'by_module': by_module,
            'by_status': by_status,
            'high_sensitivity_count': high_count,
            'medium_sensitivity_count': medium_count,
            'top_theme_label': top_theme_label,
            'top_theme_count': top_theme_count,
            'top_operational_theme': top_operational_label,
            'top_operational_theme_count': top_operational_count,
            'top_diplomatic_issue': top_diplomatic_label,
            'top_diplomatic_issue_count': top_diplomatic_count,
            'top_diplomatic_issue_refs': ((top_diplomatic or {}).get('sample_references') or [])[:5]
        },
        'ambassador_brief_points': ambassador_brief_points[:6],
        'executive_narrative': (
            f"During the reporting period, the portal received {len(cases)} submissions. "
            f"The highest-volume operational workload concerned {top_operational_label} ({top_operational_count} cases). "
            f"The main policy-sensitive issue requiring senior attention was {top_diplomatic_label}, supported by {top_diplomatic_refs}. "
            f"Additional sensitive themes included {other_high_text}. "
            "The report separates policy matters from routine operational service requests so that senior review can focus on issues requiring diplomatic visibility."
        ),
        'top_themes': top_themes,
        'policy_sensitive_issues': policy_sensitive_issues,
        'diplomatic_issues': diplomatic_issues,
        'community_service_workload': community_service_workload,
        'authority_mentions': authority_mentions,
        'operational_status': operational_status,
        'staff_accountability': {
            'summary': staff_summary,
            'by_officer': (staff_accountability or {}).get('by_officer') or []
        },
        'evidence_cases': evidence_cases,
        'evidence_annex': {
            'senior_attention': policy_evidence_cases,
            'operational_samples': operational_evidence_cases,
            'note': 'Full case records remain available in the portal by reference number.'
        },
        'recommended_followups': recommendations,
        'include_full_details': bool(include_full_details),
        'limitations': getattr(_collect_pulse_report_cases, 'last_limitations', []) or []
    }
    return report


def api_admin_ambassador_pulse_report(params, user):
    role = (user or {}).get('role')
    if role not in ('admin',):
        return {'success': False, 'error': 'Unauthorized'}
    start_date, end_date = _parse_pulse_date_range(
        (params or {}).get('start_date'),
        (params or {}).get('end_date')
    )
    include_full_details = str((params or {}).get('include_full_details', '0')).strip().lower() in ('1', 'true', 'yes', 'on')
    include_full_details = bool(include_full_details and role == 'admin')

    staff_accountability = api_admin_staff_accountability(user) if role == 'admin' else {'success': False}
    cases = _collect_pulse_report_cases(start_date, end_date, include_full_details=include_full_details)
    _build_ambassador_pulse_report._staff_accountability = staff_accountability if (staff_accountability or {}).get('success') else {}
    return _build_ambassador_pulse_report(cases, start_date, end_date, include_full_details=include_full_details)


def api_admin_notification_counts(user):
    db = get_db()
    try:
        def _count(sql, vals=()):
            try:
                row = db.execute(sql, vals).fetchone()
                return int((row['c'] if row else 0) or 0)
            except Exception:
                return 0

        role = (user or {}).get('role') or ''
        username = (user or {}).get('user') or ''
        community_scope = is_community_desk_role(role)
        can_welfare = role in WELFARE_CASE_ACCESS_ROLES or is_full_admin_role(role)
        can_facility = _facility_user_can_access(user) and not community_scope

        nurses = (
            _count("SELECT COUNT(*) c FROM nurse_registrations WHERE registration_status IN ('Pending', 'Pending Review', 'Pending Review by Embassy')")
            + _count("SELECT COUNT(*) c FROM nurse_complaints WHERE COALESCE(status, complaint_status) IN ('New', 'Submitted', 'Seen', 'Seen by Admin', 'Pending Review', 'Under Review', 'Assigned', 'In Progress')")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND confirmation_status = 'Pending Nurse Confirmation'")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND welfare_followup_required = 1")
            + _count("SELECT COUNT(*) c FROM nurse_leave_notices WHERE status IN ('Submitted', 'Pending Review', 'Under Review')")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND notice_period_start_date != '' AND date(notice_period_start_date) <= date('now') AND current_status NOT IN ('Leaving Notice Submitted', 'Left Facility', 'Closed / Archived', 'Inactive')")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND reconciliation_status = 'Reconciliation Required'")
        )
        legal_cases = 0 if community_scope else _count("SELECT COUNT(*) c FROM legal_case_requests WHERE status IN ('New', 'Submitted', 'Under Review', 'Seen by Admin') OR COALESCE(assigned_to_username, '') = ''")
        death_cases = 0 if community_scope else _count("SELECT COUNT(*) c FROM death_case_requests WHERE status IN ('New', 'Urgent Review', 'Documentation Pending', 'Submitted', 'Seen by Admin') OR COALESCE(assigned_to_username, '') = ''")
        welfare_cases = _count("SELECT COUNT(*) c FROM welfare_cases WHERE status IN ('New', 'Assigned', 'Field Verification Required', 'Awaiting Applicant', 'Awaiting Requester Response') AND status NOT IN ('Resolved', 'Closed')") if can_welfare else 0
        my_cases = _count(
            "SELECT COUNT(*) c FROM welfare_cases WHERE assigned_to = ? AND status NOT IN ('Resolved', 'Closed') AND (COALESCE(action_required, '') != '' OR (COALESCE(due_date, '') != '' AND date(due_date) < date('now')))",
            (username,)
        ) if (can_welfare and username) else 0
        ambassador_review = 0 if community_scope else (_count("SELECT COUNT(*) c FROM welfare_cases WHERE escalation_level = 'ambassador_review' AND status NOT IN ('Resolved', 'Closed')") if can_welfare else 0)
        facility_occupancy = (
            _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND confirmation_status = 'Pending Nurse Confirmation'")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND notice_period_start_date != '' AND date(notice_period_start_date) <= date('now') AND current_status NOT IN ('Leaving Notice Submitted', 'Left Facility', 'Closed / Archived', 'Inactive')")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND reconciliation_status = 'Reconciliation Required'")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND welfare_followup_required = 1")
        ) if can_facility else 0
        facility_roster = (
            _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND (nurse_registration_id IS NULL OR nurse_registration_id = 0)")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND confirmation_status = 'Pending Nurse Confirmation'")
            + _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND reconciliation_status = 'Reconciliation Required'")
        ) if can_facility else 0
        alternative_facilities = _count("SELECT COUNT(*) c FROM facility_roster WHERE active = 1 AND alternative_stay_review_required = 1") if can_facility else 0

        counts = {
            'community_welfare': 0,
            'nurses': nurses,
            'legal_cases': legal_cases,
            'death_cases': death_cases,
            'welfare_cases': welfare_cases,
            'my_cases': my_cases,
            'ambassador_review': ambassador_review,
            'facility_occupancy': facility_occupancy,
            'facility_roster': facility_roster,
            'alternative_facilities': alternative_facilities,
        }
        counts['community_welfare'] = sum(v for k, v in counts.items() if k != 'community_welfare')
        return {'success': True, 'counts': counts}
    finally:
        db.close()

# Login rate limiting: track failed attempts per IP
LOGIN_ATTEMPTS = {}  # ip -> {'count': n, 'lockout_until': timestamp}

def check_login_rate(ip):
    """Returns True if login is allowed, False if locked out"""
    now = time.time()
    if ip in LOGIN_ATTEMPTS:
        info = LOGIN_ATTEMPTS[ip]
        if info.get('lockout_until', 0) > now:
            return False
        # Reset if lockout expired
        if info.get('lockout_until', 0) <= now and info['count'] >= 5:
            LOGIN_ATTEMPTS[ip] = {'count': 0}
    return True

def record_login_failure(ip):
    now = time.time()
    if ip not in LOGIN_ATTEMPTS:
        LOGIN_ATTEMPTS[ip] = {'count': 0}
    LOGIN_ATTEMPTS[ip]['count'] += 1
    if LOGIN_ATTEMPTS[ip]['count'] >= 5:
        LOGIN_ATTEMPTS[ip]['lockout_until'] = now + 300  # 5 minute lockout

def record_login_success(ip):
    LOGIN_ATTEMPTS.pop(ip, None)

def create_session(username, role):
    token = secrets.token_hex(32)
    with SESSIONS_LOCK:
        SESSIONS[token] = {'user': username, 'role': role, 'expires': time.time() + 86400}
    return token

def get_session(cookie_str):
    if not cookie_str: return None
    c = SimpleCookie()
    c.load(cookie_str)
    token = c.get('session')
    if not token: return None
    with SESSIONS_LOCK:
        s = SESSIONS.get(token.value)
    if s and s['expires'] > time.time(): return s
    return None

def _is_restricted_staff_user(user):
    return bool(user) and is_limited_staff_role(user.get('role') or '')

def _restricted_staff_path_allowed(path):
    return _staff_base_path_allowed(path) or path == '/admin/aja-reconciliation' or path.startswith('/api/admin/aja-reconciliation/')

def _user_is_active(row_or_dict):
    try:
        value = row_or_dict['is_active']
    except Exception:
        value = 1
    return int(value if value not in (None, '') else 1) == 1

# ═══════════════════════════════════════════════════════════════
# DUPLICATE DETECTION
# ═══════════════════════════════════════════════════════════════
def check_duplicates(db, record, exclude_id=None):
    """Check for duplicates based on: Passport, CNIC, and Civil ID only.
    Name and mobile are NOT checked — different people can share names, families share mobiles."""
    flags = []
    passport = (record.get('passport') or '').strip().upper()
    cnic = re.sub(r'[\s\-]', '', record.get('cnic') or '')
    civil_id = (record.get('civil_id') or '').strip()

    if passport:
        q = "SELECT id, name FROM evacuees WHERE UPPER(TRIM(passport)) = ?"
        params = [passport]
        if exclude_id: q += " AND id != ?"; params.append(exclude_id)
        dup = db.execute(q, params).fetchone()
        if dup: flags.append(f"Passport match with #{dup['id']} ({dup['name']})")

    if cnic:
        q = "SELECT id, name FROM evacuees WHERE REPLACE(REPLACE(cnic, '-', ''), ' ', '') = ?"
        params = [cnic]
        if exclude_id: q += " AND id != ?"; params.append(exclude_id)
        dup = db.execute(q, params).fetchone()
        if dup: flags.append(f"CNIC match with #{dup['id']} ({dup['name']})")

    if civil_id:
        q = "SELECT id, name FROM evacuees WHERE TRIM(civil_id) = ?"
        params = [civil_id]
        if exclude_id: q += " AND id != ?"; params.append(exclude_id)
        dup = db.execute(q, params).fetchone()
        if dup: flags.append(f"Civil ID match with #{dup['id']} ({dup['name']})")

    return flags

# ═══════════════════════════════════════════════════════════════
# CSV IMPORT WITH SMART DEDUP
# ═══════════════════════════════════════════════════════════════
def import_csv_data(csv_text, user='system', mode='smart'):
    """mode: 'smart' = skip exact dups, update partial matches; 'force' = import all; 'skip' = skip all dups"""
    db = get_db()
    reader = csv.DictReader(io.StringIO(csv_text))
    headers_raw = reader.fieldnames or []

    # Map MS Forms / Google Forms headers to our DB fields
    header_map = {}
    for h in headers_raw:
        hl = h.lower().strip()
        if 'full name' in hl or (hl == 'name' and 'full' not in ''.join(headers_raw).lower()):
            header_map[h] = 'name'
        elif 'passport' in hl: header_map[h] = 'passport'
        elif 'gender' in hl: header_map[h] = 'gender'
        elif 'country' in hl or 'resident' in hl: header_map[h] = 'country'
        elif 'civil id' in hl or 'kuwaiti' in hl: header_map[h] = 'civil_id'
        elif 'border' in hl or 'crossing' in hl: header_map[h] = 'border_crossing'
        elif 'mobile' in hl or 'phone' in hl: header_map[h] = 'mobile'
        elif 'profession' in hl or 'company' in hl: header_map[h] = 'company'
        elif 'cnic' in hl: header_map[h] = 'cnic'
        elif 'email' in hl and 'address' in hl: header_map[h] = 'email'
        elif hl == 'email': pass  # skip the MS Forms system email
        elif 'start time' in hl or 'completion' in hl: header_map[h] = 'date_of_request'
        elif hl == 'id': header_map[h] = 'form_submission_id'
        elif 'visa' in hl and 'status' in hl: header_map[h] = 'visa_status'
        elif 'travel' in hl and 'status' in hl: header_map[h] = 'travel_status'
        elif 'airline' in hl: header_map[h] = 'airline'
        elif 'ticket' in hl: header_map[h] = 'ticket_number'
        elif 'departure' in hl or 'airport' in hl: header_map[h] = 'departure_airport'
        elif 'destination' in hl: header_map[h] = 'destination_country'
        elif 'priority' in hl: header_map[h] = 'priority'
        elif 'remark' in hl or 'note' in hl: header_map[h] = 'remarks'

    stats = {'imported': 0, 'skipped_dup': 0, 'updated': 0, 'errors': 0, 'details': []}

    for row_num, row in enumerate(reader, 1):
        try:
            rec = {}
            for orig_h, db_field in header_map.items():
                val = (row.get(orig_h) or '').strip()
                if val: rec[db_field] = val

            if not rec.get('name'):
                stats['errors'] += 1
                stats['details'].append(f"Row {row_num}: No name found, skipped")
                continue

            # Clean up data
            if rec.get('cnic'):
                rec['cnic'] = re.sub(r'[\s]', '', rec['cnic'])
            if rec.get('passport'):
                rec['passport'] = rec['passport'].strip().upper()
            if rec.get('date_of_request'):
                # Parse MS Forms date format
                try:
                    dt = datetime.strptime(rec['date_of_request'].split('.')[0], '%m/%d/%Y %H:%M')
                    rec['date_of_request'] = dt.strftime('%Y-%m-%d')
                except: pass

            # Normalize border crossing
            if rec.get('border_crossing'):
                rec['border_crossing'] = normalize_border(rec['border_crossing'])

            # Check for duplicate by passport
            passport = rec.get('passport', '')
            existing = None
            if passport:
                existing = db.execute("SELECT id, name, travel_status, visa_status FROM evacuees WHERE UPPER(TRIM(passport)) = ?", [passport.upper()]).fetchone()

            if existing:
                if mode == 'skip':
                    stats['skipped_dup'] += 1
                    stats['details'].append(f"Row {row_num}: {rec['name']} — duplicate passport {passport}, skipped")
                    continue
                elif mode == 'smart':
                    # Update only empty fields in existing record
                    updates = []
                    params = []
                    for field in ['mobile', 'civil_id', 'cnic', 'email', 'company', 'border_crossing']:
                        if rec.get(field):
                            updates.append(f"{field} = COALESCE(NULLIF({field}, ''), ?)")
                            params.append(rec[field])
                    if updates:
                        params.append(existing['id'])
                        db.execute(f"UPDATE evacuees SET {', '.join(updates)}, updated_at = CURRENT_TIMESTAMP, updated_by = ? WHERE id = ?",
                                   params[:-1] + [user, existing['id']])
                        stats['updated'] += 1
                        stats['details'].append(f"Row {row_num}: {rec['name']} — updated existing record #{existing['id']}")
                    else:
                        stats['skipped_dup'] += 1
                        stats['details'].append(f"Row {row_num}: {rec['name']} — exact duplicate, skipped")
                    continue
                # mode == 'force' falls through to insert

            # Check for duplicates and flag
            dup_flags = check_duplicates(db, rec)
            rec['dup_flag'] = 'DUPLICATE' if dup_flags else 'CLEAR'

            # Insert
            fields = [k for k in rec.keys() if k in (
                'name','passport','cnic','gender','country','civil_id','border_crossing',
                'mobile','company','visa_status','travel_status','airline','ticket_number',
                'departure_airport','destination_country','date_of_request','email',
                'dob','emergency_contact','medical','family_group_id','dependents',
                'accommodation','priority','remarks','planned_departure','saudi_city',
                'traveling_with_family','confirm_ksa_3days','dup_flag','form_submission_id'
            )]
            if 'travel_status' not in fields:
                fields.append('travel_status')
                rec['travel_status'] = 'Pending'

            placeholders = ', '.join(['?'] * len(fields))
            db.execute(
                f"INSERT INTO evacuees ({', '.join(fields)}) VALUES ({placeholders})",
                [rec.get(f, '') for f in fields]
            )
            stats['imported'] += 1
            if rec['dup_flag'] == 'DUPLICATE':
                stats['details'].append(f"Row {row_num}: {rec['name']} — imported with DUPLICATE flag ({'; '.join(dup_flags)})")
            else:
                stats['details'].append(f"Row {row_num}: {rec['name']} — imported OK")

        except Exception as e:
            stats['errors'] += 1
            stats['details'].append(f"Row {row_num}: Error — {str(e)}")

    db.commit()
    db.execute("INSERT INTO audit_log (action, user, details) VALUES (?, ?, ?)",
               ('csv_import', user, json.dumps(stats)))
    db.commit()
    db.close()
    return stats

# ═══════════════════════════════════════════════════════════════
# API HANDLERS
# ═══════════════════════════════════════════════════════════════
def _iraq_mission_dashboard_kpi(db):
    """Roll-up for main dashboard: Iraq public intake + mission batches + MOFA KW tracking."""
    public_totals = db.execute("""
        SELECT
          COUNT(*) AS pub_total,
          COALESCE(SUM(CASE WHEN COALESCE(mofa_kw_portal_visible,0)=1 THEN 1 ELSE 0 END),0) AS pub_portal,
          COALESCE(SUM(CASE WHEN status='Forwarded to Embassy Kuwait' THEN 1 ELSE 0 END),0) AS pub_fwd
        FROM iraq_public_submissions
    """).fetchone()
    pub_total = int(public_totals['pub_total'] or 0)
    pub_portal = int(public_totals['pub_portal'] or 0)
    pub_fwd = int(public_totals['pub_fwd'] or 0)
    pub_nv = int(db.execute(
        "SELECT COUNT(DISTINCT public_submission_id) c FROM iraq_dispatch_applicants"
    ).fetchone()['c'] or 0)
    dec_map = {}
    for r in db.execute("""
        SELECT decision, COUNT(*) c FROM (
            SELECT d.decision FROM iraq_applicant_decisions d
            INNER JOIN (
                SELECT public_submission_id, MAX(id) mid FROM iraq_applicant_decisions GROUP BY public_submission_id
            ) x ON d.public_submission_id = x.public_submission_id AND d.id = x.mid
        ) GROUP BY decision
    """).fetchall():
        dec_map[r['decision']] = r['c']
    pub_mofa_app = int(dec_map.get('Approved') or 0)
    pub_mofa_rej = int(dec_map.get('Rejected') or 0)
    pub_mofa_pend = int(dec_map.get('Pending') or 0)

    batch_totals = db.execute("""
        SELECT
          COUNT(*) AS batch_apps,
          COALESCE(SUM(CASE WHEN visa_status='KW Transit Approved' THEN 1 ELSE 0 END),0) AS v_app,
          COALESCE(SUM(CASE WHEN visa_status='Rejected' THEN 1 ELSE 0 END),0) AS v_rej,
          COALESCE(SUM(CASE WHEN visa_status='Pending' OR visa_status='' OR visa_status IS NULL THEN 1 ELSE 0 END),0) AS v_pend,
          COALESCE(SUM(CASE WHEN movement_status='waiting_iraq' THEN 1 ELSE 0 END),0) AS waiting_travel_iraq,
          COALESCE(SUM(CASE WHEN movement_status='waiting_kw' THEN 1 ELSE 0 END),0) AS waiting_transit_kw
        FROM iraq_applicants
    """).fetchone()
    batch_apps = int(batch_totals['batch_apps'] or 0)
    v_app = int(batch_totals['v_app'] or 0)
    v_pend = int(batch_totals['v_pend'] or 0)
    v_rej = int(batch_totals['v_rej'] or 0)
    waiting_travel_iraq = int(batch_totals['waiting_travel_iraq'] or 0)
    waiting_transit_kw = int(batch_totals['waiting_transit_kw'] or 0)

    batch_status_totals = db.execute("""
        SELECT
          COALESCE(SUM(CASE WHEN status='Pending' THEN 1 ELSE 0 END),0) AS b_pen,
          COALESCE(SUM(CASE WHEN status='Sent to MOFA Kuwait' THEN 1 ELSE 0 END),0) AS b_sent,
          COALESCE(SUM(CASE WHEN status='Processed' THEN 1 ELSE 0 END),0) AS b_proc
        FROM iraq_batches
    """).fetchone()
    b_pen = int(batch_status_totals['b_pen'] or 0)
    b_sent = int(batch_status_totals['b_sent'] or 0)
    b_proc = int(batch_status_totals['b_proc'] or 0)

    requests_received = int(pub_total) + int(batch_apps)
    mofa_kw_approved_total = int(pub_mofa_app) + int(v_app)

    # KSA approval count: union all three Iraq-related tables (de-duplicate by normalized passport)
    ksa_mofa_approved = db.execute("""
        SELECT COUNT(*) c FROM (
            SELECT UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', ''), '-', '')) AS pp
            FROM iraq_applicants WHERE ksa_mofa_status='Approved'
            UNION
            SELECT UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport,'')), ' ', ''), '-', '')) AS pp
            FROM evacuees WHERE LOWER(COALESCE(mofa_ksa_status,''))='approved'
            UNION
            SELECT UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', ''), '-', '')) AS pp
            FROM iraq_public_submissions WHERE LOWER(COALESCE(ksa_mofa_status,''))='approved'
        ) combined WHERE pp != ''
    """).fetchone()['c']

    return {
        'requests_received': requests_received,
        'mofa_kw_approved_total': mofa_kw_approved_total,
        'mofa_ksa_approved': int(ksa_mofa_approved),
        'waiting_travel_iraq': int(waiting_travel_iraq),
        'waiting_transit_kw': int(waiting_transit_kw),
        'public_total': pub_total, 'public_kw_portal': pub_portal,
        'public_forwarded_embassy': pub_fwd, 'public_in_nv': pub_nv,
        'public_mofa_approved': pub_mofa_app, 'public_mofa_rejected': pub_mofa_rej,
        'public_mofa_pending': pub_mofa_pend,
        'batch_applicants': batch_apps, 'batches_pending': b_pen,
        'batches_sent_mofa': b_sent, 'batches_processed': b_proc,
        'visa_kw_approved': v_app, 'visa_kw_pending': v_pend, 'visa_kw_rejected': v_rej,
    }


def _parse_date_safe(value):
    """Parse common portal date formats into a date object, or return None."""
    if value is None:
        return None
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value

    s = str(value).strip()
    if not s:
        return None

    s = s.replace('T', ' ').replace('Z', '')
    if '.' in s and re.match(r'^\d{1,2}/\d{1,2}/\d{4}\s+\d', s):
        s = s.split('.')[0]

    fmts = [
        '%Y-%m-%d',
        '%Y/%m/%d',
        '%d/%m/%Y',
        '%m/%d/%Y',
        '%d-%m-%Y',
        '%m-%d-%Y',
        '%Y-%m-%d %H:%M',
        '%Y-%m-%d %H:%M:%S',
        '%Y/%m/%d %H:%M',
        '%Y/%m/%d %H:%M:%S',
        '%d/%m/%Y %H:%M',
        '%d/%m/%Y %H:%M:%S',
        '%m/%d/%Y %H:%M',
        '%m/%d/%Y %H:%M:%S',
    ]
    for fmt in fmts:
        try:
            return datetime.strptime(s, fmt).date()
        except Exception:
            pass

    try:
        return datetime.fromisoformat(s).date()
    except Exception:
        return None


def _days_between(start, end):
    """Return whole-day difference for valid dates, or None for invalid/negative spans."""
    if not start or not end:
        return None
    if isinstance(start, datetime):
        start = start.date()
    if isinstance(end, datetime):
        end = end.date()
    try:
        days = (end - start).days
        return days if days >= 0 else None
    except Exception:
        return None


def _normalize_airline(value):
    """Normalize airline names for dashboard grouping."""
    if value is None:
        return 'Unknown'
    s = re.sub(r'\s+', ' ', str(value).strip())
    if not s:
        return 'Unknown'

    key = s.lower()
    aliases = {
        'jazeera': 'Jazeera Airways',
        'jazeera airways': 'Jazeera Airways',
        'kuwait airways': 'Kuwait Airways',
        'kuwait airway': 'Kuwait Airways',
        'pia': 'PIA',
        'pakistan international airlines': 'PIA',
        'emirates': 'Emirates',
        'air blue': 'Air Blue',
        'airblue': 'Air Blue',
    }
    if key in aliases:
        return aliases[key]

    if not re.sub(r'[^a-z0-9]+', '', key):
        return 'Other'
    return s.title() or 'Other'


def _extract_profession(row):
    """Best-effort profession bucketing from company, remarks, and medical notes."""
    text = ' '.join([
        str(row.get('company') or '').strip().lower(),
        str(row.get('remarks') or '').strip().lower(),
        str(row.get('medical') or '').strip().lower(),
    ])
    text = re.sub(r'\s+', ' ', text).strip()
    if not text:
        return 'Unknown'

    rules = [
        ('Doctor', ['medical officer', 'physician', 'surgeon', 'doctor']),
        ('Nurse', ['staff nurse', 'nurse']),
        ('Mechanic', ['diesel mechanic', 'auto mechanic', 'mechanic']),
        ('Electrician', ['electrician', 'electrical']),
        ('Driver', ['chauffeur', 'driver']),
        ('Technician', ['maintenance technician', 'technician', 'maintenance']),
        ('Welder / Fabricator', ['fabricator', 'welding', 'welder']),
        ('Cleaner / Housekeeping', ['housekeeping', 'janitor', 'cleaner']),
        ('Security Guard', ['security guard', 'security', 'guard']),
        ('Office / Admin', ['accountant', 'cashier', 'office', 'admin', 'clerk']),
        ('Teacher / Academic', ['lecturer', 'professor', 'teacher']),
        ('Student', ['student']),
        ('Domestic Worker', ['housemaid', 'domestic', 'maid']),
        ('Family / Dependent', ['dependent', 'wife', 'child', 'family']),
        ('MOH / Medical Staff', ['ministry of health', 'moh']),
        ('Construction Worker', ['civil work', 'construction', 'labour', 'labor', 'worker', 'helper', 'mason']),
    ]
    for label, keywords in rules:
        for keyword in keywords:
            if keyword in text:
                return label
    return 'Unknown'


def _median(numbers):
    """Return the median value for a numeric list without external dependencies."""
    vals = sorted([float(n) for n in numbers if n is not None])
    if not vals:
        return None
    mid = len(vals) // 2
    if len(vals) % 2:
        return vals[mid]
    return (vals[mid - 1] + vals[mid]) / 2.0


def _log_perf_if_slow(label, started_at, threshold_ms=250, row_count=None, extra=''):
    elapsed_ms = (time.perf_counter() - started_at) * 1000.0
    if elapsed_ms < max(float(threshold_ms or 0), 0):
        return elapsed_ms
    parts = [f"[Perf] {label}", f"{elapsed_ms:.1f}ms"]
    if row_count is not None:
        parts.append(f"rows={row_count}")
    if extra:
        parts.append(str(extra))
    print(' '.join(parts), flush=True)
    return elapsed_ms


def _dashboard_fee_metrics(db, cutoff_date=None):
    where = []
    params = []
    if cutoff_date:
        where.append("date(COALESCE(paid_at,waived_at,created_at)) >= date(?)")
        params.append(cutoff_date)
    where_sql = f"WHERE {' AND '.join(where)}" if where else ''
    row = db.execute(f"""
        SELECT
          COALESCE(SUM(CASE WHEN fee_status='paid' THEN fee_amount ELSE 0 END),0) AS fee_total_collected,
          COALESCE(SUM(CASE WHEN fee_status='waived' THEN fee_amount ELSE 0 END),0) AS fee_total_waived,
          COALESCE(SUM(CASE WHEN fee_status='paid' AND date(COALESCE(paid_at,created_at))=date('now') THEN fee_amount ELSE 0 END),0) AS fee_today_collected,
          COALESCE(SUM(CASE WHEN fee_status='waived' AND date(COALESCE(waived_at,created_at))=date('now') THEN fee_amount ELSE 0 END),0) AS fee_today_waived,
          COALESCE(SUM(CASE WHEN fee_status='paid' THEN 1 ELSE 0 END),0) AS fee_paid_count,
          COALESCE(SUM(CASE WHEN fee_status='waived' THEN 1 ELSE 0 END),0) AS fee_waived_count,
          COUNT(DISTINCT CASE
            WHEN fee_status IN ('paid','waived')
             AND date(COALESCE(paid_at,waived_at,created_at))=date('now')
            THEN source_table || ':' || source_id END) AS fee_people_served_today,
          COUNT(DISTINCT CASE
            WHEN fee_status IN ('paid','waived')
             AND date(COALESCE(paid_at,waived_at,created_at))=date('now')
            THEN source_table || ':' || source_id END) AS fee_released_today,
          COUNT(DISTINCT CASE
            WHEN fee_status IN ('paid','waived')
            THEN source_table || ':' || source_id END) AS fee_released_total
        FROM fee_collections
        {where_sql}
    """, params).fetchone()
    return dict(row or {})


def api_dashboard_stats(user=None):
    db = get_db()
    started_at = time.perf_counter()
    role = (user or {}).get('role', 'unknown')
    try:
        EV_BASE = "FROM evacuees WHERE dup_flag='CLEAR' AND (effective_route = 'kw_to_pk' OR effective_route IS NULL)"
        EV_ALL = "FROM evacuees WHERE (effective_route = 'kw_to_pk' OR effective_route IS NULL)"

        evac_totals = db.execute(f"""
            SELECT
              COUNT(*) AS total_all,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' THEN 1 ELSE 0 END),0) AS total,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND travel_status='Departed' THEN 1 ELSE 0 END),0) AS departed,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND travel_status='Visa Obtained' THEN 1 ELSE 0 END),0) AS visa_obtained,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND travel_status='Pending' THEN 1 ELSE 0 END),0) AS pending,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND visa_status='Approved' THEN 1 ELSE 0 END),0) AS visa_approved,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND country='Iraq' THEN 1 ELSE 0 END),0) AS iraq_entries,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND travel_status='Returned' THEN 1 ELSE 0 END),0) AS returned,
              COALESCE(SUM(CASE WHEN dup_flag='DUPLICATE' THEN 1 ELSE 0 END),0) AS duplicates,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND travel_status='Departed' AND departure_date=date('now') THEN 1 ELSE 0 END),0) AS departed_today,
              COALESCE(SUM(CASE WHEN dup_flag='CLEAR' AND travel_status='Returned' AND departure_date=date('now') THEN 1 ELSE 0 END),0) AS returned_today
            {EV_ALL}
        """).fetchone()

        total_all = int(evac_totals['total_all'] or 0)
        total = int(evac_totals['total'] or 0)
        departed = int(evac_totals['departed'] or 0)
        visa_obtained = int(evac_totals['visa_obtained'] or 0)
        pending = int(evac_totals['pending'] or 0)
        visa_approved = int(evac_totals['visa_approved'] or 0)
        iraq_entries = int(evac_totals['iraq_entries'] or 0)
        returned = int(evac_totals['returned'] or 0)
        duplicates = int(evac_totals['duplicates'] or 0)
        departed_today = int(evac_totals['departed_today'] or 0)
        entered_today = departed_today
        returned_today = int(evac_totals['returned_today'] or 0)
        jazeera_departed = 120

        # Kept for SITREP/report generation. These are not rendered as dashboard charts.
        by_country = [dict(r) for r in db.execute(f"""
            SELECT country, COUNT(*) total,
            SUM(CASE WHEN travel_status='Departed' THEN 1 ELSE 0 END) departed,
            SUM(CASE WHEN travel_status='Visa Obtained' THEN 1 ELSE 0 END) visa_obtained,
            SUM(CASE WHEN travel_status='Pending' THEN 1 ELSE 0 END) pending,
            SUM(CASE WHEN gender='Male' THEN 1 ELSE 0 END) males,
            SUM(CASE WHEN gender='Female' THEN 1 ELSE 0 END) females,
            SUM(CASE WHEN gender='Child' THEN 1 ELSE 0 END) children
            {EV_ALL} GROUP BY country ORDER BY COUNT(*) DESC
        """).fetchall()]

        by_gender = [dict(r) for r in db.execute(f"""
            SELECT gender, COUNT(*) count,
            SUM(CASE WHEN travel_status='Departed' THEN 1 ELSE 0 END) departed
            {EV_ALL} GROUP BY gender
        """).fetchall()]

        # Operational dashboard analytics for the main KW→PK evacuee flow.
        # Stream only the fields needed for the remaining dashboard charts.
        evac_rows = db.execute(f"""
            SELECT company, remarks, medical, travel_status, date_of_request, created_at
            {EV_BASE}
        """)

        today = datetime.now().date()

        def _request_start_date(row):
            # Prefer the explicit request date; fall back to record creation time
            # for legacy rows where date_of_request was never captured.
            return _parse_date_safe(row.get('date_of_request')) or _parse_date_safe(row.get('created_at'))

        pending_age_map = {'0-3 days': 0, '4-7 days': 0, '8-14 days': 0, '15-30 days': 0, '31+ days': 0}
        processing_trend_map = {}
        profession_groups = {}
        for raw_row in evac_rows:
            row = dict(raw_row)
            travel_status = (row.get('travel_status') or '').strip()
            profession = _extract_profession(row)
            req_date = _request_start_date(row)

            if req_date:
                iso_date = req_date.isoformat()
                slot = processing_trend_map.setdefault(iso_date, {
                    'date': iso_date,
                    'new_requests': 0,
                    'visa_obtained': 0
                })
                slot['new_requests'] += 1
                if travel_status == 'Visa Obtained':
                    slot['visa_obtained'] += 1

            profession_groups[profession] = profession_groups.get(profession, 0) + 1

            if travel_status == 'Pending' and req_date:
                pending_days = _days_between(req_date, today)
                if pending_days is not None:
                    if pending_days <= 3:
                        pending_age_map['0-3 days'] += 1
                    elif pending_days <= 7:
                        pending_age_map['4-7 days'] += 1
                    elif pending_days <= 14:
                        pending_age_map['8-14 days'] += 1
                    elif pending_days <= 30:
                        pending_age_map['15-30 days'] += 1
                    else:
                        pending_age_map['31+ days'] += 1

        pending_age_buckets = [{'label': label, 'count': count} for label, count in pending_age_map.items()]
        processing_trend = [processing_trend_map[k] for k in sorted(processing_trend_map.keys())]
        top_professions = sorted(
            [{'profession': profession, 'count': count, 'total': count}
             for profession, count in profession_groups.items() if profession != 'Unknown'],
            key=lambda x: (-x['count'], x['profession'])
        )[:10]

        longest_pending_candidates = [dict(r) for r in db.execute(f"""
            SELECT id, name, passport, visa_status, travel_status, date_of_request, created_at
            {EV_BASE}
              AND travel_status = 'Pending'
              AND COALESCE(NULLIF(date_of_request,''), created_at) IS NOT NULL
            ORDER BY COALESCE(NULLIF(date_of_request,''), created_at) ASC, id ASC
            LIMIT 50
        """).fetchall()]
        longest_pending_cases = []
        for row in longest_pending_candidates:
            req_date = _request_start_date(row)
            pending_days = _days_between(req_date, today) if req_date else None
            if pending_days is None:
                continue
            longest_pending_cases.append({
                'id': row.get('id'),
                'name': row.get('name') or '',
                'passport': row.get('passport') or '',
                'visa_status': row.get('visa_status') or '',
                'travel_status': row.get('travel_status') or '',
                'date_of_request': req_date.isoformat(),
                'pending_days': pending_days
            })
        longest_pending_cases = sorted(longest_pending_cases, key=lambda x: (-x['pending_days'], x['id'] or 0))[:10]

        try:
            mismatch_totals = db.execute("""
                SELECT
                  COALESCE(SUM(CASE WHEN route_mismatch = 1 THEN 1 ELSE 0 END),0) AS mismatch_total,
                  COALESCE(SUM(CASE WHEN review_status IN ('pending','under_review','needs_followup') THEN 1 ELSE 0 END),0) AS mismatch_pending_review,
                  COALESCE(SUM(CASE WHEN effective_route = 'pk_to_kw' AND route_mismatch = 1 THEN 1 ELSE 0 END),0) AS corrected_to_pk
                FROM evacuees
            """).fetchone()
            mismatch_total = int(mismatch_totals['mismatch_total'] or 0)
            mismatch_pending_review = int(mismatch_totals['mismatch_pending_review'] or 0)
            corrected_to_pk = int(mismatch_totals['corrected_to_pk'] or 0)
        except sqlite3.OperationalError as e:
            print(f"[Dash] route-review query fallback: {e}", flush=True)
            mismatch_total = 0
            mismatch_pending_review = 0
            corrected_to_pk = 0

        payload = {
            'kpi': {'total': total, 'total_all': total_all, 'departed': departed, 'visa_obtained': visa_obtained, 'pending': pending,
                    'visa_approved': visa_approved, 'iraq_entries': iraq_entries, 'duplicates': duplicates,
                    'departed_today': departed_today, 'entered_today': entered_today,
                    'returned': returned, 'returned_today': returned_today,
                    'jazeera_departed': jazeera_departed,
                    'mismatch_total': mismatch_total, 'mismatch_pending_review': mismatch_pending_review,
                    'corrected_to_pk': corrected_to_pk},
            'by_country': by_country,
            'by_gender': by_gender,
            'pending_age_buckets': pending_age_buckets,
            'processing_trend': processing_trend,
            'profession_stats': {
                'top_professions': top_professions
            },
            'longest_pending_cases': longest_pending_cases
        }
        _log_perf_if_slow('/api/stats', started_at, threshold_ms=350, extra=f"role={role} total={payload['kpi'].get('total', 0)}")
        return payload
    except Exception as e:
        print(f"[Dash] ERROR in api_dashboard_stats: {type(e).__name__}: {e}", flush=True)
        return {
            'kpi': {'total': 0, 'total_all': 0, 'departed': 0, 'visa_obtained': 0, 'pending': 0,
                    'visa_approved': 0, 'iraq_entries': 0, 'duplicates': 0,
                    'departed_today': 0, 'entered_today': 0, 'returned': 0, 'returned_today': 0,
                    'jazeera_departed': 120, 'mismatch_total': 0, 'mismatch_pending_review': 0, 'corrected_to_pk': 0},
            'by_country': [],
            'by_gender': [],
            'pending_age_buckets': [],
            'processing_trend': [],
            'profession_stats': {'top_professions': []},
            'longest_pending_cases': []
        }
    finally:
        db.close()

_EVACUEE_LIST_COLUMNS = """
    id, created_at, name, passport, cnic, gender, country, civil_id, border_crossing, mobile,
    company, visa_status, travel_status, departure_date, airline, ticket_number, departure_airport,
    destination_country, date_of_request, email, dob, emergency_contact, medical, family_group_id,
    dependents, accommodation, priority, remarks, planned_departure, saudi_city, traveling_with_family,
    note_verbal_number, note_verbal_date, mofa_approval_serial, manual_nv_page_no, fee_status, dup_flag, mofa_status,
    mofa_sent_date, route_mismatch, review_status, record_locked, location_review_flag
"""
ALL_RECORDS_DEFAULT_LIMIT = 10
ALL_RECORDS_MAX_LIMIT = 100


def api_records(params, session_user=None):
    db = get_db()
    started_at = time.perf_counter()
    try:
        # Single-record fetch (fresh data for View modal after approval PDF / other updates)
        if params.get('id'):
            try:
                rid = int(str(params['id']).strip())
            except (TypeError, ValueError):
                rid = 0
            if rid > 0:
                row = db.execute("SELECT * FROM evacuees WHERE id = ?", [rid]).fetchone()
                if row:
                    rec = dict(row)
                    return [_apply_nv_access_fields(db, rec, 'evacuees', session_user)]
                return []
        where = ["1=1"]
        qparams = []
        if params.get('search'):
            search_val = params['search'].strip()
            tracking_match = re.match(r'^PKE-?(\d+)$', search_val, re.IGNORECASE)
            if tracking_match:
                rec_id = int(tracking_match.group(1))
                where.append("id = ?")
                qparams.append(rec_id)
            else:
                s = f"%{search_val}%"
                compact = re.sub(r'[\s\-]+', '', search_val)
                compact_s = f"%{compact or search_val}%"
                phone_compact = re.sub(r'[\s\-\+\(\)]+', '', search_val)
                phone_s = f"%{phone_compact or search_val}%"
                record_match = re.match(r'^(?:#|record\s*#?|id\s*#?)?(\d+)$', search_val, re.IGNORECASE)
                record_id = int(record_match.group(1)) if record_match else 0
                where.append("""(
                    name LIKE ? OR passport LIKE ? OR cnic LIKE ? OR
                    REPLACE(REPLACE(IFNULL(cnic,''), '-', ''), ' ', '') LIKE ? OR
                    mobile LIKE ? OR
                    REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(IFNULL(mobile,''), ' ', ''), '-', ''), '+', ''), '(', ''), ')', '') LIKE ? OR
                    civil_id LIKE ? OR email LIKE ? OR
                    IFNULL(note_verbal_number,'') LIKE ? OR IFNULL(mofa_approval_serial,'') LIKE ? OR
                    (? > 0 AND id = ?)
                )""")
                qparams.extend([s, s, s, compact_s, s, phone_s, s, s, s, s, record_id, record_id])
        if params.get('status'):
            where.append("travel_status = ?")
            qparams.append(params['status'])
        if params.get('country'):
            where.append("country = ?")
            qparams.append(params['country'])
        if params.get('gender'):
            where.append("gender = ?")
            qparams.append(params['gender'])
        if params.get('visa'):
            where.append("visa_status = ?")
            qparams.append(params['visa'])
        if params.get('dup'):
            where.append("dup_flag = ?")
            qparams.append(params['dup'])
        if params.get('fee_status'):
            where.append("COALESCE(fee_status,'pending') = ?")
            qparams.append(params['fee_status'])
        # ── Route mismatch filters ──
        if params.get('effective_route'):
            where.append("effective_route = ?")
            qparams.append(params['effective_route'])
        if params.get('route_mismatch') == '1':
            where.append("route_mismatch = 1")
        elif params.get('route_mismatch') == '0':
            where.append("(route_mismatch = 0 OR route_mismatch IS NULL)")
        if params.get('hide_mismatch') == '1':
            where.append("(route_mismatch = 0 OR route_mismatch IS NULL)")
        if params.get('location_review_flag') == '1':
            where.append("location_review_flag = 1")
        if params.get('current_country'):
            where.append("current_country = ?")
            qparams.append(params['current_country'])
        if params.get('ip_location_status'):
            where.append("ip_location_status = ?")
            qparams.append(params['ip_location_status'])

        count_sql = f"SELECT COUNT(*) AS c FROM evacuees WHERE {' AND '.join(where)}"
        total_row = db.execute(count_sql, qparams).fetchone()
        total = int(total_row['c']) if total_row and total_row['c'] is not None else 0

        try:
            limit = int(str(params.get('limit', '')).strip() or ALL_RECORDS_DEFAULT_LIMIT)
        except (TypeError, ValueError):
            limit = ALL_RECORDS_DEFAULT_LIMIT
        limit = max(1, min(limit, ALL_RECORDS_MAX_LIMIT))

        requested_page = None
        raw_page = str(params.get('page', '')).strip()
        if raw_page:
            try:
                requested_page = int(raw_page)
            except (TypeError, ValueError):
                requested_page = None

        requested_offset = None
        raw_offset = str(params.get('offset', '')).strip()
        if raw_offset:
            try:
                requested_offset = int(raw_offset)
            except (TypeError, ValueError):
                requested_offset = None

        total_pages = max(1, ((total + limit - 1) // limit)) if total else 1
        page = 1
        offset = 0
        if requested_page and requested_page > 0:
            page = min(requested_page, total_pages)
            offset = (page - 1) * limit
        elif requested_offset is not None:
            offset = max(requested_offset, 0)
            if total > 0 and offset >= total:
                offset = max(0, (total_pages - 1) * limit)
            page = (offset // limit) + 1

        sql = f"SELECT {_EVACUEE_LIST_COLUMNS} FROM evacuees WHERE {' AND '.join(where)} ORDER BY id DESC LIMIT ? OFFSET ?"
        page_params = list(qparams) + [limit, offset]
        rows = [dict(r) for r in db.execute(sql, page_params).fetchall()]
        record_ids = [r.get('id') for r in rows]
        nv_links_by_id = bulk_fetch_nv_links_for_records(db, 'evacuees', record_ids)
        latest_releases_by_id = bulk_fetch_latest_nv_releases(db, 'evacuees', record_ids) if _is_admin_user(session_user) else {}
        result = apply_nv_access_fields_bulk(rows, nv_links_by_id, latest_releases_by_id, session_user, 'evacuees')
        _log_perf_if_slow(
            '/api/records',
            started_at,
            threshold_ms=300,
            row_count=len(result),
            extra=f"search={1 if params.get('search') else 0} total={total} page={page}"
        )
        return {
            'items': result,
            'total': total,
            'limit': limit,
            'offset': offset,
            'page': page,
            'pages': total_pages,
        }
    finally:
        db.close()

def api_returnees(params):
    db = get_db()
    where = ["ci.cancellation_status = 'active'"]
    qparams = []

    if params.get('search'):
        s = f"%{params['search'].strip()}%"
        where.append("""(
            pm.full_name LIKE ? OR
            pm.passport LIKE ? OR
            pm.cnic LIKE ? OR
            pm.civil_id LIKE ? OR
            ci.reference_number LIKE ? OR
            pm.email LIKE ? OR
            pm.mobile LIKE ? OR
            pm.whatsapp LIKE ? OR
            pm.alt_mobile LIKE ? OR
            pm.emergency_phone LIKE ?
        )""")
        qparams.extend([s, s, s, s, s, s, s, s, s, s])

    if params.get('status'):
        where.append("ci.status = ?")
        qparams.append(params['status'])

    if params.get('province'):
        where.append("ci.province_pk = ?")
        qparams.append(params['province'])

    if params.get('urgency'):
        where.append("ci.travel_urgency = ?")
        qparams.append(params['urgency'])

    if params.get('visa'):
        if params['visa'] == 'approved':
            where.append("ci.saudi_visa_approved = 'yes'")
        elif params['visa'] == 'pending':
            where.append("(ci.saudi_visa_approved = 'pending' OR ci.saudi_visa_approved = '' OR ci.saudi_visa_approved IS NULL)")
        elif params['visa'] == 'not_applied':
            where.append("(ci.saudi_visa_applied = 'no' OR ci.saudi_visa_applied = '' OR ci.saudi_visa_applied IS NULL)")

    rows = db.execute(f"""
        SELECT
            ci.id,
            ci.reference_number,
            ci.status,
            ci.travel_direction,
            ci.current_city_pk,
            ci.province_pk,
            ci.destination_area_kw,
            ci.travel_urgency,
            ci.travel_readiness,
            ci.traveling_alone,
            ci.group_size,
            ci.adults_count,
            ci.children_count,
            ci.infants_count,
            ci.interest_level,
            ci.saudi_visa_applied,
            ci.saudi_visa_approved,
            ci.dup_flag,
            ci.is_moh_employee,
            ci.moh_leave_end,
            ci.submission_timestamp,
            pm.full_name,
            pm.passport,
            pm.mobile,
            pm.whatsapp,
            pm.gender
        FROM charter_interest ci
        JOIN person_master pm ON pm.id = ci.person_id
        WHERE {" AND ".join(where)}
        ORDER BY ci.id DESC
    """, qparams).fetchall()

    db.close()
    return [dict(r) for r in rows]

def api_returnees_stats():
    db = get_db()
    try:
        total = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active'
        """).fetchone()['c']

        submitted = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active' AND status = 'Submitted'
        """).fetchone()['c']

        verified = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active' AND verification_status = 'verified'
        """).fetchone()['c']

        contacted = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active' AND followup_status = 'contacted'
        """).fetchone()['c']

        approved_visa = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active' AND saudi_visa_approved = 'yes'
        """).fetchone()['c']

        pending_visa = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active' AND (
                saudi_visa_approved = 'pending' OR
                saudi_visa_approved = '' OR
                saudi_visa_approved IS NULL
            )
        """).fetchone()['c']

        with_family = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active' AND traveling_alone = 'no'
        """).fetchone()['c']

        ready_to_travel = db.execute("""
            SELECT COUNT(*) c
            FROM charter_interest
            WHERE cancellation_status = 'active'
              AND interest_level IN ('likely', 'ready')
        """).fetchone()['c']

        by_status = [dict(r) for r in db.execute("""
            SELECT status, COUNT(*) count
            FROM charter_interest
            WHERE cancellation_status = 'active'
            GROUP BY status
            ORDER BY count DESC
        """).fetchall()]

        by_province = [dict(r) for r in db.execute("""
            SELECT COALESCE(province_pk, 'Unknown') province, COUNT(*) count
            FROM charter_interest
            WHERE cancellation_status = 'active'
            GROUP BY province_pk
            ORDER BY count DESC
        """).fetchall()]

        by_urgency = [dict(r) for r in db.execute("""
            SELECT COALESCE(travel_urgency, 'general') urgency, COUNT(*) count
            FROM charter_interest
            WHERE cancellation_status = 'active'
            GROUP BY travel_urgency
            ORDER BY count DESC
        """).fetchall()]

        processing_funnel = []
        for stage in ['Submitted', 'Under Review', 'Verified', 'Contacted', 'Confirmed', 'Allocated', 'Travel Completed']:
            cnt = db.execute("""
                SELECT COUNT(*) c
                FROM charter_interest
                WHERE cancellation_status = 'active' AND status = ?
            """, [stage]).fetchone()['c']
            processing_funnel.append({'stage': stage, 'count': cnt})

        by_visa_status = [dict(r) for r in db.execute("""
            SELECT status, COUNT(*) count
            FROM (
                SELECT CASE
                    WHEN LOWER(COALESCE(saudi_visa_approved, '')) = 'yes' THEN 'Approved'
                    WHEN LOWER(COALESCE(saudi_visa_applied, '')) = 'no' OR COALESCE(TRIM(saudi_visa_applied), '') = '' THEN 'Not Applied'
                    ELSE 'Pending'
                END AS status
                FROM charter_interest
                WHERE cancellation_status = 'active'
            ) x
            GROUP BY status
            ORDER BY count DESC
        """).fetchall()]

        by_airport = [dict(r) for r in db.execute("""
            SELECT COALESCE(NULLIF(TRIM(preferred_airport_pk), ''), 'Unknown') airport, COUNT(*) count
            FROM charter_interest
            WHERE cancellation_status = 'active'
            GROUP BY COALESCE(NULLIF(TRIM(preferred_airport_pk), ''), 'Unknown')
            ORDER BY count DESC
        """).fetchall()]

        with_family_vs_alone = [dict(r) for r in db.execute("""
            SELECT label, COUNT(*) count
            FROM (
                SELECT CASE
                    WHEN LOWER(COALESCE(traveling_alone, 'yes')) = 'no' THEN 'With Family'
                    ELSE 'Alone'
                END AS label
                FROM charter_interest
                WHERE cancellation_status = 'active'
            ) x
            GROUP BY label
            ORDER BY count DESC
        """).fetchall()]

        moh_vs_non_moh = [dict(r) for r in db.execute("""
            SELECT label, COUNT(*) count
            FROM (
                SELECT CASE
                    WHEN LOWER(COALESCE(is_moh_employee, 'no')) = 'yes' THEN 'MOH'
                    ELSE 'Non-MOH'
                END AS label
                FROM charter_interest
                WHERE cancellation_status = 'active'
            ) x
            GROUP BY label
            ORDER BY count DESC
        """).fetchall()]

        # ── Corrected evacuees now operationally PK→KW ──
        corrected_from_evacuees = db.execute("""
            SELECT COUNT(*) c FROM evacuees
            WHERE effective_route = 'pk_to_kw' AND route_mismatch = 1
        """).fetchone()['c']

        return {
            'kpi': {
                'total': total,
                'submitted': submitted,
                'verified': verified,
                'contacted': contacted,
                'approved_visa': approved_visa,
                'pending_visa': pending_visa,
                'with_family': with_family,
                'ready_to_travel': ready_to_travel,
                'corrected_from_evacuees': corrected_from_evacuees
            },
            'by_status': by_status,
            'by_province': by_province,
            'by_urgency': by_urgency,
            'processing_funnel': processing_funnel,
            'by_visa_status': by_visa_status,
            'by_airport': by_airport,
            'with_family_vs_alone': with_family_vs_alone,
            'moh_vs_non_moh': moh_vs_non_moh
        }
    except Exception as e:
        print(f"[Returnees] ERROR in api_returnees_stats: {type(e).__name__}: {e}", flush=True)
        return {
            'kpi': {
                'total': 0,
                'submitted': 0,
                'verified': 0,
                'contacted': 0,
                'approved_visa': 0,
                'pending_visa': 0,
                'with_family': 0,
                'ready_to_travel': 0,
                'corrected_from_evacuees': 0
            },
            'by_status': [],
            'by_province': [],
            'by_urgency': [],
            'processing_funnel': [],
            'by_visa_status': [],
            'by_airport': [],
            'with_family_vs_alone': [],
            'moh_vs_non_moh': []
        }
    finally:
        db.close()

def normalize_border(val):
    if not val: return val
    v = val.strip().lower()
    if 'khafji' in v or 'khafi' in v: return 'Khafji Border'
    if 'salmi' in v or 'salmy' in v: return 'Salmi Border'
    return val

def _normalize_manual_nv_page_no(value):
    raw = str(value or '').strip()
    if not raw:
        return ''
    if not re.fullmatch(r'\d+', raw):
        return ''
    page_no = int(raw)
    return str(page_no) if page_no > 0 else ''

def api_save_record(data, user, role=''):
    if data.get('border_crossing'):
        data['border_crossing'] = normalize_border(data['border_crossing'])
    if 'manual_nv_page_no' in data and role != 'admin':
        data.pop('manual_nv_page_no', None)
    if 'manual_nv_page_no' in data:
        raw_manual_page = str(data.get('manual_nv_page_no') or '').strip()
        clean_manual_page = _normalize_manual_nv_page_no(raw_manual_page)
        if raw_manual_page and not clean_manual_page:
            return {'success': False, 'error': 'Applicant page in linked NV PDF must be a positive whole number.'}
        data['manual_nv_page_no'] = clean_manual_page
    db = get_db()
    rec_id = data.get('id')
    fields = ['name','passport','cnic','gender','country','civil_id','border_crossing',
              'mobile','company','visa_status','travel_status','airline','ticket_number',
              'departure_airport','destination_country','date_of_request','email',
              'dob','emergency_contact','medical','family_group_id','dependents',
              'accommodation','priority','remarks','planned_departure','saudi_city',
              'traveling_with_family','confirm_ksa_3days','departure_date',
              'current_country','current_city_pakistan','current_area_kuwait',
              'note_verbal_number','note_verbal_date','mofa_approval_serial','manual_nv_page_no']

    if rec_id:  # Update
        # Get old record to detect changes
        old_rec = dict(db.execute("SELECT * FROM evacuees WHERE id = ?", [rec_id]).fetchone())

        # ── Only update fields actually present in the incoming data ──
        # This prevents blanking out fields not included in the request
        # (e.g. viewSave sends ~30 fields but the full list has 33+)
        update_fields = [f for f in fields if f in data]

        # ── Record Locking: DISABLED — staff can now edit all fields ──
        # Previously, identity fields were locked after MOFA submission.
        # All records are now fully editable by authenticated staff.

        sets = [f"{f} = ?" for f in update_fields]
        vals = [data.get(f, '') for f in update_fields]

        # Build a merged view of old + new data for duplicate checking
        merged_data = {f: old_rec.get(f, '') for f in fields}
        merged_data.update({f: data[f] for f in update_fields})

        dup_flags = check_duplicates(db, merged_data, exclude_id=rec_id)
        dup_flag = 'DUPLICATE' if dup_flags else 'CLEAR'
        sets.append("dup_flag = ?"); vals.append(dup_flag)
        sets.append("updated_at = CURRENT_TIMESTAMP")
        sets.append("updated_by = ?"); vals.append(user)
        vals.append(rec_id)
        db.execute(f"UPDATE evacuees SET {', '.join(sets)} WHERE id = ?", vals)
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('update', ?, ?, ?)",
                   (rec_id, user, json.dumps(data)))
        if 'manual_nv_page_no' in data:
            old_page = _normalize_manual_nv_page_no(old_rec.get('manual_nv_page_no'))
            new_page = _normalize_manual_nv_page_no(data.get('manual_nv_page_no'))
            if old_page != new_page:
                if new_page and old_page:
                    action = 'manual_nv_page_updated'
                elif new_page:
                    action = 'manual_nv_page_saved'
                else:
                    action = 'manual_nv_page_cleared'
                linked_nv = _nv_best_link_for_record(db, 'evacuees', rec_id)
                db.execute(
                    "INSERT INTO audit_log (action, record_id, user, details) VALUES (?, ?, ?, ?)",
                    [
                        action,
                        rec_id,
                        user,
                        json.dumps({
                            'tracking_id': _nv_tracking_id('evacuees', old_rec),
                            'applicant_name': old_rec.get('name', ''),
                            'passport': old_rec.get('passport', ''),
                            'old_manual_nv_page_no': old_page,
                            'new_manual_nv_page_no': new_page,
                            'linked_nv_upload_id': linked_nv.get('upload_id') if linked_nv else '',
                            'linked_nv_number': linked_nv.get('note_verbal_number') if linked_nv else '',
                            'linked_nv_date': linked_nv.get('note_verbal_date') if linked_nv else '',
                            'note_verbal_number': data.get('note_verbal_number', old_rec.get('note_verbal_number', '')),
                            'note_verbal_date': data.get('note_verbal_date', old_rec.get('note_verbal_date', '')),
                            'mofa_approval_serial': data.get('mofa_approval_serial', old_rec.get('mofa_approval_serial', '')),
                            'timestamp': _nv_now_iso(),
                        }),
                    ],
                )

        # Apply workflow rules only for fields actually sent and changed
        workflow_changes = []
        for field in ['visa_status', 'ticket_number']:
            if field in data:
                old_val = old_rec.get(field, '')
                new_val = data.get(field, '')
                if old_val != new_val:
                    wf = apply_workflow_rules(db, rec_id, field, new_val, user)
                    workflow_changes.extend(wf)

        # Auto-email when visa status transitions to Approved
        if 'visa_status' in data and old_rec.get('visa_status') != 'Approved' and data.get('visa_status') == 'Approved':
            updated = dict(db.execute("SELECT id, name, passport, email FROM evacuees WHERE id = ?", [rec_id]).fetchone())
            _queue_visa_approved_email(updated, user)
        _queue_iraq_final_approval_if_ready(db, rec_id, user)

        db.commit(); db.close()
        return {'success': True, 'id': rec_id, 'dup_flag': dup_flag, 'dup_details': dup_flags, 'workflow': workflow_changes}
    else:  # Insert
        if not data.get('date_of_request'):
            data['date_of_request'] = datetime.now().strftime('%Y-%m-%d')
        dup_flags = check_duplicates(db, data)
        dup_flag = 'DUPLICATE' if dup_flags else 'CLEAR'
        vals = [data.get(f, '') for f in fields] + [dup_flag]
        placeholders = ', '.join(['?'] * (len(fields) + 1))
        cur = db.execute(f"INSERT INTO evacuees ({', '.join(fields)}, dup_flag) VALUES ({placeholders})", vals)
        new_id = cur.lastrowid
        new_rec = dict(db.execute("SELECT id, name, passport, email FROM evacuees WHERE id = ?", [new_id]).fetchone())
        _queue_registration_email(new_rec, user)
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('create', ?, ?, ?)",
                   (new_id, user, json.dumps(data)))

        # ── Pakistan nationality/mobile heuristic at insert time ──
        # Mirrors the startup backfill (init_db) so that records matching
        # the MOFA-Export Pakistan exclusion immediately get review_status='pending',
        # ensuring they appear in Route Review instead of falling into a gap
        # where they're hidden from both MOFA Export and Route Review.
        # Skipped when ROUTE_REVIEW_ENABLED is False (records flow straight to MOFA).
        if ROUTE_REVIEW_ENABLED:
            rec_country = (data.get('country') or '').strip().lower()
            rec_mobile = (data.get('mobile') or '').strip()
            is_pk_heuristic = (
                'pakistan' in rec_country
                or rec_mobile.startswith('+92')
                or rec_mobile.startswith('03')
                or rec_mobile.startswith('92')
            )
            if is_pk_heuristic and dup_flag == 'CLEAR':
                db.execute("""UPDATE evacuees SET
                    review_status = COALESCE(NULLIF(review_status,''), 'pending'),
                    flag_reason = COALESCE(NULLIF(flag_reason,''), 'Auto-flagged: Pakistan nationality/mobile at registration')
                WHERE id = ? AND (review_status IS NULL OR review_status = '')""",
                [new_id])

        db.commit(); db.close()
        return {'success': True, 'id': new_id, 'dup_flag': dup_flag, 'dup_details': dup_flags}

def api_public_travel_details_submit(data, client_ip=''):
    """Applicant self-service travel details for approved public-tracking records."""
    try:
        rec_id = int(str(data.get('record_id') or data.get('id') or '0').strip())
    except (TypeError, ValueError):
        rec_id = 0
    token = str(data.get('tracking_token') or '').strip()
    if rec_id <= 0 or not token:
        return {'success': False, 'error': 'Invalid tracking session. Please search your record again.'}

    def clean(key, limit=160):
        return str(data.get(key) or '').strip()[:limit]

    required = {
        'travel_date': 'Travel Date',
        'airline': 'Airline',
        'flight_number': 'Flight Number',
        'ticket_number': 'Ticket Number / PNR',
        'departure_from': 'Departure From',
        'arrival_to': 'Arrival To',
        'border_route': 'Border / Transit Route'
    }
    cleaned = {k: clean(k, 220) for k in required}
    cleaned['remarks'] = clean('remarks', 1000)
    missing = [label for key, label in required.items() if not cleaned[key]]
    if missing:
        return {'success': False, 'error': 'Please complete: ' + ', '.join(missing)}

    db = get_db()
    try:
        rec = db.execute("SELECT * FROM evacuees WHERE id = ?", [rec_id]).fetchone()
        if not rec:
            return {'success': False, 'error': 'Record not found. Please search again.'}
        rec = dict(rec)
        if not _verify_public_tracking_token(rec, token):
            return {'success': False, 'error': 'Tracking verification failed. Please search your record again.'}
        if not _public_travel_details_eligible(rec):
            return {'success': False, 'error': 'Travel details can be submitted only after approval is available.'}
        if _public_travel_details_locked(rec):
            payload = _public_travel_details_payload(rec)
            payload['tracking_number'] = _tracking_no(rec_id)
            return {'success': False, 'locked': True, 'message': PUBLIC_TRAVEL_LOCKED_MESSAGE, 'data': payload}

        db.execute("""
            UPDATE evacuees SET
                applicant_travel_date = ?,
                applicant_airline = ?,
                applicant_flight_number = ?,
                applicant_ticket_number = ?,
                applicant_departure_from = ?,
                applicant_arrival_to = ?,
                applicant_border_route = ?,
                applicant_travel_remarks = ?,
                applicant_travel_submitted_at = CASE
                    WHEN applicant_travel_submitted_at IS NULL OR TRIM(applicant_travel_submitted_at) = ''
                    THEN CURRENT_TIMESTAMP ELSE applicant_travel_submitted_at END,
                applicant_travel_updated_at = CURRENT_TIMESTAMP,
                applicant_travel_source = 'tracking_portal',
                updated_at = CURRENT_TIMESTAMP,
                updated_by = 'applicant_self_service'
            WHERE id = ?
        """, [
            cleaned['travel_date'], cleaned['airline'], cleaned['flight_number'],
            cleaned['ticket_number'], cleaned['departure_from'], cleaned['arrival_to'],
            cleaned['border_route'], cleaned['remarks'], rec_id
        ])
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('public_travel_details_submit', ?, ?, ?)",
                   [rec_id, client_ip or 'public', json.dumps({'source': 'tracking_portal', 'fields': list(cleaned.keys())})])
        db.commit()
        fresh = dict(db.execute("SELECT * FROM evacuees WHERE id = ?", [rec_id]).fetchone())
        payload = _public_travel_details_payload(fresh)
        payload['tracking_number'] = _tracking_no(rec_id)
        payload['tracking_token'] = _public_tracking_token(rec_id, fresh.get('passport'))
        return {'success': True, 'message': PUBLIC_TRAVEL_SUCCESS_MESSAGE, 'data': payload}
    finally:
        db.close()

def _norm_compact(val):
    return re.sub(r'[\s\-]+', '', (val or '').strip().upper())

def _fee_state(record):
    s = (record.get('fee_status') or 'pending').strip().lower()
    return s if s in ('pending', 'paid', 'waived') else 'pending'

def _fee_is_cleared(record):
    return _fee_state(record) in ('paid', 'waived')

def _fee_source_meta(source):
    if source == 'evacuees':
        return {'table': 'evacuees', 'id_col': 'id', 'name_col': 'name', 'passport_col': 'passport', 'ref_expr': "('PKE-' || id)"}
    if source == 'iraq_applicants':
        return {'table': 'iraq_applicants', 'id_col': 'id', 'name_col': 'full_name', 'passport_col': 'passport_number', 'ref_expr': "('IRAQ-APP-' || id)"}
    if source == 'iraq_public_submissions':
        return {'table': 'iraq_public_submissions', 'id_col': 'id', 'name_col': 'full_name', 'passport_col': 'passport_number', 'ref_expr': "COALESCE(reference_number, ('IRQ-' || id))"}
    return None


def _attach_fee_applicant_names(db, rows):
    out = [dict(r) for r in (rows or [])]
    grouped_ids = {
        'evacuees': set(),
        'iraq_applicants': set(),
        'iraq_public_submissions': set(),
    }
    for row in out:
        source = str(row.get('source_table') or '').strip()
        if source not in grouped_ids:
            continue
        try:
            rid = int(row.get('source_id') or 0)
        except Exception:
            rid = 0
        if rid > 0:
            grouped_ids[source].add(rid)

    name_maps = {}
    for source, ids in grouped_ids.items():
        meta = _fee_source_meta(source)
        mapping = {}
        if meta and ids:
            for chunk in _iter_nv_record_id_chunks(ids):
                placeholders = ','.join('?' for _ in chunk)
                rows_chunk = db.execute(
                    f"SELECT {meta['id_col']} AS id, {meta['name_col']} AS applicant_name "
                    f"FROM {meta['table']} WHERE {meta['id_col']} IN ({placeholders})",
                    chunk,
                ).fetchall()
                for row in rows_chunk:
                    mapping[int(row['id'])] = row['applicant_name'] or ''
        name_maps[source] = mapping

    for row in out:
        source = str(row.get('source_table') or '').strip()
        try:
            rid = int(row.get('source_id') or 0)
        except Exception:
            rid = 0
        row['applicant_name'] = name_maps.get(source, {}).get(rid, '')
    return out

def api_fee_lookup(params):
    q_raw = (params.get('q') or '').strip()
    if not q_raw:
        return {'success': False, 'error': 'Search term required'}
    q = _norm_compact(q_raw)
    db = get_db()
    results = []
    try:
        tm = re.match(r'^PKE(\d+)$', q)
        if tm or q.isdigit():
            rid = int(tm.group(1)) if tm else int(q)
            row = db.execute("SELECT * FROM evacuees WHERE id = ?", [rid]).fetchone()
            if row:
                r = dict(row)
                results.append({
                    'source': 'evacuees', 'id': r['id'], 'name': r.get('name', ''),
                    'passport': r.get('passport', ''), 'tracking_or_reference': f"PKE-{r['id']}",
                    'status': r.get('travel_status', ''), 'fee_status': _fee_state(r),
                    'ticket_details_filled': all((r.get(k) or '').strip() for k in ('ticket_number', 'airline', 'departure_date', 'departure_airport', 'destination_country')),
                    'print_unlocked': is_letter_print_ready(r),
                })
            return {'success': True, 'results': results}

        evac_rows = db.execute("""
            SELECT * FROM evacuees
            WHERE UPPER(REPLACE(REPLACE(COALESCE(passport,''),' ',''),'-','')) = ?
               OR UPPER(name) LIKE UPPER(?)
            ORDER BY id DESC LIMIT 20
        """, [q, f"%{q_raw}%"]).fetchall()
        for rr in evac_rows:
            r = dict(rr)
            results.append({
                'source': 'evacuees', 'id': r['id'], 'name': r.get('name', ''),
                'passport': r.get('passport', ''), 'tracking_or_reference': f"PKE-{r['id']}",
                'status': r.get('travel_status', ''), 'fee_status': _fee_state(r),
                'ticket_details_filled': all((r.get(k) or '').strip() for k in ('ticket_number', 'airline', 'departure_date', 'departure_airport', 'destination_country')),
                'print_unlocked': is_letter_print_ready(r),
            })

        app_rows = db.execute("""
            SELECT * FROM iraq_applicants
            WHERE UPPER(REPLACE(REPLACE(COALESCE(passport_number,''),' ',''),'-','')) = ?
               OR UPPER(full_name) LIKE UPPER(?)
            ORDER BY id DESC LIMIT 20
        """, [q, f"%{q_raw}%"]).fetchall()
        for rr in app_rows:
            r = dict(rr)
            results.append({
                'source': 'iraq_applicants', 'id': r['id'], 'name': r.get('full_name', ''),
                'passport': r.get('passport_number', ''), 'tracking_or_reference': f"IRAQ-APP-{r['id']}",
                'status': r.get('individual_status', ''), 'fee_status': _fee_state(r),
                'ticket_details_filled': True, 'print_unlocked': is_iraq_letter_print_ready(r),
            })

        pub_rows = db.execute("""
            SELECT * FROM iraq_public_submissions
            WHERE UPPER(REPLACE(REPLACE(COALESCE(passport_number,''),' ',''),'-','')) = ?
               OR UPPER(REPLACE(REPLACE(COALESCE(reference_number,''),' ',''),'-','')) = ?
               OR UPPER(full_name) LIKE UPPER(?)
            ORDER BY id DESC LIMIT 20
        """, [q, q, f"%{q_raw}%"]).fetchall()
        for rr in pub_rows:
            r = dict(rr)
            results.append({
                'source': 'iraq_public_submissions', 'id': r['id'], 'name': r.get('full_name', ''),
                'passport': r.get('passport_number', ''), 'tracking_or_reference': r.get('reference_number') or f"IRQ-{r['id']}",
                'status': r.get('status', ''), 'fee_status': _fee_state(r),
                'ticket_details_filled': True, 'print_unlocked': is_iraq_letter_print_ready(r),
            })
        return {'success': True, 'results': results}
    finally:
        db.close()

def _upsert_fee_for_record(db, source, rec_id, action, user, amount=2.0, waiver_reason='', receipt_notes=''):
    meta = _fee_source_meta(source)
    if not meta:
        return {'success': False, 'error': 'Unsupported source'}
    row = db.execute(f"SELECT * FROM {meta['table']} WHERE {meta['id_col']} = ?", [rec_id]).fetchone()
    if not row:
        return {'success': False, 'error': 'Record not found'}
    rec = dict(row)
    cur_status = _fee_state(rec)
    if cur_status in ('paid', 'waived'):
        return {'success': False, 'error': f"Fee already {cur_status}"}
    passport = (rec.get(meta['passport_col']) or '').strip()
    ref = db.execute(f"SELECT {meta['ref_expr']} ref FROM {meta['table']} WHERE {meta['id_col']} = ?", [rec_id]).fetchone()['ref']
    if action == 'paid':
        cur = db.execute(f"""UPDATE {meta['table']} SET
            fee_status='paid', fee_amount=?, fee_currency='KWD',
            fee_paid_at=CURRENT_TIMESTAMP, fee_paid_by=?,
            fee_released=1, fee_released_at=CURRENT_TIMESTAMP, fee_released_by_logic='paid'
            WHERE {meta['id_col']} = ? AND COALESCE(fee_status,'pending')='pending'""", [amount, user, rec_id])
        if cur.rowcount <= 0:
            return {'success': False, 'error': 'Unable to mark paid (already processed)'}
        db.execute("""INSERT INTO fee_collections
            (source_table, source_id, passport_number, tracking_or_reference, fee_amount, fee_currency, fee_status, receipt_notes, paid_at, paid_by)
            VALUES (?, ?, ?, ?, ?, 'KWD', 'paid', ?, CURRENT_TIMESTAMP, ?)""",
            [source, rec_id, passport, ref, amount, receipt_notes or '', user])
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('fee_collected', ?, ?, ?)",
                   [rec_id, user, json.dumps({'source': source, 'amount': amount, 'currency': 'KWD', 'reference': ref})])
    elif action == 'waived':
        cur = db.execute(f"""UPDATE {meta['table']} SET
            fee_status='waived', fee_amount=?, fee_currency='KWD',
            fee_waived_at=CURRENT_TIMESTAMP, fee_waived_by=?, fee_waiver_reason=?,
            fee_released=1, fee_released_at=CURRENT_TIMESTAMP, fee_released_by_logic='waived'
            WHERE {meta['id_col']} = ? AND COALESCE(fee_status,'pending')='pending'""", [amount, user, waiver_reason or '', rec_id])
        if cur.rowcount <= 0:
            return {'success': False, 'error': 'Unable to waive (already processed)'}
        db.execute("""INSERT INTO fee_collections
            (source_table, source_id, passport_number, tracking_or_reference, fee_amount, fee_currency, fee_status, waived_at, waiver_approved_by, waiver_reason)
            VALUES (?, ?, ?, ?, ?, 'KWD', 'waived', CURRENT_TIMESTAMP, ?, ?)""",
            [source, rec_id, passport, ref, amount, user, waiver_reason or ''])
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('fee_waived', ?, ?, ?)",
                   [rec_id, user, json.dumps({'source': source, 'amount': amount, 'currency': 'KWD', 'reference': ref, 'reason': waiver_reason or ''})])
    else:
        return {'success': False, 'error': 'Invalid action'}
    return {'success': True}

def api_fee_collect(data, user):
    source = (data.get('source') or '').strip()
    rec_id = int(data.get('id') or 0)
    amount = float(data.get('amount') or 2.0)
    notes = (data.get('receipt_notes') or '').strip()
    if rec_id <= 0 or not source:
        return {'success': False, 'error': 'source and id required'}
    db = get_db()
    try:
        out = _upsert_fee_for_record(db, source, rec_id, 'paid', user, amount=amount, receipt_notes=notes)
        if out.get('success'):
            db.commit()
        return out
    finally:
        db.close()

