def api_fee_reset_pending(data, user):
    source = (data.get('source') or '').strip()
    rec_id = int(data.get('id') or 0)
    reason = (data.get('reason') or '').strip()
    if rec_id <= 0 or not source:
        return {'success': False, 'error': 'source and id required'}
    meta = _fee_source_meta(source)
    if not meta:
        return {'success': False, 'error': 'Unsupported source'}
    db = get_db()
    try:
        row = db.execute(f"SELECT * FROM {meta['table']} WHERE {meta['id_col']} = ?", [rec_id]).fetchone()
        if not row:
            return {'success': False, 'error': 'Record not found'}
        old = dict(row)
        db.execute(f"""UPDATE {meta['table']} SET
            fee_status='pending',
            fee_paid_at=NULL, fee_paid_by='',
            fee_waived_at=NULL, fee_waived_by='',
            fee_waiver_reason='',
            fee_released=0, fee_released_at=NULL, fee_released_by_logic='correction_reset'
            WHERE {meta['id_col']}=?""", [rec_id])
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('fee_reset_pending', ?, ?, ?)",
                   [rec_id, user, json.dumps({'source': source, 'previous_fee_status': _fee_state(old), 'reason': reason})])
        db.commit()
        return {'success': True}
    finally:
        db.close()

def _fee_cash_in_hand(db, actor=''):
    if actor:
        collected = db.execute("SELECT COALESCE(SUM(fee_amount),0) s FROM fee_collections WHERE fee_status='paid' AND paid_by = ?", [actor]).fetchone()['s']
        outflow = db.execute("""
            SELECT COALESCE(SUM(amount),0) s
            FROM fee_distributions
            WHERE action_type IN ('handed_over','withdrawn')
              AND COALESCE(NULLIF(handed_over_by,''), entered_by) = ?
        """, [actor]).fetchone()['s']
    else:
        collected = db.execute("SELECT COALESCE(SUM(fee_amount),0) s FROM fee_collections WHERE fee_status='paid'").fetchone()['s']
        outflow = db.execute("SELECT COALESCE(SUM(amount),0) s FROM fee_distributions WHERE action_type IN ('handed_over','withdrawn')").fetchone()['s']
    return float(collected or 0) - float(outflow or 0)

def _next_fee_receipt_no(db):
    v = db.execute("SELECT COUNT(*) c FROM fee_distributions WHERE receipt_number != ''").fetchone()['c']
    return f"FDR-{datetime.now().strftime('%Y%m%d')}-{int(v)+1:04d}"

def _fee_distribution_effective_actor(row):
    if not row:
        return ''
    return ((row.get('handed_over_by') or '').strip() or (row.get('entered_by') or '').strip())

def _fee_distribution_outflow_amount(row):
    if not row:
        return 0.0
    try:
        amount = float(row.get('amount') or 0)
    except Exception:
        amount = 0.0
    return amount if (row.get('action_type') or '').strip().lower() in ('handed_over', 'withdrawn') else 0.0

def _validate_fee_distribution_fields(data, default_date=''):
    wing = (data.get('wing') or '').strip().lower()
    action = (data.get('action_type') or '').strip().lower()
    notes = (data.get('notes') or '').strip()
    received_by = (data.get('received_by') or '').strip()
    d = (data.get('distribution_date') or '').strip()
    try:
        amount = float(data.get('amount') or 0)
    except Exception:
        return {'success': False, 'error': 'amount must be greater than 0'}
    if wing not in ('community_wing', 'diplomatic'):
        return {'success': False, 'error': 'wing must be community_wing or diplomatic'}
    if action not in ('allocated', 'handed_over', 'withdrawn', 'adjusted'):
        return {'success': False, 'error': 'Invalid action_type'}
    if amount <= 0:
        return {'success': False, 'error': 'amount must be greater than 0'}
    if d and not re.fullmatch(r'\d{4}-\d{2}-\d{2}', d):
        return {'success': False, 'error': 'distribution_date must be YYYY-MM-DD'}
    if action == 'handed_over' and not received_by:
        return {'success': False, 'error': 'received_by is required for handover'}
    dist_date = d or (default_date or datetime.now().strftime('%Y-%m-%d'))
    return {
        'success': True,
        'values': {
            'wing': wing,
            'action_type': action,
            'amount': amount,
            'distribution_date': dist_date,
            'received_by': received_by,
            'notes': notes,
        }
    }

def api_fee_settlement_entry(data, user):
    validated = _validate_fee_distribution_fields(data)
    if not validated.get('success'):
        return validated
    vals = validated['values']
    wing = vals['wing']
    action = vals['action_type']
    amount = vals['amount']
    notes = vals['notes']
    received_by = vals['received_by']
    handed_over_by = (data.get('handed_over_by') or '').strip() or user

    db = get_db()
    try:
        if action in ('handed_over', 'withdrawn'):
            cash = _fee_cash_in_hand(db, handed_over_by)
            if amount > cash + 1e-9:
                return {'success': False, 'error': f'Insufficient cash in hand. Available: {cash:.2f} KWD'}
        receipt_no = _next_fee_receipt_no(db) if action == 'handed_over' else ''
        dist_date = vals['distribution_date']
        cur = db.execute("""
            INSERT INTO fee_distributions (
                distribution_date, amount, currency, wing, action_type,
                handed_over_by, received_by, entered_by, notes, receipt_number,
                created_at, updated_at
            ) VALUES (?, ?, 'KWD', ?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
        """, [dist_date, amount, wing, action, handed_over_by, received_by, user, notes, receipt_no])
        dist_id = cur.lastrowid
        db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('fee_distribution_entry', ?, ?, ?)",
                   [dist_id, user, json.dumps({'wing': wing, 'action_type': action, 'amount': amount, 'received_by': received_by, 'receipt_number': receipt_no, 'distribution_date': dist_date, 'handed_over_by': handed_over_by, 'notes': notes})])
        db.commit()
        return {'success': True, 'id': dist_id, 'receipt_number': receipt_no}
    finally:
        db.close()

def api_fee_settlement_update(data, user):
    reason = (data.get('correction_reason') or data.get('edit_reason') or '').strip()
    if not reason:
        return {'success': False, 'error': 'correction reason is required'}
    try:
        dist_id = int(str(data.get('id', 0) or 0).strip())
    except Exception:
        dist_id = 0
    if dist_id <= 0:
        return {'success': False, 'error': 'Valid settlement row id is required'}

    db = get_db()
    try:
        row = db.execute("SELECT * FROM fee_distributions WHERE id = ?", [dist_id]).fetchone()
        if not row:
            return {'success': False, 'error': 'Settlement row not found'}
        old_row = dict(row)
        validated = _validate_fee_distribution_fields(data, default_date=(old_row.get('distribution_date') or '').strip())
        if not validated.get('success'):
            return validated
        vals = validated['values']
        actor = _fee_distribution_effective_actor(old_row)
        available_cash = _fee_cash_in_hand(db, actor) + _fee_distribution_outflow_amount(old_row)
        if vals['action_type'] in ('handed_over', 'withdrawn') and vals['amount'] > available_cash + 1e-9:
            return {'success': False, 'error': f'Insufficient cash in hand for this correction. Available: {available_cash:.2f} KWD'}

        db.execute("""
            UPDATE fee_distributions
            SET wing = ?,
                action_type = ?,
                amount = ?,
                distribution_date = ?,
                received_by = ?,
                notes = ?,
                edited_by = ?,
                edited_at = CURRENT_TIMESTAMP,
                edit_reason = ?,
                updated_at = CURRENT_TIMESTAMP
            WHERE id = ?
        """, [
            vals['wing'],
            vals['action_type'],
            vals['amount'],
            vals['distribution_date'],
            vals['received_by'],
            vals['notes'],
            user,
            reason,
            dist_id
        ])
        new_row = dict(db.execute("SELECT * FROM fee_distributions WHERE id = ?", [dist_id]).fetchone())
        audit_details = {
            'correction_reason': reason,
            'old_values': old_row,
            'new_values': new_row
        }
        db.execute(
            "INSERT INTO audit_log (action, record_id, user, details) VALUES ('fee_distribution_edit', ?, ?, ?)",
            [dist_id, user, json.dumps(audit_details, default=str)]
        )
        db.commit()
        return {'success': True, 'id': dist_id, 'receipt_number': old_row.get('receipt_number') or '', 'row': new_row}
    finally:
        db.close()

def _office_expense_category_label(value):
    key = (value or '').strip().lower()
    labels = {
        'tea_refreshments': 'Tea / Refreshments',
        'stationery': 'Stationery',
        'photocopy': 'Photocopy',
        'printer_supplies': 'Printer Supplies',
        'office_purchase': 'Office Purchase',
        'maintenance': 'Maintenance',
        'transport_misc': 'Transport / Miscellaneous',
        'other': 'Other'
    }
    return labels.get(key, ((value or '').replace('_', ' ').title() or '-'))

def _office_expense_payment_mode_label(value):
    key = (value or '').strip().lower()
    labels = {
        'cash': 'Cash',
        'card': 'Card',
        'bank_transfer': 'Bank Transfer',
        'other': 'Other'
    }
    return labels.get(key, ((value or '').replace('_', ' ').title() or '-'))

def _next_office_expense_record_no(db):
    v = db.execute("SELECT COUNT(*) c FROM office_expenses WHERE record_number != ''").fetchone()['c']
    return f"OEL-{datetime.now().strftime('%Y%m%d')}-{int(v)+1:04d}"

def _validate_office_expense_fields(data, default_date=''):
    expense_date = (data.get('expense_date') or '').strip() or (default_date or datetime.now().strftime('%Y-%m-%d'))
    category = (data.get('category') or '').strip().lower()
    description = (data.get('description') or '').strip()
    vendor_name = (data.get('vendor_name') or '').strip()
    payment_mode = (data.get('payment_mode') or '').strip().lower() or 'cash'
    bill_number = (data.get('bill_number') or '').strip()
    remarks = (data.get('remarks') or '').strip()
    try:
        amount = float(data.get('amount') or 0)
    except Exception:
        amount = 0
    if not re.fullmatch(r'\d{4}-\d{2}-\d{2}', expense_date):
        return {'success': False, 'error': 'expense_date must be YYYY-MM-DD'}
    if not category:
        return {'success': False, 'error': 'category is required'}
    if not description:
        return {'success': False, 'error': 'description is required'}
    if amount <= 0:
        return {'success': False, 'error': 'amount must be greater than 0'}
    if payment_mode not in ('cash', 'card', 'bank_transfer', 'other'):
        return {'success': False, 'error': 'Invalid payment_mode'}
    return {
        'success': True,
        'values': {
            'expense_date': expense_date,
            'category': category,
            'description': description,
            'vendor_name': vendor_name,
            'amount': amount,
            'payment_mode': payment_mode,
            'bill_number': bill_number,
            'remarks': remarks
        }
    }

def _office_expense_approved_total(db, exclude_id=0):
    if exclude_id:
        row = db.execute(
            "SELECT COALESCE(SUM(amount),0) s FROM office_expenses WHERE status='approved' AND id != ?",
            [exclude_id]
        ).fetchone()
    else:
        row = db.execute("SELECT COALESCE(SUM(amount),0) s FROM office_expenses WHERE status='approved'").fetchone()
    return float((row['s'] if row else 0) or 0)

def _office_expense_approval_available_cash(db, exclude_id=0):
    return float(_fee_cash_in_hand(db, '')) - _office_expense_approved_total(db, exclude_id=exclude_id)

def api_office_expense_create(data, user):
    validated = _validate_office_expense_fields(data)
    if not validated.get('success'):
        return validated
    vals = validated['values']
    db = get_db()
    try:
        record_number = _next_office_expense_record_no(db)
        cur = db.execute("""
            INSERT INTO office_expenses (
                record_number, expense_date, category, description, vendor_name, amount,
                payment_mode, bill_number, remarks, status, entered_by, created_at, updated_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending_approval', ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
        """, [
            record_number,
            vals['expense_date'],
            vals['category'],
            vals['description'],
            vals['vendor_name'],
            vals['amount'],
            vals['payment_mode'],
            vals['bill_number'],
            vals['remarks'],
            user
        ])
        expense_id = cur.lastrowid
        db.execute(
            "INSERT INTO audit_log (action, record_id, user, details) VALUES ('office_expense_created', ?, ?, ?)",
            [expense_id, user, json.dumps({'record_number': record_number, **vals}, default=str)]
        )
        db.commit()
        return {'success': True, 'id': expense_id, 'record_number': record_number}
    finally:
        db.close()

def api_office_expense_report(params, user):
    db = get_db()
    try:
        summary = dict(db.execute("""
            SELECT
                COALESCE(SUM(CASE WHEN status='approved' THEN amount ELSE 0 END),0) approved_total,
                COALESCE(SUM(CASE WHEN status='pending_approval' THEN amount ELSE 0 END),0) pending_total,
                COALESCE(SUM(CASE WHEN status='rejected' THEN amount ELSE 0 END),0) rejected_total,
                SUM(CASE WHEN status='approved' THEN 1 ELSE 0 END) approved_count,
                SUM(CASE WHEN status='pending_approval' THEN 1 ELSE 0 END) pending_count,
                SUM(CASE WHEN status='rejected' THEN 1 ELSE 0 END) rejected_count
            FROM office_expenses
        """).fetchone())
        raw_cash_in_hand = float(_fee_cash_in_hand(db, ''))
        approved_total = float(summary.get('approved_total') or 0)
        summary['raw_cash_in_hand'] = raw_cash_in_hand
        summary['net_cash_available'] = raw_cash_in_hand - approved_total
        rows = [dict(r) for r in db.execute("""
            SELECT *
            FROM office_expenses
            ORDER BY date(COALESCE(NULLIF(expense_date,''), created_at)) DESC, id DESC
            LIMIT 200
        """).fetchall()]
        for row in rows:
            row['category_label'] = _office_expense_category_label(row.get('category'))
            row['payment_mode_label'] = _office_expense_payment_mode_label(row.get('payment_mode'))
        return {'success': True, 'summary': summary, 'rows': rows}
    finally:
        db.close()

def api_office_expense_decision(data, user):
    try:
        expense_id = int(str(data.get('id', 0) or 0).strip())
    except Exception:
        expense_id = 0
    decision = (data.get('decision') or '').strip().lower()
    approval_notes = (data.get('approval_notes') or '').strip()
    if expense_id <= 0:
        return {'success': False, 'error': 'Valid expense id is required'}
    if decision not in ('approved', 'rejected'):
        return {'success': False, 'error': 'decision must be approved or rejected'}
    if not approval_notes:
        return {'success': False, 'error': 'approval notes are required'}

    db = get_db()
    try:
        row = db.execute("SELECT * FROM office_expenses WHERE id = ?", [expense_id]).fetchone()
        if not row:
            return {'success': False, 'error': 'Expense record not found'}
        old_row = dict(row)
        if decision == 'approved':
            available_cash = _office_expense_approval_available_cash(db, exclude_id=expense_id)
            try:
                amount = float(old_row.get('amount') or 0)
            except Exception:
                amount = 0
            if amount > available_cash + 1e-9:
                return {'success': False, 'error': f'Insufficient available balance. Available for approved office expenses: {available_cash:.2f} KWD'}
        db.execute("""
            UPDATE office_expenses
            SET status = ?,
                approved_by = ?,
                approved_at = CURRENT_TIMESTAMP,
                approval_notes = ?,
                updated_at = CURRENT_TIMESTAMP
            WHERE id = ?
        """, [decision, user, approval_notes, expense_id])
        new_row = dict(db.execute("SELECT * FROM office_expenses WHERE id = ?", [expense_id]).fetchone())
        action = 'office_expense_approved' if decision == 'approved' else 'office_expense_rejected'
        db.execute(
            "INSERT INTO audit_log (action, record_id, user, details) VALUES (?, ?, ?, ?)",
            [action, expense_id, user, json.dumps({'old_values': old_row, 'new_values': new_row, 'approval_notes': approval_notes}, default=str)]
        )
        db.commit()
        return {'success': True, 'id': expense_id, 'row': new_row}
    finally:
        db.close()

def api_office_expense_update(data, user):
    reason = (data.get('correction_reason') or data.get('edit_reason') or '').strip()
    if not reason:
        return {'success': False, 'error': 'correction reason is required'}
    try:
        expense_id = int(str(data.get('id', 0) or 0).strip())
    except Exception:
        expense_id = 0
    if expense_id <= 0:
        return {'success': False, 'error': 'Valid expense id is required'}

