# ═══════════════════════════════════════════════════════════════
# OPERATOR_SPECIAL FEE VIEW ADJUSTMENT
# Presentation-layer only. Does NOT change stored data.
# operator_special sees ONLY collections from cutoff date onward.
# Any collection before that date is treated as zero.
# Allocation/payment figures remain real values (no synthetic split logic).
# Admin always sees real values.
# ═══════════════════════════════════════════════════════════════
_OP_SPECIAL_FEE_CUTOFF = '2026-04-02'

def _is_operator_special(user):
    """Check if the user dict indicates operator_special role."""
    if not user:
        return False
    return (user.get('role') or '') == 'operator_special'

def _op_special_before_cutoff(date_str):
    """Return True if date is before the operator_special visibility cutoff."""
    if not date_str:
        return True  # no date = treat as before cutoff
    day = str(date_str).strip()[:10]
    return day < _OP_SPECIAL_FEE_CUTOFF

def _op_special_round(value):
    """Round a monetary value to whole number for operator_special display."""
    try:
        return int(Decimal(str(value or 0)).quantize(Decimal('1'), rounding=ROUND_HALF_UP))
    except Exception:
        return int(Decimal('0').quantize(Decimal('1'), rounding=ROUND_HALF_UP))

def _op_special_even_display_total(actual_total):
    """
    Operator-special display rule:
    1) take half of actual total
    2) force to an even integer by rounding upward when needed
    """
    try:
        a = float(actual_total or 0)
    except Exception:
        a = 0.0
    half = math.ceil(a / 2.0)
    if int(half) % 2 != 0:
        half += 1
    return float(int(max(half, 0)))

def _fallback_diplomatic_from_collected(actual_total):
    """Fallback diplomatic amount when no explicit diplomatic allocation exists."""
    return _op_special_even_display_total(actual_total) / 2.0

def api_fee_report(params):
    db = get_db()
    try:
        where = ["1=1"]
        q = []
        status = (params.get('status') or '').strip().lower()
        if status in ('paid', 'waived', 'pending'):
            where.append("fee_status = ?")
            q.append(status)
        start_date = (params.get('from') or '').strip()
        end_date = (params.get('to') or '').strip()
        if re.fullmatch(r'\d{4}-\d{2}-\d{2}', start_date):
            where.append("date(COALESCE(paid_at, waived_at, created_at)) >= date(?)")
            q.append(start_date)
        if re.fullmatch(r'\d{4}-\d{2}-\d{2}', end_date):
            where.append("date(COALESCE(paid_at, waived_at, created_at)) <= date(?)")
            q.append(end_date)
        s = (params.get('search') or '').strip()
        if s:
            sk = f"%{s}%"
            where.append("(passport_number LIKE ? OR tracking_or_reference LIKE ? OR source_table LIKE ? OR CAST(source_id AS TEXT) = ?)")
            q.extend([sk, sk, sk, s])
        rows = [dict(r) for r in db.execute(
            f"""SELECT id, source_table, source_id, passport_number, tracking_or_reference,
                       fee_amount, fee_currency, fee_status, paid_at, paid_by,
                       waived_at, waiver_approved_by, waiver_reason, receipt_notes, created_at
                FROM fee_collections
                WHERE {' AND '.join(where)}
                ORDER BY id DESC
                LIMIT 1000""", q).fetchall()]
        totals = db.execute(f"""
            SELECT
              COALESCE(SUM(CASE WHEN fee_status='paid' THEN fee_amount ELSE 0 END),0) collected_total,
              COALESCE(SUM(CASE WHEN fee_status='waived' THEN fee_amount ELSE 0 END),0) waived_total,
              SUM(CASE WHEN fee_status='paid' THEN 1 ELSE 0 END) paid_count,
              SUM(CASE WHEN fee_status='waived' THEN 1 ELSE 0 END) waived_count
            FROM fee_collections
            WHERE {' AND '.join(where)}
        """, q).fetchone()
        return {'success': True, 'rows': rows, 'totals': dict(totals)}
    finally:
        db.close()

def api_fee_statement(params, user):
    db = get_db()
    started_at = time.perf_counter()
    try:
        search = (params.get('search') or '').strip()
        status = (params.get('status') or '').strip().lower()
        actor = (params.get('collected_by') or '').strip()
        dfrom = (params.get('from') or '').strip()
        dto = (params.get('to') or '').strip()

        where = ["1=1"]
        q = []
        if status in ('paid', 'waived', 'pending'):
            where.append("f.fee_status = ?")
            q.append(status)
        if re.fullmatch(r'\d{4}-\d{2}-\d{2}', dfrom):
            where.append("date(COALESCE(f.paid_at,f.waived_at,f.created_at)) >= date(?)")
            q.append(dfrom)
        if re.fullmatch(r'\d{4}-\d{2}-\d{2}', dto):
            where.append("date(COALESCE(f.paid_at,f.waived_at,f.created_at)) <= date(?)")
            q.append(dto)
        if actor:
            where.append("(f.paid_by = ? OR f.waiver_approved_by = ?)")
            q.extend([actor, actor])
        if search:
            s = f"%{search}%"
            where.append("(f.passport_number LIKE ? OR f.tracking_or_reference LIKE ? OR CAST(f.source_id AS TEXT)=?)")
            q.extend([s, s, search])

        summary = db.execute("""
            SELECT
              (SELECT COUNT(*) FROM evacuees) + (SELECT COUNT(*) FROM iraq_applicants) + (SELECT COUNT(*) FROM iraq_public_submissions) AS total_applicants,
              (SELECT COUNT(*) FROM evacuees WHERE COALESCE(fee_status,'pending')='paid')
                + (SELECT COUNT(*) FROM iraq_applicants WHERE COALESCE(fee_status,'pending')='paid')
                + (SELECT COUNT(*) FROM iraq_public_submissions WHERE COALESCE(fee_status,'pending')='paid') AS paid_cases,
              (SELECT COUNT(*) FROM evacuees WHERE COALESCE(fee_status,'pending')='waived')
                + (SELECT COUNT(*) FROM iraq_applicants WHERE COALESCE(fee_status,'pending')='waived')
                + (SELECT COUNT(*) FROM iraq_public_submissions WHERE COALESCE(fee_status,'pending')='waived') AS waived_cases,
              (SELECT COUNT(*) FROM evacuees WHERE COALESCE(fee_status,'pending')='pending')
                + (SELECT COUNT(*) FROM iraq_applicants WHERE COALESCE(fee_status,'pending')='pending')
                + (SELECT COUNT(*) FROM iraq_public_submissions WHERE COALESCE(fee_status,'pending')='pending') AS pending_cases
        """).fetchone()

        amounts = db.execute(f"""
            SELECT
              COALESCE(SUM(CASE WHEN f.fee_status='paid' THEN f.fee_amount ELSE 0 END),0) total_collected,
              COALESCE(SUM(CASE WHEN f.fee_status='waived' THEN f.fee_amount ELSE 0 END),0) total_waived,
              COALESCE(SUM(CASE WHEN f.fee_status='paid' AND date(COALESCE(f.paid_at,f.created_at))=date('now') THEN f.fee_amount ELSE 0 END),0) today_collected,
              COUNT(DISTINCT CASE WHEN f.fee_status IN ('paid','waived') AND date(COALESCE(f.paid_at,f.waived_at,f.created_at))=date('now')
                    THEN f.source_table||':'||f.source_id ELSE NULL END) today_people_served
            FROM fee_collections f
            WHERE {' AND '.join(where)}
        """, q).fetchone()
        fee_activity_rows = _attach_fee_applicant_names(db, db.execute(f"""
            SELECT
              f.id, COALESCE(f.paid_at,f.waived_at,f.created_at) action_at,
              f.source_table, f.source_id, f.passport_number, f.tracking_or_reference,
              f.fee_status, f.fee_amount, f.fee_currency,
              f.paid_by, f.waiver_approved_by, f.waiver_reason, f.receipt_notes,
              CASE WHEN f.fee_status IN ('paid','waived') THEN 1 ELSE 0 END print_released
            FROM fee_collections f
            WHERE {' AND '.join(where)}
            ORDER BY f.id DESC
            LIMIT 2000
        """, q).fetchall())

        settlement = api_fee_settlement_report(params, user)
        result = {
            'success': True,
            'summary': {**dict(summary), **dict(amounts), **(settlement.get('summary') or {})},
            'daily': settlement.get('daily') or [],
            'rows': settlement.get('rows') or [],
            'fee_activity_rows': fee_activity_rows
        }

        # operator_special: apply visibility cutoff only.
        # Do not recompute/overwrite summary totals that already come from settlement logic.
        if _is_operator_special(user):
            cdt = _OP_SPECIAL_FEE_CUTOFF
            # Zero out daily rows before cutoff only (display constraint).
            for d in result['daily']:
                day = d.get('day', '')
                if _op_special_before_cutoff(day):
                    d['total_collected'] = 0
                    d['community_wing'] = 0
                    d['diplomatic'] = 0
                    d['handed_over'] = 0
                    d['cash_in_hand'] = 0
                    d['collected_amount'] = 0
                    d['waived_amount'] = 0
            s = result['summary']
            # Today's values: zero if before cutoff (display constraint).
            today_str = datetime.now().strftime('%Y-%m-%d')
            if _op_special_before_cutoff(today_str):
                for k in ('today_collected', 'today_people_served', 'today_community_wing',
                          'today_diplomatic', 'today_handovers', 'today_balance'):
                    s[k] = 0

            # Recompute paid/waived/pending case counts from cutoff-visible fee activity only.
            paid_cases = db.execute("""
                SELECT COUNT(DISTINCT source_table||':'||source_id) c
                FROM fee_collections
                WHERE fee_status='paid'
                  AND date(COALESCE(paid_at,created_at)) >= date(?)
            """, [cdt]).fetchone()['c']
            waived_cases = db.execute("""
                SELECT COUNT(DISTINCT source_table||':'||source_id) c
                FROM fee_collections
                WHERE fee_status='waived'
                  AND date(COALESCE(waived_at,created_at)) >= date(?)
            """, [cdt]).fetchone()['c']
            s['paid_cases'] = int(paid_cases or 0)
            s['waived_cases'] = int(waived_cases or 0)
            s['pending_cases'] = max(int(s.get('total_applicants') or 0) - s['paid_cases'] - s['waived_cases'], 0)
            # Hide individual payer rows — operator_special gets aggregate only
            result['fee_activity_rows'] = []
            result['rows'] = settlement.get('rows') or []


        _log_perf_if_slow('/api/fee-statement', started_at, threshold_ms=400, row_count=len(result.get('fee_activity_rows') or []))
        return result
    finally:
        db.close()

# ═══════════════════════════════════════════════════════════════
# WORD DOCUMENT GENERATOR (pure Python, no dependencies)
# ═══════════════════════════════════════════════════════════════
def generate_sitrep_docx(data):
    """Generate a .docx file from SITREP data using pure XML (no python-docx needed)"""
    import zipfile

    def escape_xml(s):
        return (s or '').replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')

    def make_para(text, bold=False, size=22, align='left', space_after=100):
        b_xml = '<w:b/>' if bold else ''
        sz = f'<w:sz w:val="{size}"/><w:szCs w:val="{size}"/>'
        jc = f'<w:jc w:val="{align}"/>' if align != 'left' else ''
        return f'<w:p><w:pPr>{jc}<w:spacing w:after="{space_after}"/><w:rPr>{b_xml}{sz}</w:rPr></w:pPr><w:r><w:rPr>{b_xml}{sz}</w:rPr><w:t xml:space="preserve">{escape_xml(text)}</w:t></w:r></w:p>'

    def make_multiline(text, bold=False, size=22):
        lines = (text or '').split('\n')
        return ''.join(make_para(line, bold, size) for line in lines)

    def make_section(num, title, content):
        return make_para(f'{num}. {title}', bold=True, size=24, space_after=60) + make_multiline(content, size=22)

    def make_table_row(cells, bold=False):
        row_xml = '<w:tr>'
        for cell in cells:
            b = '<w:b/>' if bold else ''
            row_xml += f'<w:tc><w:tcPr><w:tcW w:w="0" w:type="auto"/></w:tcPr><w:p><w:r><w:rPr>{b}<w:sz w:val="22"/></w:rPr><w:t xml:space="preserve">{escape_xml(cell)}</w:t></w:r></w:p></w:tc>'
        row_xml += '</w:tr>'
        return row_xml

    # Build document body
    body = ''
    body += make_para('SITUATION REPORT', bold=True, size=32, align='center', space_after=60)
    body += make_para("PAKISTAN'S MISSION IN KUWAIT", bold=True, size=26, align='center', space_after=200)

    # Header table
    body += '<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="pct"/><w:tblBorders><w:top w:val="single" w:sz="4" w:color="000000"/><w:left w:val="single" w:sz="4" w:color="000000"/><w:bottom w:val="single" w:sz="4" w:color="000000"/><w:right w:val="single" w:sz="4" w:color="000000"/><w:insideH w:val="single" w:sz="4" w:color="000000"/><w:insideV w:val="single" w:sz="4" w:color="000000"/></w:tblBorders></w:tblPr>'
    body += make_table_row(['Country/Region:', data.get('country', 'Kuwait')], bold=False)
    body += make_table_row(['Date & Time of Report:', data.get('date', '')], bold=False)
    body += make_table_row(['Emergency Hotline # of Mission:', data.get('hotline', '')], bold=False)
    body += make_table_row(['Number of Stranded Pakistanis:', data.get('stranded', 'Nil')], bold=False)
    body += '</w:tbl>'
    body += make_para('', size=10)

    body += make_section('1', 'Overall Situation', data.get('situation', ''))
    body += make_para('', size=10)

    # Diaspora Profile
    body += make_para('2. Diaspora Profile', bold=True, size=24, space_after=60)
    body += '<w:tbl><w:tblPr><w:tblW w:w="5000" w:type="pct"/><w:tblBorders><w:top w:val="single" w:sz="4" w:color="000000"/><w:left w:val="single" w:sz="4" w:color="000000"/><w:bottom w:val="single" w:sz="4" w:color="000000"/><w:right w:val="single" w:sz="4" w:color="000000"/><w:insideH w:val="single" w:sz="4" w:color="000000"/><w:insideV w:val="single" w:sz="4" w:color="000000"/></w:tblBorders></w:tblPr>'
    body += make_table_row(['Estimated Number:', data.get('diaspora_num', '101,976')])
    body += make_table_row(['Key Diaspora Locations:', data.get('diaspora_loc', '')])
    body += make_table_row(['Evacuation Requested:', data.get('evac_requested', '')])
    body += make_table_row(['Number of Stranded:', data.get('stranded', 'Nil')])
    body += make_table_row(['Registered with Mission:', data.get('registered', '')])
    body += '</w:tbl>'
    body += make_para('', size=10)

    body += make_section('3', 'Airspace Status',
        f"Airspace: {data.get('airspace', '')}\nAirport Operations: {data.get('airport', '')}\nNOTAM: {data.get('notam', '')}")
    body += make_para('', size=10)

    body += make_section('4', 'Land Routes Status & Options', data.get('land', ''))
    body += make_para('', size=10)

    body += make_section('5', 'Facilitation Measures Taken by Mission', data.get('facilitation', ''))
    body += make_para('', size=10)

    body += make_section('6', 'Coordination with Host Government', data.get('coordination', ''))
    body += make_para('', size=10)

    body += make_para('7. Evacuation Options', bold=True, size=24, space_after=60)
    body += make_para('By Air:', bold=True, size=22, space_after=40)
    body += make_multiline(data.get('evac_air', ''))
    body += make_para('By Land:', bold=True, size=22, space_after=40)
    body += make_multiline(data.get('evac_land', ''))
    body += make_para('', size=10)

    body += make_section('8', 'Status of Evacuation', data.get('evac_status', ''))
    body += make_para('', size=10)

    # Returnees section
    returnees_data = data.get('returnees_status', '')
    if returnees_data:
        body += make_para('8b. Returnees — Pakistan to Kuwait', bold=True, size=24, space_after=60)
        body += make_multiline(returnees_data, size=22)
        body += make_para('', size=10)

    body += make_section('9', 'Risks & Challenges', data.get('risks', ''))
    body += make_para('', size=10)

    body += make_section('10', 'Overall Assessment of the Mission', data.get('assessment', ''))

    # Build the complete OOXML document
    ns = 'xmlns:wpc="http://schemas.microsoft.com/office/word/2010/wordprocessingCanvas" xmlns:mc="http://schemas.openxmlformats.org/markup-compatibility/2006" xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing" xmlns:w10="urn:schemas-microsoft-com:office:word" xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:wne="http://schemas.microsoft.com/office/word/2006/wordml"'

    document_xml = f'''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document {ns}>
<w:body>{body}
<w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440"/></w:sectPr>
</w:body></w:document>'''

    content_types = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
<Default Extension="xml" ContentType="application/xml"/>
<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>
</Types>'''

    rels = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>
</Relationships>'''

    word_rels = '''<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">
</Relationships>'''

    buf = io.BytesIO()
    with zipfile.ZipFile(buf, 'w', zipfile.ZIP_DEFLATED) as zf:
        zf.writestr('[Content_Types].xml', content_types)
        zf.writestr('_rels/.rels', rels)
        zf.writestr('word/_rels/document.xml.rels', word_rels)
        zf.writestr('word/document.xml', document_xml)
    return buf.getvalue()

# ═══════════════════════════════════════════════════════════════
# IRAQ MISSION — TRANSIT VISA REQUEST APIs
# ═══════════════════════════════════════════════════════════════

def api_iraq_stats(user_filter=None, include_visa_stats=True):
    db = get_db()
    where = ""
    params = []
    if user_filter:
        where = " WHERE uploaded_by = ?"
        params = [user_filter]
    total = db.execute(f"SELECT COUNT(*) c FROM iraq_batches{where}", params).fetchone()['c']
    pending = db.execute(f"SELECT COUNT(*) c FROM iraq_batches{where}{' AND' if where else ' WHERE'} status='Pending'", params).fetchone()['c']
    sent = db.execute(f"SELECT COUNT(*) c FROM iraq_batches{where}{' AND' if where else ' WHERE'} status='Sent to MOFA Kuwait'", params).fetchone()['c']
    processed = db.execute(f"SELECT COUNT(*) c FROM iraq_batches{where}{' AND' if where else ' WHERE'} status='Processed'", params).fetchone()['c']
    total_applicants = db.execute(f"SELECT COALESCE(SUM(applicant_count),0) c FROM iraq_batches{where}", params).fetchone()['c']
    result = {'total_batches': total, 'pending': pending, 'sent': sent, 'processed': processed, 'total_applicants': total_applicants}
    # Visa approval stats — only for admin, not exposed to iraq_cwa
    if include_visa_stats:
        awhere = ""
        aparams = []
        if user_filter:
            awhere = " AND b.uploaded_by = ?"
            aparams = [user_filter]
        visa_approved = db.execute(f"SELECT COUNT(*) c FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id=b.id WHERE a.visa_status='KW Transit Approved'{awhere}", aparams).fetchone()['c']
        visa_pending = db.execute(f"SELECT COUNT(*) c FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id=b.id WHERE (a.visa_status='Pending' OR a.visa_status='' OR a.visa_status IS NULL){awhere}", aparams).fetchone()['c']
        visa_rejected = db.execute(f"SELECT COUNT(*) c FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id=b.id WHERE a.visa_status='Rejected'{awhere}", aparams).fetchone()['c']
        result['visa_approved'] = visa_approved
        result['visa_pending'] = visa_pending
        result['visa_rejected'] = visa_rejected
        # KSA approval count: union all three Iraq-related tables (de-duplicate by normalized passport)
        result['ksa_mofa_approved'] = db.execute("""
            SELECT COUNT(*) c FROM (
                SELECT UPPER(REPLACE(REPLACE(TRIM(COALESCE(a.passport_number,'')), ' ', ''), '-', '')) AS pp
                FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id=b.id
                WHERE a.ksa_mofa_status='Approved'""" + awhere + """
                UNION
                SELECT UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport,'')), ' ', ''), '-', '')) AS pp
                FROM evacuees WHERE LOWER(COALESCE(mofa_ksa_status,''))='approved'
                UNION
                SELECT UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', ''), '-', '')) AS pp
                FROM iraq_public_submissions WHERE LOWER(COALESCE(ksa_mofa_status,''))='approved'
            ) combined WHERE pp != ''
        """, aparams).fetchone()['c']
        result['waiting_travel_iraq'] = db.execute(
            f"SELECT COUNT(*) c FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id=b.id WHERE a.movement_status='waiting_iraq'{awhere}",
            aparams).fetchone()['c']
        result['waiting_transit_kw'] = db.execute(
            f"SELECT COUNT(*) c FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id=b.id WHERE a.movement_status='waiting_kw'{awhere}",
            aparams).fetchone()['c']
    db.close()
    return result

def api_iraq_batches(params, user_filter=None):
    db = get_db()
    where_parts = []
    qparams = []
    if user_filter:
        where_parts.append("b.uploaded_by = ?")
        qparams.append(user_filter)
    status_f = params.get('status', '')
    if status_f:
        where_parts.append("b.status = ?")
        qparams.append(status_f)
    search = params.get('search', '').strip()
    if search:
        s = f'%{search}%'
        where_parts.append("""(
            b.letter_number LIKE ? OR b.mofa_reference LIKE ? OR
            EXISTS (
                SELECT 1 FROM iraq_applicants a
                WHERE a.batch_id = b.id AND (
                    a.full_name LIKE ? OR a.passport_number LIKE ? OR
                    a.mobile_number LIKE ? OR a.email_address LIKE ?
                )
            )
        )""")
        qparams.extend([s, s, s, s, s, s])
    where_sql = (' WHERE ' + ' AND '.join(where_parts)) if where_parts else ''
    rows = db.execute(f"SELECT b.* FROM iraq_batches b{where_sql} ORDER BY b.id DESC", qparams).fetchall()
    db.close()
    return [dict(r) for r in rows]

def api_iraq_batch_detail(batch_id, user_filter=None, session_user=None):
    db = get_db()
    started_at = time.perf_counter()
    batch = db.execute("SELECT * FROM iraq_batches WHERE id = ?", [batch_id]).fetchone()
    if not batch:
        db.close()
        return {'error': 'Batch not found'}
    batch = dict(batch)
    if user_filter and batch['uploaded_by'] != user_filter:
        db.close()
        return {'error': 'Access denied'}
    applicants = [dict(rr) for rr in db.execute("SELECT * FROM iraq_applicants WHERE batch_id = ? ORDER BY id", [batch_id]).fetchall()]
    applicant_ids = [row.get('id') for row in applicants]
    nv_links_by_id = bulk_fetch_nv_links_for_records(db, 'iraq_applicants', applicant_ids)
    latest_releases_by_id = bulk_fetch_latest_nv_releases(db, 'iraq_applicants', applicant_ids) if _is_admin_user(session_user) else {}
    applicants = apply_nv_access_fields_bulk(applicants, nv_links_by_id, latest_releases_by_id, session_user, 'iraq_applicants')
    db.close()
    batch['applicants'] = applicants
    _log_perf_if_slow('/api/iraq-batch-detail', started_at, threshold_ms=300, row_count=len(applicants), extra=f"batch_id={batch_id}")
    return batch

def api_iraq_create_batch(data, user):
    db = get_db()
    letter_number = (data.get('letter_number') or '').strip()
    letter_date = (data.get('letter_date') or '').strip()
    applicants = data.get('applicants', [])
    if not letter_number:
        db.close()
        return {'success': False, 'error': 'Letter number is required'}
    if not applicants or len(applicants) == 0:
        db.close()
        return {'success': False, 'error': 'At least one applicant is required'}
    cur = db.execute("""INSERT INTO iraq_batches (letter_number, letter_date, uploaded_by, applicant_count, status)
        VALUES (?, ?, ?, ?, 'Pending')""", [letter_number, letter_date, user, len(applicants)])
    batch_id = cur.lastrowid
    for app in applicants:
        full_name = (app.get('full_name') or '').strip()
        if not full_name:
            continue
        db.execute("""INSERT INTO iraq_applicants (batch_id, full_name, passport_number, nationality, dob, gender, employer, current_location, destination, remarks, mobile_number, email_address, expected_travel_date)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
            [batch_id, full_name,
             (app.get('passport_number') or '').strip(),
             (app.get('nationality') or '').strip(),
             (app.get('dob') or '').strip(),
             (app.get('gender') or '').strip(),
             (app.get('employer') or '').strip(),
             (app.get('current_location') or '').strip(),
             (app.get('destination') or '').strip(),
             (app.get('remarks') or '').strip(),
             (app.get('mobile_number') or '').strip(),
             (app.get('email_address') or '').strip(),
             (app.get('expected_travel_date') or '').strip()])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_batch_create', ?, ?, ?)",
               (batch_id, user, json.dumps({'letter_number': letter_number, 'count': len(applicants)})))
    db.commit()
    db.close()
    return {'success': True, 'batch_id': batch_id, 'applicant_count': len(applicants)}

def api_iraq_batch_update(data, user):
    db = get_db()
    batch_id = data.get('id')
    if not batch_id:
        db.close()
        return {'success': False, 'error': 'Batch ID required'}
    batch = db.execute("SELECT * FROM iraq_batches WHERE id = ?", [batch_id]).fetchone()
    if not batch:
        db.close()
        return {'success': False, 'error': 'Batch not found'}
    updates = []
    params = []
    for field in ['status', 'mofa_reference', 'mofa_sent_date', 'admin_remarks']:
        if field in data:
            updates.append(f"{field} = ?")
            params.append(data[field])
    if data.get('status') and data['status'] in ('Sent to MOFA Kuwait', 'Processed'):
        # Also update all individual applicants
        db.execute("UPDATE iraq_applicants SET individual_status = ? WHERE batch_id = ?", [data['status'], batch_id])
    if data.get('update_individual'):
        app_id = data.get('applicant_id')
        app_status = data.get('individual_status')
        if app_id and app_status:
            db.execute("UPDATE iraq_applicants SET individual_status = ? WHERE id = ? AND batch_id = ?",
                       [app_status, app_id, batch_id])
    if updates:
        params.append(batch_id)
        db.execute(f"UPDATE iraq_batches SET {', '.join(updates)} WHERE id = ?", params)
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_batch_update', ?, ?, ?)",
               (batch_id, user, json.dumps(data)))
    db.commit()
    db.close()
    return {'success': True, 'id': batch_id}

def api_iraq_export_csv(params, user_filter=None):
    db = get_db()
    where_parts = ["1=1"]
    qparams = []
    if user_filter:
        where_parts.append("b.uploaded_by = ?")
        qparams.append(user_filter)
    status_f = params.get('filter', '')
    if status_f:
        where_parts.append("b.status = ?")
        qparams.append(status_f)
    batch_id = params.get('batch_id', '')
    if batch_id:
        where_parts.append("b.id = ?")
        qparams.append(int(batch_id))
    rows = db.execute(f"""SELECT a.*, b.letter_number, b.letter_date, b.status as batch_status,
        b.mofa_reference, b.mofa_sent_date, b.uploaded_by
        FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id = b.id
        WHERE {' AND '.join(where_parts)} ORDER BY b.id DESC, a.id""", qparams).fetchall()
    rows = [dict(r) for r in rows]
    db.close()
    output = io.StringIO()
    writer = csv.writer(output)
    writer.writerow(['S.No', 'Batch ID', 'Letter Number', 'Letter Date', 'Full Name', 'Passport Number',
                     'Nationality', 'Date of Birth', 'Gender', 'Employer', 'Current Location', 'Destination',
                     'Remarks', 'Mobile Number', 'Email Address', 'Expected Travel Date',
                     'Batch Status', 'Individual Status', 'KW Transit Visa', 'MOFA KSA Status', 'Movement',
                     'MOFA Reference', 'MOFA Sent Date', 'Uploaded By'])
    for i, r in enumerate(rows, 1):
        writer.writerow([i, r['batch_id'], r['letter_number'], r['letter_date'],
                        r['full_name'], r['passport_number'], r['nationality'], r['dob'],
                        r['gender'], r['employer'], r['current_location'], r['destination'],
                        r['remarks'], r.get('mobile_number', ''), r.get('email_address', ''), r.get('expected_travel_date', ''),
                        r['batch_status'], r['individual_status'],
                        r.get('visa_status', ''), r.get('ksa_mofa_status', ''), r.get('movement_status', ''),
                        r['mofa_reference'], r['mofa_sent_date'], r['uploaded_by']])
    return output.getvalue()

def import_iraq_csv(csv_text, letter_number, letter_date, user):
    stats = {'imported': 0, 'errors': 0, 'details': []}
    reader = csv.DictReader(io.StringIO(csv_text))
    col_map = {}
    for orig_col in (reader.fieldnames or []):
        cl = orig_col.strip().lower()
        if 'full' in cl and 'name' in cl: col_map[orig_col] = 'full_name'
        elif cl == 'name' or cl == 'full name': col_map[orig_col] = 'full_name'
        elif 'passport' in cl: col_map[orig_col] = 'passport_number'
        elif 'national' in cl: col_map[orig_col] = 'nationality'
        elif 'birth' in cl or 'dob' in cl: col_map[orig_col] = 'dob'
        elif 'gender' in cl or 'sex' in cl: col_map[orig_col] = 'gender'
        elif 'employer' in cl or 'company' in cl: col_map[orig_col] = 'employer'
        elif 'remark' in cl or 'note' in cl: col_map[orig_col] = 'remarks'
        elif 'mobile' in cl or 'phone' in cl or 'cell' in cl: col_map[orig_col] = 'mobile_number'
        elif 'email' in cl or 'e-mail' in cl or 'e_mail' in cl: col_map[orig_col] = 'email_address'
        elif 'travel' in cl and 'date' in cl: col_map[orig_col] = 'expected_travel_date'
        elif 'expected' in cl: col_map[orig_col] = 'expected_travel_date'
    applicants = []
    row_num = 0
    for row in reader:
        row_num += 1
        try:
            rec = {}
            for orig_col, field in col_map.items():
                val = row.get(orig_col, '').strip()
                if val:
                    rec[field] = val
            full_name = rec.get('full_name', '').strip()
            if not full_name:
                stats['errors'] += 1
                stats['details'].append(f"Row {row_num}: Missing name, skipped")
                continue
            applicants.append(rec)
            stats['imported'] += 1
            stats['details'].append(f"Row {row_num}: {full_name} — added")
        except Exception as e:
            stats['errors'] += 1
            stats['details'].append(f"Row {row_num}: Error — {str(e)}")
    if applicants:
        result = api_iraq_create_batch({
            'letter_number': letter_number,
            'letter_date': letter_date,
            'applicants': applicants
        }, user)
        stats['batch_id'] = result.get('batch_id')
    return stats

def api_iraq_bulk_visa_approval(csv_text, new_status, user):
    """Bulk update visa_status for Iraq mission applicants by passport; also matches Iraq public (MOFA KW) intake by passport."""
    stats = {'approved': 0, 'not_found': 0, 'already_done': 0, 'errors': 0, 'iraq_public_matched': 0, 'details': []}
    reader = csv.DictReader(io.StringIO(csv_text))
    # Auto-map columns
    col_map = {}
    for orig_col in (reader.fieldnames or []):
        cl = orig_col.strip().lower()
        if 'passport' in cl: col_map[orig_col] = 'passport'
        elif 'name' in cl and 'file' not in cl: col_map[orig_col] = 'name'
    if 'passport' not in col_map.values():
        return {'approved': 0, 'not_found': 0, 'already_done': 0, 'errors': 1, 'iraq_public_matched': 0,
                'details': ['Could not find a Passport column in CSV']}
    db = get_db()
    now = datetime.now().strftime('%Y-%m-%d')
    row_num = 0
    for row in reader:
        row_num += 1
        try:
            rec = {}
            for orig_col, field in col_map.items():
                val = row.get(orig_col, '').strip()
                if val: rec[field] = val
            passport = re.sub(r'[\s\-]+', '', (rec.get('passport', '') or '').strip().upper())
            name = rec.get('name', '').strip()
            if not passport:
                stats['errors'] += 1
                stats['details'].append(f"Row {row_num}: No passport, skipped")
                continue
            existing = db.execute(
                "SELECT a.id, a.full_name, a.passport_number, a.visa_status, a.batch_id FROM iraq_applicants a WHERE UPPER(REPLACE(REPLACE(TRIM(COALESCE(a.passport_number,'')), ' ', ''), '-', '')) = ?",
                [passport]).fetchone()
            if existing:
                if existing['visa_status'] == new_status:
                    stats['already_done'] += 1
                    stats['details'].append(f"Row {row_num}: {existing['full_name']} ({passport}) — already {new_status}")
                    continue
                db.execute("UPDATE iraq_applicants SET visa_status = ?, visa_approved_date = ? WHERE id = ?",
                           [new_status, now if new_status == 'KW Transit Approved' else '', existing['id']])
                db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_visa_approval', ?, ?, ?)",
                           (existing['id'], user, f"Visa {new_status} for {existing['full_name']} ({passport})"))
                stats['approved'] += 1
                stats['details'].append(f"Row {row_num}: {existing['full_name']} ({passport}) — {new_status} ✓ (mission batch)")
                continue
            pub = db.execute(
                """SELECT id, full_name, passport_number FROM iraq_public_submissions
                   WHERE UPPER(REPLACE(REPLACE(passport_number, ' ', ''), '-', '')) = ?""",
                [passport]
            ).fetchone()
            if not pub:
                stats['not_found'] += 1
                stats['details'].append(f"Row {row_num}: {name} ({passport}) — NOT FOUND (mission or Iraq public)")
                continue
            target_decision = 'Approved' if new_status == 'KW Transit Approved' else 'Rejected'
            last_dec = db.execute(
                """SELECT decision FROM iraq_applicant_decisions WHERE public_submission_id = ?
                   ORDER BY id DESC LIMIT 1""", [pub['id']]
            ).fetchone()
            cur_dec = (last_dec['decision'] if last_dec else '') or 'Pending'
            if cur_dec == target_decision:
                stats['already_done'] += 1
                stats['details'].append(f"Row {row_num}: {pub['full_name']} ({passport}) — Iraq public already {target_decision}")
                continue
            db.execute("""INSERT INTO iraq_applicant_decisions
                (public_submission_id, decision, decision_date, remarks, decided_by)
                VALUES (?, ?, ?, ?, ?)""",
                [pub['id'], target_decision, now, 'Bulk visa CSV upload', user])
            db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_visa_decision_csv', ?, ?, ?)",
                       (pub['id'], user, json.dumps({'passport': passport, 'decision': target_decision})))
            # Check if Iraq public submission now has both KW + KSA approval
            if target_decision == 'Approved':
                _queue_iraq_public_final_approval_if_ready(db, pub['id'], changed_by=user)
            stats['approved'] += 1
            stats['iraq_public_matched'] += 1
            stats['details'].append(f"Row {row_num}: {pub['full_name']} ({passport}) — {target_decision} ✓ (Iraq public / MOFA KW)")
        except Exception as e:
            stats['errors'] += 1
            stats['details'].append(f"Row {row_num}: Error — {str(e)}")
    db.commit()
    db.execute("INSERT INTO audit_log (action, user, details) VALUES (?, ?, ?)",
               ('iraq_bulk_visa_approval', user,
                f"{new_status}: {stats['approved']}, public {stats['iraq_public_matched']}, not found {stats['not_found']}, already {stats['already_done']}"))
    db.commit(); db.close()
    return stats

def api_iraq_update_individual_visa(data, user):
    """Update KW transit visa, MOFA KSA status, and/or movement bucket for one Iraq applicant (Iraq Transit Visas)."""
    db = get_db()
    app_id = data.get('applicant_id')
    if not app_id:
        db.close()
        return {'success': False, 'error': 'Applicant ID required'}
    if not db.execute("SELECT id FROM iraq_applicants WHERE id = ?", [app_id]).fetchone():
        db.close()
        return {'success': False, 'error': 'Applicant not found'}
    parts, vals = [], []
    if 'visa_status' in data:
        new_status = (data.get('visa_status') or '').strip()
        if not new_status:
            db.close()
            return {'success': False, 'error': 'Visa status required when updating visa'}
        now = datetime.now().strftime('%Y-%m-%d')
        parts.extend(["visa_status = ?", "visa_approved_date = ?"])
        vals.extend([new_status, now if new_status == 'KW Transit Approved' else ''])
    if 'ksa_mofa_status' in data:
        k = (data.get('ksa_mofa_status') or 'Pending').strip()
        if k not in ('Pending', 'Approved', 'Rejected'):
            db.close()
            return {'success': False, 'error': 'Invalid MOFA KSA status'}
        parts.append("ksa_mofa_status = ?")
        vals.append(k)
    if 'movement_status' in data:
        m = (data.get('movement_status') or '').strip()
        if m not in ('', 'waiting_iraq', 'waiting_kw'):
            db.close()
            return {'success': False, 'error': 'Invalid movement status'}
        parts.append("movement_status = ?")
        vals.append(m)
    if not parts:
        db.close()
        return {'success': False, 'error': 'No fields to update'}
    vals.append(app_id)
    db.execute(f"UPDATE iraq_applicants SET {', '.join(parts)} WHERE id = ?", vals)
    detail = {k: data.get(k) for k in ('visa_status', 'ksa_mofa_status', 'movement_status') if k in data}
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_visa_individual', ?, ?, ?)",
               (app_id, user, json.dumps(detail)))
    db.commit(); db.close()
    return {'success': True, 'id': app_id}

def api_iraq_search_applicants(params, user_filter=None, include_visa=False):
    """Search individual applicants across all batches. For CWA: filtered by uploaded_by, no visa info."""
    db = get_db()
    search = (params.get('search', '') or '').strip()
    status = params.get('status', '')
    where_parts = ["1=1"]
    qparams = []
    if user_filter:
        where_parts.append("b.uploaded_by = ?")
        qparams.append(user_filter)
    if search:
        s = f"%{search}%"
        where_parts.append("(a.full_name LIKE ? OR UPPER(a.passport_number) LIKE UPPER(?) OR a.mobile_number LIKE ? OR a.email_address LIKE ?)")
        qparams.extend([s, s, s, s])
    if status:
        where_parts.append("b.status = ?")
        qparams.append(status)
    rows = db.execute(f"""SELECT a.id, a.full_name, a.passport_number, a.nationality, a.dob, a.gender,
        a.employer, a.current_location, a.destination, a.remarks,
        a.mobile_number, a.email_address, a.expected_travel_date,
        a.individual_status, {'a.visa_status, a.visa_approved_date,' if include_visa else ''}
        a.batch_id, b.letter_number, b.letter_date, b.status as batch_status,
        b.mofa_reference, b.upload_timestamp
        FROM iraq_applicants a JOIN iraq_batches b ON a.batch_id = b.id
        WHERE {' AND '.join(where_parts)} ORDER BY a.id DESC""", qparams).fetchall()
    db.close()
    return [dict(r) for r in rows]

# ═══════════════════════════════════════════════════════════════
# IRAQ PUBLIC INTAKE WORKFLOW (SEPARATE PIPELINE)
# ═══════════════════════════════════════════════════════════════
def _new_iraq_public_ref():
    return "IRQ-" + datetime.now().strftime("%Y%m%d") + "-" + uuid.uuid4().hex[:6].upper()

def api_iraq_public_submit(data):
    db = get_db()
    full_name = (data.get('full_name') or '').strip()
    passport_number = (data.get('passport_number') or '').strip().upper()
    cnic = re.sub(r'[^0-9]', '', (data.get('cnic') or '').strip())
    nationality = (data.get('nationality') or '').strip()
    date_of_birth = (data.get('date_of_birth') or '').strip()
    gender = (data.get('gender') or '').strip()
    phone = (data.get('phone') or '').strip()
    whatsapp = (data.get('whatsapp') or '').strip()
    email = (data.get('email') or '').strip()
    current_city = (data.get('current_city') or '').strip()
    employer = (data.get('employer') or '').strip()
    travel_route = (data.get('travel_route') or '').strip()
    travel_purpose = (data.get('travel_purpose') or '').strip()
    if not all([full_name, passport_number, cnic, nationality, date_of_birth, gender, phone, whatsapp, email, current_city, employer, travel_route, travel_purpose]):
        db.close()
        return {'success': False, 'error': 'All form fields are required'}
    if not re.fullmatch(r'\d{13}', cnic):
        db.close()
        return {'success': False, 'error': 'CNIC must be exactly 13 digits'}
    if not re.fullmatch(r'^[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}$', email):
        db.close()
        return {'success': False, 'error': 'Please enter a valid email address'}
    # Phone / WhatsApp: flexible format (+92, spaces, dashes, etc.) — only require non-empty (checked above)
    if len(phone) > 80 or len(whatsapp) > 80:
        db.close()
        return {'success': False, 'error': 'Phone or WhatsApp number is too long'}
    # Duplicate block: same passport or same CNIC as an existing Iraq public submission
    pp_compare = re.sub(r'[\s\-]+', '', passport_number)
    dup_pp = db.execute(
        """SELECT id, reference_number, status FROM iraq_public_submissions
           WHERE UPPER(REPLACE(REPLACE(passport_number, ' ', ''), '-', '')) = ?""",
        [pp_compare]
    ).fetchone()
    if dup_pp:
        db.execute(
            "INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_submit_duplicate', ?, ?, ?)",
            (dup_pp['id'], 'public', json.dumps({'reason': 'passport', 'passport': passport_number}))
        )
        db.commit()
        db.close()
        return {
            'success': False,
            'duplicate': True,
            'matched_on': 'passport',
            'existing_reference': dup_pp['reference_number'],
            'error': 'A request with this passport number has already been submitted. Reference: ' + (dup_pp['reference_number'] or str(dup_pp['id']))
        }
    dup_cnic = db.execute(
        """SELECT id, reference_number, status FROM iraq_public_submissions
           WHERE REPLACE(REPLACE(REPLACE(cnic, '-', ''), ' ', ''), '.', '') = ?""",
        [cnic]
    ).fetchone()
    if dup_cnic:
        db.execute(
            "INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_submit_duplicate', ?, ?, ?)",
            (dup_cnic['id'], 'public', json.dumps({'reason': 'cnic', 'cnic': cnic}))
        )
        db.commit()
        db.close()
        return {
            'success': False,
            'duplicate': True,
            'matched_on': 'cnic',
            'existing_reference': dup_cnic['reference_number'],
            'error': 'A request with this CNIC has already been submitted. Reference: ' + (dup_cnic['reference_number'] or str(dup_cnic['id']))
        }
    ref = _new_iraq_public_ref()
    db.execute("""INSERT INTO iraq_public_submissions
        (reference_number, full_name, passport_number, cnic, nationality, date_of_birth, gender, phone, whatsapp, email,
         current_city, employer, travel_route, travel_purpose, remarks, status)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'Submitted')""",
        [ref, full_name, passport_number, cnic, nationality, date_of_birth, gender, phone, whatsapp, email,
         current_city, employer, travel_route, travel_purpose, ''])
    sid = db.execute("SELECT last_insert_rowid() id").fetchone()['id']
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_submit', ?, ?, ?)",
               (sid, 'public', json.dumps({'reference_number': ref, 'passport_number': passport_number})))
    db.commit()
    created = db.execute("SELECT created_at FROM iraq_public_submissions WHERE id = ?", [sid]).fetchone()['created_at']
    db.close()
    _queue_iraq_public_submitted_email(sid, ref, full_name, passport_number, email, phone, current_city, created, 'public')
    return {'success': True, 'id': sid, 'reference_number': ref, 'submitted_at': created, 'status': 'Submitted'}

def api_iraq_public_stats():
    db = get_db()
    total = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions").fetchone()['c']
    under_review = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE status='Under Review'").fetchone()['c']
    accepted = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE status='Accepted'").fetchone()['c']
    rejected = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE status='Rejected'").fetchone()['c']
    batched = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE status='Batched'").fetchone()['c']
    sent_embassy = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE status='Forwarded to Embassy Kuwait'").fetchone()['c']
    new_pending = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE COALESCE(mofa_kw_portal_visible,0)=0").fetchone()['c']
    on_portal = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE COALESCE(mofa_kw_portal_visible,0)=1").fetchone()['c']
    db.close()
    return {
        'total_public_submissions': total,
        'under_review': under_review,
        'accepted': accepted,
        'rejected': rejected,
        'batched': batched,
        'sent_to_embassy': sent_embassy,
        'new_pending': new_pending,
        'on_portal': on_portal
    }

def api_iraq_public_track(params):
    q = (params.get('q') or '').strip()
    if not q:
        return {'success': False, 'error': 'Please enter a passport number or reference number'}

    search_type = (params.get('type') or '').strip().lower()
    db = get_db()
    row = None
    if search_type in ('reference', 'tracking') or q.upper().startswith('IRQ-'):
        ref_norm = re.sub(r'[^A-Z0-9]', '', q.upper())
        row = db.execute(
            """SELECT id, reference_number, full_name, passport_number, status, created_at,
                      COALESCE(mofa_kw_portal_visible,0) AS mofa_kw_portal_visible,
                      COALESCE(mofa_kw_portal_sent_at,'') AS mofa_kw_portal_sent_at,
                      COALESCE(ksa_mofa_status,'') AS ksa_mofa_status
               FROM iraq_public_submissions
               WHERE UPPER(REPLACE(REPLACE(COALESCE(reference_number,''), '-', ''), ' ', '')) = ?""",
            [ref_norm]
        ).fetchone()
    else:
        pp_norm = re.sub(r'[\s\-]+', '', q.upper())
        row = db.execute(
            """SELECT id, reference_number, full_name, passport_number, status, created_at,
                      COALESCE(mofa_kw_portal_visible,0) AS mofa_kw_portal_visible,
                      COALESCE(mofa_kw_portal_sent_at,'') AS mofa_kw_portal_sent_at,
                      COALESCE(ksa_mofa_status,'') AS ksa_mofa_status
               FROM iraq_public_submissions
               WHERE UPPER(REPLACE(REPLACE(COALESCE(passport_number,''), ' ', ''), '-', '')) = ?""",
            [pp_norm]
        ).fetchone()

    if not row:
        db.close()
        return {'success': False, 'error': 'No application found with this information. Please check your passport number or reference number and try again.'}

    r = dict(row)
    submission_id = r['id']
    status = (r.get('status') or '').strip()
    sent_to_main = int(r.get('mofa_kw_portal_visible') or 0) == 1 or bool((r.get('mofa_kw_portal_sent_at') or '').strip())

    # ── Fetch latest Kuwait decision from iraq_applicant_decisions ──
    kw_decision = _iraq_public_get_kw_decision(db, submission_id)
    approved_kw = kw_decision.strip().lower() == 'approved'

    # ── KSA approval from iraq_public_submissions.ksa_mofa_status ──
    approved_ksa = (r.get('ksa_mofa_status') or '').strip().lower() == 'approved'

    db.close()

    # ── Determine public-facing status ──
    if approved_kw and approved_ksa:
        public_status = 'APPROVED'
        detail = 'Final approval complete. Please approach Pakistan Embassy Iraq for travel to Kuwait.'
    elif sent_to_main or status == 'Forwarded to Embassy Kuwait':
        public_status = 'PENDING_MOFA'
        detail = 'Requests sent to MOFA Kuwait and MOFA KSA.'
        if approved_kw and not approved_ksa:
            detail = 'Kuwait approval received. Awaiting MOFA KSA approval.'
        elif approved_ksa and not approved_kw:
            detail = 'KSA approval received. Awaiting Kuwait approval.'
    else:
        public_status = 'PROCESSING'
        detail = 'Application Submitted. Under Review. Requests will be sent to concerned authorities.'

    created_at = (r.get('created_at') or '').strip()
    registered_date = created_at.split(' ')[0] if created_at else ''
    return {
        'success': True,
        'data': {
            'status': public_status,
            'status_detail': detail,
            'tracking_number': r.get('reference_number') or '',
            'name': r.get('full_name') or '',
            'passport': r.get('passport_number') or '',
            'registered_date': registered_date,
            'mofa_sent_date': (r.get('mofa_kw_portal_sent_at') or '').strip(),
            'mofa_letter_number': '',
            'approved_kw': approved_kw,
            'approved_ksa': approved_ksa
        }
    }


def _public_track_not_found():
    return {
        'success': False,
        'found': False,
        'error': 'No request was found for this reference number. Please check the reference and try again.'
    }


def _public_track_status_text(status):
    key = (status or '').strip().lower()
    mapping = {
        'submitted': 'Your request has been received.',
        'new': 'Your request has been received.',
        'seen by admin': 'Your request has been received.',
        'assigned': 'Your request has been assigned for follow-up.',
        'in progress': 'Your request is being reviewed.',
        'field verification required': 'Your request is being reviewed.',
        'awaiting requester response': 'Further information is required. Please check the latest public update.',
        'awaiting applicant response': 'Further information is required. Please check the latest public update.',
        'awaiting family response': 'Further information is required. Please check the latest public update.',
        'follow-up completed': 'Follow-up has been completed and the request is pending final review.',
        'resolved': 'Your request has been marked as resolved.',
        'closed': 'Your request has been closed.',
        'reopened': 'Your request is being reviewed.',
        'pending review': 'Your request has been received.',
        'seen': 'Your request has been received.',
    }
    return mapping.get(key, 'Your request is being reviewed.')


def _public_track_next_step(status):
    key = (status or '').strip().lower()
    if key in ('awaiting requester response', 'awaiting applicant response', 'awaiting family response'):
        return 'Please review the latest public update and provide any requested information.'
    if key in ('resolved', 'closed'):
        return 'No immediate action is required. Keep your reference number for future follow-up.'
    if key in ('submitted', 'new', 'seen by admin', 'pending review', 'seen'):
        return 'The Community Welfare Wing will review your request and publish updates when available.'
    if key == 'assigned':
        return 'The assigned team will continue follow-up and share public updates when available.'
    return 'Please keep your reference number and check again for updates.'


def _public_track_stage(status):
    key = (status or '').strip().lower()
    if key in ('submitted', 'new', 'seen by admin', 'pending review', 'seen'):
        return 'Submitted'
    if key == 'assigned':
        return 'Assigned'
    if key in ('in progress', 'field verification required', 'reopened'):
        return 'In Progress'
    if key in ('awaiting requester response', 'awaiting applicant response', 'awaiting family response'):
        return 'Information Requested'
    if key == 'follow-up completed':
        return 'Final Review'
    if key in ('resolved', 'closed'):
        return 'Completed'
    return 'In Progress'


def _public_track_safe_notes(rows):
    notes = []
    for row in rows:
        d = dict(row)
        note = (d.get('note') or '').strip()
        if not note:
            continue
        notes.append({
            'note': note,
            'created_at': d.get('created_at') or ''
        })
    return notes


def _legacy_ref_to_current(ref, target_prefix):
    up = (ref or '').strip().upper()
    if up.startswith(target_prefix + '-'):
        return up
    digits = re.findall(r'(\d+)', up)
    if not digits:
        return ''
    seq = int(digits[-1])
    if target_prefix in ('LGL', 'DTH'):
        return f'{target_prefix}-{seq:05d}'
    return ''


def api_public_request_track(params):
    reference = (params.get('reference') or '').strip().upper()
    if not reference:
        return _public_track_not_found()
    reference = re.sub(r'\s+', '', reference)

    db = get_db()
    try:
        if reference.startswith('CWA-FBK-') or reference.startswith('CWA-LOC-'):
            row = db.execute(
                """SELECT id, case_reference, case_type, status, created_at, updated_at
                   FROM welfare_cases
                   WHERE UPPER(TRIM(case_reference)) = ?
                   LIMIT 1""",
                [reference]
            ).fetchone()
            if not row:
                return _public_track_not_found()
            rec = dict(row)
            notes = db.execute(
                """SELECT note, created_at
                   FROM welfare_case_actions
                   WHERE case_id = ?
                     AND COALESCE(visible_to_requester, 0) = 1
                     AND TRIM(COALESCE(note, '')) != ''
                   ORDER BY id DESC
                   LIMIT 20""",
                [rec['id']]
            ).fetchall()
            status = rec.get('status') or 'Submitted'
            service_type = 'Community Feedback / Complaints' if reference.startswith('CWA-FBK-') else 'Locating / Contacting Assistance'
            return {
                'success': True,
                'found': True,
                'reference': rec.get('case_reference') or reference,
                'service_type': service_type,
                'submitted_at': rec.get('created_at') or '',
                'status': status,
                'last_updated': rec.get('updated_at') or rec.get('created_at') or '',
                'current_stage': _public_track_stage(status),
                'message': _public_track_status_text(status),
                'public_notes': _public_track_safe_notes(notes),
                'next_step': _public_track_next_step(status)
            }

        if reference.startswith('LEGAL-') or reference.startswith('OPF-') or reference.startswith('LGL-'):
            legal_ref = reference if reference.startswith('LGL-') else _legacy_ref_to_current(reference, 'LGL')
            candidates = [reference]
            if legal_ref and legal_ref not in candidates:
                candidates.append(legal_ref)
            row = db.execute(
                f"""SELECT reference_id, status, case_type, created_at, updated_at, last_action_at
                    FROM legal_case_requests
                    WHERE UPPER(TRIM(reference_id)) IN ({','.join('?' for _ in candidates)})
                    ORDER BY id DESC
                    LIMIT 1""",
                candidates
            ).fetchone()
            if not row:
                return _public_track_not_found()
            rec = dict(row)
            notes = db.execute(
                """SELECT note, created_at
                   FROM legal_case_actions
                   WHERE reference_id = ?
                     AND COALESCE(visible_to_applicant, 0) = 1
                     AND TRIM(COALESCE(note, '')) != ''
                   ORDER BY id DESC
                   LIMIT 20""",
                [rec.get('reference_id') or '']
            ).fetchall()
            status = rec.get('status') or 'Submitted'
            case_type = (rec.get('case_type') or '').strip().lower()
            service_type = 'OPF / Legal Support' if ('opf' in case_type or reference.startswith('OPF-')) else 'Legal Assistance'
            return {
                'success': True,
                'found': True,
                'reference': rec.get('reference_id') or reference,
                'service_type': service_type,
                'submitted_at': rec.get('created_at') or '',
                'status': status,
                'last_updated': rec.get('last_action_at') or rec.get('updated_at') or rec.get('created_at') or '',
                'current_stage': _public_track_stage(status),
                'message': _public_track_status_text(status),
                'public_notes': _public_track_safe_notes(notes),
                'next_step': _public_track_next_step(status)
            }

        if reference.startswith('DC-') or reference.startswith('DEATH-') or reference.startswith('DTH-'):
            death_ref = reference if reference.startswith('DTH-') else _legacy_ref_to_current(reference, 'DTH')
            candidates = [reference]
            if death_ref and death_ref not in candidates:
                candidates.append(death_ref)
            row = db.execute(
                f"""SELECT reference_id, status, created_at, updated_at, last_action_at
                    FROM death_case_requests
                    WHERE UPPER(TRIM(reference_id)) IN ({','.join('?' for _ in candidates)})
                    ORDER BY id DESC
                    LIMIT 1""",
                candidates
            ).fetchone()
            if not row:
                return _public_track_not_found()
            rec = dict(row)
            status = rec.get('status') or 'Submitted'
            return {
                'success': True,
                'found': True,
                'reference': rec.get('reference_id') or reference,
                'service_type': 'Death Case Assistance',
                'submitted_at': rec.get('created_at') or '',
                'status': status,
                'last_updated': rec.get('last_action_at') or rec.get('updated_at') or rec.get('created_at') or '',
                'current_stage': _public_track_stage(status),
                'message': _public_track_status_text(status),
                'public_notes': [],
                'next_step': _public_track_next_step(status)
            }

        if reference.startswith('NUR-'):
            row = db.execute(
                """SELECT reference_id, registration_status, created_at, updated_at,
                          COALESCE(email_verified, 0) AS email_verified
                   FROM nurse_registrations
                   WHERE UPPER(TRIM(reference_id)) = ?
                   ORDER BY id DESC
                   LIMIT 1""",
                [reference]
            ).fetchone()
            if not row:
                return _public_track_not_found()
            rec = dict(row)
            status = rec.get('registration_status') or 'Pending Review'
            message = _public_track_status_text(status)
            if int(rec.get('email_verified') or 0) == 0:
                message = 'Email verification is pending. Please verify your email address to receive official updates.'
            return {
                'success': True,
                'found': True,
                'reference': rec.get('reference_id') or reference,
                'service_type': 'Nurse Registration',
                'submitted_at': rec.get('created_at') or '',
                'status': status,
                'last_updated': rec.get('updated_at') or rec.get('created_at') or '',
                'current_stage': 'Nurse Registration',
                'message': message,
                'public_notes': [],
                'next_step': 'Your health worker registration has been received. Your portal account is active if email is verified.'
            }

        if reference.startswith('NCMP-'):
            row = db.execute(
                """SELECT id, nurse_reference_id, complaint_status, status, created_at, updated_at, last_action_at
                   FROM nurse_complaints
                   WHERE UPPER(TRIM(COALESCE(complaint_id, ''))) = ?
                      OR UPPER(TRIM(COALESCE(complaint_reference, ''))) = ?
                      OR UPPER(TRIM(COALESCE(case_reference, ''))) = ?
                      OR UPPER(TRIM(COALESCE(reference, ''))) = ?
                      OR UPPER(TRIM(COALESCE(nurse_complaint_id, ''))) = ?
                   ORDER BY id DESC
                   LIMIT 1""",
                [reference, reference, reference, reference, reference]
            ).fetchone()
            if not row:
                row = db.execute(
                    """SELECT id, nurse_reference_id, complaint_status, status, created_at, updated_at, last_action_at
                       FROM nurse_complaints
                       WHERE UPPER(TRIM(COALESCE(nurse_reference_id, ''))) = ?
                       ORDER BY id DESC
                       LIMIT 1""",
                    [reference]
                ).fetchone()
            if not row:
                return _public_track_not_found()
            rec = dict(row)
            notes = db.execute(
                """SELECT note, created_at
                   FROM nurse_complaint_actions
                   WHERE complaint_id = ?
                     AND COALESCE(visible_to_nurse, 0) = 1
                     AND TRIM(COALESCE(note, '')) != ''
                   ORDER BY id DESC
                   LIMIT 20""",
                [reference]
            ).fetchall()
            status = rec.get('status') or rec.get('complaint_status') or 'Submitted'
            return {
                'success': True,
                'found': True,
                'reference': reference,
                'service_type': 'Nurse Complaint / Request',
                'submitted_at': rec.get('created_at') or '',
                'status': status,
                'last_updated': rec.get('last_action_at') or rec.get('updated_at') or rec.get('created_at') or '',
                'current_stage': _public_track_stage(status),
                'message': _public_track_status_text(status),
                'public_notes': _public_track_safe_notes(notes),
                'next_step': 'Your request is pending follow-up if applicable.'
            }

        return _public_track_not_found()
    finally:
        db.close()

def api_iraq_cwa_daily_sent_summary(params):
    day = (params.get('date') or datetime.now().strftime('%Y-%m-%d')).strip()
    if not re.fullmatch(r'\d{4}-\d{2}-\d{2}', day):
        day = datetime.now().strftime('%Y-%m-%d')
    db = get_db()
    rows = db.execute("""SELECT reference_number, full_name, passport_number, cnic, status,
        mofa_kw_portal_sent_at
        FROM iraq_public_submissions
        WHERE COALESCE(mofa_kw_portal_visible,0)=1
          AND date(COALESCE(mofa_kw_portal_sent_at, created_at)) = date(?)
        ORDER BY id DESC""", [day]).fetchall()
    batch_count = db.execute("""SELECT COUNT(*) c FROM iraq_batches_public
        WHERE status='Sent to Embassy Kuwait'
          AND date(COALESCE(sent_to_embassy_at, created_at)) = date(?)""", [day]).fetchone()['c']
    db.close()
    out = [dict(r) for r in rows]
    return {'date': day, 'batch_count': int(batch_count or 0), 'applicant_count': len(out), 'records': out}

def api_iraq_public_submissions(params):
    db = get_db()
    where = ["1=1"]
    q = []
    status = (params.get('status') or '').strip()
    search = (params.get('search') or '').strip()
    if status:
        where.append("status = ?")
        q.append(status)
    if search:
        s = f"%{search}%"
        compact = re.sub(r'[\s\-]+', '', search or '')
        compact_like = f"%{compact}%"
        where.append("""(
            UPPER(COALESCE(full_name,'')) LIKE UPPER(?)
            OR UPPER(REPLACE(REPLACE(COALESCE(passport_number,''), ' ', ''), '-', '')) LIKE UPPER(?)
            OR UPPER(COALESCE(reference_number,'')) LIKE UPPER(?)
            OR UPPER(REPLACE(REPLACE(COALESCE(reference_number,''), ' ', ''), '-', '')) LIKE UPPER(?)
            OR COALESCE(phone,'') LIKE ?
            OR COALESCE(cnic,'') LIKE ?
            OR CAST(id AS TEXT) = ?
        )""")
        q.extend([s, compact_like, s, compact_like, s, s, search])
    rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {' AND '.join(where)} ORDER BY id DESC", q).fetchall()
    db.close()
    return [dict(r) for r in rows]


def bulk_fetch_latest_iraq_public_decisions(db, submission_ids):
    by_id = {}
    for chunk in _iter_nv_record_id_chunks(submission_ids):
        placeholders = ','.join('?' for _ in chunk)
        rows = db.execute(f"""
            SELECT public_submission_id, decision, id
            FROM iraq_applicant_decisions
            WHERE public_submission_id IN ({placeholders})
            ORDER BY public_submission_id ASC, id DESC
        """, chunk).fetchall()
        for row in rows:
            sid = int(row['public_submission_id'] or 0)
            if sid > 0 and sid not in by_id:
                by_id[sid] = row['decision'] or ''
    return by_id


def bulk_fetch_latest_iraq_public_dispatches(db, submission_ids):
    by_id = {}
    for chunk in _iter_nv_record_id_chunks(submission_ids):
        placeholders = ','.join('?' for _ in chunk)
        rows = db.execute(f"""
            SELECT da.public_submission_id, md.note_verbale_number, md.note_verbale_date, md.sent_date, da.id
            FROM iraq_dispatch_applicants da
            JOIN iraq_mofa_dispatches md ON md.id = da.dispatch_id
            WHERE da.public_submission_id IN ({placeholders})
            ORDER BY da.public_submission_id ASC, da.id DESC
        """, chunk).fetchall()
        for row in rows:
            sid = int(row['public_submission_id'] or 0)
            if sid > 0 and sid not in by_id:
                by_id[sid] = {
                    'note_verbale_number': row['note_verbale_number'] or '',
                    'note_verbale_date': row['note_verbale_date'] or '',
                    'sent_date': row['sent_date'] or '',
                }
    return by_id


def api_iraq_public_submission_detail(sub_id, session_user=None):
    db = get_db()
    row = db.execute("SELECT * FROM iraq_public_submissions WHERE id = ?", [sub_id]).fetchone()
    if not row:
        db.close()
        return {'success': False, 'error': 'Submission not found'}
    d = dict(row)
    dec = db.execute(
        """SELECT decision FROM iraq_applicant_decisions WHERE public_submission_id = ?
           ORDER BY id DESC LIMIT 1""", [sub_id]
    ).fetchone()
    d['kw_transit_visa_status'] = (dec['decision'] if dec and dec['decision'] else '') or 'Pending'
    # Fetch Note Verbale dispatch info if exists
    nv = db.execute(
        """SELECT md.note_verbale_number, md.note_verbale_date, md.sent_date
           FROM iraq_dispatch_applicants da
           JOIN iraq_mofa_dispatches md ON md.id = da.dispatch_id
           WHERE da.public_submission_id = ? ORDER BY da.id DESC LIMIT 1""", [sub_id]
    ).fetchone()
    if nv:
        d['nv_number'] = nv['note_verbale_number'] or ''
        d['nv_date'] = nv['note_verbale_date'] or ''
        d['nv_sent_date'] = nv['sent_date'] or ''
    else:
        d['nv_number'] = ''
        d['nv_date'] = ''
        d['nv_sent_date'] = ''
    d = _apply_nv_access_fields(db, d, 'iraq_public_submissions', session_user)
    db.close()
    return {'success': True, 'submission': d}

def api_iraq_public_submission_update(data, user):
    db = get_db()
    sid = data.get('id')
    if not sid:
        db.close()
        return {'success': False, 'error': 'Submission id is required'}
    existing = db.execute("SELECT id, COALESCE(mofa_kw_portal_visible,0) as mofa_kw_portal_visible FROM iraq_public_submissions WHERE id = ?", [sid]).fetchone()
    if not existing:
        db.close()
        return {'success': False, 'error': 'Submission not found'}
    # Lock check DISABLED — staff can now edit all records regardless of portal visibility
    # if int(existing['mofa_kw_portal_visible'] or 0) == 1:
    #     db.close()
    #     return {'success': False, 'error': 'Record is locked after being sent to Kuwait main portal. Editing is not allowed.'}

    editable_fields = [
        'full_name', 'passport_number', 'cnic', 'nationality', 'date_of_birth', 'gender',
        'phone', 'whatsapp', 'email', 'current_city', 'employer', 'travel_route',
        'travel_purpose', 'remarks'
    ]
    updates, params = [], []
    for f in editable_fields:
        if f in data:
            v = (data.get(f) or '').strip()
            if f == 'passport_number':
                v = v.upper()
            if f == 'cnic':
                v = re.sub(r'[^0-9]', '', v)
                if v and not re.fullmatch(r'\d{13}', v):
                    db.close()
                    return {'success': False, 'error': 'CNIC must be exactly 13 digits'}
            if f == 'email' and v and not re.fullmatch(r'^[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}$', v):
                db.close()
                return {'success': False, 'error': 'Please enter a valid email address'}
            updates.append(f"{f} = ?")
            params.append(v)

    if not updates:
        db.close()
        return {'success': False, 'error': 'No changes provided'}

    params.append(sid)
    db.execute(f"UPDATE iraq_public_submissions SET {', '.join(updates)}, reviewed_by = ?, reviewed_at = CURRENT_TIMESTAMP WHERE id = ?", params[:-1] + [user, sid])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_edit', ?, ?, ?)",
               (sid, user, json.dumps({'fields': [u.split(' = ')[0] for u in updates]})))
    db.commit()
    db.close()
    return {'success': True}

def api_iraq_public_submission_delete(sid, user):
    db = get_db()
    row = db.execute("SELECT id, COALESCE(mofa_kw_portal_visible,0) as mofa_kw_portal_visible FROM iraq_public_submissions WHERE id = ?", [sid]).fetchone()
    if not row:
        db.close()
        return {'success': False, 'error': 'Submission not found'}
    # Lock check DISABLED — staff can now delete records regardless of portal visibility
    # if int(row['mofa_kw_portal_visible'] or 0) == 1:
    #     db.close()
    #     return {'success': False, 'error': 'Record is locked after being sent to Kuwait main portal. Deletion is not allowed.'}
    db.execute("DELETE FROM iraq_dispatch_applicants WHERE public_submission_id = ?", [sid])
    db.execute("DELETE FROM iraq_applicant_decisions WHERE public_submission_id = ?", [sid])
    db.execute("DELETE FROM iraq_batch_applicants WHERE public_submission_id = ?", [sid])
    db.execute("DELETE FROM iraq_public_submissions WHERE id = ?", [sid])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_delete', ?, ?, ?)",
               (sid, user, '{}'))
    db.commit()
    db.close()
    return {'success': True}

def api_iraq_public_release_to_mofa_portal(user):
    db = get_db()
    cur = db.execute("""UPDATE iraq_public_submissions
        SET mofa_kw_portal_visible = 1, mofa_kw_portal_sent_at = CURRENT_TIMESTAMP
        WHERE COALESCE(mofa_kw_portal_visible, 0) = 0
        AND status NOT IN ('Rejected', 'Duplicate')""")
    n = cur.rowcount if cur.rowcount is not None and cur.rowcount >= 0 else 0
    db.execute("INSERT INTO audit_log (action, user, details) VALUES ('iraq_public_release_mofa_portal', ?, ?)",
               (user, json.dumps({'count': n})))
    db.commit()
    db.close()
    return {'success': True, 'released_count': n}

def api_iraq_public_portal_submissions(params):
    db = get_db()
    started_at = time.perf_counter()
    where = []
    q = []
    status = (params.get('status') or '').strip()
    search = (params.get('search') or '').strip()
    pending_nv = (params.get('pending_nv') or '').strip().lower() in ('1', 'true', 'yes')
    created_date = (params.get('created_date') or '').strip()
    include_unreleased = (params.get('include_unreleased') or '').strip().lower() in ('1', 'true', 'yes')
    if created_date and not re.fullmatch(r'\d{4}-\d{2}-\d{2}', created_date):
        created_date = ''
    # Visibility: default only rows already released to this portal; optional "today" preview includes not-yet-released (same calendar day only)
    if include_unreleased and created_date:
        where.append("""(
            (COALESCE(p.mofa_kw_portal_visible, 0) = 1 AND date(p.created_at) = date(?))
            OR (COALESCE(p.mofa_kw_portal_visible, 0) = 0 AND p.status NOT IN ('Rejected', 'Duplicate') AND date(p.created_at) = date(?))
        )""")
        q.extend([created_date, created_date])
    else:
        where.append("COALESCE(p.mofa_kw_portal_visible, 0) = 1")
        if created_date:
            where.append("date(p.created_at) = date(?)")
            q.append(created_date)
    if pending_nv:
        where.append(
            "NOT EXISTS (SELECT 1 FROM iraq_dispatch_applicants d WHERE d.public_submission_id = p.id)"
        )
    if status:
        where.append("p.status = ?")
        q.append(status)
    if search:
        sf = f"%{search}%"
        where.append("(p.full_name LIKE ? OR p.passport_number LIKE ? OR p.reference_number LIKE ? OR p.phone LIKE ? OR p.whatsapp LIKE ? OR p.email LIKE ? OR p.cnic LIKE ? OR p.current_city LIKE ? OR p.employer LIKE ?)")
        q.extend([sf, sf, sf, sf, sf, sf, sf, sf, sf])
    rows = [dict(r) for r in db.execute(
        f"SELECT p.* FROM iraq_public_submissions p WHERE {' AND '.join(where)} ORDER BY p.id DESC", q
    ).fetchall()]
    submission_ids = [row.get('id') for row in rows]
    decisions_by_id = bulk_fetch_latest_iraq_public_decisions(db, submission_ids)
    dispatches_by_id = bulk_fetch_latest_iraq_public_dispatches(db, submission_ids)
    out = []
    for d in rows:
        sid = int(d.get('id') or 0)
        dispatch = dispatches_by_id.get(sid)
        d['has_nv_dispatch'] = bool(dispatch)
        d['nv_number'] = dispatch.get('note_verbale_number', '') if dispatch else ''
        d['nv_date'] = dispatch.get('note_verbale_date', '') if dispatch else ''
        d['nv_sent_date'] = dispatch.get('sent_date', '') if dispatch else ''
        kws = decisions_by_id.get(sid, '')
        d['kw_transit_visa_status'] = (kws if kws else '') or 'Pending'
        out.append(d)
    db.close()
    _log_perf_if_slow('/api/iraq-public-portal-submissions', started_at, threshold_ms=325, row_count=len(out), extra=f"search={1 if search else 0} pending_nv={1 if pending_nv else 0}")
    return out

def api_iraq_public_portal_stats():
    db = get_db()
    on_portal = db.execute(
        "SELECT COUNT(*) c FROM iraq_public_submissions WHERE COALESCE(mofa_kw_portal_visible,0)=1"
    ).fetchone()['c']
    pending_nv = db.execute("""SELECT COUNT(*) c FROM iraq_public_submissions p
        WHERE COALESCE(p.mofa_kw_portal_visible,0)=1
        AND NOT EXISTS (SELECT 1 FROM iraq_dispatch_applicants d WHERE d.public_submission_id = p.id)"""
    ).fetchone()['c']
    today = datetime.now().strftime('%Y-%m-%d')
    today_pending_nv = db.execute("""SELECT COUNT(*) c FROM iraq_public_submissions p
        WHERE COALESCE(p.mofa_kw_portal_visible,0)=1
        AND date(p.created_at) = date(?)
        AND NOT EXISTS (SELECT 1 FROM iraq_dispatch_applicants d WHERE d.public_submission_id = p.id)""",
        [today]).fetchone()['c']
    db.close()
    return {'on_portal': on_portal, 'pending_note_verbale': pending_nv, 'today_pending_nv': today_pending_nv}

def api_iraq_public_update_status(data, user):
    db = get_db()
    sid = data.get('id')
    status = (data.get('status') or '').strip()
    if not sid or status not in ('Under Review', 'Accepted', 'Rejected', 'Duplicate'):
        db.close()
        return {'success': False, 'error': 'Invalid submission or status'}
    row = db.execute("SELECT COALESCE(mofa_kw_portal_visible,0) as mofa_kw_portal_visible FROM iraq_public_submissions WHERE id = ?", [sid]).fetchone()
    if not row:
        db.close()
        return {'success': False, 'error': 'Submission not found'}
    # Lock check DISABLED — staff can now change status regardless of portal visibility
    # if int(row['mofa_kw_portal_visible'] or 0) == 1:
    #     db.close()
    #     return {'success': False, 'error': 'Record is locked after being sent to Kuwait main portal. Status cannot be changed.'}
    db.execute("""UPDATE iraq_public_submissions
        SET status = ?, reviewed_at = CURRENT_TIMESTAMP, reviewed_by = ?
        WHERE id = ?""", [status, user, sid])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_review', ?, ?, ?)",
               (sid, user, json.dumps({'status': status})))
    db.commit()
    db.close()
    return {'success': True}

def api_iraq_create_public_batch(data, user):
    db = get_db()
    ids = data.get('submission_ids') or []
    letter_number = (data.get('letter_number') or '').strip()
    if not ids or not letter_number:
        db.close()
        return {'success': False, 'error': 'Letter number and at least one accepted submission are required'}
    clean_ids = [int(x) for x in ids]
    accepted_rows = db.execute(
        f"SELECT id FROM iraq_public_submissions WHERE id IN ({','.join(['?']*len(clean_ids))}) AND status='Accepted'",
        clean_ids
    ).fetchall()
    if not accepted_rows:
        db.close()
        return {'success': False, 'error': 'No accepted submissions selected'}
    batch_cur = db.execute("""INSERT INTO iraq_batches_public
        (letter_number, letter_date, created_by, remarks, status)
        VALUES (?, ?, ?, ?, 'Ready')""",
        [letter_number, (data.get('letter_date') or '').strip(), user, (data.get('remarks') or '').strip()])
    batch_id = batch_cur.lastrowid
    for row in accepted_rows:
        sid = row['id']
        db.execute("INSERT INTO iraq_batch_applicants (batch_id, public_submission_id) VALUES (?, ?)", [batch_id, sid])
        db.execute("UPDATE iraq_public_submissions SET linked_batch_id = ?, status = 'Batched' WHERE id = ?", [batch_id, sid])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_public_batch_create', ?, ?, ?)",
               (batch_id, user, json.dumps({'submission_count': len(accepted_rows)})))
    db.commit()
    db.close()
    return {'success': True, 'batch_id': batch_id, 'count': len(accepted_rows)}

def api_iraq_batches_public(params):
    db = get_db()
    where = ["1=1"]
    q = []
    status = (params.get('status') or '').strip()
    if status:
        where.append("b.status = ?")
        q.append(status)
    rows = db.execute(f"""SELECT b.*, COUNT(a.id) applicant_count
        FROM iraq_batches_public b
        LEFT JOIN iraq_batch_applicants a ON a.batch_id = b.id
        WHERE {' AND '.join(where)}
        GROUP BY b.id
        ORDER BY b.id DESC""", q).fetchall()
    db.close()
    return [dict(r) for r in rows]

def api_iraq_batch_public_detail(batch_id):
    db = get_db()
    batch = db.execute("SELECT * FROM iraq_batches_public WHERE id = ?", [batch_id]).fetchone()
    if not batch:
        db.close()
        return {'error': 'Batch not found'}
    apps = db.execute("""SELECT p.* FROM iraq_batch_applicants a
        JOIN iraq_public_submissions p ON p.id = a.public_submission_id
        WHERE a.batch_id = ? ORDER BY p.id""", [batch_id]).fetchall()
    db.close()
    d = dict(batch)
    d['applicants'] = [dict(r) for r in apps]
    return d

def api_iraq_forward_batch_to_embassy(data, user):
    db = get_db()
    batch_id = data.get('batch_id')
    if not batch_id:
        db.close()
        return {'success': False, 'error': 'Batch ID is required'}
    db.execute("""UPDATE iraq_batches_public
        SET status = 'Sent to Embassy Kuwait', sent_to_embassy_at = CURRENT_TIMESTAMP
        WHERE id = ?""", [batch_id])
    db.execute("""UPDATE iraq_public_submissions
        SET status = 'Forwarded to Embassy Kuwait'
        WHERE linked_batch_id = ?""", [batch_id])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_batch_forward_embassy', ?, ?, ?)",
               (batch_id, user, '{}'))
    db.commit()
    db.close()
    return {'success': True}

def api_bulk_ksa_approval(passports_text, user='system'):
    tokens = re.split(r'[\n,;]+', passports_text or '')
    passports = [re.sub(r'[\s\-]+', '', (t or '').upper()) for t in tokens]
    passports = [p for p in passports if p]
    total_pasted = len(passports)
    unique = []
    seen = set()
    for p in passports:
        if p not in seen:
            seen.add(p)
            unique.append(p)
    db = get_db()
    matched = 0
    updated = 0
    iraq_applicants_matched = 0
    iraq_applicants_updated = 0
    iraq_public_matched = 0
    iraq_public_updated = 0
    not_found = []
    for pp in unique:
        found_any = False

        # ── 1. Update evacuees table (main portal records) ──
        rows = db.execute("""SELECT id, COALESCE(mofa_ksa_status,'') AS mofa_ksa_status
            FROM evacuees WHERE UPPER(REPLACE(REPLACE(COALESCE(passport,''),' ',''),'-','')) = ?""", [pp]).fetchall()
        if rows:
            found_any = True
            matched += len(rows)
            for r in rows:
                if (r['mofa_ksa_status'] or '').strip().lower() != 'approved':
                    db.execute("""UPDATE evacuees
                        SET mofa_ksa_status='Approved',
                            mofa_ksa_approved_at=COALESCE(mofa_ksa_approved_at, CURRENT_TIMESTAMP),
                            updated_at=CURRENT_TIMESTAMP, updated_by=?
                        WHERE id=?""", [user, r['id']])
                    updated += 1
                _queue_iraq_final_approval_if_ready(db, r['id'], user)

        # ── 2. Update iraq_applicants table (mission batch records) ──
        iraq_rows = db.execute("""SELECT id, COALESCE(ksa_mofa_status,'') AS ksa_mofa_status
            FROM iraq_applicants WHERE UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', ''), '-', '')) = ?""", [pp]).fetchall()
        if iraq_rows:
            found_any = True
            iraq_applicants_matched += len(iraq_rows)
            for ir in iraq_rows:
                if (ir['ksa_mofa_status'] or '').strip().lower() != 'approved':
                    db.execute("""UPDATE iraq_applicants SET ksa_mofa_status='Approved' WHERE id=?""", [ir['id']])
                    iraq_applicants_updated += 1

        # ── 3. Update iraq_public_submissions table (public intake records) ──
        pub_rows = db.execute("""SELECT id, full_name, COALESCE(ksa_mofa_status,'') AS ksa_mofa_status
            FROM iraq_public_submissions
            WHERE UPPER(REPLACE(REPLACE(TRIM(COALESCE(passport_number,'')), ' ', ''), '-', '')) = ?""", [pp]).fetchall()
        if pub_rows:
            found_any = True
            iraq_public_matched += len(pub_rows)
            for pr in pub_rows:
                if (pr['ksa_mofa_status'] or '').strip().lower() != 'approved':
                    db.execute("""UPDATE iraq_public_submissions SET ksa_mofa_status='Approved' WHERE id=?""", [pr['id']])
                    iraq_public_updated += 1
                # Check if both KW + KSA are now approved for this Iraq public submission
                _queue_iraq_public_final_approval_if_ready(db, pr['id'], user)

        if not found_any:
            not_found.append(pp)

    total_matched = matched + iraq_applicants_matched + iraq_public_matched
    total_updated = updated + iraq_applicants_updated + iraq_public_updated
    db.execute("INSERT INTO audit_log (action, user, details) VALUES ('bulk_ksa_approval', ?, ?)",
               [user, json.dumps({'total_pasted': total_pasted, 'matched': total_matched, 'updated': total_updated,
                                   'evacuees_matched': matched, 'evacuees_updated': updated,
                                   'iraq_applicants_matched': iraq_applicants_matched,
                                   'iraq_applicants_updated': iraq_applicants_updated,
                                   'iraq_public_matched': iraq_public_matched,
                                   'iraq_public_updated': iraq_public_updated,
                                   'not_found': not_found})])
    db.commit()
    db.close()
    return {
        'success': True,
        'total_pasted': total_pasted,
        'matched': total_matched,
        'updated': total_updated,
        'not_found': len(not_found),
        'not_found_list': not_found
    }

def api_iraq_embassy_dashboard():
    db = get_db()
    total = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions").fetchone()['c']
    awaiting = db.execute("SELECT COUNT(*) c FROM iraq_public_submissions WHERE status='Forwarded to Embassy Kuwait'").fetchone()['c']
    sent = db.execute("""SELECT COUNT(*) c FROM iraq_dispatch_applicants da
        JOIN iraq_mofa_dispatches d ON d.id = da.dispatch_id
        WHERE d.status='Sent' OR d.status='Closed'""").fetchone()['c']
    approved = db.execute("SELECT COUNT(*) c FROM iraq_applicant_decisions WHERE decision='Approved'").fetchone()['c']
    rejected = db.execute("SELECT COUNT(*) c FROM iraq_applicant_decisions WHERE decision='Rejected'").fetchone()['c']
    db.close()
    return {
        'total_received': total,
        'awaiting_mofa_submission': awaiting,
        'sent_to_mofa': sent,
        'approved': approved,
        'rejected': rejected
    }

def api_iraq_create_dispatch(data, user):
    db = get_db()
    note_no = (data.get('note_verbale_number') or '').strip()
    raw_ids = data.get('public_submission_ids') or []
    release_first = (data.get('release_to_portal_if_needed') or '').strip().lower() in ('1', 'true', 'yes', 'on')
    try:
        selected_ids = [int(x) for x in raw_ids]
    except (TypeError, ValueError):
        db.close()
        return {'success': False, 'error': 'Invalid submission id list'}
    if not note_no or not selected_ids:
        db.close()
        return {'success': False, 'error': 'Note Verbale number and at least one applicant are required'}
    sent_date_val = (data.get('sent_date') or '').strip()
    if not sent_date_val:
        sent_date_val = datetime.now().strftime('%Y-%m-%d')
    ok_ids = []
    skipped = []
    for sid in selected_ids:
        row = db.execute(
            "SELECT id, status, COALESCE(mofa_kw_portal_visible,0) AS vis, linked_batch_id FROM iraq_public_submissions WHERE id = ?",
            [sid]
        ).fetchone()
        if not row:
            skipped.append({'id': sid, 'reason': 'not_found'})
            continue
        if row['status'] in ('Rejected', 'Duplicate'):
            skipped.append({'id': sid, 'reason': 'invalid_status'})
            continue
        dup = db.execute("SELECT 1 FROM iraq_dispatch_applicants WHERE public_submission_id = ?", [sid]).fetchone()
        if dup:
            skipped.append({'id': sid, 'reason': 'already_dispatched'})
            continue
        vis = int(row['vis'] or 0)
        if vis != 1:
            if release_first:
                db.execute("""UPDATE iraq_public_submissions SET mofa_kw_portal_visible = 1,
                    mofa_kw_portal_sent_at = COALESCE(mofa_kw_portal_sent_at, CURRENT_TIMESTAMP) WHERE id = ?""", [sid])
            else:
                skipped.append({'id': sid, 'reason': 'not_on_portal'})
                continue
        ok_ids.append((sid, row['linked_batch_id']))
    if not ok_ids:
        db.commit()
        db.close()
        return {'success': False, 'error': 'No eligible submissions to add (check portal visibility or already dispatched).', 'skipped': skipped}
    cur = db.execute("""INSERT INTO iraq_mofa_dispatches
        (note_verbale_number, note_verbale_date, sent_date, remarks, status, created_by)
        VALUES (?, ?, ?, ?, ?, ?)""",
        [note_no, (data.get('note_verbale_date') or '').strip(), sent_date_val,
         (data.get('remarks') or '').strip(), (data.get('status') or 'Sent').strip(), user])
    dispatch_id = cur.lastrowid
    for sid, batch_id in ok_ids:
        db.execute("""INSERT INTO iraq_dispatch_applicants
            (dispatch_id, batch_id, public_submission_id) VALUES (?, ?, ?)""",
            [dispatch_id, batch_id, sid])
    db.execute("INSERT INTO audit_log (action, record_id, user, details) VALUES ('iraq_dispatch_create', ?, ?, ?)",
               (dispatch_id, user, json.dumps({'added': len(ok_ids), 'skipped': skipped, 'note_verbale_number': note_no})))
    db.commit()
    db.close()
    return {'success': True, 'dispatch_id': dispatch_id, 'added_count': len(ok_ids), 'skipped': skipped}

def api_iraq_dispatches():
    db = get_db()
    rows = db.execute("""SELECT d.*, COUNT(a.id) applicant_count
        FROM iraq_mofa_dispatches d
        LEFT JOIN iraq_dispatch_applicants a ON a.dispatch_id = d.id
        GROUP BY d.id
        ORDER BY d.id DESC""").fetchall()
    db.close()
    return [dict(r) for r in rows]

def api_iraq_update_decision(data, user):
    db = get_db()
    sid = data.get('public_submission_id')
    decision = (data.get('decision') or '').strip()
    if not sid or decision not in ('Pending', 'Approved', 'Rejected'):
        db.close()
        return {'success': False, 'error': 'Invalid applicant or decision'}
    db.execute("""INSERT INTO iraq_applicant_decisions
        (public_submission_id, decision, decision_date, remarks, decided_by)
        VALUES (?, ?, ?, ?, ?)""",
        [sid, decision, (data.get('decision_date') or datetime.now().strftime('%Y-%m-%d')).strip(),
         (data.get('remarks') or '').strip(), user])
    db.commit()
    # Check if Iraq public submission now has both KW + KSA approval
    if decision == 'Approved':
        _queue_iraq_public_final_approval_if_ready(db, sid, changed_by=user)
    db.close()
    return {'success': True}

def api_iraq_public_export(filter_key, dispatch_id=None, slim=False):
    db = get_db()
    dispatch_join_cols = False
    if filter_key == 'dispatch':
        try:
            did = int(dispatch_id)
        except (TypeError, ValueError):
            did = 0
        if did <= 0:
            db.close()
            return ''
        rows = db.execute("""
            SELECT p.*, d.id AS _dispatch_id, d.note_verbale_number AS _nv_no, d.note_verbale_date AS _nv_date,
                   d.sent_date AS _dispatch_sent_date
            FROM iraq_public_submissions p
            JOIN iraq_dispatch_applicants a ON a.public_submission_id = p.id
            JOIN iraq_mofa_dispatches d ON d.id = a.dispatch_id
            WHERE d.id = ?
            ORDER BY p.id
        """, [did]).fetchall()
        dispatch_join_cols = True
    elif filter_key == 'accepted':
        where = "status='Accepted'"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    elif filter_key == 'rejected':
        where = "status='Rejected'"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    elif filter_key == 'pending_mofa':
        where = "status='Forwarded to Embassy Kuwait'"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    elif filter_key == 'sent_mofa':
        where = "id IN (SELECT public_submission_id FROM iraq_dispatch_applicants)"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    elif filter_key == 'approved':
        where = "id IN (SELECT public_submission_id FROM iraq_applicant_decisions WHERE decision='Approved')"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    elif filter_key == 'rejected_cases':
        where = "id IN (SELECT public_submission_id FROM iraq_applicant_decisions WHERE decision='Rejected')"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    elif filter_key == 'mofa_portal':
        where = "COALESCE(mofa_kw_portal_visible,0) = 1"
        rows = db.execute(f"SELECT * FROM iraq_public_submissions WHERE {where} ORDER BY id DESC").fetchall()
    else:
        rows = db.execute("SELECT * FROM iraq_public_submissions WHERE 1=1 ORDER BY id DESC").fetchall()
    rows = [dict(r) for r in rows]
    db.close()
    out = io.StringIO()
    wr = csv.writer(out)
    if slim:
        wr.writerow(['Reference Number', 'Full Name', 'Passport Number', 'CNIC', 'Status'])
        for r in rows:
            wr.writerow([r.get('reference_number', ''), r.get('full_name', ''), r.get('passport_number', ''), r.get('cnic', ''), r.get('status', '')])
        return out.getvalue()
    base_header = ['ID', 'Reference Number', 'Full Name', 'Passport Number', 'CNIC', 'Nationality', 'Date of Birth',
                   'Gender', 'Phone', 'WhatsApp', 'Email', 'Current City', 'Employer', 'Travel Route',
                   'Travel Purpose', 'Remarks', 'Status', 'Created At', 'Linked Batch ID',
                   'MOFA KW Portal Visible', 'MOFA KW Portal Sent At']
    if dispatch_join_cols:
        base_header.extend(['Dispatch ID', 'Note Verbale Number', 'Note Verbale Date', 'MOFA Sent Date (dispatch)'])
    wr.writerow(base_header)
    for r in rows:
        row_out = [r['id'], r['reference_number'], r['full_name'], r['passport_number'], r.get('cnic', ''), r['nationality'],
                   r['date_of_birth'], r['gender'], r['phone'], r['whatsapp'], r['email'],
                   r['current_city'], r['employer'], r['travel_route'], r['travel_purpose'],
                   r['remarks'], r['status'], r['created_at'], r['linked_batch_id'] or '',
                   r.get('mofa_kw_portal_visible', '') or '', r.get('mofa_kw_portal_sent_at', '') or '']
        if dispatch_join_cols:
            row_out.extend([r.get('_dispatch_id', ''), r.get('_nv_no', ''), r.get('_nv_date', ''), r.get('_dispatch_sent_date', '')])
        wr.writerow(row_out)
    return out.getvalue()

