                fp = APPROVAL_UPLOADS_DIR / row['filename']
                if not fp.exists():
                    self.send_html('<p>Stored approval PDF file is missing on server.</p>', 404); return
                body = fp.read_bytes()
                safe_filename = re.sub(r'[\r\n"]+', '_', str(row['original_filename'] or row['filename'] or 'approval.pdf'))
